INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1, 'Стяжка должна сохнуть 28 дней. Через две недели можно ходить, но класть плитку — только через месяц. Иначе трещины.', '2026-04-22 19:21:46.231733'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2, 'Перед началом работ сфотографируйте все стены с уровнем и рулеткой. Когда бригада скажет «так и было», покажете фото.', '2026-04-22 19:21:49.486453'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3, 'Никогда не давайте аванс больше 30%. Проверено на сотне объектов: кто дал 50% и больше — тот потерял и деньги, и нервы.', '2026-04-22 19:21:52.764297'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (4, 'Выравнивание стен. Под обои достаточно штукатурки по маякам с финишной шпаклёвкой в один слой. Под покраску нужно три слоя шпаклёвки и шлифовка каждой стены. Разница в цене — в два раза. Если бюджет ограничен, клейте обои. Они скроют мелкие дефекты. А покраска покажет каждую ямку и царапину.', '2026-04-22 19:21:56.040712'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (5, 'История. Заказчик купил ламинат 32 класса в коридор. Я предупреждал — нужен 33 или кварцвинил. Через полгода покрытие вздулось и пошло волнами. Теперь заказчик винит меня, хотя я советовал. Больше не работаю с теми, кто игнорирует рекомендации.', '2026-04-22 19:21:59.436277'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (6, 'Натяжные потолки и люстры. Если решите перевесить люстру сами — отключите автомат. Один клиент открутил старую, замкнуло, выбило пробки, а он в темноте прожёг потолок феном. Ремонт обошёлся в стоимость нового полотна.', '2026-04-22 19:22:03.024538'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (7, 'Дешевые материалы — дорогая переделка. Пример: акриловая затирка для швов плитки стоит 500 рублей, эпоксидная — 2000. Через год акриловая в душевой почернела и выкрошилась. Пришлось выскребать всё и перетирать заново.', '2026-04-22 19:22:06.282263'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (8, 'Правило трёх цветов в отделке: основной (60%), вторичный (30%), акцент (10%). Нарушаете — получается винегрет. Работает для любой комнаты.', '2026-04-22 19:22:09.456248'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (9, 'Зачем нужен технадзор? Чтобы бригада не заливала стяжку без демпферной ленты, не штробила несущие стены, не забывала про грунтовку. Моя знакомая сэкономила на технадзоре — теперь стены в новой квартире пошли трещинами, потому что рабочие переувлажнили раствор.', '2026-04-22 19:22:12.832909'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (10, 'Ошибка новичков: начинают ремонт с закупки мебели. А потом оказывается, что диван не влезает в проём, а шкаф стоит на кривом полу. Сначала черновая отделка, потом замеры, потом мебель.', '2026-04-22 19:22:16.211151'::timestamp, 1);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (11, 'Белая коробка — это не дизайн, это больница. Добавьте хотя бы один акцентный цвет.', '2026-04-22 19:22:19.504156'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (12, 'Самый частый спор с заказчиком: «хочу чёрные стены в спальне». В маленькой комнате это превратит её в пещеру. Исключение — если комната с двумя окнами или больше 25 метров.', '2026-04-22 19:22:23.399377'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (13, 'Забудьте про одну люстру посередине. Сделайте три сценария освещения: общий свет (люстра на диммере), рабочее освещение (треки или споты), акцентное (подсветка картин, ниш, растений). Цветовая температура: 2700K для спальни и гостиной, 4000K для кухни и кабинета, 3000K для коридора. И не экономьте на количестве розеток — их всегда не хватает.', '2026-04-22 19:22:26.660329'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (14, 'Кейс: заказчик хотел «как на пинтересте» — открытые полки на кухне вместо верхних шкафов. Сделали. Через месяц он понял, что вся посуда покрылась жирной пылью. Пришлось ставить стеклянные дверцы. Красиво, но непрактично.', '2026-04-22 19:22:30.156160'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (15, 'Правило для маленьких ванных: напольный унитаз с инсталляцией скрадывает 10 см глубины, но зато его легко мыть. Компромисс — компакт с закрытой ножкой.', '2026-04-22 19:22:33.477236'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (16, 'История. Клиентка настояла на розовых стенах в гостиной. Я предлагал бледно-розовый, она выбрала фуксию. Через месяц перекрасили в серый, потому что от яркого цвета болели глаза. 50 тысяч на ветер.', '2026-04-22 19:22:37.102130'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (17, 'Гардины до пола визуально поднимают потолок. Короткие шторы убивают любую дорогую отделку. Карниз крепите под самый потолок, а не над окном.', '2026-04-22 19:22:40.687695'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (18, 'В спальне розетки с USB — мастхэв. Но не над изголовьем, а сбоку от кровати, чтобы не торчали провода над лицом.', '2026-04-22 19:22:44.068437'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (19, 'Расстановка мебели по стенам — ошибка прошлого века. Попробуйте поставить диван в центре комнаты спинкой к рабочей зоне. Зонирование светом и коврами работает лучше, чем глухие перегородки.', '2026-04-22 19:22:49.286337'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (20, 'Самая частая ошибка при выборе краски: смотрят на маленький образец в магазине. Красьте кусок ватмана 30х30 и прикладывайте к разным стенам при разном освещении. Цвет на большой площади всегда темнее.', '2026-04-22 19:22:52.870613'::timestamp, 2);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (21, 'МДФ и ДСП — главные источники формальдегида в квартире. Массив, фанера или шпон — дороже, но дышать легче. Особенно в спальне и детской.', '2026-04-22 19:22:56.376217'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (22, 'Краски с нулевым содержанием летучих органических соединений стоят дороже, но вы не будете травиться месяц после ремонта. Акрил на водной основе — безопасен.', '2026-04-22 19:22:59.641887'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (23, 'Пробковый пол — лучшее для детской. Тёплый, амортизирует, не скользит, легко моется. Минус: дорого и боится когтей животных.', '2026-04-22 19:23:03.113366'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (24, 'Что реально опасно в отделке: дешёвый линолеум (фталаты и бензол), виниловые обои (не дышат, под ними плесень), клей с высоким содержанием толуола. На безопасных аналогах не экономьте.', '2026-04-22 19:23:06.303364'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (25, 'Льняные шторы регулируют влажность и не накапливают статическое электричество. Плюс смотрятся очень дорого, если правильно погладить.', '2026-04-22 19:23:09.869853'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (26, 'Органическая вата в качестве утеплителя — огнестойкая, дышащая, мыши её не грызут. Стекловату выбрасывайте, она колется и со временем проседает.', '2026-04-22 19:23:13.083494'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (27, 'Вентиляция с рекуперацией стоит своих денег. Форточки — прошлый век, они выстужают комнату, а не обновляют воздух. Особенно важно для герметичных окон ПВХ.', '2026-04-22 19:23:16.216247'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (28, 'Кейс: клиент хотел «натуральное дерево» на кухне. Поставил массив сосны без защиты. Через месяц от масла и воды остались пятна. Пришлось шлифовать и покрывать твёрдым маслом. Сосна слишком мягкая для кухни, нужен дуб или ясень.', '2026-04-22 19:23:19.597328'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (29, 'Эмали на водной основе пахнут меньше, сохнут быстрее и не желтеют со временем. Алкидные краски желтеют и токсичны до полного высыхания.', '2026-04-22 19:23:23.093056'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (30, 'Если бюджет не тянет всё натуральное — сделайте экологичными хотя бы спальню и кухню. В прихожей и коридоре можно использовать качественные, но более дешёвые материалы.', '2026-04-22 19:23:26.765431'::timestamp, 3);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (31, 'Медная проводка сечением 2.5 квадрата на розетки — минимум. Алюминий под запретом уже 20 лет.', '2026-04-22 19:23:30.042629'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (32, 'Самая частая причина пожаров после ремонта — плохая скрутка и отсутствие УЗО. Дифавтоматы класса А — ваша страховка.', '2026-04-22 19:23:33.308342'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (33, 'Ставьте больше розеток. На кухне — 5-6 двойных. В гостиной — по 3 на каждую стену. Лучше перебдеть, чем потом удлинители по плинтусу.', '2026-04-22 19:23:36.289541'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (34, 'Ванная комната: все розетки через УЗО на 10 мА (не 30!), влагозащищённые крышки IP44, отдельные автоматы на стиралку и бойлер, сечение кабеля 3х2.5. Никаких удлинителей из соседней комнаты.', '2026-04-22 19:23:39.617484'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (35, 'Диммеры для светодиодных ламп нужны специальные. Обычные будут моргать или жужжать. Проверяйте совместимость на сайте производителя.', '2026-04-22 19:23:42.917611'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (36, 'Не ведите кабель в стяжке без гофры. Бетон со временем разрушает изоляцию, и короткое замыкание в полу — весёлая перспектива.', '2026-04-22 19:23:45.810657'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (37, 'Кондиционер требует отдельного автомата 16А и кабеля 3х2.5. Если его сажают на общую розетку — через год плавятся контакты.', '2026-04-22 19:23:49.394465'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (38, 'История. Заказчик попросил сделать «подешевле», без УЗО. Через месяц его жена ударилась током от стиральной машины — босиком на мокром полу. Хорошо, что сердце выдержало. После этого он доплатил за полную замену щитка.', '2026-04-22 19:23:52.616389'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (39, 'Заземление — не опция. Если в доме нет контура — сделайте свой. Спасёт жизнь при пробое фазы на корпус холодильника или бойлера.', '2026-04-22 19:23:55.973339'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (40, 'Встраиваемый свет: шаг между точками не больше 60 см для равномерного освещения. Часто экономят — получается тёмная комната с отдельными прожекторами.', '2026-04-22 19:23:59.129929'::timestamp, 4);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (41, 'Качественные смесители: Grohe, Hansgrohe, Ceza. Китайский кран за 800 рублей потечёт через полгода.', '2026-04-22 19:24:02.926517'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (42, 'Полипропиленовые трубы с армировкой стекловолокном лучше, чем с алюминием. Не расслаиваются и легче паяются.', '2026-04-22 19:24:06.217293'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (43, 'При монтаже унитаза не жалейте силикона. Но не заливайте сливное отверстие, иначе потом отдирать.', '2026-04-22 19:24:09.273912'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (44, 'Ошибки при монтаже водяного тёплого пола: длина контура более 80 метров (обратка холодная), укладка без теплоизоляции (греете перекрытие), шаг более 15 см (холодные зоны), заливка без опрессовки (потекут — переделка дороже в 10 раз).', '2026-04-22 19:24:12.864347'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (45, 'Трап в душевой — лучшее решение для ванной. Убирает порожек, вода не застаивается. Нужен уклон пола не менее 1 см на метр.', '2026-04-22 19:24:17.600935'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (46, 'Не экономьте на фитингах. Дешёвые латунные тройники часто имеют микротрещины. Проявятся через месяц — затопление соседей.', '2026-04-22 19:24:20.743867'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (47, 'Самый частый геморрой — смещение выводов для смесителя в ванной. Допуск 2 мм, а делают на глаз. Потом смеситель не налезает.', '2026-04-22 19:24:24.315346'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (48, 'История. Вызвали на затопление из-за лопнувшего шланга под мойкой. Оказалось, хозяин поставил дешёвый шланг в оплётке из алюминия. Влага разъела оплётку, и шланг лопнул. Только нержавеющая оплётка или силикон.', '2026-04-22 19:24:27.998708'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (49, 'Сифон с разборной колбой — спасение. Иначе когда волосы забьются, будете откручивать всё целиком и вдыхать запах.', '2026-04-22 19:24:31.085561'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (50, 'Перед зашивкой труб в короба обязательно опрессовка давлением 1.5 от рабочего. Потекут — переделывать с разбитой плиткой.', '2026-04-22 19:24:34.570325'::timestamp, 5);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (51, 'Составьте смету до первого удара перфоратором. Добавьте резерв 20% на непредвиденные расходы.', '2026-04-22 19:24:37.932845'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (52, 'Самая большая статья экономии — не материалы, а работа. Не ведитесь на «дёшево», потом переделка дороже.', '2026-04-22 19:24:41.718547'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (53, 'Как не разориться: определите класс (эконом, комфорт, премиум). Эконом — краска и ламинат. Премиум — штукатурка под покраску и паркет. Закладывайте стоимость работ в 50-70% от материалов.', '2026-04-22 19:24:45.098866'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (54, 'Скрытые работы (стяжка, электрика, сантехника) — 30% бюджета. На них не экономят никогда. Отделка — 50%. Мебель и техника — 20% сверху.', '2026-04-22 19:24:48.683453'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (55, 'Покупка материалов самостоятельно? Только если вы профессионал. Иначе купите не то количество или не ту фракцию.', '2026-04-22 19:24:51.550475'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (56, 'Акции на стройматериалы часто с подвохом: товар с истекшим сроком годности или битый. Проверяйте каждую позицию.', '2026-04-22 19:24:55.031251'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (57, 'Договаривайтесь о поэтапной оплате: 30% аванс, 40% после черновой, 30% после приёмки. Никогда не платите 100% вперёд.', '2026-04-22 19:24:58.325161'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (58, 'Кейс. Заказчик повёлся на «ремонт под ключ за 600 тысяч» для двушки. В процессе выяснилось, что это только черновая отделка. Итоговая цена выросла до 1.2 млн. Читайте договор.', '2026-04-22 19:25:01.995412'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (59, 'Самые дорогие ошибки: перепланировка без согласования (штраф и возврат), неправильный замер дверей (нестандарт +300%), замена стяжки, когда можно выровнять наливным полом.', '2026-04-22 19:25:04.879010'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (60, 'Налоговый вычет за ремонт возможен только при покупке новостройки без отделки. Сохраняйте все чеки и акты.', '2026-04-22 19:25:08.465305'::timestamp, 6);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (61, 'В малогабаритке каждый сантиметр на счету. Забудьте про распашные двери — только раздвижные.', '2026-04-22 19:25:12.234961'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (62, 'Используйте вертикальное пространство: шкафы до потолка, полки под потолком. Мёртвые зоны превращайте в хранение.', '2026-04-22 19:25:15.410028'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (63, 'Светлые стены + зеркала + глянцевый потолок визуально расширяют комнату. Матовый и тёмный — убивают.', '2026-04-22 19:25:18.890404'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (64, 'Что реально работает в малогабаритке: кровать-подъёмник с вертикальным механизмом (горизонтальный ломается), стол-панно на стене, выдвижной диван с ортопедическим матрасом, подоконник-стол шириной 60 см.', '2026-04-22 19:25:23.209221'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (65, 'Встроенная техника — мастхэв. Посудомойка 45 см вместо 60, холодильник под столешницу.', '2026-04-22 19:25:26.775547'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (66, 'Используйте один и тот же цвет пола во всей квартире. Стыки разных покрытий съедают пространство.', '2026-04-22 19:25:30.565645'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (67, 'Зеркальные фасады шкафов — рабочий приём. Но напротив кровати не ставьте, будете пугаться ночью.', '2026-04-22 19:25:33.918289'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (68, 'История. Заказчик настаивал на острове на кухне в 18 метрах общей площади. Вместо этого сделали полуостров, примыкающий к стене. И рабочая зона, и стол. Клиент был доволен.', '2026-04-22 19:25:36.826793'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (69, 'Ошибки в малогабаритке: слишком много мелкого декора (визуальный шум), громоздкая люстра (съедает высоту), длинные шторы (уменьшают пространство). Лаконичность — друг.', '2026-04-22 19:25:40.600334'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (70, 'Перила и стойки вместо глухих стен в зонировании. Воздухопроницаемость важнее изоляции в маленькой квартире.', '2026-04-22 19:25:44.185395'::timestamp, 7);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (71, 'В ванной главное — гидроизоляция. Два слоя обмазочной на стены и пол с заходом на 30 см. Иначе плесень.', '2026-04-22 19:25:48.176016'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (72, 'Подогрев пола в ванной — не роскошь, а необходимость. Иначе зимой будете бегать по ледяному кафелю.', '2026-04-22 19:25:51.146828'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (73, 'Ниша в душевой лучше полки. Убирает углы и мыльные разводы. Главное — уклон внутрь, чтобы вода стекала.', '2026-04-22 19:25:54.480338'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (74, 'Как выбрать сантехнику: унитаз подвесной легко мыть, но дороже. Раковина тюльпан практична, но теряется место. Ванна акриловая тёплая, но царапается. Чугун холодный, но вечный. Душевая лучше открытая со стеклом и трапом.', '2026-04-22 19:25:58.124189'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (75, 'Швы между плиткой обрабатывайте эпоксидной затиркой. Цементная почернеет и потрескается во влажной зоне.', '2026-04-22 19:26:01.403552'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (76, 'Вентиляция в ванной — отдельный вытяжной канал. Если совмещена с кухней, запахи будут гулять.', '2026-04-22 19:26:04.663837'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (77, 'Потолок в ванной: натяжной ПВХ не боится пара и брызг. Реечный алюминиевый дорого, но стильно.', '2026-04-22 19:26:08.145194'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (78, 'Кейс. Клиент решил сэкономить на гидроизоляции под душевой. Через 3 месяца соседи снизу залило. Пришлось снимать плитку, сушить стяжку месяц, переделывать. Экономия 5 тысяч вылилась в 150.', '2026-04-22 19:26:11.830335'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (79, 'Если места мало, ставьте душевой угол 80х80 вместо ванны. А для детей есть складные ванночки.', '2026-04-22 19:26:15.106060'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (80, 'Дверь в ванную — только влагостойкая. МДФ разбухнет. ПВХ или стекло — лучший выбор.', '2026-04-22 19:26:18.280962'::timestamp, 8);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (81, 'Треугольник «холодильник-мойка-плита» — основа эргономики. Расстояние между ними не больше 1.2 м и не меньше 0.6 м.', '2026-04-22 19:26:22.687400'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (82, 'Фартук из закалённого стекла или керамогранита на всю стену. Плитка красиво, но швы мыть тяжело.', '2026-04-22 19:26:26.372918'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (83, 'Вытяжка должна быть шире плиты на 10 см с каждой стороны. Иначе запах уходит мимо.', '2026-04-22 19:26:29.956374'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (84, 'Организация хранения на кухне: выдвижные ящики вместо полок, угловые карусели, рейлинги на фартук, бутылочница в узкую щель, шкафы до потолка. Открытые полки над рабочей зоной — всё покрывается жирной пылью.', '2026-04-22 19:26:33.296010'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (85, 'Столешница из искусственного камня — лучшее соотношение цена/качество. Натуральный гранит холодный и впитывает масло.', '2026-04-22 19:26:37.023379'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (86, 'Розетки на фартуке: 4-5 штук на разной высоте. Для блендера, чайника, миксера. С крышками от брызг.', '2026-04-22 19:26:40.417007'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (87, 'Мойка из нержавейки практична и дёшева. Гранитная красиво, но тяжёлая и бьёт посуду.', '2026-04-22 19:26:44.193776'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (88, 'История. Заказчик захотел варочную панель на острове. Сделали, но забыли про мощную вытяжку. Теперь готовит только когда никого нет, потому что вытяжка над головой мешает общаться.', '2026-04-22 19:26:47.671043'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (89, 'Свет над рабочей зоной: светодиодная лента под верхними шкафами + точечные светильники. Одна люстра посередине не подходит — будете стоять спиной к свету.', '2026-04-22 19:26:50.947575'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (90, 'Оставляйте зазор 5 см между холодильником и стеной для вентиляции. Иначе компрессор будет работать постоянно.', '2026-04-22 19:26:54.120215'::timestamp, 9);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (91, 'Утепление балкона: экструдированный пенополистирол 50 мм по всем поверхностям, включая пол и парапет. Минеральная вата боится влаги.', '2026-04-22 19:26:57.499791'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (92, 'На балконе нельзя старить тяжёлую мебель без усиления плиты. Максимальная нагрузка — 200 кг на квадратный метр.', '2026-04-22 19:27:00.777399'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (93, 'Остекление балкона: холодное алюминиевое или тёплое ПВХ. Для жилого помещения только ПВХ с двухкамерным стеклопакетом.', '2026-04-22 19:27:04.360365'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (94, 'Как превратить балкон в кабинет: утепление, тёплый пол электрический, розетка, стол-подоконник, светодиодный свет. Площадь от 3 метров хватит для работы за ноутбуком.', '2026-04-22 19:27:07.843321'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (95, 'Водоснабжение на балконе — только если перенесли радиатор с разрешения. Самовольный перенос батареи на балкон незаконен и приведёт к штрафу.', '2026-04-22 19:27:11.529579'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (96, 'Пол на балконе: керамогранит (не боится перепадов температур), кварцвинил (тёплый), доска из лиственницы (красиво, но требует ухода). Ламинат нельзя — поведёт от влаги.', '2026-04-22 19:27:15.285603'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (97, 'История. Клиент утеплил балкон, поставил диван, повесил телевизор. Через год обнаружил, что конденсат на окнах и плесень на стенах. Забыл про пароизоляцию и вентиляцию. Пришлось переделывать.', '2026-04-22 19:27:18.491011'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (98, 'Хранение на балконе: закрытые шкафы до потолка. Открытые полки — всё покрывается пылью и копотью, если рядом дорога.', '2026-04-22 19:27:21.563790'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (99, 'Зонирование длинного балкона: выделите зону отдыха (шезлонг, столик), зону хранения (шкаф), зону растений (стеллаж с подсветкой).', '2026-04-22 19:27:25.149041'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (100, 'Самая частая ошибка: остекление без согласования с архитектурным надзором. В новостройках за это штрафуют и требуют демонтажа.', '2026-04-22 19:27:28.936288'::timestamp, 10);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (101, 'Тест-драйв нового Geely Monjaro: реальный расход по трассе 9.5 л на 100 км, заявлено 7.8. Маркетинг, ничего личного.', '2026-04-22 19:27:39.787817'::timestamp, 11);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (102, 'Почему китайские авто за два года теряют 40% стоимости? Переизбыток моделей, демпинг дилеров и страх перед гарантией.', '2026-04-22 19:27:43.279688'::timestamp, 11);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (103, 'Сравнил Mazda CX-5 и Toyota RAV4: Мазда управляется лучше, но у Тойоты клиренс выше на 2 см. Для бездорожья выбирайте вторую.', '2026-04-22 19:27:46.857246'::timestamp, 11);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (104, 'Длинный опыт эксплуатации Kia Rio 1.6 на автомате. За 5 лет и 120 тыс. км: заменил задние амортизаторы на 90 тыс., сайлентблоки передних рычагов на 105 тыс. Масло лил каждые 8 тыс. — двигатель жив, коробка держит. Единственное — кузов начал цвести на порогах. Бюджетный седан, который честно отрабатывает свои деньги.', '2026-04-22 19:27:50.973523'::timestamp, 11);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (105, 'Топ-5 ошибок при тест-драйве: не проверять работу кондиционера на холодную, не включать все режимы АКПП, не слушать подвеску на лежачих полицейских, не смотреть люфт руля на скорости, не открывать капот после горячей поездки. Делайте всё это — потом не пожалеете.', '2026-04-22 19:27:54.534801'::timestamp, 11);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (106, 'Почему масло 5W-30 лучше 0W-20 для большинства атмосферных моторов? Вторая цифра отвечает за вязкость при рабочих температурах, и 30 защищает лучше при высоких нагрузках.', '2026-04-22 19:27:58.634189'::timestamp, 12);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (107, 'Признаки умирающего турбокомпрессора: синий дым на холодную, масложор более 0.5 л на 1000 км, свист при разгоне. Не тяните — вскроет и заклинит, и двигатель каюк.', '2026-04-22 19:28:02.218292'::timestamp, 12);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (108, 'Можно ли промывать двигатель при замене масла? Если льешь ту же марку и интервал не более 10 тыс. — не надо. При переходе с минералки на синтетику или после покупки б/у авто — только мягкая пятиминутная промывка, не агрессивная.', '2026-04-22 19:28:05.697106'::timestamp, 12);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (109, 'Расскажу историю. Приехал клиент с Nissan Qashqai 2.0: стук в двигателе. Вскрываем — разрушен вкладыш шатуна. Оказалось, предыдущий «мастер» залил масло 10W-40 вместо 5W-30 и перепутал фильтр — с другим давлением открытия. В итоге замена двигателя в сборе за 280 тысяч. Экономия на правильном масле вышла боком.', '2026-04-22 19:28:09.796180'::timestamp, 12);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (110, 'Коротко про цепи ГРМ: ресурс оригинальной цепи на BMW N57 — 150-200 тыс. км. Если слышите дребезжание на холодную или ошибки по фазорегуляторам — не ждите обрыва, меняйте сразу с башмаками и натяжителем.', '2026-04-22 19:28:13.312429'::timestamp, 12);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (111, 'Заряжать электромобиль до 100% каждый день — убивать батарею. Оптимально 20-80%, а 100% только перед дальней поездкой.', '2026-04-22 19:28:16.755007'::timestamp, 13);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (112, 'Тесла Model 3 против BYD Seal: китаец дешевле на 700 тысяч, но теряет в софте и автопилоте. Зато BYD строит свои батареи LFP — они живут дольше и безопаснее.', '2026-04-22 19:28:19.874046'::timestamp, 13);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (113, 'На быстрых зарядках мощностью 150 кВт батарея деградирует быстрее на 15-20% за 5 лет. Если заряжаться дома на 7 кВт, потеря ёмкости минимальна.', '2026-04-22 19:28:23.207520'::timestamp, 13);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (114, 'Длинный опыт: езжу на Kia EV6 уже 2 года, пробег 45 тыс. км. Зимой запас хода падает на 35% (в мороз -25°C), летом держит обещанные 480 км. Из болячек: разбило нижнюю защиту батареи об лёд — ремонт 90 тысяч. Теперь поставил стальную пластину. Экономия на топливе огромная, но готовьтесь к дорогому каско и страху уронить батарею.', '2026-04-22 19:28:26.687892'::timestamp, 13);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (115, 'Чего ждать от электромобилей в 2025-м? Твердотельные батареи от Toyota обещают запас 1200 км и зарядку за 10 минут. Но цена будет запредельная — первые модели от 8 миллионов. Пока литий-железо-фосфат — король практичности.', '2026-04-22 19:28:30.783317'::timestamp, 13);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (116, 'На скользкой дороге газом тормозят, а не педалью тормоза. Сбросьте газ — автомобиль начнёт поворачивать, плавно нажмите — выровняется.', '2026-04-22 19:28:34.266954'::timestamp, 14);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (117, 'Почему новички боятся заноса? Потому что не умеют смотреть туда, куда хотят поехать. Взгляд в поворот — руки сами выкрутят руль.', '2026-04-22 19:28:37.295690'::timestamp, 14);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (118, 'Торможение двигателем на механике: перед крутым спуском включите вторую передачу и отпустите газ. Колодки не перегреваются, управление стабильнее.', '2026-04-22 19:28:41.346070'::timestamp, 14);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (119, 'Мой опыт инструктажа: пришёл ученик на Subaru BRZ, жаловался, что машина не слушается. Оказалось, он держал руль двумя пальцами и боялся давить газ в повороте. После часа упражнений на сухом льду полигона он понял: чтобы машина повернула, нужно дозированное ускорение. Теперь ездит быстрее меня.', '2026-04-22 19:28:45.119033'::timestamp, 14);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (120, 'Короткий чек-лист для первого трек-дня: проверьте давление в шинах (на треке снижайте до 2.0), залейте тормозную жидкость DOT 5.1, снимите всё лишнее из салона, возьмите с собой второй комплект колодок. И главное — не включайте азарт в первой сессии, дайте автомобилю и резине прогреться.', '2026-04-22 19:28:49.009506'::timestamp, 14);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (121, 'Керамическое покрытие стоит своих денег только если полировка сделана идеально. Без неё керамика зафиксирует все царапины, и машина будет выглядеть хуже, чем до.', '2026-04-22 19:28:52.715630'::timestamp, 15);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (122, 'Чем мыть машину зимой? Бесконтактная мойка с пеной для холодного времени (у нее ниже замерзание). Потом ручная мойка в тёплом боксе. И обязательно продувайте замки и дверные уплотнители — иначе утром не откроете.', '2026-04-22 19:28:56.296885'::timestamp, 15);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (123, 'Самые убитые места ЛКП на современных авто: передняя кромка капота (абразив на трассе), пороги (песок и гравий из-под колёс), арки (соль и реагенты). Оклейка полиуретаном этих зон продлевает жизнь краске в разы.', '2026-04-22 19:29:00.253334'::timestamp, 15);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (124, 'Кейс: клиент пригнал BMW X5 после зимы — вся краска в кратерах, будто кислотой полили. Оказалось, мыл на обычной мойке, где щётками с песком. Полировка не спасла — только перекрас всех дверей за 250 тысяч. С тех пор сам вожу машину только на ручную мойку с микрофиброй.', '2026-04-22 19:29:04.187453'::timestamp, 15);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (125, 'Как выбрать воск? Жидкий воск наносится за 30 минут, но держится 2-3 мойки. Пастообразный — 4 часа работы, эффект до 6 месяцев. Если машина не стоит в гараже — берите жидкий и обновляйте раз в месяц.', '2026-04-22 19:29:07.856210'::timestamp, 15);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (126, 'Чип-тюнинг атмосферного двигателя даст 5-7 л.с. и лучшую отзывчивость на газ, но не ждите 20 сил — это маркетинг.', '2026-04-22 19:29:11.845113'::timestamp, 16);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (127, 'Почему я против «колхозного» занижения пружинами? Геометрия подвески ломается, амортизаторы работают вне диапазона, и через 10 тыс. км их менять.', '2026-04-22 19:29:15.546029'::timestamp, 16);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (128, 'Самый полезный тюнинг для зимы — подогрев руля и форсунок омывателя. А самый бесполезный — светодиодные ленты в салоне, которые слепят ночью.', '2026-04-22 19:29:19.339315'::timestamp, 16);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (129, 'История: клиент хотел выхлоп «громче» на Toyota Mark II. Поставил прямоточную банку без резонатора. В итоге на низах потерял тягу, а при 4000 об/мин в салоне стоял гул, от которого закладывало уши. Через месяц вернулся, поставил штатный глушитель с перепускным клапаном. Громко только на высоких оборотах, но динамика не пострадала.', '2026-04-22 19:29:22.904515'::timestamp, 16);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (130, 'Длинный тред про колёсные диски. Литые легче штампованных на 20-30%, что уменьшает неподрессоренные массы и улучшает управляемость. Кованые ещё легче, но дороже в 3 раза. Размер: на 2 дюйма больше штатного — красиво, но жестче на ямах. Ширина: +1 дюйм к стоку — можно ставить резину шире, улучшается сцепление, но растёт расход топлива. Мой выбор для ежедневной езды — литьё на один размер больше штатного, без экстремальных вылетов.', '2026-04-22 19:29:26.490010'::timestamp, 16);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (131, 'Как проверить пробег по косвенным признакам: стёртая кожа на руле и кресле — 100+ тыс., потёртости на кнопках аудиосистемы — 80+, износ педалей — 150+. Суммируйте всё.', '2026-04-22 19:29:30.481593'::timestamp, 17);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (132, 'Почему не стоит брать BMW 5 серии E60 с пробегом за 400 тысяч? Потому что ремонт подвески и АКПП ZF выльется в ещё 300, и будете чинить каждый месяц.', '2026-04-22 19:29:34.273044'::timestamp, 17);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (133, 'Короткий гид по покупке Hyundai Solaris б/у: после 2015 года поменяли слабые сайлентблоки передних рычагов, и мотор G4FG стал надёжнее. Берите 1.6 на механике, автомат умирает к 150 тыс.', '2026-04-22 19:29:38.182499'::timestamp, 17);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (134, 'Кейс: клиент позвал на осмотр Skoda Octavia A7 1.8 TSI 2014 года. Продавец божился, что пробег 90 тыс., а сам я нашёл сервисную книжку с записью о замене цепи ГРМ на 180 тысячах. Плюс краска на капоте была слоёной — явно красили после ДТП. Посоветовал уйти. Через месяц клиент позвонил: купил другую, но уже после проверки на подъёмнике. Сэкономил около 200 тысяч на будущих ремонтах.', '2026-04-22 19:29:42.155852'::timestamp, 17);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (135, 'Что обязательно проверить перед покупкой: толщиномером краску (все детали должны быть в пределах 100-200 мкм, если больше — красили), сканнером OBD2 ошибки (даже если лампочка check не горит, могут быть сохранённые), поддомкратить каждое колесо и покачать (люфт в шаровой или ступице). И никогда не верьте фразам «битая вся, но дешёво».', '2026-04-22 19:29:45.493505'::timestamp, 17);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (136, 'Для бездорожья важнее клиренс, чем привод. Toyota Land Cruiser 200 с 22 см просвета пройдёт там, где Range Rover с 18 сядет на брюхо.', '2026-04-22 19:29:48.810847'::timestamp, 18);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (137, 'Почему пикапы так популярны в США? Потому что рамная конструкция, огромный багажник и налог на машины как на легковые. У нас же их считают грузовиками, поэтому пошлины высокие.', '2026-04-22 19:29:51.908866'::timestamp, 18);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (138, 'Внедорожные шины: Mud Terrain (MT) — для грязи, но шумят на трассе. All Terrain (AT) — универсалы. Если ездите по городу 90% времени, ставьте AT, MT только для трофи.', '2026-04-22 19:29:55.364706'::timestamp, 18);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (139, 'Длинный отчёт об экспедиции на УАЗ Патриот на Байкал. Проехали 5000 км, из них 1000 по грунтовкам и пескам. Патриот с родными мостами выдержал, но подвеска убилась в хлам — заменили все сайлентблоки и стойки стабилизатора. Салон не предназначен для дальних поездок: кресла жесткие, шумоизоляции ноль. Зато полный привод с блокировками тащил везде, а лебёдка выручала трижды. Совет: берите Патриот только если готовы к ежемесячным мелким доработкам и не боитесь расхода 18 литров.', '2026-04-22 19:29:58.845936'::timestamp, 18);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (140, 'Что выбрать между Toyota Hilux и Mitsubishi L200? Хайлюкс надёжнее, но жёсткая подвеска. Л200 мягче, но кузов гниёт быстрее. Для севера — Hilux, для юга — L200, если обработать антикором.', '2026-04-22 19:30:02.023807'::timestamp, 18);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (141, 'Восстановление ВАЗ 2107: самый геморрой — найти оригинальные детали кузова без китайского металла. Капот «оригинал» из Китая гнётся пальцем.', '2026-04-22 19:30:06.630980'::timestamp, 19);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (142, 'Почему классические Mercedes W124 считаются вечными? Многорычажка сзади, рядная шестёрка M104, оцинковка кузова. Но только если не убитый.', '2026-04-22 19:30:10.390161'::timestamp, 19);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (143, 'Короткий совет по уходу за ретро-автомобилем: каждую весну обрабатывайте скрытые полости антикором, храните в сухом гараже с вентиляцией, заводите раз в неделю, чтобы масло не стекло.', '2026-04-22 19:30:14.105533'::timestamp, 19);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (144, 'История реставрации Volvo 240. Привёз из Финляндии кузов без гнили за 150 тысяч. Потратил два года и около 700 тысяч на переборку двигателя (B230), коробки (МКПП), замену проводки и салона. Сейчас машина как новая, езжу каждый день. Что понял: восстанавливать имеет смысл только редкие модели или эмоционально значимые. Вложения не окупятся никогда, зато кайф от вождения — бесценный.', '2026-04-22 19:30:18.215421'::timestamp, 19);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (145, 'Где искать запчасти на старые европейские авто? Разборки в Германии (eBay-Kleinanzeigen), специализированные форумы, барахолки в соцсетях. Китайское литьё и пластик — зло, ставят только на продажу, а не для себя.', '2026-04-22 19:30:21.783621'::timestamp, 19);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (146, 'Если у вас угнали машину, а вы заявили в полицию через 3 дня — шансы найти стремится к нулю. Подавайте заявление в первые же часы, лучше через приложение МВД, чтобы зафиксировать время.', '2026-04-22 19:30:25.061112'::timestamp, 20);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (147, 'Что делать при ДТП без пострадавших: заполните европротокол, сфотографируйте расположение авто и повреждения, не перемещайте машины до приезда ГИБДД. Если второй водитель пьян — вызывайте инспектора.', '2026-04-22 19:30:28.850556'::timestamp, 20);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (148, 'Срок исковой давности по ОСАГО — 3 года. Но если страховая затягивает выплату, пишите досудебную претензию, а потом в суд. Финансовая санкция и неустойка часто превышают саму выплату.', '2026-04-22 19:30:32.947772'::timestamp, 20);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (149, 'Кейс из практики: клиент попал в ДТП, виновник скрылся. Каско отказалось платить, потому что не было справки из ГИБДД о ДТП. Я подал заявление о розыске, через месяц нашли виновника — он был пьян и без прав. Суд встал на сторону клиента, страховая виновника выплатила 1.2 млн рублей плюс неустойку. Совет: всегда добивайтесь розыска, не бросайте дело.', '2026-04-22 19:30:36.754455'::timestamp, 20);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (150, 'Как наказать продавца за скрученный пробег? Если у вас есть документы, подтверждающие реальный пробег (сервисная книжка, диагностика ОД), можно подать в суд по ст. 14.7 КоАП (обман потребителя). Суд обязывает продавца вернуть разницу в цене. Мой рекорд — взыскал 450 тысяч рублей за скрученные 120 тыс. км на BMW X5.', '2026-04-22 19:30:40.010565'::timestamp, 20);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (151, 'Как снизить расход топлива на 15%: держите давление в шинах 2.2-2.4 (не 2.0!), уберите ненужный хлам из багажника, не грейте двигатель на месте дольше минуты.', '2026-04-22 19:30:44.374944'::timestamp, 21);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (152, 'Почему на механике расход меньше? Потому что вы сами выбираете обороты. Оптимальный режим для экономии — 1500-2000 об/мин, передача максимально возможная без детонации.', '2026-04-22 19:30:47.813798'::timestamp, 21);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (153, 'Кондиционер летом повышает расход на 0.5-1 л на 100 км. Открытые окна на скорости свыше 80 км/ч — ещё больше из-за аэродинамики. Так что лучше пользоваться кондиционером.', '2026-04-22 19:30:51.042490'::timestamp, 21);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (154, 'Длинный эксперимент: месяц ездил на Toyota Camry 3.5 с целью минимизировать расход. Старт-стоп на светофорах, плавные разгоны, круиз-контроль на трассе 90 км/ч, отключил обогрев зеркал и сидений летом. Итог: средний расход упал с 12.5 до 9.8 л на 100 км. Минус — меня бесили медленные обгоны, и я вернулся к обычному стилю. Но если вам критична каждая копейка — метод работает.', '2026-04-22 19:30:54.576487'::timestamp, 21);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (155, 'Какое топливо экономичнее: 92 или 95? На современных двигателях с высокой степенью сжатия 95 даёт чуть больше мощности, что позволяет ехать на меньших оборотах. Но разница в расходе редко превышает 2-3%, а цена 95 выше на 5-7%. Выгоднее лить 92, если двигатель это позволяет.', '2026-04-22 19:30:58.340018'::timestamp, 21);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (156, 'Стук спереди при проезде неровностей — чаще всего втулки стабилизатора. Менять их проще и дешевле всего, не надо менять амортизаторы.', '2026-04-22 19:31:01.927392'::timestamp, 22);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (157, 'После замены рычагов или рулевых наконечников обязательно делайте развал-схождение. Даже если ничего не трогали, каждые 20 тыс. км проверяйте.', '2026-04-22 19:31:05.306755'::timestamp, 22);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (158, 'Признак уставших пружин: машина просела спереди на 2-3 см, кренится в поворотах, часто пробивает отбойники. Меняйте парами, не по одной.', '2026-04-22 19:31:08.478810'::timestamp, 22);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (159, 'История: клиент жаловался на сильную вибрацию при 100 км/ч. Сделал балансировку дважды — не помогло. Я поднял машину и обнаружил, что одно из колёс погнуто изнутри — предыдущий ремонт диска был некачественным. Заменил диск — вибрация ушла. Совет: если балансировка не помогает, проверяйте геометрию дисков и шин на специальном станке.', '2026-04-22 19:31:12.162748'::timestamp, 22);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (160, 'Короткий ликбез по амортизаторам. Газомасляные жёстче и лучше на треке, но менее комфортны. Масляные мягче, но быстрее перегреваются. Для обычных дорог берите масляные Kayaba или Bilstein, они прослужат лет 5. При замене обязательно меняйте в сборе с пыльниками и отбойниками, иначе новый амортизатор убьётся за год.', '2026-04-22 19:31:15.659340'::timestamp, 22);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (161, 'Вариатор Jatco на Nissan не любит пробуксовок — металлический ремень проскальзывает и умирает за 30 тыс. км. И масло меняйте каждые 40 тыс., а не 60, как пишут.', '2026-04-22 19:31:19.126087'::timestamp, 23);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (162, 'Как проверить АКПП при покупке: заведите машину, прогрейте коробку, переключите D->R->D с паузой 2 секунды. Если толчки — гидроблок или фрикционы изношены.', '2026-04-22 19:31:22.403690'::timestamp, 23);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (163, 'Механику можно и нужно ремонтировать: при износе синхронизаторов или подшипников дешевле перебрать, чем менять всю коробку.', '2026-04-22 19:31:25.885396'::timestamp, 23);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (164, 'Кейс: приехал Mercedes E350 с 7G-Tronic на диагностике: рывки при переключении 2-3. Диагностика показала низкое давление в гидроблоке. Разобрали — соленоиды забиты продуктами износа фрикционов. Промыли гидроблок, заменили соленоиды, поменяли масло. Рывки ушли, клиент сэкономил 150 тысяч вместо замены гидроблока в сборе. Мойте гидроблок каждые 100 тыс. км, даже если коробка работает нормально.', '2026-04-22 19:31:29.079917'::timestamp, 23);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (165, 'Почему робот DSG на Volkswagen лучше вариатора? DSG (с мокрыми сцеплениями) выдерживает момент до 500 Нм, переключается быстро, и его можно обслуживать. Вариатор слаб и капризен, но плавный. Для города и спокойной езды вариатор ок, для драйва — DSG.', '2026-04-22 19:31:32.439492'::timestamp, 23);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (166, 'Самая частая ошибка бортового компьютера — P0171 (бедная смесь). Чаще всего виноват подсос воздуха через трещину во впускном коллекторе или грязный MAF-датчик.', '2026-04-22 19:31:36.036633'::timestamp, 24);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (167, 'Как выбрать OBD2 сканер? Для личного пользования хватит ELM327 за 1000 рублей с приложением Torque. Для диагностики сложных ошибок — специальный под ваш бренд (например, VCDS для VAG).', '2026-04-22 19:31:39.606242'::timestamp, 24);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (168, 'Глючит магнитола или климат? Частая причина — просадка напряжения в бортовой сети. Проверьте аккумулятор и генератор, а не меняйте блоки управления.', '2026-04-22 19:31:43.191924'::timestamp, 24);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (169, 'История: Hyundai Solaris 2016 не заводился, стартер крутил, но не схватывал. Механик грешил на бензонасос. Я подключил сканер, увидел ошибку по иммобилайзеру. Оказалось, чип в ключе рассыпался от старости. Заменил ключ — машина завелась. Электроника может обмануть любого, всегда читайте ошибки перед заменой деталей.', '2026-04-22 19:31:46.980021'::timestamp, 24);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (170, 'Длинный тред про CAN-шину. Если не в курсе, CAN-шина — это сеть, по которой общаются все блоки автомобиля. При плохом контакте в фишке или перетирании провода могут возникать глюки: не работают стеклоподъёмники, загорается «чек» без причины. Первым делом прозванивайте CAN-линии тестером, а не меняйте блоки. И никогда не цепляйтесь к проводам CAN для питания дополнительных приборов — собьёте протокол.', '2026-04-22 19:31:50.565553'::timestamp, 24);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (171, 'Зимой не глушите двигатель сразу после быстрой езды — дайте ему поработать минуту на холостых, чтобы турбина остыла. Иначе коксуется масло.', '2026-04-22 19:31:54.045441'::timestamp, 25);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (172, 'Почему аккумулятор умирает в мороз? Потому что ёмкость падает на 30-40%, а стартеру нужно больше энергии. Ставьте батарею с током холодного пуска не менее 500 А.', '2026-04-22 19:31:57.321040'::timestamp, 25);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (173, 'Как облегчить запуск в -30°C: выжмите сцепление (если механика), включите дальний свет на 10 секунд (прогреет электролит), потом выключите и крутите стартер.', '2026-04-22 19:32:01.024114'::timestamp, 25);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (174, 'Мой опыт эксплуатации дизеля зимой. Mazda CX-5 2.2 дизель при -25°C заводится только с Webasto или после 3-4 прогрева свечей накала. Солярка обязательно арктическая (не выше -35°C по температуре застывания). Один раз залил обычную зимнюю — парафин забил топливный фильтр, машина заглохла на трассе. С тех пор ношу с собой присадку-депрессатор и запасной фильтр.', '2026-04-22 19:32:04.797035'::timestamp, 25);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (175, 'Зимние шины: шипованные лучше на льду, липучка (нешипованная) лучше на чистом асфальте и мокром снегу. Для города с редким гололёдом — липучка Nokian или Michelin. Для трассы и частых обледенений — шипы, но будьте готовы к шуму и худшей управляемости на сухом асфальте.', '2026-04-22 19:32:09.508216'::timestamp, 25);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (176, 'Перед трек-днём обязательно залейте тормозную жидкость DOT 5.1 с высокой температурой кипения (не ниже 270°C сухой), иначе после трёх кругов педаль провалится.', '2026-04-22 19:32:13.703970'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (177, 'Спортивные колодки (например, EBC Yellowstuff) нуждаются в прогревке. Первые два круга тормозите плавно, чтобы разогреть их до рабочей температуры.', '2026-04-22 19:32:17.714164'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (178, 'Почему на треке расход топлива 30 литров на 100 км? Потому что вы постоянно едете на 5000-6000 об/мин, а смесь обогащается для защиты двигателя.', '2026-04-22 19:32:21.506050'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (179, 'Длинный отчёт о трек-дне на Subaru BRZ. Автомобиль полностью стоковый. После 5 кругов закипело масло в двигателе (температура 130°C). Пришлось установить масляный радиатор. Тормоза после 3 кругов потеряли эффективность — колодки дотерлись до железа. Теперь перед каждым треком меняю колодки на более агрессивные (Ferodo DS2500) и заливаю масло 10W-60. Резина — полуслики Nankang AR-1, они живут 2-3 трек-дня. Итог: трек — дорогое удовольствие, но драйв несравним с обычной дорогой.', '2026-04-22 19:32:25.246481'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (180, 'Совет новичкам на треке: не гоняйтесь с выключенным ESP. Оно спасёт вас от вращения, пока учитесь. Включайте трек-режим только когда почувствуете машину на 100%.', '2026-04-22 19:32:28.570684'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (181, 'ISOFIX — обязательно, но не все детские кресла подходят к вашим креплениям. Проверьте совместимость по каталогу, а не просто на глаз.', '2026-04-22 19:32:32.340934'::timestamp, 27);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (182, 'Для семьи из 4 человек берите универсал, а не кроссовер. У универсала багажник больше и доступ ниже — ребёнку легче залезть самому.', '2026-04-22 19:32:35.412790'::timestamp, 27);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (183, 'Что важно в семейном авто: климат-контроль для задних пассажиров, шторки на окнах от солнца, электростеклоподъёмники с защитой от защемления.', '2026-04-22 19:32:38.607480'::timestamp, 27);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (184, 'Кейс: выбирал машину для двойни. Рассматривал Kia Sorento и Skoda Kodiaq. Соренто просторнее на втором ряду, но багажник меньше. Кодиак чуть уже, но багажник огромный, плюс диван складывается в ровный пол. Взял Кодиак, установил сзади планшетники в подголовники — дети смотрят мультики в дороге, тишина. За 3 года владения только плановое ТО. Минус: полный привод на асфальте бесполезен, ест лишнее топливо. Если не ездите в поля, берите передний привод и экономьте.', '2026-04-22 19:32:42.067817'::timestamp, 27);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (185, 'Почему я не рекомендую компактвэны (Citroen C4 Picasso, Ford C-Max)? У них слабые двигатели на 1.6, вариаторы, и подвеска дорогая в обслуживании. Лучше обычный универсал (Octavia, Focus) или кроссовер с атмосферным мотором 2.0 и классическим автоматом.', '2026-04-22 19:32:45.037802'::timestamp, 27);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (186, 'В городе на механике левая нога устаёт. Поэтому я за автомат или робот с режимом «гараж» (ползёт без газа).', '2026-04-22 19:32:49.044387'::timestamp, 28);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (187, 'Компактный автомобиль для парковки: длина до 4.2 метра, ширина до 1.7 м. Идеально — Suzuki Swift, Kia Picanto, Hyundai i10.', '2026-04-22 19:32:52.308218'::timestamp, 28);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (188, 'Самый удобный городской движок — 1.4-1.6 атмосферный. Турбо 1.0 ест не меньше, а ресурс ниже из-за перегрева в пробках.', '2026-04-22 19:32:55.691052'::timestamp, 28);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (189, 'Длинный опыт владения Smart Fortwo. Плюсы: паркуется где угодно, расход 6 литров, налог копеечный. Минусы: жесткая подвеска (каждая яма бьёт в спину), роботизированная коробка тупит на переключениях, багажника нет, а мотор за сиденьем гудит как пылесос. Продал через полгода. Для города лучше взять что-то типа Toyota Aygo — почти такой же маленький, но мягче и с нормальным багажником.', '2026-04-22 19:32:58.761937'::timestamp, 28);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (190, 'Как парковаться параллельно в узком дворе? Совет: сначала поравняйтесь с зеркалом впереди стоящей машины, выкрутите руль до упора, сдайте назад, пока не увидите фару авто сзади, потом выкрутите в другую сторону и доверните. Тренируйтесь на пустой парковке с конусами. Через неделю будете парковаться с закрытыми глазами.', '2026-04-22 19:33:03.206233'::timestamp, 28);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (191, 'Для грязи обязательно иметь шноркель (даже если не топите двигатель — он помогает набирать чистый воздух выше пыли).', '2026-04-22 19:33:06.866195'::timestamp, 29);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (192, 'Лебёдка должна быть мощностью не менее 12 000 lb для тяжёлого внедорожника. И всегда держите в машине якорь-лепесток и стропу.', '2026-04-22 19:33:10.344577'::timestamp, 29);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (193, 'Песок: снизьте давление в шинах до 1.0-1.2 бара, не газуйте резко, двигайтесь накатом. Если застряли — не буксуйте, вылезайте с помощью мат-треков.', '2026-04-22 19:33:13.964019'::timestamp, 29);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (194, 'История экспедиции на Land Rover Discovery 3 по Карелии. Проехали 200 км по лесам и болотам. Машина на пневме: поднял кузов — клиренс 30 см, прошёл всё. Но пневма на кочках боится ударов — прокололи шланг, пришлось чинить в полевых условиях. Теперь вожу с собой запасной компрессор и ремкомплект. Итог: для серьёзного бездорожья лучше старая рамная Toyota LC 80 с обычной рессорой — ломаться нечему.', '2026-04-22 19:33:17.189930'::timestamp, 29);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (195, 'Обязательный набор для оффроуда: лопата (сапёрная), якорь-лепесток, два мягких буксировочных стропа, динамический строп для рывков, компрессор для накачки колёс, набор ключей, трек-матты. Без этого в лес лучше не соваться, даже если у вас «вездеход».', '2026-04-22 19:33:20.369749'::timestamp, 29);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (196, 'В 2025 году в России запретят ввоз автомобилей без системы ЭРА-ГЛОНАСС. Цены на параллельный импорт вырастут на 15-20%.', '2026-04-22 19:33:23.948527'::timestamp, 30);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (197, 'Китайские бренды вытесняют европейцев: в 2024 году Chery и Geely заняли 35% рынка новых авто. Основной драйвер — цена на 20% ниже европейских аналогов.', '2026-04-22 19:33:27.187621'::timestamp, 30);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (198, 'Государство продлило программу льготного автокредитования до конца 2025-го, но только для электромобилей и машин локальной сборки.', '2026-04-22 19:33:30.378577'::timestamp, 30);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (199, 'Аналитика рынка б/у: средний возраст автомобиля в России вырос до 13 лет. Самые продаваемые иномарки с пробегом: Kia Rio, Hyundai Solaris, Ford Focus. Их популярность объясняется дешевизной запчастей и ремонтопригодностью.', '2026-04-22 19:33:34.183857'::timestamp, 30);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (200, 'Прогноз по ценам на новые авто к 2026 году: из-за повышения утильсбора на 20-30% самые бюджетные иномарки подорожают до 2.5 миллионов, а LADA Granta — до 1.2 миллионов. Лучше покупать сейчас или ждать падения курса рубля? Если бюджет позволяет, берите сейчас, к осени будет только дороже.', '2026-04-22 19:33:37.301302'::timestamp, 30);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (201, 'REST — это хорошо, но если у вас больше 5 эндпоинтов с вложенными ресурсами и кучей фильтров, пора смотреть в сторону GraphQL. Не из моды, а из боли.', '2026-04-22 19:33:44.636064'::timestamp, 31);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (202, 'Спор REST против GraphQL бессмысленен. Используйте REST для простых CRUD и публичных API, GraphQL — для сложных клиентских запросов и агрегации данных. Я видел проекты, где GraphQL убил производительность из-за глубоких вложенных запросов. Всегда ставьте лимиты глубины и complexity.', '2026-04-22 19:33:47.807711'::timestamp, 31);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (203, 'Версионируйте API с детства. /v1/ — в URL, /v2/ — рядом. Заголовки Accept-Version — зло, их не видно в логах и сложно тестировать. Клиенты должны явно видеть версию.', '2026-04-22 19:33:50.776975'::timestamp, 31);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (204, 'История: мы выпустили новую версию API, удалив один deprecated параметр. Клиент не заметил предупреждений за полгода. В день релиза их сервис лёг. Теперь у нас политика: депрекейтим минимум 9 месяцев и отправляем email-уведомления на все контакты.', '2026-04-22 19:33:54.463752'::timestamp, 31);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (205, 'OpenAPI (Swagger) — мастхэв. Генерируйте клиентов, валидируйте запросы, документируйте автоматически. Ручная документация устаревает в тот же момент, когда вы меняете код.', '2026-04-22 19:33:57.538078'::timestamp, 31);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (206, 'Индексы — это не магия. EXPLAIN ANALYZE ваш лучший друг. Если видите Seq Scan на таблице с миллионом строк — срочно ставьте индекс.', '2026-04-22 19:34:01.119993'::timestamp, 32);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (207, 'Миграции должны быть идемпотентными. Никогда не пишите ''INSERT INTO users...'' без ''IF NOT EXISTS''. И оборачивайте в транзакцию.', '2026-04-22 19:34:04.516134'::timestamp, 32);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (208, 'Почему я против EAV (Entity-Attribute-Value) в реляционных БД? Потому что через полгода вы не сможете написать ни одного адекватного запроса без кучи джойнов и кастомных агрегаций. Лучше денормализуйте или переходите на документоориентированную БД.', '2026-04-22 19:34:07.878092'::timestamp, 32);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (209, 'Длинный кейс: у нас был запрос, который выполнялся 40 секунд. EXPLAIN показал merge join без индексов. Поставили составной индекс на (user_id, created_at) — время упало до 50 мс. Но через месяц нагрузка выросла, и индекс перестал помогать. Оказалось, проблема в неселективном user_id (один пользователь генерил 90% записей). Пришлось делать партиционирование по диапазону created_at. Теперь запросы летают, а мы поняли: индексы лечат симптомы, партиционирование — причину.', '2026-04-22 19:34:11.376171'::timestamp, 32);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (210, 'В PostgreSQL не забывайте про VACUUM и ANALYZE. Автовакуум — хорошо, но при больших UPDATE он не успевает. Настройте параметры или запускайте вручную в часы низкой нагрузки.', '2026-04-22 19:34:14.683302'::timestamp, 32);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (211, 'Если у вас 5 разработчиков и монолит работает — не переходите на микросервисы. Распределённая сложность убьёт вас быстрее, чем монолит начнёт тормозить.', '2026-04-22 19:34:18.322352'::timestamp, 33);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (212, 'Сага (Saga) вместо двухфазного коммита. 2PC в микросервисах — это ад по производительности и доступности. Лучше примите eventual consistency и пишите компенсирующие транзакции.', '2026-04-22 19:34:21.498888'::timestamp, 33);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (213, 'Service Mesh (istio, linkerd) решает 80% проблем с наблюдаемостью и безопасностью, но добавляет 20% латентности и кучу новых абстракций. Для 3-5 сервисов не надо, для 20+ — must have.', '2026-04-22 19:34:24.978173'::timestamp, 33);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (214, 'История: мы разделили монолит на 30 микросервисов. Через полгода поняли, что любой запрос проходит через 12 сервисов, латентность выросла в 5 раз, а прод упал трижды из-за неправильных таймаутов. Пришлось выкатывать aggregator-сервис, который склеивает данные на бэкенде. Теперь у нас гибрид: несколько доменных монолитов, а внутри — микросервисы по необходимости.', '2026-04-22 19:34:28.386364'::timestamp, 33);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (215, 'Таймауты, ретраи и circuit breaker — святая троица. Без них ваша система рассыплется при малейшей задержке зависимого сервиса. Resilience4j или Hystrix (хоть и мёртвый) — берите что-то.', '2026-04-22 19:34:32.047839'::timestamp, 33);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (216, 'Никогда не храните секреты в коде. Даже в репозитории с приватным доступом. Используйте HashiCorp Vault, AWS Secrets Manager или хотя бы зашифрованные переменные окружения.', '2026-04-22 19:34:35.326848'::timestamp, 34);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (217, 'JWT — подписывайте, не шифруйте (если только нет критичных данных). И не храните в JWT больше, чем нужно. Размер токена влияет на заголовки запросов.', '2026-04-22 19:34:38.905167'::timestamp, 34);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (218, 'Почему я ненавижу ''самописную аутентификацию''? Потому что каждый второй забывает про rate limiting на логин, хэширует пароли MD5 или хранит соли в той же таблице. Берите OAuth2 + OpenID Connect, не изобретайте велосипед.', '2026-04-22 19:34:42.196174'::timestamp, 34);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (219, 'SQL-инъекции до сих пор в топе OWASP. Используйте параметризованные запросы, ORM или query builder. Никакой конкатенации строк даже для ''безопасных'' значений.', '2026-04-22 19:34:45.560015'::timestamp, 34);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (220, 'Длинный разбор инцидента. К нам пришли с утечкой данных: злоумышленник получил доступ к API через скомпрометированный JWT. Оказалось, мы не проверяли ''alg: none'' в заголовке. Да, библиотека JWT по умолчанию разрешала эту атаку. После этого сменили библиотеку и добавили валидацию алгоритма. И включили короткое время жизни токенов (15 минут) с refresh-токенами в httpOnly cookies.', '2026-04-22 19:34:48.838073'::timestamp, 34);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (221, 'Dockerfile — держите слои в порядке: сначала редко меняющиеся (основной образ, зависимости), потом часто меняющиеся (код). Кэш слоёв сэкономит часы сборки.', '2026-04-22 19:34:52.215581'::timestamp, 35);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (222, 'Health check в Kubernetes — liveness и readiness разные вещи. Liveness перезапустит зависший контейнер, readiness — уберёт трафик при старте или временной неготовности. Путать нельзя.', '2026-04-22 19:34:55.800090'::timestamp, 35);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (223, 'Почему я против ''latest'' тега в продакшене? Потому что вы никогда не узнаете, какая версия реально развёрнута, и не сможете откатиться. Используйте git commit hash как тег.', '2026-04-22 19:34:58.871982'::timestamp, 35);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (224, 'Кейс: на прод полезла новая версия сервиса, которая упала из-за отсутствия переменной окружения. Мы откатились за 30 секунд, потому что в ArgoCD настроили автоматический rollback при неудачном health check. Без этого откат занял бы час ручного дерганья.', '2026-04-22 19:35:01.943987'::timestamp, 35);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (225, 'Терраформ — храните state в удалённом бэкенде (S3, GCS) с блокировками. И никогда не коммитьте state в git — там могут быть секреты.', '2026-04-22 19:35:05.531172'::timestamp, 35);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (226, 'Кэширование — это всегда компромисс. CDN для статики, Redis для сессий и частых запросов, локальный кэш в памяти для данных, которые редко меняются. Но не кэшируйте всё подряд — анлим кэш = анлим проблемы с актуальностью.', '2026-04-22 19:35:08.720433'::timestamp, 36);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (227, 'N+1 запрос — классика ORM. Используйте batch load или включите логирование SQL, чтобы ловить такие места. Лучше один запрос с JOIN, чем 100 запросов по одному ID.', '2026-04-22 19:35:11.771743'::timestamp, 36);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (228, 'Gzip/Brotli на уровне веб-сервера сжимает ответы API в 5-10 раз. Но не сжимайте уже сжатые картинки и видео — бесполезно.', '2026-04-22 19:35:15.050096'::timestamp, 36);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (229, 'Длинная история оптимизации: у нас был эндпоинт, который грузился 3 секунды. Профилирование показало, что 2.5 секунды — это сериализация огромного JSON-дерева в Python. Мы переписали на streaming JSON (одна строка за раз) и отдавали клиенту по чанкам. Время до первого байта упало до 200 мс. Пользователи счастливы.', '2026-04-22 19:35:18.224724'::timestamp, 36);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (230, 'Connection pool — настраивайте правильно. Слишком маленький пул — ждите в очередях. Слишком большой — БД захлебнётся. Стартуйте с 10-20 на ядро приложения и смотрите на количество активных соединений в БД.', '2026-04-22 19:35:21.516631'::timestamp, 36);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (231, 'AWS vs Azure vs GCP — не важно. Важно: используйте managed сервисы, где это возможно. RDS, S3, SQS снимают тонну операционной работы. Но не забывайте про vendor lock-in.', '2026-04-22 19:35:25.288836'::timestamp, 37);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (232, 'Serverless (Lambda, Cloud Functions) — круто для spiky нагрузки и асинхронных обработчиков. Для high-load realtime приложений лучше контейнеры. Cold start никуда не делся.', '2026-04-22 19:35:28.569200'::timestamp, 37);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (233, 'Стоимость облака: самая большая неожиданность — это egress трафик. Данные из облака наружу платные. Проектируйте архитектуру так, чтобы минимизировать исходящий трафик.', '2026-04-22 19:35:31.845619'::timestamp, 37);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (234, 'Кейс: мы перенесли монолит на ECS Fargate. Сэкономили на управлении кластером, но получили счёт в 2 раза выше из-за того, что забыли настроить auto-scaling по CPU. Сервис крутил 10 реплик, хотя хватало 2. Настроили масштабирование — счёт упал.', '2026-04-22 19:35:35.168044'::timestamp, 37);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (235, 'DR (Disaster Recovery) — не просто бэкапы. RTO и RPO нужно прописывать в SLA. Для критичных сервисов — active-active регионы, для менее важных — warm standby. И тестируйте восстановление раз в квартал.', '2026-04-22 19:35:38.053883'::timestamp, 37);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (236, 'Пирамида тестов: 70% unit, 20% integration, 10% e2e. Много e2e — тесты будут долгими и хрупкими. Мало unit — будете ловить баги на стыках.', '2026-04-22 19:35:41.369274'::timestamp, 38);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (237, 'Мокайте внешние зависимости, но не мокайте то, чем не управляете (например, API погоды). Лучше пишите интеграционные тесты с реальным вызовом в тестовой среде.', '2026-04-22 19:35:44.643011'::timestamp, 38);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (238, 'Property-based testing (hypothesis, fast-check) часто находит баги, которые вы даже не представляли. Вместо конкретных чисел задаёте свойства и диапазоны.', '2026-04-22 19:35:47.817946'::timestamp, 38);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (239, 'Длинная история: у нас был баг, который проявлялся только в високосный год 29 февраля. Юнит-тесты с конкретной датой не поймали. Написали property-based тест, который генерирует случайные даты за 100 лет — и он нашёл ещё 3 краевых случая с часовыми поясами.', '2026-04-22 19:35:52.325046'::timestamp, 38);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (240, 'Testcontainers — бест практис для интеграционных тестов с БД, очередями, Kafka. Поднимает реальный контейнер, тест идёт к реальной БД, а не in-memory. Потом контейнер убивается. Чисто, быстро, надёжно.', '2026-04-22 19:35:55.499025'::timestamp, 38);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (241, 'Legacy код — не тот, который старый, а тот, у которого нет тестов. Прежде чем рефакторить, обложите интеграционными тестами критические пути.', '2026-04-22 19:35:58.675100'::timestamp, 39);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (242, 'Страшный рефакторинг — это когда меняете одну сущность, а падает всё. Признак: отсутствие чётких границ модулей. Начните с выделения интерфейсов.', '2026-04-22 19:36:01.744101'::timestamp, 39);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (243, 'Метод Бойскаута: всегда оставляйте код чище, чем он был. Даже маленькое переименование переменной уменьшает технический долг.', '2026-04-22 19:36:05.139374'::timestamp, 39);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (244, 'Кейс: мы рефакторили монолит на 500 тысяч строк. Выделили модуль работы с платежами. Стратегия: сначала написали антикоррупционный слой (facade), потом постепенно переносили реализацию, фича-флагами включая новый код для 1% трафика. Через месяц переключили 100%, старый код удалили. Ни одного инцидента.', '2026-04-22 19:36:08.605598'::timestamp, 39);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (245, 'Инструменты: статический анализ (SonarQube, ESLint), автоматическое форматирование (Prettier, Black), проверки на этапе CI. Человек не должен тратить время на обсуждение форматирования.', '2026-04-22 19:36:12.598339'::timestamp, 39);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (246, 'Асинхронщина не делает код быстрее магически. Она позволяет не блокировать поток на I/O. Для CPU-bound задач нужны отдельные процессы.', '2026-04-22 19:36:16.353536'::timestamp, 40);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (247, 'Event-driven архитектура: хорошо для слабо связанных сервисов, плохо для отладки и трассировки. Добавьте correlation-id во все сообщения.', '2026-04-22 19:36:19.768982'::timestamp, 40);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (248, 'Backpressure — обязателен. Если очередь растёт, а консьюмеры не успевают, надо или уменьшать продюсера (через отказ от новых запросов), или масштабировать консьюмеров.', '2026-04-22 19:36:23.161024'::timestamp, 40);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (249, 'Длинный пример: мы построили систему на Kafka с 10 консьюмерами. В какой-то момент очередь выросла до 1 млн сообщений. Оказалось, один из консьюмеров завис, а остальные 9 не могли его заменить, потому что партиции были закреплены. Перешли на Consumer Group с автоматическим ребалансом. Теперь при падении одного, партиции перераспределяются.', '2026-04-22 19:36:26.936629'::timestamp, 40);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (250, 'Асинхронность в Python: asyncio хорош для I/O, но блокирующий вызов внутри корутины убьёт весь event loop. Всегда используйте run_in_executor для блокирующего кода.', '2026-04-22 19:36:30.313329'::timestamp, 40);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (251, 'API Gateway — не просто маршрутизатор. Он может делать rate limiting, аутентификацию, кэширование, трансформацию ответов. Выносите эту логику из микросервисов.', '2026-04-22 19:36:34.127007'::timestamp, 41);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (252, 'Kong vs Nginx vs Traefik. Nginx — надёжный и быстрый, но конфиги на Lua. Kong — расширяется плагинами на Lua, но тяжелее. Traefik — простой, автоматически находит сервисы в Docker/K8s.', '2026-04-22 19:36:38.525196'::timestamp, 41);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (253, 'Обязательно ставьте global rate limit на шлюзе, чтобы один агрессивный клиент не положил всю систему. И отдельно — per-user/per-IP лимиты.', '2026-04-22 19:36:41.844601'::timestamp, 41);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (254, 'Кейс: у нас был DDoS на эндпоинт авторизации. API Gateway отсек 95% трафика по IP-репутации и отдавал 429 на остальных. Микросервис авторизации даже не заметил нагрузки.', '2026-04-22 19:36:45.262870'::timestamp, 41);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (255, 'WebSocket через API Gateway — боль. Не все шлюзы умеют пробрасывать WebSocket долго. Для критичных соединений лучше использовать отдельный сервис с прямой маршрутизацией.', '2026-04-22 19:36:48.358823'::timestamp, 41);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (256, 'Нормализация в 3NF — для транзакционных систем. Денормализация и витрины — для аналитики. Не пытайтесь сделать и то и другое в одной схеме.', '2026-04-22 19:36:52.083789'::timestamp, 42);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (257, 'Уникальные ключи и foreign keys — ваша страховка от битых данных. Я видел базы, где no constraints, потому что ''мы на уровне приложения проверяем''. Приложение ошибается.', '2026-04-22 19:36:55.298475'::timestamp, 42);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (258, 'В MongoDB — проектируйте схему под запросы, а не под нормализацию. Документы могут быть вложенными, если вы их всегда читаете вместе.', '2026-04-22 19:36:58.577923'::timestamp, 42);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (259, 'Длинная история: мы спроектировали схему PostgreSQL для соцсети. Всё было красиво, но запрос ленты новостей (друзья + их посты) делал 5 джойнов. Пришлось создать материализованное представление, которое обновляется раз в минуту. Жертвуем свежестью ради скорости.', '2026-04-22 19:37:02.058078'::timestamp, 42);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (260, 'Используйте UUID как первичные ключи только если есть распределённая генерация. Для обычных таблиц SERIAL/Bigint быстрее и компактнее.', '2026-04-22 19:37:05.541710'::timestamp, 42);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (261, 'Redis — король кэширования, но не используйте его как основное хранилище. Данные могут потеряться при перезагрузке (если не включили AOF).', '2026-04-22 19:37:09.035290'::timestamp, 43);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (262, 'Cache stampede — когда много запросов одновременно промахиваются и начинают пересчитывать значение. Решение: блокировка (setnx) или background refresh до истечения TTL.', '2026-04-22 19:37:12.295233'::timestamp, 43);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (263, 'Write-through vs write-behind. Write-through — консистентно, но медленнее. Write-behind — быстрее, но может потерять данные при падении.', '2026-04-22 19:37:15.674194'::timestamp, 43);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (264, 'Кейс: кэш с TTL 5 минут. Внезапно нагрузка выросла в 10 раз, и каждый запрос стал промахиваться ровно в момент истечения TTL. Сервис рухнул от пересчёта. Внедрили jitter (случайное добавление к TTL) и background refresh — нагрузка распределилась.', '2026-04-22 19:37:18.849033'::timestamp, 43);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (265, 'CDN — это ваш лучший друг для статики и даже для API, если данные редко меняются. Включите stale-while-revalidate, чтобы при истечении кэша CDN отдавала старую версию и обновляла фоном.', '2026-04-22 19:37:21.920948'::timestamp, 43);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (266, 'Логи — это не хранилище данных. Не пишите в лог всю бизнес-логику. Структурированные логи (JSON) с уровнем: ERROR, WARN, INFO, DEBUG. На проде — INFO и выше.', '2026-04-22 19:37:25.214301'::timestamp, 44);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (267, 'Корреляция запросов: каждый входящий запрос получает X-Request-ID. Передаёте его во все внутренние вызовы и логируете. Потом легко собрать весь трейс.', '2026-04-22 19:37:28.475818'::timestamp, 44);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (268, 'Метрики: RED (Rate, Errors, Duration) для каждого сервиса. Чёрный ящик мониторинга. Золотые сигналы Google: latency, traffic, errors, saturation.', '2026-04-22 19:37:31.735708'::timestamp, 44);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (269, 'Длинный инцидент: перестали приходить алерты. Оказалось, диск с логами заполнился, и система мониторинга не смогла записать метрики. С тех пор логи и метрики пишем на разные тома, и ротируем логи раз в сутки с автоматической очисткой.', '2026-04-22 19:37:35.352127'::timestamp, 44);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (270, 'ELK (Elasticsearch, Logstash, Kibana) или Loki + Grafana. Loki дешевле и проще для логов в Kubernetes, но ELK мощнее для сложных запросов.', '2026-04-22 19:37:38.320051'::timestamp, 44);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (271, 'Kubernetes — сложен. Если у вас 10 серверов, можно обойтись Docker Swarm или Nomad. K8s нужен от 20+ микросервисов или требованиям auto-scaling.', '2026-04-22 19:37:41.690271'::timestamp, 45);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (272, 'PodDisruptionBudget — чтобы при обновлении кластера не вырубились все реплики сразу. Обязательно настраивайте.', '2026-04-22 19:37:44.976555'::timestamp, 45);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (273, 'Resource requests и limits — не игнорируйте. Без requests планировщик может напихать кучу подов на одну ноду. Без limits один под может сожрать всю память.', '2026-04-22 19:37:48.544244'::timestamp, 45);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (274, 'Кейс: наше приложение стало падать с OOMKilled. Оказалось, мы поставили memory limit 1Gi, а приложение в пике потребляло 1.2Gi. Увеличили limit до 2Gi и настроили HPA по CPU и памяти. Теперь поды создаются автоматически при нагрузке.', '2026-04-22 19:37:52.333545'::timestamp, 45);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (275, 'Helm — стандарт для упаковки приложений. Не пишите свои чарты с нуля, используйте бибилотечные (bitnami) или хотя бы генераторы. И храните values в отдельном репозитории с секретами (SealedSecrets).', '2026-04-22 19:37:55.407496'::timestamp, 45);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (276, 'Kafka vs RabbitMQ. Kafka — для потоков событий и больших объёмов, RabbitMQ — для сложной маршрутизации и RPC-стиля. Не путайте.', '2026-04-22 19:37:58.800866'::timestamp, 46);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (277, 'Idempotent consumers — обязательны. Сообщение может быть доставлено дважды (at-least-once). Делайте обработку так, чтобы повтор не ломал состояние.', '2026-04-22 19:38:01.856864'::timestamp, 46);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (278, 'Dead Letter Queue (DLQ) — спасает, когда сообщение не может быть обработано (ошибка в данных). Вместо бесконечных ретраев, уходите в DLQ и алертите.', '2026-04-22 19:38:04.929500'::timestamp, 46);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (279, 'Длинная история: у нас был consumer, который зависал на сообщении с некорректным JSON. Очередь блокировалась. Настроили DLQ: после 3 неудачных попыток сообщение уходит в другую очередь, а consumer продолжает работу. И добавили мониторинг на рост DLQ.', '2026-04-22 19:38:08.102979'::timestamp, 46);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (280, 'Партиционирование в Kafka: если ключ партиции плохой (например, user_id), то у одного пользователя все сообщения пойдут в одну партицию. При большой нагрузке этот consumer не успеет. Используйте составные ключи или round-robin.', '2026-04-22 19:38:11.393765'::timestamp, 46);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (281, 'JWT — храните только в httpOnly secure cookies, а не в localStorage. Иначе XSS украдёт токен.', '2026-04-22 19:38:14.758666'::timestamp, 47);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (282, 'Refresh token должен иметь более длительный срок жизни, но храниться на сервере в чёрном списке при логауте. Иначе скомпрометированный refresh token даст вечный доступ.', '2026-04-22 19:38:18.137474'::timestamp, 47);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (283, 'OAuth2 — не используйте Implicit Flow (устарел). Authorization Code Flow with PKCS — стандарт для SPA.', '2026-04-22 19:38:21.533188'::timestamp, 47);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (284, 'Кейс: мы реализовали SSO через JWT. Но забыли про ротацию ключей. Через год приватный ключ скомпрометировали через утекший репозиторий. Пришлось срочно перевыпускать все токены. Теперь ключи живут 3 месяца и ротируются автоматически через Vault.', '2026-04-22 19:38:24.707519'::timestamp, 47);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (285, 'JWT не для отзыва. Если вам нужен мгновенный отзыв сессии, храните чёрный список в Redis или используйте сессии на сервере, а JWT только как временный билет.', '2026-04-22 19:38:28.085633'::timestamp, 47);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (286, 'Rate limiting — на уровне API Gateway, но дублируйте критические лимиты в коде (defense in depth).', '2026-04-22 19:38:31.654686'::timestamp, 48);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (287, 'Алгоритмы: token bucket (равномерный расход, допускает всплески), sliding window (более справедливый, без всплесков). leaky bucket — устарел.', '2026-04-22 19:38:35.357354'::timestamp, 48);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (288, 'Ответ 429 — обязателен с заголовком Retry-After. Клиенты должны знать, через сколько пробовать снова.', '2026-04-22 19:38:38.758267'::timestamp, 48);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (289, 'Длинный опыт: один клиент делал 1000 запросов в секунду к нашему API, хотя лимит был 100. Наш rate limiter на базе Redis (алгоритм sliding window) корректно отдавал 429. Но Redis начал тормозить, потому что каждая проверка делала 2-3 операции. Оптимизировали с помощью Lua скрипта на стороне Redis — latency упала в 10 раз.', '2026-04-22 19:38:41.688280'::timestamp, 48);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (290, 'Распределённый rate limiting — сложно. Если у вас 10 инстансов сервиса, а лимит на пользователя 1000/час, нужно общее хранилище (Redis). Но это добавляет задержку. Компромисс: локальный лимит с большим запасом + глобальный только для агрессивных ботов.', '2026-04-22 19:38:44.829318'::timestamp, 48);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (291, 'Бэкапы бесполезны, если вы не проверяете восстановление. Раз в месяц поднимайте базу из бэкапа на тестовом окружении.', '2026-04-22 19:38:48.140270'::timestamp, 49);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (292, '3-2-1 правило: 3 копии данных, 2 разных носителя, 1 оффсайт. В облаке это легко: S3 + репликация в другой регион + Glacier.', '2026-04-22 19:38:51.329339'::timestamp, 49);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (293, 'Point-in-time recovery (PITR) — позволяет откатиться на любую минуту. Включайте для всех продовых БД.', '2026-04-22 19:38:54.914446'::timestamp, 49);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (294, 'Кейс: у нас была катастрофа — человеческая ошибка: DROP TABLE users в проде. Благодаря WAL-архивам PostgreSQL мы восстановили базу на момент за 1 минуту до. Потеряли всего 60 секунд данных. Без WAL потеряли бы всё.', '2026-04-22 19:38:58.279251'::timestamp, 49);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (295, 'Автоматизируйте бэкапы через crontab или встроенные средства (AWS Backup, Azure Backup). И храните бэкапы минимум 30 дней, а для финансовых данных — годы.', '2026-04-22 19:39:01.555942'::timestamp, 49);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (296, 'CI/CD без тестов — просто непрерывная доставка багов. Всегда запускайте линтеры, юнит-тесты, интеграционные тесты перед деплоем.', '2026-04-22 19:39:05.754400'::timestamp, 50);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (297, 'GitHub Actions, GitLab CI, Jenkins. Выбирайте то, что интегрировано с вашим репозиторием. Jenkins мощный, но требует обслуживания.', '2026-04-22 19:39:08.817555'::timestamp, 50);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (298, 'Артефакты билда должны храниться в реестре (Docker registry, npm, PyPI). Не копируйте файлы с билд-агента напрямую на сервер.', '2026-04-22 19:39:12.920104'::timestamp, 50);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (299, 'Длинная история: мы внедрили CI, который автоматически деплоил на staging при каждом push в main. Но кто-то запушил битый коммит, staging упал, а прод продолжал работать на старой версии. Сделали так: сначала деплой на staging, прогон smoke-тестов, и только после успеха создаётся PR для прод-деплоя. Всё через approve в PR.', '2026-04-22 19:39:16.094477'::timestamp, 50);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (300, 'GitOps (ArgoCD, Flux) — декларативный подход: состояние окружения в git, оператор синхронизирует кластер. Откат — просто git revert. Дорого в начале, но окупается прозрачностью.', '2026-04-22 19:39:19.065240'::timestamp, 50);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (301, 'Эффективность в нападении (ORtg) Денвера с Йокичем на площадке — 122.3, без него — 108.1. Вот вам и MVP.', '2026-04-22 19:39:26.539229'::timestamp, 51);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (302, 'Интересно: в этом сезоне 12 игроков набирают 30+ PPG. В 90-х таких было двое (Джордан, Мэлоун). Защиту убили правилами.', '2026-04-22 19:39:29.510504'::timestamp, 51);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (303, 'Мой прогноз на финал Запада: Денвер — Финикс в 7 играх. Но если Пол Джордж здоров — Клипперс могут вынести всех.', '2026-04-22 19:39:33.878183'::timestamp, 51);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (304, 'Виньетка по защите Бостона: они перекрывают краску и вынуждают бросать средние. Против Милуоки это работает, против Майами с их движением — нет.', '2026-04-22 19:39:37.107031'::timestamp, 51);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (305, 'Реальный кейс: в прошлом году я анализировал +/- Луки Дончича в клатче. Он был минусовым, хотя все хвалили его героизм. В этом сезоне Маверикс подтянули защиту вокруг него — и результат на лицо.', '2026-04-22 19:39:40.584993'::timestamp, 51);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (306, 'Почему зонная защита 2-3 почти не работает в НБА? Из-за угловых трёх и быстрых передач через центр. В Евролиге — да, там площадка меньше.', '2026-04-22 19:39:43.844330'::timestamp, 52);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (307, 'Самый недооценённый элемент тактики: подбор на чужом щите. Одна вторая атака за possession даёт +5 очков за матч.', '2026-04-22 19:39:46.932282'::timestamp, 52);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (308, 'Если соперник часто использует пик-н-ролл, попробуйте «hedge and recover» — выходи навстречу с тяжёлым форвардом и возвращайся. Не давай разыгрывающему проход.', '2026-04-22 19:39:50.193001'::timestamp, 52);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (309, 'Разбирал матч ЦСКА — Реал. Реал переключился на схему «5 аут» (все вне трёшки), растянул защиту и забивал из краски через разрезающие передачи. Противоядие — быстрая ротация и активные руки.', '2026-04-22 19:39:53.265051'::timestamp, 52);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (310, 'История: тренировал юношескую команду. Мы проигрывали 5 матчей подряд из-за плохого возврата в защиту. Ввели правило: после броска все бегут к своей корзине, никто не смотрит на отскок. Следующие 4 игры выиграли, пропуская на 12 очков меньше.', '2026-04-22 19:39:56.746792'::timestamp, 52);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (311, 'На улице нет трёхсекундной зоны и фолов в нападении. Поэтому бэкдауны в краске работают безотказно.', '2026-04-22 19:40:00.654579'::timestamp, 53);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (312, 'Лучший кроссовер не тот, который красивый, а тот, после которого защитник улетел и у тебя чистое пространство. Аллен Айверсон — эталон.', '2026-04-22 19:40:04.135002'::timestamp, 53);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (313, 'Почему стритбол — лучшая школа дриблинга? Потому что там каждый контакт — фол, если ты не пробил. Учишься обыгрывать без опоры на судью.', '2026-04-22 19:40:07.504507'::timestamp, 53);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (314, 'Играл турнир в Нью-Йорке на Ракер-парке. Местные не дают расслабиться ни на секунду — контакт, локти, словесные атаки. После такого игра в зале кажется прогулкой.', '2026-04-22 19:40:10.981771'::timestamp, 53);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (315, 'Мой сет упражнений: 100 кроссоверов между ног, 100 за спиной, 100 кроссоверов в движении — каждый день. Через месяц защиты как не бывало.', '2026-04-22 19:40:14.153749'::timestamp, 53);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (316, 'Евролига — тактический баскетбол. Счёт 75-70 в матче ЦСКА — Реал говорит о защите и дисциплине больше, чем 130-120 в НБА.', '2026-04-22 19:40:17.635880'::timestamp, 54);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (317, 'Мадридский Реал выигрывает за счёт глубины состава. У них 12 игроков, которые могут выдать 10 минут на высоком уровне. Это убивает соперников во второй половине.', '2026-04-22 19:40:20.708220'::timestamp, 54);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (318, 'Почему в Европе так важен центровой? Потому что нет правила «defensive three seconds», и бигмен может сидеть в краске всё время, блокируя проходы.', '2026-04-22 19:40:23.984491'::timestamp, 54);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (319, 'Смотрю финал Евролиги 2019 — ЦСКА против Анадолу Эфес. У ЦСКА не было ответа на пик-н-ролл с Ларкиным и Дуняма. Простой заслон, а наши центровые не знали, выходить или нет.', '2026-04-22 19:40:27.894434'::timestamp, 54);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (320, 'Кейс: «Панатинаикос» в 2024-м вернулся в топ-4 за счёт прессинга на 94 футах. Они заставляли соперников тратить 12 секунд на проход середины — в итоге оставалось мало времени на атаку. Работает, если есть свежие защитники.', '2026-04-22 19:40:31.256225'::timestamp, 54);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (321, 'При оценке проспекта смотри на три вещи: баскетбольный IQ, характер и здоровье. Атлетизм — четвёртое.', '2026-04-22 19:40:34.957684'::timestamp, 55);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (322, 'Виктор Вембаньяма — уникальный талант, но его риск травм из-за роста и манеры игры выше среднего. Сан-Антонио бережёт его, давая отдыхать в бэкап-ту-бэках.', '2026-04-22 19:40:38.445395'::timestamp, 55);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (323, 'В этом драфте недооценивают гардов из колледжа, которые умеют защищаться. Нападение можно поставить, а защиту — нет.', '2026-04-22 19:40:42.519855'::timestamp, 55);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (324, 'Скаутил игрока в NCAA, который набирал 25 очков, но не умел играть без мяча и плохо защищался. В НБА он провалился, потому что тренеры быстро убрали изоляции. Берите универсалов.', '2026-04-22 19:40:45.899136'::timestamp, 55);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (325, 'История: перед драфтом 2020 все хвалили Ламело Болла за креатив, но его 3-очковый был 25%. Скауты Шарлотт поверили в механику, и не прогадали. Сейчас он бросает 37% с дальней. Главное — вера в коррекцию.', '2026-04-22 19:40:50.074252'::timestamp, 55);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (326, 'Плиометрика важнее жима лёжа для баскетболиста. Вертикальный прыжок набирается через прыжки в ящик и выпрыгивания.', '2026-04-22 19:40:53.271057'::timestamp, 56);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (327, 'Как снизить риск травм колена? Укрепляй бицепс бедра (сгибатели) и ягодицы. В отрыве квадрицепсы доминируют, и это ведёт к разрывам крестов.', '2026-04-22 19:40:56.861583'::timestamp, 56);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (328, 'Кардио для баскетбола — интервалы. 30 секунд спринт, 30 секунд шаг, 10 повторений. Имитирует игровой пульс.', '2026-04-22 19:41:00.249657'::timestamp, 56);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (329, 'Тренировал игрока, который часто хватал судороги в четвёртой четверти. Посадил на магний и электролиты, добавил растяжку после каждой тренировки. Судороги ушли.', '2026-04-22 19:41:03.511932'::timestamp, 56);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (330, 'Комплекс на восстановление: 10 минут лёгкой велотренажёра, затем ролл (бедро, голень, ягодицы), затем холодный душ. Ускоряет регенерацию после матча на 40%.', '2026-04-22 19:41:06.292553'::timestamp, 56);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (331, 'Бриттни Грайнер после возвращения в WNBA набирает 18 очков и 7 подборов. Психологическая стойкость — космос.', '2026-04-22 19:41:09.553957'::timestamp, 57);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (332, 'Женская игра медленнее, но тактически богаче. Посмотрите, как сборная США двигается без мяча — все знают, куда бежать.', '2026-04-22 19:41:12.418214'::timestamp, 57);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (333, 'Почему в WNBA зарплаты в 100 раз ниже мужских? Контракт с телевидением приносит 50 млн в год, против 2.6 млрд у НБА. Но аудитория растёт.', '2026-04-22 19:41:15.592269'::timestamp, 57);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (334, 'Разбор матча УГМК — Прага. УГМК проиграла из-за того, что не нашла ответ на зонный прессинг Праги в первой четверти. Семь потерь за 5 минут.', '2026-04-22 19:41:19.075136'::timestamp, 57);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (335, 'История: в 2018 году я был на финале WNBA — Сиэтл против Вашингтона. Брианна Стюарт выключила режим «монстр» в четвёртой игре: 30 очков, 10 подборов, 4 блока. Её спокойствие под давлением — пример для всех.', '2026-04-22 19:41:22.454168'::timestamp, 57);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (336, 'До 14 лет не делай акцент на результат. Важно, чтобы ребёнок полюбил баскетбол, иначе уйдёт в 16.', '2026-04-22 19:41:26.156506'::timestamp, 58);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (337, 'Тренировка для детей 10-12 лет: 70% времени — игровые упражнения (1x1, 2x2, эстафеты). 30% — техника. Скучная работа оттолкнёт.', '2026-04-22 19:41:29.329963'::timestamp, 58);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (338, 'Ошибка тренеров ДЮСШ: учат много дриблинга, но не учат защите. Без защиты в 15 лет игрока просто не выпустят на паркет.', '2026-04-22 19:41:33.021880'::timestamp, 58);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (339, 'Мой опыт: пришёл мальчик 13 лет, с плохой координацией. За год простых упражнений с мячом (ведение с закрытыми глазами, жонглирование двумя мячами) он стал лидером команды по передачам.', '2026-04-22 19:41:36.278043'::timestamp, 58);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (340, 'Совет родителям: не заставляйте детей специализироваться рано. Пока рост не определился, пусть играют и на 1-м, и на 3-м номере. Позицию можно выбрать после 15-16 лет.', '2026-04-22 19:41:39.862342'::timestamp, 58);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (341, 'Игра центрового — не только пик-н-ролл. Бэкдаун с последующим скипом на дальний угол убивает защиту.', '2026-04-22 19:41:44.170440'::timestamp, 59);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (342, 'Как отбирать подбор: блокируй ближайшего соперника предплечьем, а не руками. Судьи редко свистят, а пространство выиграно.', '2026-04-22 19:41:47.954458'::timestamp, 59);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (343, 'Самый недооценённый навык для бигмена — передача из поста. Йокич и Сэбонис делают игру команды в 2 раза легче.', '2026-04-22 19:41:51.124551'::timestamp, 59);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (344, 'Тренировал центрового, который не умел защищаться на периметре после свитча. Посадил его на дриблинг с защитниками — через 3 месяца он стал терпимо перемещаться.', '2026-04-22 19:41:54.606406'::timestamp, 59);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (345, 'Кейс из Евролиги: Кайл Хайнс в ЦСКА при росте 198 см играл пятого номера за счёт тайминга блока и борьбы на щитах. Покажи это своим высоким игрокам — не ростом единым.', '2026-04-22 19:41:58.368405'::timestamp, 59);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (346, 'Задача первого номера — чувствовать темп. Если команда проигрывает 0-12, нужно замедлить игру и идти в краску, а не бросать трёхи.', '2026-04-22 19:42:02.082131'::timestamp, 60);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (347, 'Пас между ног в разрез — самый опасный, но и самый эффективный. Тренируй его с защитником на тренировках, чтобы не бояться в игре.', '2026-04-22 19:42:05.666346'::timestamp, 60);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (348, 'Как обыгрывать прессинг? Не останавливайся, двигайся зигзагом, держи спину к защитнику. Остановка — сразу два игрока на тебе.', '2026-04-22 19:42:08.670271'::timestamp, 60);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (349, 'Совет молодым разыгрывающим: записывай каждую свою потерю на видео и разбирай. Я так уменьшил свои потери с 4 до 1.5 за игру.', '2026-04-22 19:42:12.115977'::timestamp, 60);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (350, 'История: в 2019 году Стеф Карри рассказал, что тренирует «закрытое ведение» — когда защитник касается мяча, ты не теряешь контроль. Это упражнение с теннисным мячом изменило мою игру.', '2026-04-22 19:42:15.512436'::timestamp, 60);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (351, 'Индивидуальная защита: держи руку на поясе нападающего, чтобы чувствовать его движение, а не смотри на мяч.', '2026-04-22 19:42:18.977392'::timestamp, 61);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (352, 'Почему зона 3-2 против команды с двумя снайперами на крыльях — самоубийство? Потому что они растягивают, и центровой не успевает подстраховывать углы.', '2026-04-22 19:42:22.462462'::timestamp, 61);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (353, 'Лучший способ остановить быстрый прорыв — фол на подбирающем. Пока он на полу, твоя команда успевает построиться.', '2026-04-22 19:42:25.735671'::timestamp, 61);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (354, 'Обучал игрока, который постоянно смотрел на мяч в защите и терял своего. Поставил резинку между его запястьем и поясницей — если рука поднималась выше пояса, резинка тянула. Через месяц привык.', '2026-04-22 19:42:29.438595'::timestamp, 61);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (355, 'Кейс: «Майами Хит» переключились на зону 2-3 в плей-офф 2023 против Бостона. Татум не знал, где находится свободное пространство, и набирал 24 очка вместо 30. Адаптация — ключ.', '2026-04-22 19:42:33.008381'::timestamp, 61);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (356, 'Слухи: Дэмьян Лиллард может пойти в «Майами» до дедлайна. Майки отдадут Хирро, три пика и Дункана Робинсона. Тяжело, но возможно.', '2026-04-22 19:42:36.693122'::timestamp, 62);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (357, 'Почему «Юта» выменяла Джона Коллинза? Потому что отдали мало, а получили снайпера с 36% из-за дуги под схему Харди. Идеально.', '2026-04-22 19:42:40.379599'::timestamp, 62);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (358, 'Если «Голден Стэйт» не обменяет Уиггинса до плей-офф, их второй юнит будет слаб. Уиггинс проваливает защиту в этом сезоне.', '2026-04-22 19:42:44.064882'::timestamp, 62);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (359, 'Инсайд: в «Филадельфии» ищут разыгрывающего на замену Макси, если он уйдёт. Кандидаты — Тайс Джонс из «Вашингтона» и Малкольм Брогдон.', '2026-04-22 19:42:48.570839'::timestamp, 62);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (360, 'Реальная история: в 2021-м я писал, что «Кливленду» нужен Джарретт Аллен, и они взяли его за три вторых раунда. Через год он стал защитником года в конференции. Скауты иногда ошибаются, но не в этом случае.', '2026-04-22 19:42:52.481284'::timestamp, 62);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (361, 'Ключ к трёхе — не кисть, а ноги. Подготовка: широкие шаги, колени согнуты, вес на переднюю часть стопы.', '2026-04-22 19:42:55.739392'::timestamp, 63);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (362, 'Как исправить низкий процент штрафных? Выработай ритуал: 2 удара мячом, глубокий вдох, выдох — бросок. Убирает нервы.', '2026-04-22 19:42:59.030698'::timestamp, 63);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (363, 'Ошибка новичков — локоть в сторону. Правильный локоть смотрит на кольцо, локоть и запястье — одна линия.', '2026-04-22 19:43:02.395407'::timestamp, 63);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (364, 'Тренировал игрока с 25% трёхи. Изменил траекторию выпуска: мяч выше лба, взгляд на ближнюю дужку. Через месяц 34%.', '2026-04-22 19:43:05.570122'::timestamp, 63);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (365, 'Упражнение для точности: бросай с 5 точек подряд (углы, крылья, центр) — 5 попаданий с каждой. Потом увеличивай дистанцию. Простая статистика не врёт.', '2026-04-22 19:43:09.051075'::timestamp, 63);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (366, 'Майкл Джордан в финале 1998 года за 5 секунд украл мяч у Карла Мэлоуна и забил победный. Это был не только талант, но и знание привычек соперника.', '2026-04-22 19:43:12.633783'::timestamp, 64);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (367, '«Детройт Пистонс» 80-х — почему их называли «Плохие парни»? Потому что они легально фолили жёстко, а правила тогда были мягче. Билл Лэймбир — король провокаций.', '2026-04-22 19:43:16.729510'::timestamp, 64);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (368, 'Правило 24 секунд ввели в 1954 году, чтобы ускорить игру. До этого команды держали мяч по 5 минут, счёт был 19-18.', '2026-04-22 19:43:20.242058'::timestamp, 64);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (369, 'Пересматривал матч «Селтикс» — «Лейкерс» 1984. Ларри Бёрд украл передачу в решающий момент, хотя у него была температура 39. Настоящий победитель.', '2026-04-22 19:43:23.795641'::timestamp, 64);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (370, 'Рассказ: в 1992 году «Дрим Тим» выиграла золото в Барселоне со средней разницей +44 очка. Это было шоу, но и предупреждение миру: профессиональный баскетбол — космос.', '2026-04-22 19:43:27.607997'::timestamp, 64);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (371, 'Единая лига ВТБ: «Зенит» в этом году играет в 5 раз быстрее, чем при Паскуале. Спасибо Карасёву за свободу.', '2026-04-22 19:43:31.373247'::timestamp, 65);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (372, 'Почему российские команды плохо выступают в Евролиге? Из-за слабой глубины состава. В Лиге ВТБ уровень средних игроков ниже.', '2026-04-22 19:43:35.747601'::timestamp, 65);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (373, 'Алексей Швед — гений или проблема? Он набирает 22 очка, но на его защите соперники тоже набирают 25. Для топ-команды это слишком.', '2026-04-22 19:43:39.068646'::timestamp, 65);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (374, 'Кейс: молодой игрок ЦСКА 18 лет попал в ротацию из-за травм. В первых матчах боялся бросать. После доверия тренера стал набирать 12+5. Сейчас он в первой пятёрке.', '2026-04-22 19:43:42.806954'::timestamp, 65);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (375, 'Сравниваю Никиту Курбанова в 25 лет и сейчас. Раньше он был атлетичным форвардом, теперь — интеллектуальным защитником, который читает атаку на 2 шага вперёд. Эволюция.', '2026-04-22 19:43:46.384600'::timestamp, 65);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (376, 'Фол в нападении: если атакующий выпрямляет руку в защитника или отталкивается, свисток обязателен. Часто судьи пропускают.', '2026-04-22 19:43:49.599494'::timestamp, 66);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (377, 'Как отличить блок-фол от зарядного? Защитник должен занять позицию до начала движения атакующего. Если за секунду — не успел.', '2026-04-22 19:43:53.185140'::timestamp, 66);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (378, 'Самый сложный момент: фол при броске, когда игрок сам инициирует контакт (например, Джеймс Харден). По правилам это фол в нападении, но в НБА редко свистят.', '2026-04-22 19:43:56.563877'::timestamp, 66);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (379, 'Обучался в FIBA на курсах: нам давали видео, где 80% судей ошибаются в правиле «вертикальности». Руки вверх — не фол, руки вперёд — фол.', '2026-04-22 19:43:59.635247'::timestamp, 66);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (380, 'История: на чемпионате Европы судья пропустил откровенный пробежку в последней атаке. После игры он сказал: «Я смотрел на контакт под щитом и упустил ноги». Концентрация — главное.', '2026-04-22 19:44:03.220404'::timestamp, 66);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (381, 'В фэнтези бери игроков, которые набирают статы в нескольких категориях (ассист, подбор, блок). Узкие специалисты — риск.', '2026-04-22 19:44:06.700907'::timestamp, 67);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (382, 'Совет: смотри на минуты. Если игрок получает 30+ минут, но его рейтинг 15 PPG — бери. Время на площадке важнее таланта.', '2026-04-22 19:44:10.286488'::timestamp, 67);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (383, 'Не бери новичков в первых раундах. Вембаньяма — исключение, но обычно руки до 10-го пика.', '2026-04-22 19:44:13.560621'::timestamp, 67);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (384, 'Анализ: в этом сезоне недооценены Тайриз Халибертон (ассисты, трёхи) и Алперен Шенгюн (подборы, передачи из поста). Они поднимаются в топ-15.', '2026-04-22 19:44:16.837386'::timestamp, 67);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (385, 'Кейс: я взял на драфте Джа Моранта в 4-м раунде из-за дисквалификации на 25 игр. Когда он вернулся, выдавал топ-10 значения. Игра на долгую дистанцию.', '2026-04-22 19:44:20.131674'::timestamp, 67);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (386, 'В плей-офф сокращается ротация. 8 игроков — максимум. Тренеры доверяют только проверенным.', '2026-04-22 19:44:23.698343'::timestamp, 68);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (387, 'Клатчевый игрок — тот, кто не боится брать последний бросок. По статистике, Дэмэнт Лиллард и Леброн Джеймс — лучшие в истории по реализации в последних 5 секундах.', '2026-04-22 19:44:26.975212'::timestamp, 68);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (388, 'Почему «Денвер» выиграл титул? Потому что Майкл Мэлоун подстроил защиту под Майами: он менял Йокича на Батлера в пик-н-ролле, и это сбивало ритм.', '2026-04-22 19:44:30.559218'::timestamp, 68);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (389, 'Момент, который запомнился: Кавай Леонард в 2019 году забил отскоком от щита в 7-й игре против Филадельфии. Это не удача — он тренировал такие броски с рикошетом.', '2026-04-22 19:44:33.836751'::timestamp, 68);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (390, 'История: в 2004 году «Детройт» в плей-офф держали Шакила на 22 очках вместо 28 за счёт двойной подстраховки и фолов. Шак ненавидел бить штрафные, и они выбили Лейкерс. Тактика — королева.', '2026-04-22 19:44:37.445554'::timestamp, 68);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (391, 'ФИБА — другой баскетбол: меньше времени на атаку (24 секунды), нет трёхсекундной в защите, поэтому игра плотнее.', '2026-04-22 19:44:41.021854'::timestamp, 69);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (392, 'Сборная Испании выигрывает за счёт преемственности. Их резервисты знают систему с 18 лет. У нас в России — каждый год новая тактика.', '2026-04-22 19:44:44.177280'::timestamp, 69);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (393, 'Олимпиада 2024: США привезут лучших, но Франция с Вембаньямой и Гобером может навязать борьбу в краске.', '2026-04-22 19:44:47.302416'::timestamp, 69);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (394, 'Разбор финала Евробаскета 2022: Испания против Франции. Испанцы выключили Гобера с помощью 5-го номера, который уводил его из краски, а потом бросал трёхи.', '2026-04-22 19:44:50.526167'::timestamp, 69);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (395, 'Рассказ: в 2010 году я помогал сборной России. Дэвид Блатт ввёл систему «книга» — каждый игрок знал не только свою роль, но и роль соседа. Мы взяли бронзу. Система важнее талантов.', '2026-04-22 19:44:53.752947'::timestamp, 69);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (396, 'Продвинутая статистика: PER — хорошо, но VORP (Value Over Replacement Player) лучше показывает вклад в победы. Йокич лидирует оба последних года.', '2026-04-22 19:44:57.296489'::timestamp, 70);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (397, 'Эффективность в защите (DRtg) команды коррелирует с выигрышами сильнее, чем ORtg. Чемпионы всегда в топ-5 по защите.', '2026-04-22 19:45:00.884931'::timestamp, 70);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (398, 'True Shooting Percentage (TS%) учитывает штрафные и трёхи. У Джеймса Хардена в лучшие годы было 62% — на уровне Карри.', '2026-04-22 19:45:04.146658'::timestamp, 70);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (399, 'Смотрю на on/off команды: у Леброна в Лейкерс разница +9 очков на 100 владений, когда он на площадке. Без него минус 3. Вот вам MVP 2020 года.', '2026-04-22 19:45:07.532813'::timestamp, 70);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (400, 'Кейс: мы анализировали, почему «Голден Стэйт» провалил сезон 2024. Оказалось, что их эффективность в защите без Дрэймонда Грина падала на 12 пунктов. Защита — это не про блоки, а про коммуникацию.', '2026-04-22 19:45:11.211760'::timestamp, 70);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (401, 'ДНК-полимераза читает матрицу только в направлении 3''->5'', а синтезирует новую цепь в направлении 5''->3''. Это фундаментальное ограничение, из-за которого теломеры укорачиваются при каждом делении клетки.', '2026-04-22 19:45:17.984774'::timestamp, 71);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (402, 'РНК-интерференция позволяет глушить конкретные гены. За это открытие дали Нобелевку в 2006, а сейчас на этой технологии делают лекарства от рака и вирусных инфекций.', '2026-04-22 19:45:21.568310'::timestamp, 71);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (403, 'В 2020 году расшифровали геном коронавируса SARS-CoV-2 за рекордные 10 дней. Для сравнения: геном ВИЧ расшифровывали несколько лет. Прогресс секвенирования — это чистая магия.', '2026-04-22 19:45:25.342417'::timestamp, 71);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (404, 'Альтернативный сплайсинг — одна из причин, почему у человека всего 20 тысяч генов, а сложность организма выше, чем у червя с 19 тысячами генов. Один ген кодирует десятки разных белков.', '2026-04-22 19:45:28.354926'::timestamp, 71);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (405, 'CRISPR-Cas9 — система редактирования генома, позаимствованная у бактерий. Cas9 — это ножницы, которые режут ДНК в заданном месте. Гидовой РНК задаёшь мишень. Проблема: off-target эффекты, когда режется не там. Сейчас делают Cas9 с мутациями, которые повышают точность в 100 раз.', '2026-04-22 19:45:31.809625'::timestamp, 71);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (406, 'Митохондриальная ДНК передаётся только от матери. У отца митохондрии сперматозоида разрушаются в яйцеклетке. Поэтому все мы несём в себе митохондрии нашей мамы, её мамы и так до самой Евы.', '2026-04-22 19:45:35.071067'::timestamp, 71);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (407, 'Эпигенетика: ваши привычки, стресс и питание меняют метилирование ДНК и модификацию гистонов. Эти изменения могут передаваться детям. Голод в Нидерландах зимой 1944-45 привёл к изменению метилирования генов у внуков переживших голод.', '2026-04-22 19:45:38.465736'::timestamp, 71);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (408, 'Митохондрии — электростанции клетки, но они же и главный поставщик активных форм кислорода, которые повреждают ДНК. Теория старения связывает возрастные болезни именно с накоплением митохондриальных мутаций.', '2026-04-22 19:45:42.236745'::timestamp, 72);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (409, 'Лизосомы не просто переваривают мусор. Они ещё и сенсоры питательных веществ. Если лизосомы видят, что аминокислот мало, они запускают аутофагию — самоочищение клетки. За открытие этого механизма дали Нобелевку в 2016.', '2026-04-22 19:45:46.026014'::timestamp, 72);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (410, 'Цитоскелет из микротрубочек и актиновых филаментов — это не просто каркас. По микротрубочкам как по рельсам ездят моторные белки кинезин и динеин, доставляя грузы от ядра к мембране и обратно. Скорость — до 2 микрометров в секунду.', '2026-04-22 19:45:49.507419'::timestamp, 72);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (411, 'Я изучал деление клеток HeLa. Эти клетки бессмертны, потому что у них нарушен клеточный цикл. Их взяли у Генриетты Лакс в 1951 без её согласия, и до сих пор они используются в лабораториях по всему миру. Этическая дилемма, но биологическая ценность колоссальна.', '2026-04-22 19:45:52.581253'::timestamp, 72);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (412, 'Эндоплазматический ретикулум бывает гладким и шероховатым. Шероховатый — на нём рибосомы синтезируют белки для секреции. Гладкий — синтезирует липиды и детоксицирует яды. В клетках печени гладкий ЭПР занимает почти весь объём, потому что печень — главный фильтр организма.', '2026-04-22 19:45:55.754034'::timestamp, 72);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (413, 'Апоптоз — программируемая клеточная смерть. Митохондрии выпускают цитохром с, он активирует каспазы, и клетка аккуратно разрезается на апоптотические тельца, которые съедают макрофаги. Никакого воспаления. Когда апоптоз ломается — либо рак (клетки не умирают), либо аутоиммунные болезни (слишком много смерти).', '2026-04-22 19:45:59.646521'::timestamp, 72);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (414, 'Ядерная мембрана не просто мешок. С внутренней стороны к ней крепится ядерная ламина из белков ламинов. Мутации в ламинах вызывают прогерию — болезнь ускоренного старения у детей. Эти дети выглядят как старики и умирают в 12-15 лет.', '2026-04-22 19:46:02.923059'::timestamp, 72);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (415, 'Мутация в гене CCR5 делает людей устойчивыми к ВИЧ. Вирус проникает в клетку через рецептор CCR5, а если рецептор сломан — не заходит. «Берлинский пациент» получил пересадку костного мозга от донора с такой мутацией и вылечился от ВИЧ.', '2026-04-22 19:46:06.404092'::timestamp, 73);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (416, 'Ген FOXP2 называют «геном речи». У людей он немного отличается от шимпанзе. Но мутации в этом гене у человека вызывают тяжёлые расстройства речи и артикуляции.', '2026-04-22 19:46:09.697154'::timestamp, 73);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (417, 'Синдром Дауна — трисомия 21 хромосомы. Лишняя хромосома нарушает баланс экспрессии генов. У мышей трисомия по 16 хромосоме (она соответствует человеческой 21) вызывает похожие симптомы.', '2026-04-22 19:46:13.483467'::timestamp, 73);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (418, 'Наследственность признаков не всегда менделевская. Есть импринтинг — когда ген работает только если унаследован от конкретного родителя. Синдром Ангельмана и синдром Прадера-Вилли — классические примеры.', '2026-04-22 19:46:16.749270'::timestamp, 73);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (419, 'В Исландии компания deCODE genetics секвенировала полные геномы почти половины населения. Выяснили, что у исландцев очень низкое генетическое разнообразие, зато много редких мутаций, повышающих риск болезней. Зато нашли защитный вариант в гене APP, предотвращающий болезнь Альцгеймера.', '2026-04-22 19:46:19.817402'::timestamp, 73);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (420, 'Полиплоидия. У растений кратные наборы хромосом — норма. Пшеница гексаплоидная (6 наборов), клубника — октаплоидная (8 наборов). Полиплоиды часто крупнее и выносливее. У человека полиплоидия летальна, но бывает в клетках печени и костного мозга.', '2026-04-22 19:46:23.095001'::timestamp, 73);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (421, 'Генетика цвета глаз: не один ген, а минимум 16. Цвет определяет не пигмент, а количество меланина в радужке. Голубые глаза — это отсутствие меланина, а синий цвет — эффект рассеяния света (как небо).', '2026-04-22 19:46:26.270910'::timestamp, 73);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (422, 'Биоразнообразие стабилизирует экосистемы. Чем больше видов, тем выше шанс, что кто-то выживет после засухи. Эксперимент в Cedar Creek показал: при 10 видах продуктивность на 50% выше, чем при одном.', '2026-04-22 19:46:29.460596'::timestamp, 74);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (423, 'Инвазивные виды — вторая после уничтожения среды причина вымирания. Борщевик Сосновского в России, кролики в Австралии, змееголов в США.', '2026-04-22 19:46:32.839339'::timestamp, 74);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (424, 'Повышение температуры на 2 градуса к 2050 году сместит климатические зоны на 300-400 км к полюсам. Многие виды не смогут мигрировать так быстро.', '2026-04-22 19:46:36.508790'::timestamp, 74);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (425, 'Волки в Йеллоустоуне. Когда их истребили, олени расплодились и съели всю растительность по берегам рек. Реки изменили русло. Когда волков вернули — всё восстановилось.', '2026-04-22 19:46:40.093712'::timestamp, 74);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (426, 'Круговорот азота. Бактерии-азотфиксаторы превращают N2 в аммиак. Нитрифицирующие бактерии делают нитриты и нитраты. Человек синтезом аммиака по Габеру-Бошу удвоил количество связанного азота, вызвав эвтрофикацию водоёмов.', '2026-04-22 19:46:42.960614'::timestamp, 74);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (427, 'Коралловые рифы — симбиоз полипа и водорослей зооксантелл. При нагреве воды полипы выгоняют водоросли (обеление) и умирают. В 2016 году Большой Барьерный риф потерял 30% кораллов за год.', '2026-04-22 19:46:46.441112'::timestamp, 74);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (428, 'Микропластик найден в облаках, в снегу Арктики, в крови человека. Частицы меньше 5 микрон проникают через гематоэнцефалический барьер. Эксперименты на мышах показывают воспаление и снижение фертильности.', '2026-04-22 19:46:49.426843'::timestamp, 74);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (429, 'Естественный отбор работает на благо индивидуального генома, а не вида. У акул эмбрионы поедают друг друга в утробе — выживает самый агрессивный.', '2026-04-22 19:46:53.522819'::timestamp, 75);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (430, 'Рудименты и атавизмы: аппендикс, копчик, третье веко. У китов есть кости задних конечностей. У некоторых людей рождается хвост — атавизм.', '2026-04-22 19:46:57.019296'::timestamp, 75);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (431, 'Конвергентная эволюция. Сумчатый волк и плацентарный волк имеют почти одинаковую форму черепа, хотя их предки разошлись 160 млн лет назад.', '2026-04-22 19:47:00.266133'::timestamp, 75);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (432, 'Эволюция человека не остановилась. Ген устойчивости к ВИЧ CCR5-Δ32 распространился в Европе за последние 700 лет из-за эпидемий чумы. Мы теряем гены обоняния.', '2026-04-22 19:47:03.440299'::timestamp, 75);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (433, 'Индустриальный меланизм у берёзовой пяденицы. В Англии из-за сажи чёрные бабочки стали выживать чаще. Частота чёрной формы выросла с 1% до 95%. Потом сажу убрали — белые снова доминируют.', '2026-04-22 19:47:06.409417'::timestamp, 75);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (434, 'Почему мы стареем? Теория антагонистической плейотропии: гены, полезные в молодости, вредны в старости. Отбору плевать, что после 40.', '2026-04-22 19:47:10.198675'::timestamp, 75);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (435, 'У людей 1-4% генома от неандертальцев. Эти гены отвечают за иммунитет, цвет кожи, депрессию и зависимость от никотина. У африканцев их почти нет.', '2026-04-22 19:47:14.497201'::timestamp, 75);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (436, 'Вирусы не живые. У них нет метаболизма, они не размножаются вне клетки. Бактериофаги — вирусы, убивающие бактерий, — альтернатива антибиотикам.', '2026-04-22 19:47:17.878466'::timestamp, 76);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (437, 'Кишечная палочка E. coli — модельный организм. Делится каждые 20 минут, маленький геном. Мы знаем о ней почти всё.', '2026-04-22 19:47:21.373509'::timestamp, 76);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (438, 'Антибиотики убивают бактерий, но не вирусы. Поэтому при гриппе и ОРВИ они бесполезны. Зато бактериальные инфекции без них не лечатся.', '2026-04-22 19:47:24.430365'::timestamp, 76);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (439, 'Пенициллин открыли случайно: Флеминг заметил, что плесень убила бактерии в чашке Петри. С тех пор спасли миллиарды жизней.', '2026-04-22 19:47:28.015075'::timestamp, 76);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (440, 'Микробиом человека — 100 триллионов бактерий, в 10 раз больше наших собственных клеток. Весят около 2 кг. Влияют на иммунитет, настроение, вес.', '2026-04-22 19:47:31.102821'::timestamp, 76);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (441, 'Лихорадка Эбола убивает до 90% заражённых. Вирус атакует эндотелий сосудов, вызывая геморрагический синдром — кровь выходит через кожу.', '2026-04-22 19:47:34.781957'::timestamp, 76);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (442, 'Дрожжи Saccharomyces cerevisiae — тоже грибы. Используются в хлебопечении, пивоварении и как модельный организм для изучения клеточного цикла.', '2026-04-22 19:47:38.313170'::timestamp, 76);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (443, 'Фотосинтез — процесс превращения CO2 и воды в глюкозу с помощью света. КПД — всего 3-6%. Но без него не было бы кислорода.', '2026-04-22 19:47:41.939960'::timestamp, 77);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (444, 'Растения чувствуют гравитацию с помощью статолитов — крахмальных зёрен в клетках корня. Они падают вниз, и клетки знают, где низ.', '2026-04-22 19:47:45.113997'::timestamp, 77);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (445, 'У хищных растений (венерина мухоловка) листья захлопываются за 0.1 секунды. Механизм — изменение тургорного давления.', '2026-04-22 19:47:48.409714'::timestamp, 77);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (446, 'Фиторемедиация: некоторые растения вытягивают из почвы тяжёлые металлы. Тополь и ива используются для очистки загрязнённых земель.', '2026-04-22 19:47:51.683849'::timestamp, 77);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (447, 'Гормон этилен заставляет плоды созревать. Один переспелый банан в пакете ускорит созревание остальных. Это знают торговцы фруктами.', '2026-04-22 19:47:54.740056'::timestamp, 77);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (448, 'Дуб может жить 1000 лет. Его древесина не гниёт из-за дубильных веществ. Самый старый дуб в Европе — 1500 лет (в Литве).', '2026-04-22 19:47:57.829635'::timestamp, 77);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (449, 'Кактусы запасают воду в стеблях. Их корни расползаются на 2-3 метра в стороны, чтобы собирать влагу после редких дождей.', '2026-04-22 19:48:00.782094'::timestamp, 77);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (450, 'Осьминоги — три сердца, голубая кровь (гемоцианин вместо гемоглобина), и 500 миллионов нейронов, большая часть в щупальцах.', '2026-04-22 19:48:03.956558'::timestamp, 78);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (451, 'Летучие мыши — единственные млекопитающие, способные к активному полёту. Используют эхолокацию: ультразвук, отражённый от насекомого.', '2026-04-22 19:48:07.292269'::timestamp, 78);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (452, 'Гидра (пресноводный полип) практически бессмертна. Она постоянно обновляет клетки и не стареет. Размножается почкованием.', '2026-04-22 19:48:10.713086'::timestamp, 78);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (453, 'Тараканы могут жить без головы неделю. У них не заканчивается дыхание (дышат через дыхальца на теле) и нет большого кровяного давления.', '2026-04-22 19:48:13.683855'::timestamp, 78);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (454, 'Колибри — единственные птицы, умеющие летать назад. Их сердце бьётся до 1200 ударов в минуту в полёте.', '2026-04-22 19:48:16.755627'::timestamp, 78);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (455, 'Слоны помнят места водопоя и родственников десятилетиями. Мозг слона весит 5 кг, больше, чем у любого другого сухопутного животного.', '2026-04-22 19:48:20.647357'::timestamp, 78);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (456, 'Белая акула чувствует запах крови за 5 км. У неё особые клетки в носу — обонятельные луковицы размером с кулак.', '2026-04-22 19:48:23.517461'::timestamp, 78);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (457, 'Ферменты ускоряют реакции в миллионы раз. Карбоангидраза делает 10^6 превращений в секунду. Без неё углекислый газ выводился бы часами.', '2026-04-22 19:48:27.012543'::timestamp, 79);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (458, 'АТФ — универсальная энергетическая валюта клетки. Одна молекула АТФ даёт 30.5 кДж энергии при гидролизе.', '2026-04-22 19:48:30.580975'::timestamp, 79);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (459, 'Гемоглобин связывает кислород с помощью гема (железо). При отравлении угарным газом связывание в 200 раз прочнее — кислород не поступает.', '2026-04-22 19:48:33.872749'::timestamp, 79);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (460, 'Инсулин — гормон, снижающий сахар. При диабете 1 типа поджелудочная не вырабатывает инсулин. Раньше это был смертельный диагноз.', '2026-04-22 19:48:36.991947'::timestamp, 79);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (461, 'Холестерин нужен для построения мембран и синтеза гормонов. Его избыток вызывает атеросклероз. Печень производит 80% холестерина.', '2026-04-22 19:48:40.308315'::timestamp, 79);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (462, 'Рибозимы — молекулы РНК с ферментативной активностью. Это аргумент в пользу «мира РНК» — первой формы жизни на Земле.', '2026-04-22 19:48:43.443013'::timestamp, 79);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (463, 'Метаболизм алкоголя: алкогольдегидрогеназа превращает этанол в ацетальдегид (токсин), ацетальдегиддегидрогеназа — в ацетат. У азиатов часто мутация второй фермента — краснеют и пьянеют быстрее.', '2026-04-22 19:48:47.100453'::timestamp, 79);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (464, 'Нейроны передают сигнал с помощью потенциала действия — резкого изменения мембранного потенциала с -70 до +40 мВ. Скорость — до 120 м/с.', '2026-04-22 19:48:50.694988'::timestamp, 80);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (465, 'Синапс — место контакта между нейронами. Приходит импульс — выделяются нейромедиаторы (дофамин, серотонин), которые связываются с рецепторами следующего нейрона.', '2026-04-22 19:48:54.259495'::timestamp, 80);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (466, 'Дофамин — не «гормон счастья», а нейромедиатор предвкушения. Он выделяется, когда ждёшь награду, а не когда получаешь.', '2026-04-22 19:48:57.512372'::timestamp, 80);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (467, 'Миелиновая оболочка ускоряет проведение импульса. При рассеянном склерозе она разрушается — нервные сигналы затухают.', '2026-04-22 19:49:00.747946'::timestamp, 80);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (468, 'Гиппокамп отвечает за память. У лондонских таксистов, изучающих карту города, гиппокамп физически увеличивается в размерах.', '2026-04-22 19:49:04.781474'::timestamp, 80);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (469, 'Нейропластичность — мозг меняет структуру в ответ на опыт. Это основа обучения. Например, у музыкантов увеличены зоны коры, отвечающие за пальцы.', '2026-04-22 19:49:08.382421'::timestamp, 80);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (470, 'Зеркальные нейроны активируются и когда вы делаете действие, и когда видите, как его делает другой. Считается, что это основа эмпатии.', '2026-04-22 19:49:11.742988'::timestamp, 80);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (471, 'Вакцины тренируют иммунитет, создавая антитела и Т-клетки памяти. После встречи с реальным патогеном ответ быстрее и сильнее.', '2026-04-22 19:49:14.831108'::timestamp, 81);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (472, 'Антитела (иммуноглобулины) — Y-образные белки, которые связываются с антигенами вирусов и бактерий, помечая их для уничтожения.', '2026-04-22 19:49:17.886750'::timestamp, 81);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (473, 'Т-киллеры убивают заражённые клетки. Они распознают фрагменты вирусных белков на поверхности клетки и запускают апоптоз.', '2026-04-22 19:49:20.856492'::timestamp, 81);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (474, 'Аллергия — гиперреакция иммунитета на безвредные вещества (пыльцу, арахис). Вырабатываются антитела IgE, вызывающие выброс гистамина.', '2026-04-22 19:49:23.934660'::timestamp, 81);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (475, 'Аутоиммунные болезни — иммунитет атакует свои клетки. При ревматоидном артрите — суставы, при диабете 1 типа — бета-клетки поджелудочной.', '2026-04-22 19:49:27.426813'::timestamp, 81);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (476, 'Гной — это скопление погибших нейтрофилов (белых клеток крови) и бактерий. Нейтрофилы пожирают бактерий и сами умирают.', '2026-04-22 19:49:30.188696'::timestamp, 81);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (477, 'Температура при болезни — защитная реакция. Многие бактерии и вирусы размножаются хуже при 39°C. Поэтому сбивать температуру до 38.5 не рекомендуется.', '2026-04-22 19:49:33.771461'::timestamp, 81);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (478, 'Глубоководные рыбы имеют биолюминесценцию — светятся с помощью бактерий-симбионтов или собственных фотофоров. Привлекают добычу и партнёров.', '2026-04-22 19:49:37.651270'::timestamp, 82);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (479, 'Китовая акула — самая большая рыба в мире (до 18 метров). Питается планктоном, фильтруя воду через жаберные щели.', '2026-04-22 19:49:41.029706'::timestamp, 82);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (480, 'Кальмар-вампир (Vampyroteuthis) живёт на глубине 600-900 метров. Не нападает, а защищается биолюминесцентными «огненными шоу».', '2026-04-22 19:49:44.349956'::timestamp, 82);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (481, 'Рифы — это «тропические леса моря». На них живёт 25% всех морских видов, хотя они занимают меньше 1% океанского дна.', '2026-04-22 19:49:47.890373'::timestamp, 82);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (482, 'Дельфины спят с одним открытым глазом и активным полушарием мозга, чтобы всплывать для дыхания.', '2026-04-22 19:49:50.884665'::timestamp, 82);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (483, 'Морские черепахи возвращаются на тот же пляж, где родились, чтобы отложить яйца. Ориентируются по магнитному полю Земли.', '2026-04-22 19:49:54.674579'::timestamp, 82);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (484, 'Глубоководный удильщик: самка имеет удочку с приманкой (светящаяся железа). Самец в 10 раз меньше и прирастает к самке, паразитируя на ней.', '2026-04-22 19:49:57.823723'::timestamp, 82);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (485, 'BLAST — алгоритм поиска схожих последовательностей в базах данных. Сравнивает нуклеотиды или аминокислоты и показывает гомологию.', '2026-04-22 19:50:01.305270'::timestamp, 83);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (486, 'Секвенирование нового поколения (NGS) позволяет прочитать миллиарды фрагментов ДНК одновременно. Цена полного генома человека упала с $100 млн до $1000.', '2026-04-22 19:50:05.093488'::timestamp, 83);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (487, 'Филогенетические деревья строят по генетическим дистанциям. Чем меньше различий в консервативных генах (например, цитохром с), тем ближе виды.', '2026-04-22 19:50:08.472749'::timestamp, 83);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (488, 'Генетическая база данных NCBI GenBank содержит более 200 миллиардов нуклеотидных последовательностей. Доступна бесплатно.', '2026-04-22 19:50:11.763496'::timestamp, 83);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (489, 'Альфа-фолд — нейросеть Google DeepMind, предсказывающая 3D структуру белка по аминокислотной последовательности. Решила 50-летнюю проблему.', '2026-04-22 19:50:15.215266'::timestamp, 83);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (490, 'Пангеном — совокупность всех генов вида, включая редкие варианты. У человека в пангеноме на 100-200 млн пар оснований больше, чем в референсном геноме.', '2026-04-22 19:50:18.627130'::timestamp, 83);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (491, 'CRISPR-screen — метод, где с помощью библиотеки гидовых РНК выключают каждый ген по очереди и смотрят, какие нужны для роста клеток.', '2026-04-22 19:50:22.090419'::timestamp, 83);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (492, 'Сердце сокращается 100 тысяч раз в день, перекачивая 7-8 тысяч литров крови. За 70 лет — 2.5 миллиарда сокращений.', '2026-04-22 19:50:25.680072'::timestamp, 84);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (493, 'Лёгкие содержат 300 миллионов альвеол. Их общая площадь — 70-100 м², как теннисный корт.', '2026-04-22 19:50:28.995651'::timestamp, 84);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (494, 'Кожа — самый большой орган (2 м², 5 кг). Обновляется каждые 28 дней. За жизнь человек сбрасывает 40 кг омертвевших клеток.', '2026-04-22 19:50:31.600155'::timestamp, 84);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (495, 'Печень выполняет 500 функций: синтез белков, детоксикация, хранение гликогена. Может регенерировать до 70% после удаления.', '2026-04-22 19:50:34.789817'::timestamp, 84);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (496, 'Почечный клубочек фильтрует 180 литров крови в сутки. 99% воды возвращается обратно. Моча — концентрированный остаток.', '2026-04-22 19:50:37.962714'::timestamp, 84);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (497, 'Глаз различает 10 миллионов цветов, но только 1% цветовосприятия приходится на палочки (черно-белое ночное зрение).', '2026-04-22 19:50:41.752027'::timestamp, 84);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (498, 'Кишечник — 7-8 метров в длину. Площадь всасывания за счёт ворсинок — 200 м². Микробиом кишечника весит 1.5 кг.', '2026-04-22 19:50:45.058144'::timestamp, 84);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (499, 'Оплодотворение: сперматозоид проникает в яйцеклетку, запуская кортикальную реакцию — блокируется вход других сперматозоидов.', '2026-04-22 19:50:48.613611'::timestamp, 85);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (500, 'Дробление зиготы: первые деления не сопровождаются ростом — клетки становятся меньше. На стадии бластулы образуется полость.', '2026-04-22 19:50:51.581940'::timestamp, 85);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (501, 'Гаструляция — образование трёх зародышевых листков: эктодерма (кожа, нервы), мезодерма (мышцы, кости), энтодерма (кишечник, лёгкие).', '2026-04-22 19:50:55.371784'::timestamp, 85);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (502, 'Нейруляция: эктодерма на спинной стороне прогибается и образует нервную трубку — будущий мозг и спинной мозг.', '2026-04-22 19:50:58.956376'::timestamp, 85);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (503, 'Гомеозисные гены (Hox) определяют план тела: где быть голове, рукам, ногам. У дрозофилы мутация Hox превращает усики в ноги.', '2026-04-22 19:51:02.232039'::timestamp, 85);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (504, 'Тератогены — факторы, вызывающие уродства. Алкоголь — фетальный алкогольный синдром. Талидомид (лекарство) — отсутствие конечностей.', '2026-04-22 19:51:05.815466'::timestamp, 85);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (505, 'Старение — запрограммированный процесс. Укорачивание теломер, накопление мутаций митохондрий, снижение аутофагии.', '2026-04-22 19:51:08.801609'::timestamp, 85);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (506, 'Перечитал «Войну и мир» в 30 лет — совсем другое восприятие, чем в школе. Андрей Болконский теперь не герой, а эгоист с кризисом среднего возраста.', '2026-04-22 19:51:14.210733'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (507, 'Достоевский слишком многословен, но когда доходит до кульминации — пробирает до мурашек. «Преступление и наказание» читаешь и чувствуешь эту духоту Петербурга.', '2026-04-22 19:51:17.602421'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (508, 'Почему «Гордость и предубеждение» до сих пор читают? Потому что мистер Дарси — архетип мужчины, который меняется ради любви. Женщины ждут этого 200 лет.', '2026-04-22 19:51:20.867961'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (509, 'Флобер писал «Мадам Бовари» два года, переписывая каждую страницу по десять раз. Результат — каждая фраза как отточенный нож. Эмма — жертва не мужчин, а своих иллюзий.', '2026-04-22 19:51:23.969597'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (510, 'Интересно, что «1984» Оруэлла воспринимается сейчас не как антиутопия, а как инструкция. Двухминутка ненависти — это любой ток-шоу на ТВ. Двоемыслие — обычный когнитивный диссонанс.', '2026-04-22 19:51:27.216382'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (511, 'Толстой гениально описал внутренний монолог. Когда Анна Каренина едет на вокзал и у неё мелькают мысли о моде, о детях, о Вронском — это чистая правда сознания.', '2026-04-22 19:51:30.304798'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (512, '«Улисс» Джойса я осилил с третьего раза. Первые сто страниц — пытка, потом втягиваешься в поток сознания и ловишь кайф от языка. Но обычному читателю не надо.', '2026-04-22 19:51:33.511375'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (513, 'Из современной классики: «Щегол» Донны Тартт — великий роман о травме и искусстве. 800 страниц пролетают незаметно, хотя в середине провисает сюжет.', '2026-04-22 19:51:36.468280'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (514, 'Чехов не писал романов, только рассказы и пьесы. «Вишнёвый сад» — трагикомедия, где никто не виноват, но всем больно. Лопахин — самый несчастный, потому что получил то, что хотел.', '2026-04-22 19:51:39.504642'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (515, 'Гюго в «Отверженных» мог отвлечься на 50 страниц, чтобы описать битву при Ватерлоо. Это бесит, но когда доходишь до финала, понимаешь: без этих отступлений не было бы масштаба.', '2026-04-22 19:51:42.882230'::timestamp, 86);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (516, 'Властелин колец — не про кольцо, а про травму войны. Фродо возвращается домой и не может найти себя. Толкин знал, о чём писал.', '2026-04-22 19:51:46.892478'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (517, 'Сандерсон придумал магическую систему с твёрдыми правилами — это гениально. В «Рожденном туманом» металлы работают как законы физики, а не как рояль в кустах.', '2026-04-22 19:51:49.862122'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (518, 'Почему «Имя ветра» Ротфусса так любят? Потому что Квоут — гений, который всё про*бывает. Мы видим себя в его падениях, а не в взлётах.', '2026-04-22 19:51:52.917904'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (519, '«Песнь льда и пламени» Мартина не закончится никогда. Я смирился. Но первые три книги — шедевр политического фэнтези, где умирают все, кого ты полюбил.', '2026-04-22 19:51:56.195277'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (520, 'Урсула Ле Гуин в «Волшебнике Земноморья» показала, что истинная сила — в принятии тени. Гед победил не заклинанием, а тем, что назвал дракона по имени.', '2026-04-22 19:52:00.803777'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (521, 'Цикл «Ведьмак» Сапковского — это не про монстров, а про выбор меньшего зла. Геральт пытается быть нейтральным, но мир заставляет его выбирать.', '2026-04-22 19:52:04.507785'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (522, '«Гарри Поттер» для детей, но взрослые плачут на моменте с Сириусом. Роулинг гениально вписала темы смерти и выбора в детскую книгу.', '2026-04-22 19:52:07.928970'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (523, 'Нил Гейман в «Американских богах» показал, что старые боги живут среди нас. Тень — идеальный антигерой: молчаливый, сильный, сломленный.', '2026-04-22 19:52:11.554948'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (524, 'Читал «Чёрный принц» Корнелии Функе — лучшее young adult про чернильную магию. Жаль, что третья книга не дотянула до первых двух.', '2026-04-22 19:52:15.972147'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (525, '«Король Воронов» от Лоуренса — тёмное фэнтези с антигероем, который вызывает отвращение. Но к концу ты начинаешь его понимать.', '2026-04-22 19:52:19.438685'::timestamp, 87);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (526, 'Агата Кристи написала 66 детективных романов. Пуаро появляется в 33 из них. И нигде не описана его смерть, кроме финального романа «Занавес».', '2026-04-22 19:52:23.256928'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (527, '«Молчание ягнят» Харриса страшнее фильма. В книге Лектер ещё более изощрённый, а Кларисса Старлинг — глубже показана её травма.', '2026-04-22 19:52:26.402374'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (528, 'Триллеры Ю Несбё про Харри Холе — нордический нуар. Осло никогда не выглядит уютно. Алкоголизм главного героя не романтизирован, а показан как болезнь.', '2026-04-22 19:52:29.782297'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (529, 'Почему «Остров проклятых» Лехейна — шедевр? Потому что концовку нельзя предугадать, но когда дочитываешь — понимаешь, что все улики были разбросаны с первой главы.', '2026-04-22 19:52:33.058474'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (530, 'Деннис Лихэйн в «Мистической реке» написал трагедию о том, как детская травма определяет жизнь. Трое друзей, и один из них убийца — спойлер не страшен, важен путь.', '2026-04-22 19:52:37.053210'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (531, '«Девушка с татуировкой дракона» Стига Ларссона — это не детектив, а социальный роман о насилии над женщинами. Лисбет Саландер — икона феминизма.', '2026-04-22 19:52:40.329578'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (532, 'Я обожаю «Стеклянный ключ» Хэммета — классический нуар. Там нет крутого детектива, есть политикан, который ищет убийцу, потому что это выгодно.', '2026-04-22 19:52:43.399916'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (533, 'Пелевин написал «Тайные виды на гору Фудзи» — вроде детектив, а на самом деле философский трактат о деньгах и реальности. Но читается как триллер.', '2026-04-22 19:52:47.101747'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (534, 'Из новинок: «Только спокойствие» Харли — про маньяка в маленьком городке. Автор психолог, поэтому поведение жертв и убийцы прописано очень реалистично.', '2026-04-22 19:52:50.568398'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (535, 'Шведские детективы: Хокан Нессер круче, чем Ларссон. Серия про инспектора Барбротти — медленные, тягучие, но когда развязка наступает — мороз по коже.', '2026-04-22 19:52:53.662149'::timestamp, 88);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (536, '«Гордость и предубеждение» — идеальный роман, потому что Элизабет сначала ненавидит Дарси. Любовь из ненависти работает всегда.', '2026-04-22 19:52:57.022984'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (537, 'Николас Спаркс пишет слёзовыжималки, но «Спеши любить» честен. Смерть в финале не ради драмы, а ради того, чтобы показать ценность каждого дня.', '2026-04-22 19:53:00.603594'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (538, 'Современная романтика: «После» Анны Тодд — toxic relationship, который нравится подросткам. Но взрослые читают «Любовь с первого клика» Хейзелвуд — умные герои и диалоги.', '2026-04-22 19:53:04.138451'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (539, 'Джоджо Мойес в «До встречи с тобой» создала этическую дилемму: имеет ли право человек на эвтаназию. Любовь не лечит всё, и это честно.', '2026-04-22 19:53:07.463943'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (540, '«Книжный вор» Маркуса Зусака — не совсем роман, но любовь к книгам и девочке Лизель спасает во время войны. Одна из самых трогательных книг.', '2026-04-22 19:53:10.370568'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (541, 'Романтика в фэнтези: «Жена между нами» — про любовь через время. Авторы играют с памятью и чувством вины. Не ожидал такого от жанра.', '2026-04-22 19:53:13.224921'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (542, '«Вино из одуванчиков» Брэдбери — это ностальгия и первая любовь. Читаешь и чувствуешь запах лета и травы. Идеально для уютного вечера.', '2026-04-22 19:53:16.577030'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (543, 'Хейзелвуд в «Любви с первого клика» показала, что герои могут быть умными и говорить как взрослые люди. Наконец-то нет тропа «тупая блондинка».', '2026-04-22 19:53:19.649108'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (544, '«Элеанор Олифант в полном порядке» — не совсем роман, но история любви к себе. Главная героиня — социально неуклюжая, и ты за неё болеешь.', '2026-04-22 19:53:23.029355'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (545, 'Из классики: «Джейн Эйр» Шарлотты Бронте. Джейн выбирает себя, а не мужчину. Это прогрессивно даже для современного романа.', '2026-04-22 19:53:26.305835'::timestamp, 89);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (546, '«Автостопом по галактике» Дугласа Адамса — лучшая пародия на научную фантастику. Ответ на главный вопрос — 42, и это гениально в своей абсурдности.', '2026-04-22 19:53:29.786659'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (547, 'Айзек Азимов придумал Три закона роботехники, и потом все писатели с ними спорили. «Стальные пещеры» — детектив с роботом, лучшее введение в его вселенную.', '2026-04-22 19:53:33.437037'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (548, 'Филип Дик в «Мечтают ли андроиды об электроовцах?» поднял вопрос о том, что такое человек. Эмпатия — вот критерий. Адаптация «Бегущий по лезвию» изменила концовку, но книга глубже.', '2026-04-22 19:53:36.852921'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (549, '«Гиперион» Дэна Симмонса — это «Кентерберийские рассказы» в космосе. Каждый паломник рассказывает свою историю, и все они связаны с Шрайком — чудовищем вне времени.', '2026-04-22 19:53:40.114994'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (550, 'Орсон Скотт Кард в «Игре Эндера» показал, что гениальный ребёнок — это не мило, а трагедия. Эндер не хотел уничтожать целую расу, но его обманули.', '2026-04-22 19:53:43.097934'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (551, '«Три проблемы» Лю Цысиня — китайская твёрдая НФ. Физика там такая, что голова идёт кругом, а игра с инопланетным разумом через компьютерную игру — оригинально.', '2026-04-22 19:53:46.680924'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (552, 'Урсула Ле Гуин в «Левой руке тьмы» придумала планету, где люди не имеют пола, а становятся мужчинами или женщинами раз в месяц. Как меняется общество и любовь?', '2026-04-22 19:53:49.725131'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (553, 'Нил Стивенсон в «Алмазном веке» описал будущее, где микротехнологии изменили всё. Но главное — наноассемблеры и иллюзия бессмертия.', '2026-04-22 19:53:52.928054'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (554, '«Вспомни о Флебе» Вернора Винджа — это hard sci-fi, где сверхразумный ИИ и люди пытаются выжить. Автор — математик, поэтому техническая сторона безупречна.', '2026-04-22 19:53:57.040677'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (555, 'Короткая и страшная: «Я, робот» — не только позитивные истории. Есть рассказ, где роботы пришли к выводу, что лучшее для человечества — лишить его свободы.', '2026-04-22 19:54:00.198459'::timestamp, 90);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (556, '«Имя розы» Умберто Эко — детектив в монастыре 14 века. Но на самом деле книга о библиотеках, знании и том, как смех разрушает власть.', '2026-04-22 19:54:03.680181'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (557, 'Кенотафий? Нет, «Сто лет одиночества» Маркеса — это история Колумбии через призму семьи. Каждый персонаж — аллегория, а финальный ураган сметает всё.', '2026-04-22 19:54:07.469631'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (558, '«Война и мир» — исторический роман, но Толстой переписал историю, сделав Кутузова гением, а Наполеона — карикатурой. Увлекательно, но не фактологично.', '2026-04-22 19:54:10.626894'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (559, '«Столпы земли» Фоллетта — строительство собора в 12 веке. Неожиданно триллер: заговоры, убийства, интриги. И всё на фоне реальной истории Англии.', '2026-04-22 19:54:14.230381'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (560, '«Триумфальная арка» Ремарка — любовь в Париже накануне войны. Герои — эмигранты без паспортов. Каждая глава дышит безысходностью и надеждой.', '2026-04-22 19:54:17.154292'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (561, 'Шёлк Баррико — тонкая новелла о путешествиях и любви. 100 страниц, но читаешь как поэму. Япония 19 века, торговля шёлком и тайное чувство.', '2026-04-22 19:54:20.165400'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (562, '«Крестный отец» Пьюзо — не только про мафию, но и про иммиграцию. Семья Корлеоне — сицилийцы, которые строят свой мир в Америке. Исторический контекст важен.', '2026-04-22 19:54:23.677894'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (563, 'Гилад Атлант расправил плечи? Нет, «Один день Ивана Денисовича» Солженицына — точный срез жизни в ГУЛАГе. Один день, без сантиментов.', '2026-04-22 19:54:26.924452'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (564, '«Мушкетёры» Дюма — исторический роман, где история переписана ради авантюры. Но читается как блокбастер. И королевские подвески — реальная деталь.', '2026-04-22 19:54:30.373226'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (565, '«Граф Монте-Кристо» — это месть как двигатель сюжета. Но в историческом контексте показано, как менялась Франция после Наполеона. Эдмон — жертва системы.', '2026-04-22 19:54:33.896352'::timestamp, 91);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (566, 'Маяковский в стихах рубит ритм как топором. «Послушайте! Ведь если звезды зажигают — значит это кому-нибудь нужно?» — гениальная простота.', '2026-04-22 19:54:37.267007'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (567, 'Анна Ахматова писала «Реквием» 30 лет. Каждая строфа — о потерянном сыне и женской боли. Читать это вслух невозможно без комка в горле.', '2026-04-22 19:54:40.339107'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (568, 'Уильям Блейк: «Видеть мир в одной песчинке». Его пророческие книги не понять с первого раза, но его лирика — чистая энергия.', '2026-04-22 19:54:43.711703'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (569, 'Бродский в «Полночных стихах» соединил русский язык и английский ритм. Эмигрантская тоска, но без сентиментов. «Ни страны, ни погоста не хочу выбирать».', '2026-04-22 19:54:47.908047'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (570, 'Роберт Фрост — кажется простым, но на самом деле сложен. «Невыбранная дорога» — это не про выбор, а про самооправдание. Любая дорога ведёт туда же.', '2026-04-22 19:54:51.294620'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (571, 'Пабло Неруда писал оды обычным вещам — луку, носкам, артишоку. Это учит замечать красоту в быту. «Ода луку» — восхитительная.', '2026-04-22 19:54:55.009976'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (572, 'Есенин — хулиган и неженка одновременно. «Письмо матери» читаешь и чувствуешь вину перед своими родителями. Искренность спасает от слащавости.', '2026-04-22 19:54:58.462816'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (573, 'Цветаева — самый сильный женский голос в поэзии. «Мне нравится, что вы больны не мной» — игра чувств, скрытая под маской равнодушия.', '2026-04-22 19:55:01.843164'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (574, 'Из современной поэзии: Вера Полозкова. «Небо над головой не терпит соседства с высоким званием женщины». Жёстко и точно.', '2026-04-22 19:55:05.529382'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (575, 'Басё: хайку в 17 слогов. «Старый пруд. Прыгнула лягушка. Всплеск воды». Минимум слов, максимум смысла. Медитация.', '2026-04-22 19:55:08.703264'::timestamp, 92);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (576, '«Стив Джобс» Уолтера Айзексона — честный портрет гения-мудака. Джобс был жестоким манипулятором, но без этого Apple не стала бы Apple.', '2026-04-22 19:55:12.082534'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (577, '«Черный лебедь» Нассима Талеба — не биография, но он рассказывает о своей жизни трейдера. Как случайность и риск меняют всё.', '2026-04-22 19:55:15.786345'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (578, 'Прочитал мемуары Андре Агасси «Открыто». Он ненавидел теннис, но стал легендой. Честно о боли, наркотиках и любви к Штеффи Граф.', '2026-04-22 19:55:19.176869'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (579, '«К себе нежно» Лены Соколовой — история девушки, которая пережила буллинг и нашла себя. Психологическая биография, которая помогает.', '2026-04-22 19:55:23.183216'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (580, '«Автобиография Бенджамина Франклина» — как стать успешным в 18 веке. 13 добродетелей, ежедневный контроль, ранний подъём. До сих пор актуально.', '2026-04-22 19:55:28.656929'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (581, '«Конец тура» Дэвида Липски — про писателя Дэвида Фостера Уоллеса. Депрессия, гениальность, одиночество. Читать тяжело, но важно.', '2026-04-22 19:55:32.269824'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (582, 'Майкл Джексон: «Moonwalk» — его автобиография. Написана белыми пятнами, многое скрыто. Но о детстве и музыке честно.', '2026-04-22 19:55:35.942680'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (583, '«Илон Маск» Эшли Вэнс — портрет человека, который спит по 4 часа и увольняет друзей. Гениальность и социопатия идут рука об руку.', '2026-04-22 19:55:39.000223'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (584, '«Вся кремлёвская рать» Зыгаря — коллективная биография путинского окружения. Политический репортаж, читается как роман.', '2026-04-22 19:55:42.391249'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (585, '«Бесконечная шутка» — это не биография, а автобиографичный роман Уоллеса. Теннис, наркотики и поиск счастья. Объём пугает, но оно того стоит.', '2026-04-22 19:55:46.384796'::timestamp, 93);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (586, '«7 навыков высокоэффективных людей» Стивена Кови. Главный навык — быть проактивным, а не реактивным. Между стимулом и реакцией есть свобода выбора.', '2026-04-22 19:55:49.984070'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (587, '«Думай медленно, решай быстро» Канерамана — как наши мозги ошибаются. Система 1 (быстрая) и Система 2 (медленная). Когнитивные искажения.', '2026-04-22 19:55:53.246416'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (588, '«Богатый папа, бедный папа» Кийосаки — учит отличать активы от пассивов. Но не всё там правда, некоторые истории выдуманы.', '2026-04-22 19:55:57.238898'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (589, '«Атомные привычки» Клира: улучшай себя на 1% каждый день. Система важнее целей. Сделай привычку очевидной, привлекательной, лёгкой и удовлетворяющей.', '2026-04-22 19:56:00.722361'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (590, '«Сила воли» Макгонигал: почему мы прокрастинируем. Воля как мышца — её можно тренировать, но она устаёт. Сахар восстанавливает.', '2026-04-22 19:56:04.218628'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (591, '«Выбор» Эдит Ева Эгер — психолог, пережившая Освенцим. О том, что свобода — это выбор реакции на обстоятельства. Мощнейшая книга.', '2026-04-22 19:56:07.293368'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (592, '«Эссенциализм» Маккеона: делай меньше, но лучше. Отсекай всё неважное. Правило 90% — если не «вау», то нет.', '2026-04-22 19:56:10.552940'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (593, '«Как завоёвывать друзей» Карнеги — старая, но работающая. Искренне интересуйся другими, улыбайся, помни имя.', '2026-04-22 19:56:13.587756'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (594, '«Гибкое сознание» Двека — о том, что установка на рост важнее таланта. Хвали не ум, а усилия. Ребёнок с установкой на рост не боится ошибок.', '2026-04-22 19:56:16.900793'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (595, '«Счастливый человек» Михая Чиксентмихайи — поток как состояние полного погружения. Когда вызов соответствует навыкам — время останавливается.', '2026-04-22 19:56:20.148721'::timestamp, 94);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (596, '«Маленький принц» Сент-Экзюпери — взрослые не понимают, о чём книга. Лис: «Мы в ответе за тех, кого приручили». О дружбе и одиночестве.', '2026-04-22 19:56:23.762459'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (597, '«Винни Пух» Милна — не просто про плюшевого медведя. Это философия: ослик Иа — депрессия, Пятачок — тревожность, а Пух — принятие.', '2026-04-22 19:56:27.037758'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (598, '«Гарри Поттер и философский камень» — лучший вход в большое чтение для детей. Школа магии, дружба и выбор между правильным и лёгким.', '2026-04-22 19:56:30.213570'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (599, '«Малыш и Карлсон» Линдгрен — история о том, как ребёнок справляется с одиночеством. Карлсон — воображаемый друг, который живёт на крыше.', '2026-04-22 19:56:33.568601'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (600, '«Алиса в стране чудес» Кэрролла — абсурд, который учит не бояться логики. С ума сошёл не только Шляпник, но и весь мир.', '2026-04-22 19:56:36.867818'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (601, '«Чук и Гек» Гайдара — про путешествие детей к папе в геологическую экспедицию. Честность, взаимовыручка и романтика тайги.', '2026-04-22 19:56:40.042813'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (602, '«Том Сойер» Твена — дети красят забор, играют в пиратов, сбегают на остров. Но книга про взросление и умение брать ответственность.', '2026-04-22 19:56:43.429022'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (603, '«Мэри Поппинс» Трэверс — строгая няня, которая умеет летать. Она учит детей видеть чудеса в обыденности. Но уходит, когда ветер меняется.', '2026-04-22 19:56:46.814186'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (604, '«Незнайка на Луне» Носова — сатира на капитализм, которую дети читают как приключение. Остров дураков и акционерные общества.', '2026-04-22 19:56:50.383690'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (605, '«Крокодил Гена и его друзья» Успенского — Чебурашка стал символом добра. Книга о том, как найти друзей, когда ты одинок.', '2026-04-22 19:56:53.722361'::timestamp, 95);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (606, 'Реакция SN2 идёт с инверсией конфигурации. Если не верите, поставьте эксперимент с хиральным субстратом — оптическая активность поменяется на противоположную.', '2026-04-22 19:57:01.827511'::timestamp, 96);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (607, 'Ароматичность по Хюккелю: 4n+2 π-электронов в циклической сопряжённой системе. Бензол (6 электронов) — ароматичен, циклобутадиен (4) — нет, он димер.', '2026-04-22 19:57:05.554437'::timestamp, 96);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (608, 'Механизм реакций электрофильного замещения в ароматическом кольце: сначала образование σ-комплекса (медленно), затем отрыв протона. Нитрование бензола — классика.', '2026-04-22 19:57:09.023033'::timestamp, 96);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (609, 'Гидрирование алкенов на палладии или никеле идёт с син-присоединением. Платина даёт ту же стереохимию. Для анти-присоединения нужна натриевая аммиачная редукция алкинов.', '2026-04-22 19:57:12.296787'::timestamp, 96);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (610, 'Почему третичные карбокатионы стабильнее первичных? Гиперконъюгация и индуктивный эффект алкильных групп. Это основа правила Марковникова.', '2026-04-22 19:57:15.982853'::timestamp, 96);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (611, 'Кристаллическое поле: октаэдрическое расщепление d-орбиталей на eg и t2g. У Cr3+ в [Cr(H2O)6]3+ три неспаренных электрона — параметр Рака B 918 см⁻¹.', '2026-04-22 19:57:19.669463'::timestamp, 97);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (612, 'Правило 18 электронов для комплексов переходных металлов. У Fe(CO)5 — 18 электронов (Fe 8 + 5×2 = 18). У V(CO)6 — 17, он парамагнитен.', '2026-04-22 19:57:23.401290'::timestamp, 97);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (613, 'Изомерия в координационных соединениях: геометрическая (цис-транс) и оптическая. Цис- [Pt(NH3)2Cl2] противоопухолевый (цисплатин), транс- неактивен.', '2026-04-22 19:57:26.633401'::timestamp, 97);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (614, 'Кислоты Льюиса: AlCl3, BF3, FeCl3 — классические катализаторы алкилирования. Они акцепторы электронной пары. Основания Льюиса — доноры.', '2026-04-22 19:57:30.011540'::timestamp, 97);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (615, 'Силикаты — основа земной коры. Кварц (SiO2) — трёхмерный каркас, слюды — слоистые, тальк — тоже слоистый, чем объясняется его мягкость.', '2026-04-22 19:57:33.509408'::timestamp, 97);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (616, 'Моль — это количество вещества, содержащее столько же частиц, сколько атомов в 12 г углерода-12. Число Авогадро 6.022×10²³. Запомните раз и навсегда.', '2026-04-22 19:57:36.875561'::timestamp, 98);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (617, 'Степень окисления — это формальный заряд атома, вычисленный по правилам: у кислорода в оксидах -2, у водорода +1 (кроме гидридов). В пероксидах у кислорода -1.', '2026-04-22 19:57:39.858687'::timestamp, 98);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (618, 'Оксиды делятся на солеобразующие (основные, кислотные, амфотерные) и несолеобразующие (CO, NO). Основные оксиды реагируют с кислотами, кислотные — с щелочами.', '2026-04-22 19:57:43.244260'::timestamp, 98);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (619, 'Электролитическая диссоциация: кислоты — это электролиты, которые при растворении отщепляют катионы водорода. Сильные кислоты (HCl, H2SO4) диссоциируют полностью.', '2026-04-22 19:57:46.807056'::timestamp, 98);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (620, 'Периодический закон Менделеева: свойства элементов зависят от заряда ядра. Радиус атома уменьшается в периоде слева направо (из-за роста заряда ядра).', '2026-04-22 19:57:50.390430'::timestamp, 98);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (621, 'Полиэтилен высокого давления (LDPE) — разветвлённый, низкой плотности. Низкого давления (HDPE) — линейный, плотный. Разные свойства из-за механизма полимеризации.', '2026-04-22 19:57:53.466999'::timestamp, 99);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (622, 'Степень полимеризации — среднее число мономерных звеньев в цепи. Для ПЭ бутылки ~ 5000. Чем выше степень, тем прочнее и твёрже полимер.', '2026-04-22 19:57:56.961585'::timestamp, 99);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (623, 'Термопласты (полиэтилен, полипропилен) размягчаются при нагревании — это обратимый процесс. Реактопласты (эпоксидка, фенолформальдегид) отверждаются необратимо.', '2026-04-22 19:58:00.322865'::timestamp, 99);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (624, 'Стеклование и плавление полимеров. Температура стеклования Tg — переход из стеклообразного в высокоэластичное состояние. У ПЭ Tg ~ -80°C, поэтому он эластичен при комнатной температуре.', '2026-04-22 19:58:04.031165'::timestamp, 99);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (625, 'Металлоценовые катализаторы позволяют получать изотактический полипропилен с высокой стереорегулярностью — кристаллизуется до 60%.', '2026-04-22 19:58:07.797979'::timestamp, 99);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (626, 'Гликолиз: расщепление глюкозы до двух молекул пирувата. Выход — 2 АТФ и 2 НАДН. Без кислорода пируват превращается в лактат (у животных) или этанол (у дрожжей).', '2026-04-22 19:58:11.790045'::timestamp, 100);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (627, 'Цикл Кребса: ацетил-КоА окисляется до CO2, восстанавливая НАД⁺ до НАДН и ФАД до ФАДН2. Один оборот цикла даёт 3 НАДН, 1 ФАДН2, 1 ГТФ.', '2026-04-22 19:58:15.594344'::timestamp, 100);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (628, 'Ферменты — биокатализаторы. Лизоцим гидролизует пептидогликан бактериальной стенки, понижая энергию активации с 53 до 8 ккал/моль.', '2026-04-22 19:58:18.547928'::timestamp, 100);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (629, 'Гемоглобин связывает O2 кооперативно — кривая диссоциации сигмоидная. Присоединение первой молекулы кислорода увеличивает сродство к остальным (эффект гема).', '2026-04-22 19:58:21.825036'::timestamp, 100);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (630, 'АТФ — универсальный переносчик энергии. Гидролиз АТФ до АДФ и неорганического фосфата даёт -30.5 кДж/моль. Этого хватает на многие реакции.', '2026-04-22 19:58:25.119687'::timestamp, 100);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (631, 'ВЭЖХ — высокоэффективная жидкостная хроматография. Обращённая фаза (C18, C8) — самая распространённая. Подвижная фаза — вода/ацетонитрил/метанол.', '2026-04-22 19:58:28.685827'::timestamp, 101);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (632, 'Масс-спектрометрия с ионизацией электроспреем (ESI) позволяет анализировать биомолекулы без деструкции. Белки с молекулярной массой до 200 кДа летят.', '2026-04-22 19:58:32.167496'::timestamp, 101);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (633, 'Титрование сильной кислоты сильным основанием: скачок pH вблизи точки эквивалентности. Фенолфталеин меняет цвет при pH 8.2-10.0, метилоранж — 3.1-4.4.', '2026-04-22 19:58:35.649968'::timestamp, 101);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (634, 'Атомно-абсорбционная спектроскопия: определяет металлы по поглощению резонансного излучения. Предел обнаружения для свинца — 0.1 ppb.', '2026-04-22 19:58:39.250359'::timestamp, 101);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (635, 'ЯМР-спектроскопия: химический сдвиг зависит от электронного окружения. Сигнал альдегидного протона при 9-10 м.д., ароматического — 7-8.', '2026-04-22 19:58:42.406436'::timestamp, 101);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (636, 'Фотохимический смог образуется при участии оксидов азота и углеводородов под действием ультрафиолета. Основной компонент — озон и пероксиацилнитраты (ПАН).', '2026-04-22 19:58:46.297977'::timestamp, 102);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (637, 'Эвтрофикация водоёмов — избыток фосфатов и нитратов вызывает цветение водорослей. Затем водоросли отмирают, бактерии разлагают их, потребляя кислород — рыбы гибнут.', '2026-04-22 19:58:49.784933'::timestamp, 102);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (638, 'Антидетонационные присадки: тетраэтилсвинец запрещён из-за токсичности. Сейчас используют метил-трет-бутиловый эфир (МТБЭ) или ферроцен.', '2026-04-22 19:58:52.953684'::timestamp, 102);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (639, 'Парниковый эффект: CO2, метан, фреоны поглощают ИК-излучение. Глобальное потепление за 100 лет — примерно 1°C. Вклад CO2 ~ 60%, метана ~ 20%.', '2026-04-22 19:58:56.659192'::timestamp, 102);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (640, 'Очистка сточных вод: механическая (отстаивание), биологическая (активный ил), химическая (хлорирование или озонирование). Фосфор удаляют осаждением алюминатами.', '2026-04-22 19:59:00.531482'::timestamp, 102);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (641, 'Процесс Габера-Боша: N2 + 3H2 ⇌ 2NH3. Давление 200 атм, температура 400-500°C, катализатор — губчатое железо с оксидами. Выход ~ 20% за проход.', '2026-04-22 19:59:04.322270'::timestamp, 103);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (642, 'Контактный способ получения серной кислоты: обжиг пирита → SO2, окисление до SO3 на V2O5, абсорбция концентрированной H2SO4. Олеум — раствор SO3 в H2SO4.', '2026-04-22 19:59:07.802425'::timestamp, 103);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (643, 'Электролиз расплава NaCl: на катоде — натрий, на аноде — хлор. Процесс энергоёмкий (4 кВт·ч на кг натрия). Используется для получения активных металлов.', '2026-04-22 19:59:11.094395'::timestamp, 103);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (644, 'Крекинг нефти: термический и каталитический (цеолитсодержащие катализаторы). Каталитический крекинг даёт больше бензина и протекает при 450-500°C.', '2026-04-22 19:59:15.026034'::timestamp, 103);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (645, 'Производство аммиака из природного газа: паровой риформинг метана до синтез-газа (CO+H2), затем конверсия CO в CO2 и водород, далее синтез NH3.', '2026-04-22 19:59:18.569155'::timestamp, 103);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (646, 'Квантовые точки — полупроводниковые нанокристаллы (CdSe, InAs). Размер 2-10 нм. Энергия запрещённой зоны зависит от размера: чем меньше, тем синее свечение.', '2026-04-22 19:59:22.547649'::timestamp, 104);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (647, 'Углеродные нанотрубки: свёрнутый графеновый лист. Типы: «кресло» (проводник), «зигзаг» (полупроводник). Прочность выше стали в 100 раз.', '2026-04-22 19:59:25.926667'::timestamp, 104);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (648, 'Золь-гель метод позволяет получать нанопорошки из металлакоксидов. Гидролиз тетраэтоксисилана → золь → гель → высушивание → аэрогель.', '2026-04-22 19:59:29.222508'::timestamp, 104);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (649, 'Плазмонный резонанс в золотых наночастицах: поглощение света в видимой области. Сферические частицы 20 нм дают красный цвет, палочки — синий.', '2026-04-22 19:59:32.685965'::timestamp, 104);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (650, 'Самоорганизация молекул: супрамолекулярная химия. Пример — мицеллы ПАВ: гидрофильные головы наружу, гидрофобные хвосты внутрь.', '2026-04-22 19:59:36.064890'::timestamp, 104);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (651, 'Ректификация — разделение смесей по температуре кипения. Колонна с тарелками или насадкой. Число теоретических тарелок зависит от эффективности.', '2026-04-22 19:59:39.545507'::timestamp, 105);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (652, 'Кристаллизация из растворов: метод охлаждения или выпаривания. Удельная теплота кристаллизации равна теплоте плавления. Пересыщение — движущая сила.', '2026-04-22 19:59:42.515959'::timestamp, 105);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (653, 'Экстракция: распределение вещества между двумя несмешивающимися жидкостями. Коэффициент распределения K = C1/C2. Чем выше, тем эффективнее.', '2026-04-22 19:59:45.808346'::timestamp, 105);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (654, 'Мембранные технологии: обратный осмос (задержка ионов), нанофильтрация (молекулы > 200 Да), ультрафильтрация (белки, коллоиды).', '2026-04-22 19:59:49.170393'::timestamp, 105);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (655, 'Сушка распылением: раствор подаётся в горячий воздух через форсунку. Испарение воды происходит мгновенно, образуются сферические частицы.', '2026-04-22 19:59:52.242413'::timestamp, 105);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (656, 'Аспирин (ацетилсалициловая кислота) — нестероидное противовоспалительное. Ингибирует циклооксигеназу, снижая синтез простагландинов.', '2026-04-22 19:59:55.947821'::timestamp, 106);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (657, 'Пенициллины содержат β-лактамное кольцо. Оно связывается с транспептидазой, нарушая синтез клеточной стенки бактерий. Бета-лактамазы разрушают кольцо.', '2026-04-22 19:59:59.121514'::timestamp, 106);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (658, 'Хиральность в лекарствах: энантиомеры могут иметь разную активность. (S)-ибупрофен активен, (R)-изомер неактивен. В организме медленно рацемизируется.', '2026-04-22 20:00:02.586604'::timestamp, 106);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (659, 'Пролекарства: неактивное соединение, которое в организме превращается в активное. Леводопа (против паркинсонизма) проходит гематоэнцефалический барьер.', '2026-04-22 20:00:05.865005'::timestamp, 106);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (660, 'Правило пяти Липински для пероральных препаратов: MW < 500, logP < 5, доноров H-связей < 5, акцепторов < 10. Нарушение ухудшает всасывание.', '2026-04-22 20:00:09.651285'::timestamp, 106);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (661, 'Катализатор не смещает равновесие, а только ускоряет его достижение. Понижает энергию активации, но ΔG реакции остаётся тем же.', '2026-04-22 20:00:14.203791'::timestamp, 107);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (662, 'Гетерогенный катализ: поверхность металла (Pt, Pd, Ni) адсорбирует реагенты. Адсорбция Лэнгмюра — мономолекулярная, Фрейндлиха — эмпирическая.', '2026-04-22 20:00:18.047565'::timestamp, 107);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (663, 'Цеолиты — микропористые алюмосиликаты. Их кислотные центры катализируют крекинг, алкилирование, изомеризацию. Размер пор ~ 5-10 Å.', '2026-04-22 20:00:21.324470'::timestamp, 107);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (664, 'Ферменты — биокатализаторы с активным центром. Модель «ключ-замок» Фишера и индуцированного соответствия Коша. Активность зависит от pH и температуры.', '2026-04-22 20:00:24.812495'::timestamp, 107);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (665, 'Отравление катализатора: серосодержащие соединения необратимо связываются с Pt в автокатализаторах. Поэтому требуют низкосернистое топливо.', '2026-04-22 20:00:27.844653'::timestamp, 107);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (666, 'Радиоактивный распад: закон N = N0·e^{-λt}. Период полураспада T½ = ln2/λ. У урана-238 T½ = 4.5 млрд лет, у полония-210 — 138 дней.', '2026-04-22 20:00:31.563719'::timestamp, 108);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (667, 'Типы распада: α (ядро гелия-4), β⁻ (электрон), β⁺ (позитрон), γ (фотон). α-распад характерен для тяжёлых ядер, β-распад — при избытке нейтронов.', '2026-04-22 20:00:35.149649'::timestamp, 108);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (668, 'Деление ядер: ²³⁵U + n → осколки + 2-3 нейтрона + энергия ~ 200 МэВ. Критическая масса для урана-235 — около 50 кг, для плутония-239 — 10 кг.', '2026-04-22 20:00:38.586894'::timestamp, 108);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (669, 'Ядерный синтез в звёздах: протон-протонный цикл (4H → He + 2e⁺ + 2ν + 26.7 МэВ). При массе > 1.4 солнечных работает CNO-цикл.', '2026-04-22 20:00:42.534756'::timestamp, 108);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (670, 'Радиоактивные индикаторы: ¹⁴C в датировании органики, ⁹⁹mTc в медицине (период 6 часов, гамма 140 кэВ). Радиофармпрепараты вводят внутривенно.', '2026-04-22 20:00:46.726283'::timestamp, 108);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (671, 'Закалка стали: аустенит при быстром охлаждении превращается в мартенсит — пересыщенный твёрдый раствор углерода в α-Fe. Твёрдость до 65 HRC.', '2026-04-22 20:00:50.302379'::timestamp, 109);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (672, 'Полупроводники: кремний (Eg 1.12 эВ), германий (0.66 эВ), арсенид галлия (1.43 эВ). Проводимость легированием донорами (n-тип) или акцепторами (p-тип).', '2026-04-22 20:00:53.505241'::timestamp, 109);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (673, 'Сверхпроводимость: у ртути при 4.2 К открыл Камерлинг-Оннес. ВТСП (YBa2Cu3O7) работают при температуре жидкого азота (77 К).', '2026-04-22 20:00:57.014789'::timestamp, 109);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (674, 'Керамика: оксид алюминия (Al2O3) — высокая твёрдость, используется как абразив. Карбид кремния (SiC) — полупроводник и сверхтвёрдый материал.', '2026-04-22 20:01:00.340356'::timestamp, 109);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (675, 'Пьезоэлектрики: кварц, титанат бария. При деформации возникает электрический потенциал. Применяются в датчиках и кварцевых резонаторах.', '2026-04-22 20:01:04.025569'::timestamp, 109);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (676, 'Коагуляция золей: добавление электролита уменьшает ζ-потенциал. Правило Шульце-Гарди: коагулирующее действие иона определяется его зарядом (Al³⁺ > Ca²⁺ > Na⁺).', '2026-04-22 20:01:07.599614'::timestamp, 110);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (677, 'Поверхностное натяжение воды при 25°C — 72 мН/м. Эффект Лотус: микроструктура листа лотоса делает его супергидрофобным (угол смачивания > 150°).', '2026-04-22 20:01:11.113151'::timestamp, 110);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (678, 'Эмульсии: масло в воде (молоко) и вода в масле (масляные кремы). Эмульгаторы (лецитин, твины) снижают межфазное натяжение.', '2026-04-22 20:01:14.599709'::timestamp, 110);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (679, 'Гели — структурированные коллоидные системы с трёхмерной сеткой. Желатин — пример термообратимого геля (разжижается при нагреве).', '2026-04-22 20:01:17.874609'::timestamp, 110);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (680, 'Критическая концентрация мицеллообразования (ККМ) ПАВ: для додецилсульфата натрия ~ 8 ммоль/л. При ККМ начинают образовываться мицеллы.', '2026-04-22 20:01:21.638858'::timestamp, 110);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (681, 'Уравнение Нернста: E = E⁰ - (RT/nF) lnQ. При 25°C: E = E⁰ - (0.059/n) lgQ. Позволяет рассчитать потенциал электрода в нестандартных условиях.', '2026-04-22 20:01:24.809572'::timestamp, 111);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (682, 'Гальванический элемент Даниэля: Zn|Zn²⁺||Cu²⁺|Cu. ЭДС 1.1 В. Анод (Zn) окисляется, катод (Cu²⁺) восстанавливается.', '2026-04-22 20:01:28.397367'::timestamp, 111);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (683, 'Электролиз расплава NaCl: катодный процесс Na⁺ + e⁻ → Na, анодный 2Cl⁻ → Cl₂ + 2e⁻. Продукты — натрий и хлор.', '2026-04-22 20:01:31.774628'::timestamp, 111);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (684, 'Коррозия металлов: электрохимический процесс. Защита — катодная (жертвенные аноды) и анодная (оксидные плёнки). Лужение и цинкование.', '2026-04-22 20:01:34.795996'::timestamp, 111);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (685, 'Водородный показатель pH = -log[H⁺]. Водородный электрод — первичный стандарт. Стеклянный электрод используется в pH-метрах.', '2026-04-22 20:01:37.832358'::timestamp, 111);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (686, 'Глютамат натрия (E621) усиливает вкус умами. Он активирует рецепторы мРНК4. Содержится в сыре, грибах, томатах.', '2026-04-22 20:01:41.337293'::timestamp, 112);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (687, 'Карamelзация сахара: при 160°C образуются 5-гидроксиметилфурфурол и дикарбонильные соединения. Коричневый цвет и запах карамели.', '2026-04-22 20:01:44.486510'::timestamp, 112);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (688, 'Реакция Майяра между аминокислотами и сахарами даёт аромат жареного мяса и хлебной корочки. Скорость максимальна при pH 6-8 и 140-160°C.', '2026-04-22 20:01:47.952998'::timestamp, 112);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (689, 'Антиоксиданты: аскорбиновая кислота (витамин C) и токоферолы (витамин E) прерывают радикальные цепные реакции окисления жиров.', '2026-04-22 20:01:51.435626'::timestamp, 112);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (690, 'Консерванты: бензоат натрия (E211) ингибирует ферменты микроорганизмов. Сорбиновая кислота подавляет дегидрогеназы дрожжей и плесеней.', '2026-04-22 20:01:55.145606'::timestamp, 112);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (691, 'Закон постоянства гранных углов: у всех кристаллов одного вещества углы между соответствующими гранями одинаковы. Измерял Роме де Лиль в 1783.', '2026-04-22 20:01:58.243513'::timestamp, 113);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (692, 'Сингонии: кубическая (алмаз), тетрагональная (рутил), гексагональная (кварц), ромбическая (сера), моноклинная (гипс), триклинная (бирюза).', '2026-04-22 20:02:02.714145'::timestamp, 113);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (693, 'Дефекты кристаллов: точечные (вакансии, примеси), линейные (дислокации), поверхностные (границы зёрен). Дислокации отвечают за пластичность.', '2026-04-22 20:02:06.590595'::timestamp, 113);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (694, 'Рост кристаллов из раствора: метод с понижением температуры. Пересыщение — движущая сила. Кристаллы растут на затравке.', '2026-04-22 20:02:11.606434'::timestamp, 113);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (695, 'Металлическая связь — модель свободных электронов. Ближний и дальний порядок. Кристаллическая решётка определяет электро- и теплопроводность.', '2026-04-22 20:02:15.260355'::timestamp, 113);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (696, 'Озоновый слой на высоте 15-35 км. Образование O2 + hν → 2O, O + O2 + M → O3 + M. Разрушение под действием хлорфторуглеродов: Cl + O3 → ClO + O2.', '2026-04-22 20:02:18.996351'::timestamp, 114);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (697, 'Парниковые газы: CO2 поглощает ИК в области 15 мкм. Метан — в 7.7 мкм, его потенциал глобального потепления в 25 раз выше, чем у CO2.', '2026-04-22 20:02:22.768277'::timestamp, 114);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (698, 'Кислотные дожди: SO2 и NOx окисляются в атмосфере до H2SO4 и HNO3. pH осадков в промышленных районах достигает 4-4.5.', '2026-04-22 20:02:26.046212'::timestamp, 114);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (699, 'Аэрозоли: сульфаты, нитраты, сажа, пыль. Они рассеивают солнечный свет (прямой эффект) и влияют на облачность (косвенный эффект).', '2026-04-22 20:02:29.528261'::timestamp, 114);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (700, 'Фотохимический смог: оксиды азота и углеводороды при солнечном свете дают озон и пероксиацилнитраты. Характерен для Лос-Анджелеса.', '2026-04-22 20:02:32.804491'::timestamp, 114);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (701, 'В межзвёздной среде обнаружено более 200 молекул: H2, CO, H2O, CH3OH, HCOOH, глицин (простейшая аминокислота). Молекулярные облака — фабрики звёзд.', '2026-04-22 20:02:36.490757'::timestamp, 115);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (702, 'Ротационная спектроскопия в миллиметровом диапазоне позволяет идентифицировать молекулы по их вращательным переходам. Для CO — линия 2.6 мм.', '2026-04-22 20:02:40.911482'::timestamp, 115);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (703, 'Изотопный состав метеоритов: отношение ¹²C/¹³C ~ 90, а в солнечной системе ~ 89. Аномалии указывают на дозвёздное происхождение.', '2026-04-22 20:02:44.391021'::timestamp, 115);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (704, 'Сложные органические молекулы в кометах: 67P/Чурюмова-Герасименко содержит глицин, фосфор, этиленгликоль. Кометы могли занести на Землю пребиотики.', '2026-04-22 20:02:47.753773'::timestamp, 115);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (705, 'Химия атмосферы Титана: метан под действием УФ и электронов распадается, образуя полимерный туман — толуин. Озёра жидкого метана.', '2026-04-22 20:02:51.235500'::timestamp, 115);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (706, 'Пользователь никогда не читает экран — он сканирует. Первое, на что падает взгляд: заголовки, кнопки, изображения. Иерархия решает всё.', '2026-04-22 20:02:56.969821'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (707, 'Пять человек в юзабилити-тестировании находят 85% проблем. Нанять лабораторию за миллион? Нет, просто позвать коллег с печеньками.', '2026-04-22 20:03:00.351852'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (708, 'Закон Фиттса: время достижения цели зависит от расстояния и размера. Кнопка «Купить» должна быть большой и близко к курсору.', '2026-04-22 20:03:04.014981'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (709, 'Карточки в интерфейсе — это тренд, но не панацея. Для сложных данных лучше таблица. Не гонитесь за модой, думайте о задаче.', '2026-04-22 20:03:07.927795'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (710, 'Запомните: сначала исследование, потом дизайн. Я видел проекты, где рисовали интерфейс месяц, а потом выяснялось, что пользователям нужен совсем другой сценарий.', '2026-04-22 20:03:11.613175'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (711, 'Чеклист для UX-ревью: понятна ли цель экрана? Минимальны ли когнитивные усилия? Есть ли обратная связь на действия?', '2026-04-22 20:03:14.888229'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (712, 'Онбординг из трёх экранов при первом запуске? Пользователь уже хочет внутрь. Покажите ценность сразу, а не рассказывайте, как тыкать пальцем.', '2026-04-22 20:03:18.473209'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (713, 'Я тестировал прототип интернет-банка. Кнопка «Перевести» была справа, а люди искали слева. Переместил — конверсия выросла на 23%.', '2026-04-22 20:03:22.056024'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (714, 'Айтрекинг показывает: в форме регистрации люди смотрят сначала на поля, потом на лейблы. Лейблы над полями быстрее, чем внутри.', '2026-04-22 20:03:25.336296'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (715, 'Принцип «последнего выбора»: если пользователь сомневается, он выбирает последний вариант. Размещайте нужное действие последним в группе.', '2026-04-22 20:03:28.799468'::timestamp, 116);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (716, 'Шрифт с засечками для длинных текстов? Да, если это печать. Для экрана лучше гротески: Roboto, Inter, Open Sans. Читаемость выше.', '2026-04-22 20:03:32.245337'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (717, 'Модульная сетка — основа любой композиции. 12 колонок — универсальный стандарт для веба. Но главное — ритм, а не количество.', '2026-04-22 20:03:35.519142'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (718, 'Золотое сечение 1.618 работает в природе и в дизайне. Попробуйте поделить макет в этой пропорции — глаз скажет спасибо.', '2026-04-22 20:03:38.717622'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (719, 'Цветовой круг Иттена: противоположные цвета создают напряжение (красный-зелёный), соседние — гармонию (синий-фиолетовый).', '2026-04-22 20:03:41.921882'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (720, 'Воздух между элементами важнее самих элементов. Отступы — это тишина в музыке. Без неё какофония.', '2026-04-22 20:03:45.302927'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (721, 'Скругления углов: 4px для элементов, 8px для карточек, 16px для модальных окон. Единая система радиусов делает интерфейс цельным.', '2026-04-22 20:03:48.437429'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (722, 'Градиенты вернулись, но не как в 2010-м. Легкие переходы между близкими оттенками, а не кислотные взрывы.', '2026-04-22 20:03:51.745994'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (723, 'Тени делают интерфейс объёмным, но одна тень на всю карточку — признак новичка. Используйте несколько слоёв с разным размытием.', '2026-04-22 20:03:55.192482'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (724, 'Иконки должны быть узнаваемы за 0.5 секунды. Лупа — поиск, домик — домой. Не изобретайте велосипед, используйте стандарты.', '2026-04-22 20:03:58.586112'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (725, 'Проверка на чёрно-белое: если макет читается без цвета — вы молодец. Цвет — это акцент, а не каркас.', '2026-04-22 20:04:01.923405'::timestamp, 117);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (726, 'Логотип должен работать в двух цветах и на спичечном коробке. Если нечитаем — переделывать.', '2026-04-22 20:04:05.436120'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (727, 'Айдентика — это не логотип, а вся экосистема: шрифты, паттерны, носители. Бренд живёт в деталях.', '2026-04-22 20:04:08.805714'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (728, 'Красный — цвет страсти и опасности. Синий — надёжность и спокойствие. Жёлтый — энергия и дешевизна. Подбирайте под ценности.', '2026-04-22 20:04:12.129132'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (729, 'Маскот как часть бренда? Mailchimp, GitHub, Duolingo — отличные примеры. Персонаж создаёт эмоциональную связь.', '2026-04-22 20:04:15.423426'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (730, 'Гайдлайн по бренду должен быть не толще 30 страниц. Иначе его никто не читает. Только правила и примеры.', '2026-04-22 20:04:18.992923'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (731, 'Я переделывал айдентику сети кофеен. Старый логотип был сложным и не читался на чашке. Сделал монохромную букву и фирменный паттерн из зёрен — узнаваемость выросла на 40%.', '2026-04-22 20:04:22.166407'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (732, 'Бренд-платформа: миссия, ценности, тон голоса. Без этого дизайн — просто красивые картинки.', '2026-04-22 20:04:25.316225'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (733, 'Ребрендинг — это не смена логотипа. Это смена восприятия. Пример: «Вкусно и точка» — узнаваемо, но потеряло магию старого бренда.', '2026-04-22 20:04:28.393076'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (734, 'Шрифтовая пара: один шрифт для заголовков (жирный, контрастный) и один для текста (удобочитаемый). Не больше трёх гарнитур.', '2026-04-22 20:04:31.380817'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (735, 'Паттерн (повторяющийся элемент) создаёт настроение. Полоски — спорт, горох — ретро, треугольники — технологии.', '2026-04-22 20:04:35.272716'::timestamp, 118);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (736, 'MVP — не страшный уродливый продукт. Это минимальный набор функций, который решает проблему. Дизайн должен быть аккуратным.', '2026-04-22 20:04:38.811860'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (737, 'JTBD (Jobs To Be Done): пользователь «нанимает» ваш продукт, чтобы выполнить работу. Какая работа? Вот главный вопрос.', '2026-04-22 20:04:41.621249'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (738, 'Карта пути пользователя (CJM) — 5 шагов: осознание проблемы, поиск решения, выбор, покупка, пост-взаимодействие.', '2026-04-22 20:04:45.117850'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (739, 'KPI дизайна: время выполнения задачи, ошибки, удовлетворённость (SUS). Если не измеряете — вы не знаете, что улучшать.', '2026-04-22 20:04:48.277158'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (740, 'Принцип «двух пицц»: команда должна быть такой, чтобы накормить двумя пиццами. Дизайн-спринт за 5 дней работает именно в малых группах.', '2026-04-22 20:04:51.963626'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (741, 'В продуктовой аналитике смотрю на воронку: где падает больше всего пользователей? Часто это экран с непонятной формой или длинная регистрация.', '2026-04-22 20:04:55.249484'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (742, 'Фича-флаг: выкатили новый интерфейс для 5% пользователей, собрали фидбек, доработали. Без риска для всех.', '2026-04-22 20:04:58.412209'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (743, 'Один мой проект — приложение для такси. После добавления виджета с примерной ценой до подтверждения заказа конверсия выросла на 18%. Люди хотят знать, сколько заплатят.', '2026-04-22 20:05:01.436811'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (744, 'Дизайн-критика в команде: правило «нет идей — нет проблем». Каждое решение должно быть обосновано, а не «мне так кажется».', '2026-04-22 20:05:04.969089'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (745, 'Приоритизация фич по RICE: Reach (охват), Impact (влияние), Confidence (уверенность), Effort (усилия). Считаете и выбираете.', '2026-04-22 20:05:09.483125'::timestamp, 119);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (746, 'Микроанимация: кнопка меняет цвет при наведении — это обратная связь. Длительность 150-300 мс, плавно через ease-out.', '2026-04-22 20:05:13.173868'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (747, 'Жесты в мобильных приложениях: свайп назад должен работать везде, где есть навигация. Не заставляйте искать кнопку «Назад».', '2026-04-22 20:05:16.844290'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (748, 'Правило 12 кадров в секунду для веб-анимации — хватит для плавности. Не нужно 60 кадров, это перегрузка.', '2026-04-22 20:05:20.239052'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (749, 'Анимация появления должна быть быстрой (200 мс) и незаметной. Заставки на 2 секунды бесят. Пользователь хочет к делу.', '2026-04-22 20:05:23.405792'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (750, 'Использую принцип «оживления» (squash and stretch) для интерактивных элементов. Кнопка как будто пружинит при нажатии.', '2026-04-22 20:05:26.242614'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (751, 'Типографическая анимация: буквы приезжают, появляются или меняют прозрачность. Но только для заголовков, для текста — нельзя.', '2026-04-22 20:05:29.439950'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (752, 'В одном проекте мы добавили партиклы (вспышку) при завершении задачи. Пользователи стали чаще доводить дела до конца — положительное подкрепление работает.', '2026-04-22 20:05:32.410658'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (753, 'Lottie-анимация весит мало, а выглядит как видео. Идеально для иконок и иллюстраций. JSON-файл вместо видеоплеера.', '2026-04-22 20:05:35.522978'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (754, 'Анимация загрузки (скелетон) лучше спиннера. Пользователь видит структуру страницы и понимает, что скоро будет.', '2026-04-22 20:05:38.871053'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (755, 'Не анимируйте трансформацию ширины — это дёргает соседние элементы. Используйте opacity + transform (scale, translate).', '2026-04-22 20:05:41.829008'::timestamp, 120);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (756, 'Веб-шрифты: Google Fonts бесплатен, но замедляет первый заход. Лучше подключать только нужные начертания (400, 700).', '2026-04-22 20:05:45.224876'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (757, 'Высота строки (line-height) для текста — 1.4-1.6 от кегля. Для заголовков — 1.2. Иначе буквы слипаются или слишком разрежены.', '2026-04-22 20:05:48.485572'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (758, 'Интерлиньяж между заголовком и подзаголовком должен быть меньше, чем между подзаголовком и текстом. Так работает группировка.', '2026-04-22 20:05:52.173339'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (759, 'Не используйте Caps Lock для длинных фраз. Заглавные буквы читаются на 30% медленнее. Только для акронимов и коротких кнопок.', '2026-04-22 20:05:55.156789'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (760, 'Вертикальный ритм: все элементы на странице должны быть кратны базовой единице (например, 8px). Тогда линии текста совпадают.', '2026-04-22 20:05:58.844208'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (761, 'Я анализировал читаемость: шрифты с человеческими пропорциями (Georgia, Lora) лучше для художественной литературы. Гротески — для интерфейсов.', '2026-04-22 20:06:02.411984'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (762, 'Правило «золотого сечения» в типографике: кегль текста 16px, интерлиньяж 26px, отступы между абзацами 26/2 = 13px.', '2026-04-22 20:06:05.808143'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (763, 'Длина строки (ширина колонки) — 50-75 символов. Широкий текст утомляет глаз возвращаться к следующей строке.', '2026-04-22 20:06:09.289512'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (764, 'Трекинг (расстояние между буквами) для заголовков можно увеличить на 5-10%. Для основного текста трекинг должен быть стандартным.', '2026-04-22 20:06:12.768502'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (765, 'Вёрстка многоязычного текста: английский и русский шрифты должны быть сбалансированы по насыщенности. Иногда нужно подключать разные гарнитуры.', '2026-04-22 20:06:16.353835'::timestamp, 121);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (766, 'Дизайн-токены — это переменные: цвет, шрифт, отступ, тень. Храните их в JSON, синхронизируйте с кодом. Тогда дизайн не расходится с разработкой.', '2026-04-22 20:06:19.820699'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (767, 'Атомы (кнопки, инпуты), молекулы (форма поиска), организмы (шапка) — методология БЭМ и Atomic Design работают вместе.', '2026-04-22 20:06:23.710975'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (768, 'Сторибук (Storybook) — лучший инструмент для документации компонентов. Разработчик видит все состояния кнопки: disabled, hover, active.', '2026-04-22 20:06:26.577720'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (769, 'Пиксель-перфект — это вредно. Вместо этого договаривайтесь о допусках: отступ может быть 12-16px, главное — относительное расположение.', '2026-04-22 20:06:29.767672'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (770, 'Я создавал дизайн-систему для крупного маркетплейса. Потратили 4 месяца, зато теперь новый интерфейс собирается за день, а не за неделю.', '2026-04-22 20:06:34.259401'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (771, 'Версионирование компонентов: v1.0, v2.0. Не ломайте обратную совместимость. Старый дизайн должен жить, пока команда не переедет.', '2026-04-22 20:06:37.450388'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (772, 'Репозиторий дизайн-системы: Figma + Zeroheight + GitHub. Дизайнеры работают в Figma, разработчики смотрят документацию.', '2026-04-22 20:06:41.120503'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (773, 'Токены для тёмной темы: меняются только цветовые переменные. Компоненты остаются те же. Это легко поддерживать.', '2026-04-22 20:06:44.512142'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (774, 'Компонент карточки товара должен иметь 5-6 вариаций: с картинкой, без, с кнопкой, с рейтингом. Не плодите сущности, делайте параметры.', '2026-04-22 20:06:47.570870'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (775, 'Чеклист для дизайн-системы: есть ли у каждого компонента описание, пример использования, код, ограничения (доступность).', '2026-04-22 20:06:51.029469'::timestamp, 122);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (776, 'WCAG 2.1: контраст текста и фона — минимум 4.5:1 для обычного текста, 3:1 для крупного. Проверяйте на webaim.org.', '2026-04-22 20:06:54.840371'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (777, 'Скринридеры: ваша семантика HTML важнее внешнего вида. Используйте <button>, а не <div> с классом .btn.', '2026-04-22 20:06:58.286197'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (778, 'Фокус-таймер: когда пользователь табулирует по интерфейсу, фокус должен быть видимым. outline: none — зло.', '2026-04-22 20:07:01.495781'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (779, 'Альтернативный текст для иконок: если иконка без текста, нужен атрибут alt или aria-label. «Лупа» не равно «Поиск»? alt=«Поиск».', '2026-04-22 20:07:04.787662'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (780, 'Цветовая слепота (протанопия, дейтеранопия): не полагайтесь только на цвет. Добавляйте значки, текстовые метки.', '2026-04-22 20:07:08.153207'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (781, 'Я тестировал интерфейс с программой экранного доступа. Оказалось, порядок навигации был хаотичным. Исправил таб-индекс — люди со скринридерами стали работать в 2 раза быстрее.', '2026-04-22 20:07:11.633129'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (782, 'Анимация при эпилепсии: никаких мигающих элементов чаще 3 раз в секунду. Это может вызвать приступ.', '2026-04-22 20:07:15.215895'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (783, 'Увеличивайте текст без поломки вёрстки: используйте rem, а не px. Пользователь с плохим зрением должен поставить масштаб 200% и читать.', '2026-04-22 20:07:18.495668'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (784, 'Скрытый контент для скринридеров: класс .visually-hidden, который делает текст невидимым для глаз, но доступным для ассистивных технологий.', '2026-04-22 20:07:21.667553'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (785, 'Доступность — это не только инвалиды. Пожилые люди, временные травмы (сломанная рука), плохой интернет — все выигрывают.', '2026-04-22 20:07:24.740001'::timestamp, 123);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (786, 'Навигация: глубина не более 3 кликов до любой страницы. Иначе пользователь теряется и уходит.', '2026-04-22 20:07:28.033451'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (787, 'Хлебные крошки (breadcrumbs) — для сайтов с иерархией (интернет-магазины, документация). Для лендинга — не нужны.', '2026-04-22 20:07:31.703617'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (788, 'Поиск должен быть виден без скролла. В 90% случаев пользователь хочет найти конкретную вещь, а не бродить по каталогу.', '2026-04-22 20:07:35.183906'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (789, 'Кнопка с надписью «Отправить» лучше, чем иконка. Иконки неоднозначны. Если используете иконку, обязательно добавляйте текст.', '2026-04-22 20:07:38.382320'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (790, 'Форма входа: две кнопки — «Войти» и «Зарегистрироваться». Не нужно «Войти или зарегистрироваться» — это сбивает.', '2026-04-22 20:07:41.533056'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (791, 'Я перепроектировал корзину в интернет-магазине: добавил блок «Вам также может понравиться». Средний чек вырос на 12%.', '2026-04-22 20:07:44.956289'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (792, 'Бесконечная лента (infinite scroll) хороша для соцсетей, но плоха для интернет-магазина. Пользователь не может добраться до подвала и ссылок на контакты.', '2026-04-22 20:07:48.086262'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (793, 'Модальные окна: не закрывайте крестиком единственный способ закрыть. Пользователь может не заметить. Добавьте кнопку «Закрыть».', '2026-04-22 20:07:51.567905'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (794, 'Скелетон (skeleton screen) для загрузки: показывайте контуры контента, а не спиннер. Пользователь видит, что скоро будет.', '2026-04-22 20:07:54.947357'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (795, 'Принцип «прогрессивного раскрытия»: показывайте сложные настройки только по требованию. Не перегружайте интерфейс.', '2026-04-22 20:07:58.855485'::timestamp, 124);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (796, 'Mobile first: сначала проектируйте для 320px, потом добавляйте медиа-запросы для больших экранов. Так вы не потеряете важное.', '2026-04-22 20:08:02.748383'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (797, 'Точки перелома (breakpoints): 576px (телефоны), 768px (планшеты), 992px (десктопы), 1200px (широкие экраны).', '2026-04-22 20:08:06.519537'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (798, 'Картинки: используйте srcset для разных разрешений. Не показывайте на телефоне картинку шириной 2000px — это трафик.', '2026-04-22 20:08:09.899015'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (799, 'Тач-цели: кнопки должны быть не меньше 44x44px на мобильных. Иначе пальцем не попасть.', '2026-04-22 20:08:13.378790'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (800, 'Я переделывал верстку для сайта недвижимости. На телефоне фильтры были в отдельной вкладке — никто не использовал. Вынес вниз страницы — активность выросла на 300%.', '2026-04-22 20:08:17.272140'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (801, 'Адаптивные шрифты: clamp(14px, 4vw, 24px) — плавно меняется от телефона к монитору. Без медиа-запросов.', '2026-04-22 20:08:20.445526'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (802, 'Гамбургер-меню — компромисс. На планшетах и выше лучше показывать полную навигацию. Спрятанное меню не находят.', '2026-04-22 20:08:23.942717'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (803, 'Сетка на флексах или гридах? Grid для общей структуры, flex для выравнивания внутри блоков. Вместе работают отлично.', '2026-04-22 20:08:27.512473'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (804, 'Изображения с высоким разрешением для экранов Retina: 2x, 3x. media query -webkit-min-device-pixel-ratio: 2.', '2026-04-22 20:08:31.401677'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (805, 'Сенсорные жесты на десктопе тоже важны. Колесо мыши — это не то же самое, что свайп. Не удаляйте полосы прокрутки.', '2026-04-22 20:08:34.986345'::timestamp, 125);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (806, 'Инфляция в России по итогам 2024 года ожидается на уровне 7-8%, хотя ключевая ставка уже 16%. Это показывает, что монетарная политика работает с лагом в 6-9 месяцев.', '2026-04-22 20:08:41.614867'::timestamp, 126);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (807, 'ВВП на душу в Китае по ППС уже обогнал США? Нет, всё ещё отстаёт в 1.5 раза, но разрыв сокращается. В 2030 году могут сравняться.', '2026-04-22 20:08:44.816067'::timestamp, 126);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (808, 'Дефицит бюджета США в 2024 — $1.7 трлн. Отношение долга к ВВП превысило 120%. При сохранении текущих тенденций процентные платежи съедят все налоги к 2035.', '2026-04-22 20:08:48.333587'::timestamp, 126);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (809, 'Безработица в России на рекордно низком уровне — 2.9%. Но это не потому, что все работают, а из-за сокращения рабочей силы на 2 млн за 3 года.', '2026-04-22 20:08:51.880859'::timestamp, 126);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (810, 'Сальдо торгового баланса РФ за 2023 упало на 60% из-за падения цен на нефть и эмбарго. Но экспорт в Китай вырос на 20%.', '2026-04-22 20:08:55.040837'::timestamp, 126);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (811, 'Почему курс рубля так волатилен? Потому что доля нефтегазовых доходов в экспорте 50%, а ЦБ не интервенционирует как раньше. Чистое плавание.', '2026-04-22 20:08:58.435247'::timestamp, 126);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (812, 'Производительность труда в России в 3 раза ниже, чем в Германии. Причина — не только технологии, но и избыточная занятость на низких переделах.', '2026-04-22 20:09:01.713060'::timestamp, 126);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (813, 'Дивидендная доходность Сбера за 2023 — 12%. При инфляции 7.5% реальная доходность 4.5%. Лучше депозита, но риски выше.', '2026-04-22 20:09:05.194489'::timestamp, 127);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (814, 'Золото обновило исторический максимум — $2400 за унцию. Драйверы: покупки центробанков (Китай, Турция, Россия) и ожидание снижения ставки ФРС.', '2026-04-22 20:09:08.881691'::timestamp, 127);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (815, 'Акции Ozon упали на 70% с 2021 года. Причина: жёсткая конкуренция с Wildberries и рост ставки, которая давит на оценку e-commerce.', '2026-04-22 20:09:11.965494'::timestamp, 127);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (816, 'Облигации федерального займа с фиксированным купоном сейчас дают 14-15% годовых. Если ключевая ставка пойдёт вниз, будут расти в цене.', '2026-04-22 20:09:15.125861'::timestamp, 127);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (817, 'Доллар США — 36% мировых резервов. Это исторический минимум. Китай и Россия переходят в золото и юань. Де-долларизация идёт.', '2026-04-22 20:09:18.918519'::timestamp, 127);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (818, 'ETF на российские акции торгуются в Казахстане (KASE). Дисконт к базовому активу достигает 20% из-за санкционных рисков.', '2026-04-22 20:09:22.411866'::timestamp, 127);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (819, 'Венчурные инвестиции в РФ упали в 10 раз с 2021 года. Стартапы переезжают в Казахстан, ОАЭ, Турцию. Рынок почти умер.', '2026-04-22 20:09:25.594717'::timestamp, 127);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (820, 'Маржинальность SaaS-бизнеса в РФ 70-80%, но клиентов мало, LTV низкий. Европейский рынок закрыт, свой не платит.', '2026-04-22 20:09:28.642692'::timestamp, 128);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (821, 'Кросс-курс юаня к рублю — 12.5. Многие импортёры переходят на расчёты в юанях, сэкономив на конвертации через доллар 2-3%.', '2026-04-22 20:09:31.835165'::timestamp, 128);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (822, 'Самый прибыльный бизнес сейчас — параллельный импорт электроники. Наценка 100-200%, но риски блокировки платежей и таможни.', '2026-04-22 20:09:34.990992'::timestamp, 128);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (823, 'Франшиза «Додо Пицца» окупается за 2-3 года при среднем чеке 800 рублей. Рентабельность 25% — отлично для общепита.', '2026-04-22 20:09:38.473666'::timestamp, 128);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (824, 'Wildberries в 2024 поднял комиссию до 15-20% в некоторых категориях. Продавцы уходят на Ozon, но там трафик в 2 раза ниже.', '2026-04-22 20:09:41.851643'::timestamp, 128);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (825, 'Бизнес на маркетплейсах: формула успеха — уникальный товар с наценкой x3 от себестоимости, иначе реклама съест всё.', '2026-04-22 20:09:44.821782'::timestamp, 128);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (826, 'Государственные субсидии по ставке 3% для МСП в приоритетных отраслях (IT, производство). Но получить сложно, банки не верят.', '2026-04-22 20:09:48.610293'::timestamp, 128);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (827, 'EBITDA — не всегда показатель здоровья. У компании может быть высокая EBITDA, но большой долг и отрицательный денежный поток.', '2026-04-22 20:09:51.681298'::timestamp, 129);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (828, 'Рентабельность собственного капитала (ROE) Сбера — 24%. Это выше, чем у американских банков (JPMorgan — 15%). Но риски выше.', '2026-04-22 20:09:54.975968'::timestamp, 129);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (829, 'Долговая нагрузка: отношение чистого долга к EBITDA больше 3 — красная зона. У «Магнита» 2.2, у X5 — 1.8. Безопасно.', '2026-04-22 20:09:58.226366'::timestamp, 129);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (830, 'Дисконтирование денежных потоков (DCF) — стандартный метод оценки. Ставка дисконтирования = безрисковая ставка + премия за риск.', '2026-04-22 20:10:01.718428'::timestamp, 129);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (831, 'Free cash flow (FCF) компании «Газпром» в 2023 отрицательный — минус 300 млрд руб. Инвестиции превышают продажи.', '2026-04-22 20:10:04.995348'::timestamp, 129);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (832, 'Чистая процентная маржа банков в РФ сейчас 5-6% из-за высоких ставок. Но просрочка по кредитам растёт — 8% в сегменте необеспеченных.', '2026-04-22 20:10:08.371635'::timestamp, 129);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (833, 'Коэффициент P/E (цена/прибыль) российского рынка — 4-5, а у США 20-25. Формально российские акции недооценены, но санкционный дисконт.', '2026-04-22 20:10:11.853122'::timestamp, 129);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (834, 'Индекс потребительской уверенности в РФ упал до 85 пунктов (100 — нейтрально). Люди боятся тратить, сберегают.', '2026-04-22 20:10:15.767103'::timestamp, 130);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (835, 'Доля онлайн-продаж в розничной торговле РФ достигла 15%. Лидеры: Wildberries (40%), Ozon (35%), Яндекс.Маркет (10%).', '2026-04-22 20:10:19.226880'::timestamp, 130);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (836, 'Средний чек в продуктовом ритейле вырос на 18% за год, а объём покупок в кг упал на 5%. Люди экономят на количестве.', '2026-04-22 20:10:23.220017'::timestamp, 130);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (837, 'Рынок такси в Москве: поездка подорожала на 30% за год из-за дефицита водителей (мигрантов стало меньше).', '2026-04-22 20:10:26.390963'::timestamp, 130);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (838, 'Туристический поток в Турцию из РФ вырос на 40% в 2024. Виза не нужна, цены приемлемые, политика не мешает.', '2026-04-22 20:10:29.519593'::timestamp, 130);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (839, 'Потребительские предпочтения: 70% россиян перешли на более дешёвые бренды. Частные марки (Светофор, Пятёрочка) растут на 30%.', '2026-04-22 20:10:32.965378'::timestamp, 130);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (840, 'Рынок смартфонов: китайские бренды (Xiaomi, Realme, Tecno) заняли 80% рынка. Samsung и Apple — только через параллельный импорт.', '2026-04-22 20:10:36.329898'::timestamp, 130);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (841, 'Кривая Филлипса в России не работает: безработица падает, а инфляция растёт. Это из-за структурных сдвигов и монополизма.', '2026-04-22 20:10:40.015722'::timestamp, 131);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (842, 'Теория сравнительных преимуществ Рикардо: России выгодно экспортировать сырьё и импортировать готовую продукцию. Но это консервация отсталости.', '2026-04-22 20:10:44.355909'::timestamp, 131);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (843, 'Институциональные ловушки: когда неэффективные нормы закрепляются. Пример — институт прописки в СССР, который сдерживал миграцию рабочей силы.', '2026-04-22 20:10:47.492500'::timestamp, 131);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (844, 'Парадокс Кондратьева: большие циклы конъюнктуры 40-60 лет. Мы сейчас в фазе понижательной волны (с 2008 года).', '2026-04-22 20:10:50.767106'::timestamp, 131);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (845, 'Эластичность спроса на нефть по цене в краткосрочном периоде 0.05 — почти неэластично. Поэтому ОПЕК может манипулировать ценой.', '2026-04-22 20:10:53.852275'::timestamp, 131);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (846, 'Теорема Коуза: при нулевых трансакционных издержках распределение прав собственности не влияет на эффективность. В реальности издержки высоки.', '2026-04-22 20:10:57.028744'::timestamp, 131);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (847, 'Ловушка среднего дохода: Россия в ней с 2010 года. ВВП на душу $15 тыс., а нужно $30 тыс., чтобы перейти к инновационной экономике.', '2026-04-22 20:10:59.981256'::timestamp, 131);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (848, 'Стратегия «голубого океана» — создание новой ниши. Пример: Wildberries создал рынок онлайн-торговли в РФ с нуля в 2000-х.', '2026-04-22 20:11:04.897030'::timestamp, 132);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (849, 'Оптимизация логистики: кросс-докинг сокращает время хранения на складе с 5 дней до 1 дня. Экономия 30% на аренде.', '2026-04-22 20:11:07.765360'::timestamp, 132);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (850, 'KPI для розницы: оборачиваемость запасов (Inventory Turnover) — 6-8 раз в год. У X5 Retail — 9, отлично.', '2026-04-22 20:11:10.936724'::timestamp, 132);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (851, 'Бережливое производство (Lean) снижает потери до 30%. Внедрение 5S на заводе КАМАЗ дало рост производительности 15%.', '2026-04-22 20:11:14.215808'::timestamp, 132);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (852, 'Аутсорсинг непрофильных функций: бухгалтерия, IT, колл-центр. Экономия ФОТ 40% за счёт масштаба подрядчика.', '2026-04-22 20:11:17.288701'::timestamp, 132);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (853, 'Цифровая трансформация: внедрение ERP в «Магните» заняло 3 года, но дало снижение операционных затрат на 8%.', '2026-04-22 20:11:20.776758'::timestamp, 132);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (854, 'Мотивация персонала: KPI + бонусы за перевыполнение плана. В рознице план 110% даёт премию 50% от оклада.', '2026-04-22 20:11:24.249770'::timestamp, 132);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (855, 'Технический анализ: уровень 3000 пунктов по индексу Мосбиржи — сильное сопротивление. Три раза отскакивали.', '2026-04-22 20:11:27.629232'::timestamp, 133);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (856, 'Корреляция нефти и рубля: при цене Urals $80 курс 90, при $70 — 100. Уравнение регрессии с R2 = 0.85.', '2026-04-22 20:11:30.906344'::timestamp, 133);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (857, 'Торговля на волатильности: стреддл на фьючерсах RTS при ставке ЦБ перед заседанием. Имхо, лучшая стратегия.', '2026-04-22 20:11:34.187353'::timestamp, 133);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (858, 'Объём торгов в шорт: 20% от рынка в акциях Сбера. Медвежий сигнал, когда коротких позиций становится >15%.', '2026-04-22 20:11:37.269071'::timestamp, 133);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (859, 'Рыночные циклы: сейчас фаза накопления. Объёмы низкие, индекс консолидируется. Следующее движение — вниз?', '2026-04-22 20:11:40.490787'::timestamp, 133);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (860, 'Ликвидность: спред по акциям Лукойла 0.2%, по третьему эшелону — 2-3%. Не лезь туда без ликвидности.', '2026-04-22 20:11:44.028083'::timestamp, 133);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (861, 'Новостной трейдинг: выход инфляции в США выше прогноза — сразу продавать доллар, покупать золото. Срабатывает в 60% случаев.', '2026-04-22 20:11:47.532572'::timestamp, 133);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (862, 'Почему в России дорогая ипотека? Ключевая ставка 16% + маржа банка 3% = 19%. А в США 6-7%, потому что ФРС печатает деньги.', '2026-04-22 20:11:50.666012'::timestamp, 134);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (863, 'Прожиточный минимум в 2024 — 15 тыс. руб. Реально выжить на это невозможно. МРОТ 19 тыс. — тоже нищета.', '2026-04-22 20:11:54.250950'::timestamp, 134);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (864, 'Кривая Лаффера для налогов в РФ: оптимальная ставка НДФЛ 13-15%. Выше — уход в тень. 13% уже 25 лет.', '2026-04-22 20:11:57.325593'::timestamp, 134);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (865, 'Парадокс бережливости: если все начнут больше сберегать, экономика упадёт, потому что упадёт потребление. Пример — Япония 1990-х.', '2026-04-22 20:12:00.970368'::timestamp, 134);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (866, 'Что такое денежный мультипликатор? Банк выдал кредит 100 руб., они вернулись в другой банк, тот выдал 80. В итоге 500 руб. в экономике.', '2026-04-22 20:12:04.395346'::timestamp, 134);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (867, 'Рыночная капитализация российского фондового рынка — $60 млрд. Это меньше, чем одна Apple. Рынка почти нет.', '2026-04-22 20:12:07.786989'::timestamp, 134);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (868, 'Пособие по безработице в РФ — 12 тыс. руб. В Германии — 1000 евро. Поэтому в Германии не хотят работать, а в РФ боятся уволиться.', '2026-04-22 20:12:11.151121'::timestamp, 134);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (869, 'Программа материнского капитала за 15 лет увеличила рождаемость на 10% в краткосрочной перспективе, но эффект исчерпан.', '2026-04-22 20:12:14.934530'::timestamp, 135);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (870, 'Налог на самозанятых 4-6% — успех: 8 млн зарегистрировались. Теневой сектор сократился на 15%.', '2026-04-22 20:12:17.806503'::timestamp, 135);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (871, 'Повышение пенсионного возраста до 65/60 дало бюджету 500 млрд руб. в год. Цена — снижение ожидаемой продолжительности жизни мужчин.', '2026-04-22 20:12:21.184737'::timestamp, 135);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (872, 'Плоская шкала НДФЛ 13% ввели в 2001 году, чтобы вывести зарплаты из тени. Сработало: собираемость выросла на 50%.', '2026-04-22 20:12:24.355055'::timestamp, 135);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (873, 'Субсидирование ипотеки под 8% в 2020-2022 привело к пузырю на рынке жилья. Цены выросли на 40%.', '2026-04-22 20:12:27.839983'::timestamp, 135);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (874, 'Госпрограмма импортозамещения в промышленности: потрачено 2 трлн руб., но доля импорта снизилась всего на 5%.', '2026-04-22 20:12:31.216284'::timestamp, 135);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (875, 'Экономический рост в 2024 — 2.5% (прогноз Минэкономразвития). Драйверы: военные расходы, импортозамещение, стройка.', '2026-04-22 20:12:34.098521'::timestamp, 135);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (876, 'Закон Оукена: рост безработицы на 1% снижает ВВП на 2.5%. Сейчас безработица 3%, могло быть 2.5%? Не сходится.', '2026-04-22 20:12:37.983607'::timestamp, 136);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (877, 'Кривая Лоренца и коэффициент Джини в России — 0.42 (высокое неравенство). В Скандинавии — 0.25.', '2026-04-22 20:12:41.149824'::timestamp, 136);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (878, 'Чем отличается номинальная и реальная зарплата? Номинальная — сколько денег, реальная — сколько товаров можно купить.', '2026-04-22 20:12:44.527203'::timestamp, 136);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (879, 'Монополия, олигополия, монополистическая конкуренция. В России большинство рынков — олигополия (связь, нефть, ритейл).', '2026-04-22 20:12:47.804571'::timestamp, 136);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (880, 'Что такое паритет покупательной способности? Бигмак в России стоит 150 руб., в США $5. Курс ППС = 30 руб./$.', '2026-04-22 20:12:51.185914'::timestamp, 136);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (881, 'Теорема Столпера-Самуэльсона: свободная торговля выгодна владельцам изобильных факторов. В России — экспортёрам нефти.', '2026-04-22 20:12:54.870368'::timestamp, 136);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (882, 'Эффект дохода и эффект замещения: при росте цены на бензин люди либо меньше ездят (замещение), либо экономят на другом (доход).', '2026-04-22 20:12:57.877707'::timestamp, 136);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (883, 'Ипотека 19% годовых убила спрос. Цены на жильё в новостройках Москвы упали на 10% за полгода.', '2026-04-22 20:13:01.219079'::timestamp, 137);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (884, 'Доходность аренды жилья в Москве — 4-5% годовых, депозит даёт 15%. Продавать выгоднее, чем сдавать.', '2026-04-22 20:13:04.496058'::timestamp, 137);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (885, 'Льготная ипотека на новостройки под 8% продлена до 2024, но только для семей с детьми и IT-специалистов.', '2026-04-22 20:13:08.674622'::timestamp, 137);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (886, 'Квадратный метр в Сочи стоит 300 тыс. руб., в Воронеже — 100 тыс. Разрыв из-за туристического спроса.', '2026-04-22 20:13:11.765684'::timestamp, 137);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (887, 'Инвестиции в коммерческую недвижимость: склады дают 12-14% доходности, офисы — 10%, торговая — 8%.', '2026-04-22 20:13:14.939226'::timestamp, 137);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (888, 'Риски девелопера: рост стоимости стройматериалов на 20% в 2024, повышение ключевой ставки — проекты замораживаются.', '2026-04-22 20:13:18.012209'::timestamp, 137);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (889, 'Эскроу-счета: теперь застройщик получает деньги только после сдачи дома. Риск покупателя снизился, но цены выросли на 15%.', '2026-04-22 20:13:21.303758'::timestamp, 137);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (890, 'ЦБ повысил ключевую ставку до 16%. Инфляция в мае 7.5%. Снижения ждать не раньше осени.', '2026-04-22 20:13:24.688109'::timestamp, 138);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (891, 'Минфин планирует ввести прогрессивную шкалу НДФЛ: 15% при доходе от 5 млн в год. Даст бюджету 200 млрд.', '2026-04-22 20:13:27.638456'::timestamp, 138);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (892, 'Рубль укрепился до 90 за доллар из-за обязательной продажи валютной выручки экспортёрами.', '2026-04-22 20:13:30.626155'::timestamp, 138);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (893, 'ВВП России по итогам I квартала вырос на 3.5%. Промышленность — на 5%, сельское хозяйство — на 2%.', '2026-04-22 20:13:33.494400'::timestamp, 138);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (894, 'Инфляционные ожидания населения — 13% (опрос ЦБ). Люди не верят, что рост цен замедлится.', '2026-04-22 20:13:36.561357'::timestamp, 138);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (895, 'Банки подняли ставки по вкладам до 15-16%. Спрос на депозиты вырос в 2 раза за месяц.', '2026-04-22 20:13:39.498893'::timestamp, 138);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (896, 'Акции Яндекса на Мосбирже после редомициляции выросли на 30%. Инвесторы поверили в новую структуру.', '2026-04-22 20:13:43.534568'::timestamp, 138);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (897, 'Цифровой рубль: пилот запущен в 2024. Транзакции бесплатны, но банки теряют комиссионные доходы.', '2026-04-22 20:13:47.404616'::timestamp, 139);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (898, 'СБП (Система быстрых платежей) — 80% переводов между физлицами. Комиссия для банков 0.4%.', '2026-04-22 20:13:51.100261'::timestamp, 139);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (899, 'Криптовалюта в РФ: майнинг разрешён, оборот запрещён. Но через P2P-обменники можно купить.', '2026-04-22 20:13:54.055862'::timestamp, 139);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (900, 'Open banking: клиент может делиться своими банковскими данными с финтех-сервисами. Закона пока нет.', '2026-04-22 20:13:57.230786'::timestamp, 139);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (901, 'Нейросети в кредитовании: Сбер использует нейросеть для скоринга, ошибка меньше, чем у людей.', '2026-04-22 20:14:00.508612'::timestamp, 139);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (902, 'Биометрия в банках: 30% операций в отделениях уже по лицу и голосу. Без паспорта.', '2026-04-22 20:14:03.476977'::timestamp, 139);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (903, 'Мгновенные платежи через QR-код: 10% всех безналичных оплат в рознице. Удобно, быстро.', '2026-04-22 20:14:06.753712'::timestamp, 139);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (904, 'В 1998 году рубль девальвировали в 4 раза за один день. Потерял все сбережения. Никогда не храни деньги в одной валюте.', '2026-04-22 20:14:09.928811'::timestamp, 140);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (905, 'В 2008 году нефть упала с $140 до $40. Рынок акций рухнул на 70%. Потом отыграл за 2 года.', '2026-04-22 20:14:12.998747'::timestamp, 140);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (906, 'Приватизация в 90-х: ваучеры раздали, но заводы достались директорам и банкирам. Народ остался ни с чем.', '2026-04-22 20:14:16.701350'::timestamp, 140);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (907, 'Гиперинфляция 1992 года — 2500% в год. Зарплату давали раз в неделю, и за неделю она обесценивалась вдвое.', '2026-04-22 20:14:19.757481'::timestamp, 140);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (908, 'Дефолт 1998 года — отказ от выплат по ГКО. Многие банки обанкротились, люди потеряли вклады.', '2026-04-22 20:14:22.630375'::timestamp, 140);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (909, 'В 2014 году рубль обвалился вдвое из-за падения нефти и санкций. Ключевая ставка взлетела до 17%.', '2026-04-22 20:14:25.903115'::timestamp, 140);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (910, 'Самое надёжное вложение за 30 лет — недвижимость в Москве. Выросла в 100 раз. Акции — в 50 раз, доллар — в 10 раз.', '2026-04-22 20:14:28.770379'::timestamp, 140);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (911, 'На течении лучше работает джиг с лёгкой головой 10-14 г. Тяжёлый груз тащится по дну, а лёгкий играет даже на медленной проводке.', '2026-04-22 20:14:36.044637'::timestamp, 141);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (912, 'Щука в июле стоит у границы водорослей и тени. Заброс вдоль кувшинок с паузой после всплеска — почти гарантированная поклёвка.', '2026-04-22 20:14:39.009768'::timestamp, 141);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (913, 'Плетёнка 0.12 мм на спиннинг для окуня — идеал. Чувствуешь каждое касание дна, а на забросе дальше монофила на 20 метров.', '2026-04-22 20:14:42.014560'::timestamp, 141);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (914, 'Поменял тройники на Owner ST-36 — количество сходов щуки снизилось в разы. Родные воблерные крючки часто тупятся после первой рыбы.', '2026-04-22 20:14:45.561149'::timestamp, 141);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (915, 'Колебалка Mepps Syclops 15 г работает по судаку в отвес с лодки. Опускаешь на дно, резко поднимаешь на метр, пауза. Судак берёт на падении.', '2026-04-22 20:14:48.661327'::timestamp, 141);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (916, 'Для фидера на реке кормушка должна быть на 20-30% тяжелее, чем для стоячей воды. У меня на течении 70 г «клетка» держится стабильно.', '2026-04-22 20:14:51.968513'::timestamp, 142);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (917, 'Прикормка на основе панировки с добавлением рубленого червя и кукурузы. Насадка — пенопластовый шарик поверх червя: держит насадку над илом.', '2026-04-22 20:14:55.597035'::timestamp, 142);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (918, 'Вершинка 3 унции для ловли леща на дальней дистанции (80 м). Свингтип для ближней зоны чувствительнее на поклёвку мелкой рыбы.', '2026-04-22 20:14:59.078601'::timestamp, 142);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (919, 'Пескарь — первый признак чистоты воды и хороший прилов на фидер. Если клюёт пескарь, значит лещ и плотва уже рядом.', '2026-04-22 20:15:02.150909'::timestamp, 142);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (920, 'Крючок №12 Gamakatsu на мотыля. С длинным цевьём легче насаживать, и лещ меньше сходит при вываживании.', '2026-04-22 20:15:05.545978'::timestamp, 142);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (921, 'Бойл размером 18 мм и цвет тигровый орех. На незнакомом водоёме сначала даю 10 штук в точку, потом жду час. Карп не любит суеты.', '2026-04-22 20:15:09.231885'::timestamp, 143);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (922, 'Монтаж волосяной оснастки с пенопластовым поп-апом. Крючок остаётся острым, бойл лежит на дне, а пенопласт поднимает жало вверх.', '2026-04-22 20:15:12.594926'::timestamp, 143);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (923, 'Карп ночью выходит на мелководье кормиться ракушкой. Заброс под самый берег в тихую погоду даёт шанс на трофей.', '2026-04-22 20:15:15.973302'::timestamp, 143);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (924, 'У меня было: карп увёл фидер в воду. Пришлось лодкой догонять. С тех пор ставлю на стойку сигналку с громким динамиком.', '2026-04-22 20:15:19.267247'::timestamp, 143);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (925, 'Самодельная прикормка: кукурузная крупа паренная + мёд + жмых. Аромат стойкий, карп начинает брать через 40 минут.', '2026-04-22 20:15:22.220393'::timestamp, 143);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (926, 'Поплавок с длинной антенной (30 см) лучше виден при боковом ветре. Антенна наклоняется, но не ложится на воду.', '2026-04-22 20:15:25.394813'::timestamp, 144);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (927, 'Плотва весной на опарыша в полводы. Сначала прикормка с мелкой панировкой и сухим молоком — муть привлекает рыбу со всей акватории.', '2026-04-22 20:15:28.570196'::timestamp, 144);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (928, 'Грузило «оливка» и подпасок. На течении лучше скользящая оливка, чтобы рыба не чувствовала веса при поклёвке.', '2026-04-22 20:15:31.760044'::timestamp, 144);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (929, 'Линь на поплавок берёт очень осторожно. Лучше использовать камышовый поплавок с минимальной огрузкой и поводок 0.1 мм.', '2026-04-22 20:15:35.123294'::timestamp, 144);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (930, 'Самая крупная плотва попадается на крючок №14 с одним опарышем. Два опарыша — мелочь начинает теребить.', '2026-04-22 20:15:38.708232'::timestamp, 144);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (931, 'Мормышка «чёрт» с тремя крючками и бусинкой. При игре кивок 4 см амплитуды, частота 2 раза в секунду. Окунь берёт на подъёме.', '2026-04-22 20:15:42.310804'::timestamp, 145);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (932, 'Балансир 5 см для ловли судака на глубоких бровках. Первый лёд — лучший клёв. Стук балансира о лёд привлекает хищника.', '2026-04-22 20:15:45.686008'::timestamp, 145);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (933, 'Червь под лёд? Мормышку с кусочком червя насаживаю на цевьё. Даже пассивный лещ соблазняется на запах.', '2026-04-22 20:15:48.742418'::timestamp, 145);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (934, 'В глухозимье лучшая наживка — мотыль. Опарыш перестаёт работать. Насаживаю 3-4 личинки крест-накрест.', '2026-04-22 20:15:52.253023'::timestamp, 145);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (935, 'На малой глубине (до 2 м) сверлю лунки в шахматном порядке через 3-4 м. Стая окуня ходит, и если не клюёт в одной, через 10 минут клюнет в соседней.', '2026-04-22 20:15:55.301766'::timestamp, 145);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (936, 'Для ловли на средиземноморском побережье лучшая снасть — спиннинг с тестом до 40 г и катушка размером 4000. Камбала берёт на креветку.', '2026-04-22 20:15:58.573305'::timestamp, 146);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (937, 'Зубатка клюёт на ракушку-перловицу. Нужен поводок из титана, иначе перекусит даже 0.6 мм сталь.', '2026-04-22 20:16:01.643263'::timestamp, 146);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (938, 'Скат на пикер с мясом сардины. Вываживание: не давать слабину, но и не тащить на берег резко — сорвётся.', '2026-04-22 20:16:04.695408'::timestamp, 146);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (939, 'Скумбрия осенью ходит косяками у поверхности. Кастинговая сеть с ячейкой 20 мм даёт улов за один заброс — 10-15 штук.', '2026-04-22 20:16:08.216094'::timestamp, 146);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (940, 'Морской окунь в скалах — только лёгкий джиг 7-10 г с силиконовой креветкой. Проводка ступенька с паузами у дна.', '2026-04-22 20:16:11.270298'::timestamp, 146);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (941, 'Мушка-стример на щуку. Цвет чёрный с серебряной люрексной нитью. Проводка короткими рывками — имитация раненой рыбки.', '2026-04-22 20:16:14.648253'::timestamp, 147);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (942, 'Сухая мушка на ручьевую форель. Размер №14, цвет оливковый. Заброс вверх по течению, чтобы мушку сносило естественно.', '2026-04-22 20:16:17.842928'::timestamp, 147);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (943, 'Нахлыстовый шнур с плавающим конусом (интермедиат) для ловли в средних слоях. Глубина до 1.5 метра.', '2026-04-22 20:16:20.934063'::timestamp, 147);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (944, 'Самый сложный в забросе — ветер. При боковом ветре делаю петлевой заброс с задержкой, чтобы шнур не складывался.', '2026-04-22 20:16:24.273656'::timestamp, 147);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (945, 'Кумжа на мокрую мушку с золотой головкой. Вечером перед закатом, когда рыба поднимается к поверхности за насекомыми.', '2026-04-22 20:16:27.550526'::timestamp, 147);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (946, 'Для карася в стоячей воде: пареный горох с чесноком. Чеснок привлекает, а горох держится на крючке лучше, чем тесто.', '2026-04-22 20:16:30.418001'::timestamp, 148);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (947, 'Прикормка на леща: пшено + отруби + кормовой мотыль. На реке добавляю глину для веса. За час до рыбалки — 2 кг в точку.', '2026-04-22 20:16:33.285223'::timestamp, 148);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (948, 'Мастырка на плотву: гороховая мука с мёдом. Вязкая, не размокает в воде. Клюёт селективно — мелочь отсекается.', '2026-04-22 20:16:36.269344'::timestamp, 148);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (949, 'Бойл собственного варения: манка + соевый соус + анисовое масло. Карп на анис идёт лучше, чем на фруктовые ароматы.', '2026-04-22 20:16:39.532738'::timestamp, 148);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (950, 'Червь-выползок для крупного голавля. Насаживаю на крючок №6, оставляя хвост свободным. Голавль берёт шумно, с плеском.', '2026-04-22 20:16:42.705195'::timestamp, 148);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (951, 'Катушка Shimano Stradic 2500 с фрикционом передним. Плавность хода и идеальная укладка лески. Для лёгкого спиннинга лучший вариант.', '2026-04-22 20:16:45.997770'::timestamp, 149);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (952, 'Плетёный шнур Power Pro 0.15 мм на 15 lb. Не растягивается, передаёт каждое прикосновение. Минус — надо следить за износом.', '2026-04-22 20:16:49.427207'::timestamp, 149);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (953, 'Воблер ZipBaits Khamsin 110 F для ловли щуки в коряжнике. Заглубление 1.5 м, идёт ровно, не заваливается на бок.', '2026-04-22 20:16:53.354383'::timestamp, 149);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (954, 'Монолеска Sufix Elite 0.25 мм для фидера. Хорошая память, но крепкая и абразивоустойчивая. На каменистом дне выдерживает больше, чем плетёнка.', '2026-04-22 20:16:56.646560'::timestamp, 149);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (955, 'Складной подсак из карбона длиной 3 м — спасение при ловле с высокого берега. Складывается в рюкзак, весит 400 г.', '2026-04-22 20:16:59.928861'::timestamp, 149);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (956, 'На быстром течении грузило-пуля 30 г. Катится по дну, не цепляется за камни. Поклёвка передаётся на вершинку резким толчком.', '2026-04-22 20:17:03.391612'::timestamp, 150);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (957, 'Язь в омуте после переката. Забрасываю кормушку с опарышем и пареной пшеницей. Лучшее время — раннее утро, пока солнце не поднялось.', '2026-04-22 20:17:06.566753'::timestamp, 150);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (958, 'Проводка с придержкой. Когда поплавок проходит перспективный участок, придерживаю леску пальцем — насадка всплывает, провоцируя поклёвку.', '2026-04-22 20:17:09.636266'::timestamp, 150);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (959, 'Жерех на кастмастер. Дальний заброс, быстрая проводка у поверхности. Жерех бьёт хвостом — всплеск, и сразу подсечка.', '2026-04-22 20:17:13.014273'::timestamp, 150);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (960, 'На подлещика на реке работает поводок из флюорокарбона 0.14 мм. Невидимка в воде, но надо чаще проверять на узлы.', '2026-04-22 20:17:16.292454'::timestamp, 150);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (961, 'На озере с илистым дном использую кормушку-плоскодонку. Не зарывается, прикормка остаётся на поверхности ила.', '2026-04-22 20:17:19.994928'::timestamp, 151);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (962, 'Карась в жару берёт на перловку с ванилью. Прикармливаю распаренной пшеницей. Клёв начинается через 30-40 минут.', '2026-04-22 20:17:23.664943'::timestamp, 151);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (963, 'Линь любит тихие заливы с рогозом. Поплавок огружаю так, чтобы над водой оставалась только антенна. Леска 0.18 мм, крючок №10.', '2026-04-22 20:17:27.145838'::timestamp, 151);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (964, 'Ротан в торфяных озёрах клюёт на кусочек мяса или рыбьего филе. Жадный, хватает сразу. Мелочь отсекается насадкой размером с фалангу.', '2026-04-22 20:17:30.115391'::timestamp, 151);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (965, 'Судак на озере в отвес с лодки. Вертикальный блеснением на глубине 7-9 м. Игра — резкий подъём на 0.5 м и свободное падение.', '2026-04-22 20:17:33.905604'::timestamp, 151);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (966, 'Твичинг воблера Lucky Craft Flash Pointer 95. Рывки короткие, пауза 2-3 секунды. Щука атакует на паузе, когда воблер зависает.', '2026-04-22 20:17:37.080746'::timestamp, 152);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (967, 'Силиконовая рыба Keitech Swing Impact 3.5 дюйма на джиг-голове 10 г. Проводка равномерная у дна. Окунь берёт на первом же забросе.', '2026-04-22 20:17:40.153169'::timestamp, 152);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (968, 'Жерлица на живца для щуки. Ставлю на глубине у кромки камыша. Пескарь или плотвичка 5-7 см — идеальный размер.', '2026-04-22 20:17:43.389429'::timestamp, 152);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (969, 'Спиннинг для судака с берега — заброс поперёк течения, джиг волочится по дну. Поклёвка ощущается как удар в руку.', '2026-04-22 20:17:47.625602'::timestamp, 152);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (970, 'Голавль на вращающуюся блесну Mepps 3 с оперением. Заброс вверх по течению, проводка внатяг. Голавль берёт в момент, когда блесна выходит из струи.', '2026-04-22 20:17:50.493025'::timestamp, 152);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (971, 'Плотва на манку-болтушку. Консистенция жидкая, насаживаю шприцем без иглы на крючок. Мелочь не сбивает, крупная берёт аккуратно.', '2026-04-22 20:17:54.091905'::timestamp, 153);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (972, 'Карась на хлебный мякиш с добавлением мёда и подсолнечного масла. Медленно тонет, провоцирует карася на хватку.', '2026-04-22 20:17:57.191788'::timestamp, 153);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (973, 'Лещ на макароны-звёздочки. Варю до полуготовности, насаживаю на крючок №8. Держатся крепко, не слетают при забросе.', '2026-04-22 20:17:59.997661'::timestamp, 153);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (974, 'Уклейка на муравьиные яйца. Лучшая наживка для ловли в полводы. Поплавок стоит торчком, уклейка топит его резко.', '2026-04-22 20:18:03.108132'::timestamp, 153);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (975, 'Густера на тесто с анисом. Прикормка из сухарей и жмыха. Ловится на фидер и поплавок, предпочитает ямы за перекатами.', '2026-04-22 20:18:06.176553'::timestamp, 153);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (976, 'Сом на квок. Лодка на якоре, квокаю ритмично каждые 10 секунд. Наживка — пучок червей или лягушка. Клюёт в полной темноте.', '2026-04-22 20:18:09.761613'::timestamp, 154);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (977, 'Ночной поплавок с химическим светлячком. На реке при ловле леща светлячок креплю на антенну. Поклёвка — медленное погружение.', '2026-04-22 20:18:13.137162'::timestamp, 154);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (978, 'Угорь на выползка. Донка с поводком из лески 0.3 мм. Угорь клюёт резко, утягивает грузило. Вываживать надо осторожно — скользкий.', '2026-04-22 20:18:15.788715'::timestamp, 154);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (979, 'Ночью щука часто выходит на отмели 1-2 м глубины. Воблер с шумовой капсулой (Rat-L-Trap) работает отлично.', '2026-04-22 20:18:18.774578'::timestamp, 154);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (980, 'Фонарь с красным светом не пугает рыбу. Ставлю на берегу, чтобы видеть кончик удилища. Для ночного фидера — незаменимая вещь.', '2026-04-22 20:18:22.134637'::timestamp, 154);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (981, 'Для рыбалки с детьми беру поплавочную удочку с мягким хлыстиком. Ребёнку легче подсекать, и риск сломать снасть меньше.', '2026-04-22 20:18:25.120931'::timestamp, 155);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (982, 'Плотва на кукурузу — самая уловистая и простая наживка для школьника. Держится на крючке, не требует частой смены.', '2026-04-22 20:18:27.868920'::timestamp, 155);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (983, 'Складные стульчики и тент от солнца — обязательный набор. Дети быстро устают сидеть на траве, а тент спасает от ожогов.', '2026-04-22 20:18:31.861593'::timestamp, 155);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (984, 'Лучшее место для начинающих — пруд с карасём. Клюёт часто, рыба некрупная, ребёнок не устаёт вываживать.', '2026-04-22 20:18:35.447692'::timestamp, 155);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (985, 'Кулинарный мастер-класс на берегу: пойманную рыбу чистим и жарим на костре. Дети запоминают не только улов, но и общее дело.', '2026-04-22 20:18:38.892066'::timestamp, 155);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (986, 'Поход на 3 дня с палаткой к лесному озеру. Беру с собой минимум: фидер, надувную лодку, газовую горелку. Рыба — основной источник еды.', '2026-04-22 20:18:42.305498'::timestamp, 156);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (987, 'В тайге на горной реке лучшая снасть — ультралайт 0-7 г. Хариус на крошечную вертушку 00 размера. Азарт и красота природы.', '2026-04-22 20:18:46.095233'::timestamp, 156);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (988, 'Навигатор Garmin с картами глубин помогает найти ямы. Без эхолота ориентируюсь по перепадам береговой линии.', '2026-04-22 20:18:49.166013'::timestamp, 156);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (989, 'Самостраховка: на реке с быстрым течением всегда надеваю жилет. Мобильный телефон в гермопакете и аварийный маяк.', '2026-04-22 20:18:52.531804'::timestamp, 156);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (990, 'Ночлег на острове посреди озера. Вечером ловлю окуня с берега, утром — щуку. Тишина и звёзды дорогого стоят.', '2026-04-22 20:18:55.823427'::timestamp, 156);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (991, 'Эхолот Lowrance Hook2 с картографией. Понимаю структуру дна — коряги, ямы, бровки. Время поиска рыбы сокращается в разы.', '2026-04-22 20:18:59.304028'::timestamp, 157);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (992, 'Подводная камера Aqua-Vu. Опускаю в лунку, вижу, как рыба реагирует на мормышку. Позволяет подобрать игру.', '2026-04-22 20:19:03.011033'::timestamp, 157);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (993, 'Power-Pole — якорная система для лодки. Кнопкой опускаю штырь в дно, лодка стоит неподвижно даже на сильном ветру.', '2026-04-22 20:19:06.574787'::timestamp, 157);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (994, 'Электронный зуммер на фидерную стойку. Поклёвку слышно из палатки. Ночью можно спать, не упустив момент.', '2026-04-22 20:19:10.588494'::timestamp, 157);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (995, 'GPS-маркер для запоминания уловистых точек. Сохраняю координаты ям и коряжников, в следующий раз иду точно туда.', '2026-04-22 20:19:14.048799'::timestamp, 157);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (996, 'После рыбалки всегда убираю за собой леску и пластик. Леска на дне убивает рыбу и птиц. Оставленные пакеты ветром сносит в воду.', '2026-04-22 20:19:17.325612'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (997, 'Запрет на ловлю в нерест — не просто формальность. Видел, как браконьеры вывозили щуку с икрой мешками. Ресурс восстанавливается годами.', '2026-04-22 20:19:20.806585'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (998, 'Съедобный силикон — будущее. Если оборвал приманку, она разлагается в воде, а не остаётся на десятилетия.', '2026-04-22 20:19:23.996751'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (999, 'Безопасное обращение с рыбой: мокрые руки, резиновый коврик, зажим для удаления крючка. Отпускаю трофей без повреждений.', '2026-04-22 20:19:26.849388'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1000, 'Чистка прибрежной зоны от мусора перед началом рыбалки — ритуал. Чистота привлекает рыбу, и приятнее сидеть на берегу.', '2026-04-22 20:19:29.937331'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1001, 'Однажды на Оке вытащил щуку на 7 кг на воблер. Пока вываживал, лодку течением снесло под коряги. Рыбу взял, но винт погнул.', '2026-04-22 20:19:33.607615'::timestamp, 159);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1002, 'Знакомый поймал сома на донку с выползком. Когда подсекал, сом рванул и утащил удочку в воду. Пришлось за ним вплавь.', '2026-04-22 20:19:36.783345'::timestamp, 159);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1003, 'Зимой на Рыбинке пробурил 30 лунок, ни поклёвки. На 31-й — окунь на 1.2 кг. С тех пор всегда сверлю до последнего.', '2026-04-22 20:19:40.062045'::timestamp, 159);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1004, 'Дед рассказывал, как на Волге до войны ловили белугу на живую утку. Сажали утку на крюк, и она плавала, пока белуга не хватала.', '2026-04-22 20:19:43.130292'::timestamp, 159);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1005, 'Самый большой карась в моей жизни — 2.8 кг. Клюнул на хлеб в заросшем пруду, куда никто не ходил. Чистая удача.', '2026-04-22 20:19:46.426023'::timestamp, 159);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1006, 'Новичку лучше начать с поплавочной удочки длиной 5 м. Оснастка: основная леска 0.2 мм, поводок 0.14 мм, крючок №12, поплавок 2 г.', '2026-04-22 20:19:49.580956'::timestamp, 160);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1007, 'Не берите дорогие снасти сразу. На первое время хватит удилища за 1000 руб. и катушки за 500. Остальное придёт с опытом.', '2026-04-22 20:19:52.552647'::timestamp, 160);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1008, 'Простейший узел для крючка — клинч. Пропустите леску в ушко, оберните 5 раз, продете в петлю и затяните. Надёжно и просто.', '2026-04-22 20:19:55.625285'::timestamp, 160);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1009, 'Наживка №1 для начинающего — червь. Держится на крючке, клюёт почти вся рыба. Опарыш чуть сложнее в насаживании.', '2026-04-22 20:19:58.694824'::timestamp, 160);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1010, 'Первые рыбалки лучше на платном пруду. Гарантированный клёв, комфортные места, можно взять снасти напрокат.', '2026-04-22 20:20:02.093970'::timestamp, 160);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1011, 'Старый «Уэмбли» пах мокрой травой и историей. Новый — пластиком и деньгами. Но когда забивают, мурашки одинаковые.', '2026-04-22 20:20:09.550224'::timestamp, 161);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1012, 'Сектор активных болельщиков на 90 минут становится единым организмом. Крики, шарфы, взрыв после гола — ради этого и хожу.', '2026-04-22 20:20:12.635422'::timestamp, 161);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1013, 'В Ливерпуле фанаты поют «You''ll Never Walk Alone» даже за минуту до финального свистка при счёте 0-3. Вот что значит быть двенадцатым игроком.', '2026-04-22 20:20:15.794224'::timestamp, 161);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1014, 'Эмоции от гола на последних минутах — наркотик. Адреналин, объятия с незнакомцами, хриплый голос наутро. Лучшее в футболе.', '2026-04-22 20:20:18.662411'::timestamp, 161);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1015, 'Однажды я стоял за воротами, когда забивали хозяева. Сетка колыхнулась в метре от меня, а мяч прилетел обратно. Этот свист я запомнил навсегда.', '2026-04-22 20:20:21.785988'::timestamp, 161);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1016, 'Прессинг не работает без смещения. Если крайний защитник идёт вперёд, вингер должен закрывать его зону. Баланс — всё.', '2026-04-22 20:20:25.011676'::timestamp, 162);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1017, 'Почему Месси не бегал много? Потому что его рывок на 10 метров был точнее, чем у других на 30. Эффективность, а не километраж.', '2026-04-22 20:20:28.288654'::timestamp, 162);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1018, 'Ложная девятка заставляет центральных защитников выходить из зоны. Открывается пространство для инсайдов. Гвардиола это довёл до совершенства.', '2026-04-22 20:20:31.994410'::timestamp, 162);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1019, 'При розыгрыше аута в чужой штрафной важно не просто кинуть, а создать численное преимущество. Быстрое введение — половина успеха.', '2026-04-22 20:20:35.559182'::timestamp, 162);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1020, 'В защите позиция важнее отбора. Проиграл корпус — проиграл эпизод. Ставить ногу в подкат нужно только в крайнем случае.', '2026-04-22 20:20:38.453121'::timestamp, 162);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1021, 'Был на «Сантьяго Бернабеу» в Эль-Класико. Тишина, когда забивает Барселона, и рёв, когда забивает Реал. Контрасты испанского футбола.', '2026-04-22 20:20:42.003929'::timestamp, 163);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1022, 'На «Альянц Арене» фанаты не садятся на свои места до первого гола. Стоят, поют, барабанят. Атмосфера как в метро в час пик, только дружная.', '2026-04-22 20:20:45.178539'::timestamp, 163);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1023, 'В Англии на «Энфилде» я понял, почему говорят, что стены там дышат футболом. Каждая старая трибуна хранит голы Далглиша и Джеррарда.', '2026-04-22 20:20:48.557495'::timestamp, 163);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1024, 'Итальянский «Сан-Сиро» показался мне музеем. Бетонные дорожки, старые кресла, но когда миланское дерби — земля трясётся.', '2026-04-22 20:20:51.913062'::timestamp, 163);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1025, 'Марсель, «Велодром», Южная трибуна. Такое ощущение, что стадион взлетает. Французский юг умеет зажигать даже в середине недели.', '2026-04-22 20:20:55.060066'::timestamp, 163);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1026, 'Тони Кроос не бегал быстро. Он отдавал пас за секунду до того, как соперник начинал движение. Чтение игры на 2 хода вперёд.', '2026-04-22 20:20:58.491577'::timestamp, 164);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1027, 'Лучшие полузащитники — те, кто подсказывают. Кричат, показывают, страхуют. Молчаливая «восьмёрка» — мёртвая.', '2026-04-22 20:21:01.869577'::timestamp, 164);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1028, 'При переходе из обороны в атаку первый пас должен быть коротким и точным. Длинная заброска — потеря владения в 80% случаев.', '2026-04-22 20:21:06.374913'::timestamp, 164);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1029, 'В центре поля нельзя бояться ошибки. Трусливый полузащитник всегда отдаёт назад, убивая атаку. Риск — часть игры.', '2026-04-22 20:21:09.447186'::timestamp, 164);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1030, 'Разворот на 180 градусов с мячом — главное оружие центрхава. Это убивает прессинг и открывает коридоры.', '2026-04-22 20:21:12.318666'::timestamp, 164);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1031, 'Выбор позиции — 90% успеха вратаря. Реакция нужна, когда позиция проиграна. Лучший вратарь — тот, кто двигается меньше всех.', '2026-04-22 20:21:15.801421'::timestamp, 165);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1032, 'Игра ногами для голкипера сейчас важнее, чем ловля верховых. Высокий вынос — потеря, точный пас — продолжение атаки.', '2026-04-22 20:21:18.786428'::timestamp, 165);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1033, 'Один на один: опускайся на колено как можно позже. Слишком ранний шпагат — и форвард перебрасывает.', '2026-04-22 20:21:22.061478'::timestamp, 165);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1034, 'Буффон никогда не брал перчатки с большими пальцами, пришитыми отдельно. Говорил, что чувство мяча теряется. В этом весь Джанлуиджи.', '2026-04-22 20:21:25.425477'::timestamp, 165);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1035, 'Стена при штрафном должна закрывать ближний угол. А вратарь смещается на дальний. Половинчатость — верный пропущенный гол.', '2026-04-22 20:21:28.704613'::timestamp, 165);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1036, 'Дриблинг — это не скорость, это смена ритма. Сделай паузу, ложный замах, рывок. Защитник клюнет.', '2026-04-22 20:21:31.876958'::timestamp, 166);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1037, 'Фланговый игрок должен уметь бить с обеих ног. Если ты всегда уходишь под правую, тебя читают на раз.', '2026-04-22 20:21:34.862814'::timestamp, 166);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1038, 'Лучший способ обыграть крайнего защитника — не смотреть на него. Смотри на мяч, на ворота, но не на оппонента. Он сам начнёт гадать.', '2026-04-22 20:21:37.919375'::timestamp, 166);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1039, 'Прострел низом опаснее навеса. В суете штрафной любой рикошет может привести к голу. А навес — это дуэль с вратарём.', '2026-04-22 20:21:40.786137'::timestamp, 166);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1040, 'Роббен сделал карьеру на одном движении: уход в центр и удар левой. Но никто не мог остановить, потому что момент удара был неуловим.', '2026-04-22 20:21:43.872220'::timestamp, 166);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1041, 'Капитан не тот, кто носит повязку. А тот, кто в раздевалке поднимет голос, когда все молчат. Даже если у самого руки дрожат.', '2026-04-22 20:21:47.338010'::timestamp, 167);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1042, 'Назначить пенальти — это искусство. Психологически устойчивый игрок пробьёт, а звезда может сломаться под давлением.', '2026-04-22 20:21:50.206731'::timestamp, 167);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1043, 'Лучшие капитаны — это не крикуны. Это те, кто подойдёт к новичку после ошибки и скажет: «Забей, дальше играем».', '2026-04-22 20:21:53.278778'::timestamp, 167);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1044, 'Когда судья подходит к тебе с предупреждением, не спорь. Кивни, улыбнись и уйди. Иначе следующее предупреждение может быть красным.', '2026-04-22 20:21:56.061375'::timestamp, 167);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1045, 'Копа Америка 2015, Месси не подошёл к судье перед серией пенальти. Маскерано взял инициативу. Вот что значит капитанская суть.', '2026-04-22 20:21:59.116933'::timestamp, 167);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1046, 'Купил билет на гостевой сектор «Спартак» — ЦСКА. Стоял, пел, хрипел. Нас было 500, а шумели мы на весь стадион. Вот он, выезд.', '2026-04-22 20:22:02.625136'::timestamp, 168);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1047, 'Фанатское братство не объяснить. Когда у твоего соседа по трибуне слёзы на глазах, потому что любимый клуб вылетает — ты плачешь вместе с ним.', '2026-04-22 20:22:05.772010'::timestamp, 168);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1048, 'Еврокубковый выезд в Неаполь. Местные фанаты угощали пиццей и показывали дорогу. Полиция не верила, что мы не враги.', '2026-04-22 20:22:09.048784'::timestamp, 168);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1049, 'Стадион «Фишт» в Сочи. Море, горы и футбол. Не хватает только торсиды, но закат над полем компенсирует всё.', '2026-04-22 20:22:12.015949'::timestamp, 168);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1050, 'Когда сын впервые закричал «ГОООЛ!» вместе с трибуной — понял, что воспитал его правильно. Традиция живёт.', '2026-04-22 20:22:14.989469'::timestamp, 168);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1051, 'Тренировка по владению мячом 6 на 2 в квадрате. Игроки ненавидят, но без автоматизма в пасе не выйдешь из-под прессинга.', '2026-04-22 20:22:18.467708'::timestamp, 169);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1052, 'После разгрома 0-5 не ругал команду. Посмотрел запись, разобрал ошибки. На следующей неделе выиграли 2-0. Умный тренер учится на поражениях.', '2026-04-22 20:22:21.848784'::timestamp, 169);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1053, 'Лучшее упражнение на скорость принятия решения — игра в «два касания». Тормозов в штрафной не должно быть.', '2026-04-22 20:22:25.021970'::timestamp, 169);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1054, 'В молодёжке важно не зарубить талант. Парень теряет мяч — скажи, как исправить. Ошибка — часть роста.', '2026-04-22 20:22:28.402850'::timestamp, 169);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1055, 'Схема 4-3-3 требует крайних защитников с выносливостью. Если латераль не накрывает свой фланг, вся система рушится.', '2026-04-22 20:22:31.783481'::timestamp, 169);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1056, 'Олд Фирм: «Селтик» — «Рейнджерс». Напряжение такое, что даже разминка кажется битвой. А когда забивают, стадион взрывается ненавистью и любовью одновременно.', '2026-04-22 20:22:35.261471'::timestamp, 170);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1057, 'Римское дерби: «Лацио» — «Рома». Флаги, дым, хореография. И тишина на минуте памяти. Уважение к истории важнее счёта.', '2026-04-22 20:22:38.334665'::timestamp, 170);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1058, '«Фенербахче» — «Галатасарай». Шаманство, барабаны, факелы. Стадион трясётся за час до матча. Турецкие дерби — это психбольница в лучшем смысле.', '2026-04-22 20:22:41.507320'::timestamp, 170);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1059, 'Миланское дерби в Лиге чемпионов. Иба и Дзанетти на поле. Тогда ещё не было Мбаппе и Холанна, но класс был космическим.', '2026-04-22 20:22:44.988984'::timestamp, 170);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1060, 'Шальке — Боруссия Дортмунд. Рурское дерби на «Фельтинс-Арене». Болельщики сменяют друг друга, но ненависть к соседям не утихает годами.', '2026-04-22 20:22:48.470044'::timestamp, 170);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1061, 'На «Камп Ноу» газон идеален. Каждая травинка на своём месте. Но почему-то по телевизору он кажется искусственным, а вживую — живым.', '2026-04-22 20:22:51.748086'::timestamp, 171);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1062, 'На «Уэмбли» поле огромное. Ширина 68 метров, длина 105. Пока добежишь от одной бровки до другой, атака уже закончилась.', '2026-04-22 20:22:54.733891'::timestamp, 171);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1063, 'Зимой на российских стадионах газон подогревают. Пар идёт, мяч не прыгает, но скользко. Специальная зимняя бутса решает.', '2026-04-22 20:22:57.701401'::timestamp, 171);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1064, 'Натуральная трава — это запах. Искусственная — это резиновая крошка в бутсах. Настоящие профессионалы тоскуют по земле.', '2026-04-22 20:23:01.066044'::timestamp, 171);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1065, 'В дождь мяч скользит. Игроки не любят мокрый газон, но именно тогда случаются самые нелепые голы и красивые скользящие падения.', '2026-04-22 20:23:04.548812'::timestamp, 171);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1066, 'На пресс-конференции Моуринью может говорить час, а после взять и уйти, не ответив на главный вопрос. И это — тоже искусство.', '2026-04-22 20:23:07.825092'::timestamp, 172);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1067, 'Лучший матч в карьере журналиста — когда не надо ничего выдумывать. Эмоции на поле сильнее любых заголовков.', '2026-04-22 20:23:10.589044'::timestamp, 172);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1068, 'Писать о футболе 10 лет. Понял: болельщикам не нужна аналитика. Им нужна страсть. Цифры — скучно, а крик души — продаётся.', '2026-04-22 20:23:13.558433'::timestamp, 172);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1069, 'Бербатов однажды дал интервью на 15 минут. Ответил на 2 вопроса, но так, что статья разошлась на цитаты. Харизма важнее слов.', '2026-04-22 20:23:16.526876'::timestamp, 172);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1070, 'Журналист на стадионе — это привилегия. Видеть игру под другим углом, слышать разговоры на поле, чувствовать запах решительности.', '2026-04-22 20:23:19.907153'::timestamp, 172);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1071, 'Угловой, поданный на ближнюю штангу, опаснее навеса на дальнюю. Защитник ошибается чаще, вратарь боится.', '2026-04-22 20:23:23.899844'::timestamp, 173);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1072, 'Роналду всегда бил по мячу так, что вратарь боялся выйти. Кручёный удар от углового — ещё одна опция для гола.', '2026-04-22 20:23:26.460447'::timestamp, 173);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1073, 'При розыгрыше углового короткий пас сбивает защиту с толку. Двое разбегаются, а третий простреливает. Гол, как по нотам.', '2026-04-22 20:23:29.430855'::timestamp, 173);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1074, 'Вратарь на угловом должен командовать штрафной. Крик «Моя!» снимает неопределённость. Молчание — пропущенный гол.', '2026-04-22 20:23:32.826132'::timestamp, 173);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1075, 'Красивый угловой — тот, после которого мяч влетает под перекладину. Неважно, кто коснулся. Главное — удар.', '2026-04-22 20:23:35.983801'::timestamp, 173);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1076, 'Форварду нужна наглость. Ударить с неудобной ноги, пробить, когда закрыт угол, рискнуть. Стеснительный нападающий не забьёт.', '2026-04-22 20:23:39.261364'::timestamp, 174);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1077, 'Лучший приём в штрафной — ложное замахивание. Вратарь ложится, а ты катишь в пустой угол.', '2026-04-22 20:23:43.673298'::timestamp, 174);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1078, 'Не бить по воротам, если есть открытый партнёр. Жадность — это не гол, это потеря.', '2026-04-22 20:23:46.479066'::timestamp, 174);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1079, 'Форвард-столб (как Жиру) ценен даже без голов. Скидки, давление на защиту, борьба на втором этаже. Игра не только про голы.', '2026-04-22 20:23:49.603324'::timestamp, 174);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1080, 'Моуринью говорил: «Лучший нападающий — тот, кто забивает, когда команда играет плохо». Такие решают судьбу матчей.', '2026-04-22 20:23:52.776981'::timestamp, 174);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1081, 'Перед дерби мы рисовали баннер 50 метров две недели. Краска, кисти, бессонные ночи. Когда вывесили на стадионе, мурашки по коже.', '2026-04-22 20:23:56.156850'::timestamp, 175);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1082, 'Хореография в секторе — это координация с соседями. Ошибётся один — и картинка рушится. Но когда получается, это магия.', '2026-04-22 20:23:59.244714'::timestamp, 175);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1083, 'Итальянские ультрас — законодатели моды. Флаги, пиротехника, растяжки. Их перфомансы — современное искусство.', '2026-04-22 20:24:02.417923'::timestamp, 175);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1084, 'На «Алльянц Арене» фанаты создали изображение клубного герба из тысяч маленьких картонок. Технологично и душевно.', '2026-04-22 20:24:05.577678'::timestamp, 175);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1085, 'Против расизма на стадионах болельщики делают акции. Баннер «Футбол без цвета кожи» трогает сильнее, чем любое официальное заявление.', '2026-04-22 20:24:08.754157'::timestamp, 175);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1086, 'В академии мы учили не только пасу, но и тактической дисциплине. 12-летний парень должен знать, куда бежать при потере.', '2026-04-22 20:24:11.843424'::timestamp, 176);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1087, 'Родители на детском футболе — главная проблема. Кричат, давят, мешают. Лучше сидеть дома и смотреть запись спокойно.', '2026-04-22 20:24:14.792277'::timestamp, 176);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1088, 'Самый талантливый выпускник последних лет — Мусиала. В 16 уже читал игру как взрослый. Уникальное чутьё.', '2026-04-22 20:24:17.863036'::timestamp, 176);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1089, 'Травма в юном возрасте может убить карьеру. Поэтому восстановление и контроль нагрузок — главное.', '2026-04-22 20:24:20.951933'::timestamp, 176);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1090, 'Из дворового футбола в профессиональный — единицы. Но те, кто прошёл, имеют характер. Их не сломать давлением.', '2026-04-22 20:24:23.905713'::timestamp, 176);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1091, 'Ехать на выезд в другой город на поезде 12 часов, чтобы потом 90 минут орать на стадионе — это любовь. Настоящая.', '2026-04-22 20:24:26.978100'::timestamp, 177);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1092, 'Выездной сектор всегда поёт громче. Даже если проигрываешь 0-3, фанаты не замолкают. Позор тем, кто уходит раньше.', '2026-04-22 20:24:30.254401'::timestamp, 177);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1093, 'Мент на гостевом входе в Ростове обыскал меня так, будто я нёс бомбу. Но пиво пропустил. В России болельщиков любят с осторожностью.', '2026-04-22 20:24:33.444878'::timestamp, 177);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1094, 'В Лондоне на выезде к «Арсеналу» попал в пробку. Опоздал к началу, но услышал гол со стоянки. Радость была всеобщей.', '2026-04-22 20:24:36.329627'::timestamp, 177);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1095, 'Когда тебя в гостевом секторе обзывают, а ты улыбаешься — это победа над ненавистью. Футбол должен объединять.', '2026-04-22 20:24:39.366390'::timestamp, 177);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1096, 'VAR не убил футбол. Он убил безграмотность судей. Теперь ошибки видны, и спорить бесполезно.', '2026-04-22 20:24:42.644741'::timestamp, 178);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1097, 'Лучший судья — тот, кого не замечают. Кто свистит только тогда, когда нарушение очевидно. Игра должна течь.', '2026-04-22 20:24:45.716135'::timestamp, 178);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1098, 'Офсайд в 2 сантиметра — это офсайд. Правило есть правило. Пусть обидно, но так честнее.', '2026-04-22 20:24:48.804771'::timestamp, 178);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1099, 'Жёлтая карточка за симуляцию должна быть обязательной. Футбол — игра мужчин, а не театр.', '2026-04-22 20:24:51.941794'::timestamp, 178);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1100, 'Когда игрок орёт на судью, надо сразу показывать карточку. Уважение к рефери — основа игры.', '2026-04-22 20:24:55.240433'::timestamp, 178);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1101, 'Сезон 2011/12: «Манчестер Сити» вырывает чемпионство в добавленное время. Агуэроооо! Я тогда упал с дивана. Лучший момент в истории АПЛ.', '2026-04-22 20:24:58.823175'::timestamp, 179);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1102, 'В прошлом сезоне мой клуб занял 6-е место. Но выиграл кубок. Неоднозначно, но трофей есть трофей.', '2026-04-22 20:25:01.997758'::timestamp, 179);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1103, 'Трансферное окно закрыто. Мы купили двух защитников, а продали лучшего бомбардира. Тренер говорит, что это стратегия. Посмотрим.', '2026-04-22 20:25:05.188745'::timestamp, 179);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1104, 'Зимняя пауза в РПЛ нужна. Но после неё команды выходят как варёные. Сборы в Турции не заменяют игровой тонус.', '2026-04-22 20:25:09.079534'::timestamp, 179);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1105, 'Плей-офф Лиги чемпионов — это отдельный турнир. Здесь не важна форма, важна психология. «Реал» это знает лучше всех.', '2026-04-22 20:25:12.546084'::timestamp, 179);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1106, 'После матча криотерапия — лучший друг. 2 минуты в минус 100 градусов, и ноги не гудят наутро.', '2026-04-22 20:25:15.617026'::timestamp, 180);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1107, 'Растяжка после игры снижает риск травм на 30%. Но футболисты её ненавидят. Скучно, больно, долго.', '2026-04-22 20:25:18.397647'::timestamp, 180);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1108, 'Протеиновый коктейль в течение 30 минут после финального свистка запускает восстановление мышц. Многие этим пренебрегают.', '2026-04-22 20:25:21.673443'::timestamp, 180);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1109, 'Сон 8 часов — обязателен. Недосып замедляет регенерацию в два раза. Звёзды спят как младенцы, но с персональными тренерами.', '2026-04-22 20:25:24.952041'::timestamp, 180);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1110, 'Игровая нагрузка в неделю — 3 матча. Если не восстанавливаться, будет разрыв крестов. Физиотерапевт — самый важный человек в клубе.', '2026-04-22 20:25:27.904990'::timestamp, 180);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1111, 'Grid-контейнер с display: grid не даёт автоматического отступа между ячейками. Используйте gap: 16px или margin у дочерних элементов.', '2026-04-22 20:25:33.229263'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1112, 'Адаптивные шрифты: clamp(16px, 4vw, 24px) — лучший способ. Медиазапросы для шрифтов уже не нужны.', '2026-04-22 20:25:36.315320'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1113, 'Псевдокласс :has() работает во всех современных браузерах. Можно стилизовать родителя по наличию потомка: .card:has(img) — отличный трюк.', '2026-04-22 20:25:39.391168'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1114, 'Верстка письма для почтовиков — ад. Используйте таблицы, inline-стили, не доверяйте flexbox и grid. Даже в 2025.', '2026-04-22 20:25:42.548405'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1115, 'Сброс стилей: лучше не * { margin: 0; padding: 0 }, а нормалайз или сброс через :where(), чтобы сохранить специфичность.', '2026-04-22 20:25:46.540601'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1116, 'Свойство content-visibility: auto ускоряет рендеринг длинных списков. Браузер пропускает отрисовку элементов вне вьюпорта.', '2026-04-22 20:25:50.022175'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1117, 'Самый частый баг с position: sticky — забывают задать top, left или bottom. Без них элемент не прилипнет.', '2026-04-22 20:25:53.211322'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1118, 'SVG-спрайты через <use> до сих пор работают быстрее, чем иконочные шрифты. И доступнее.', '2026-04-22 20:25:56.473434'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1119, 'Плавный скролл: scroll-behavior: smooth. Но пользователи с vestibular disorders могут страдать — учитывайте в медиа prefers-reduced-motion.', '2026-04-22 20:25:59.751284'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1120, 'Инспектировать сетку в Firefox — лучший инструмент. Показывает имена линий, области, зазоры. Chrome догоняет, но медленно.', '2026-04-22 20:26:03.130159'::timestamp, 181);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1121, 'useEffect с пустыми зависимостями выполняет колбэк после монтирования. Не для всех операций подходит — read layout effect.', '2026-04-22 20:26:06.573566'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1122, 'Ключи в списках должны быть стабильными и уникальными. Индекс массива — плохо при переупорядочивании, фильтрации.', '2026-04-22 20:26:10.109842'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1123, 'React.memo бесполезен, если компонент принимает children, которые пересоздаются при рендере родителя.', '2026-04-22 20:26:13.470553'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1124, 'Контекст в React: если значение меняется часто, перерендериваются все потребители. Используйте библиотеки (zustand, jotai) для часто меняющихся данных.', '2026-04-22 20:26:16.457442'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1125, 'Правило: поднимайте состояние как можно ниже. Если состояние нужно только в одном компоненте — не кладите в глобальный стор.', '2026-04-22 20:26:19.528115'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1126, 'React 18 и concurrent features: useTransition для маркировки не срочных обновлений. Интерфейс остаётся отзывчивым при фильтрации больших списков.', '2026-04-22 20:26:22.497194'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1127, 'Серверные компоненты (RSC) не имеют состояния и хуков. Идеальны для статических частей и запросов к базе.', '2026-04-22 20:26:25.572218'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1128, 'Хук useCallback нужен не всегда. Мемоизируйте только если функция передаётся в мемоизированный дочерний компонент или в useEffect.', '2026-04-22 20:26:28.728814'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1129, 'Ошибка: мутация state напрямую (state.count++). Всегда используйте setState с новым объектом.', '2026-04-22 20:26:31.613186'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1130, 'Next.js 14: App Router с параллельными маршрутами и перехватом роутов. Но документация всё ещё запутанная.', '2026-04-22 20:26:34.546674'::timestamp, 182);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1131, 'Lighthouse в CI: настройте бюджет производительности (LCP < 2.5с, CLS < 0.1). Прогоняйте на каждом PR.', '2026-04-22 20:26:38.048329'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1132, 'Изображения: используйте srcset для разных разрешений, формат WebP (или AVIF), lazy-loading для оффскрина.', '2026-04-22 20:26:40.916490'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1133, 'Размер main thread: сократите длинные задачи (>50ms) разбиением на микро-задачи через setTimeout или scheduler.yield().', '2026-04-22 20:26:43.883679'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1134, 'Анализируйте бандл: webpack-bundle-analyzer, vite-bundle-visualizer. Ищите дублированные библиотеки (например, lodash в двух версиях).', '2026-04-22 20:26:47.058360'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1135, 'Core Web Vitals: оптимизация LCP — ускорить загрузку самого большого элемента (обычно картинка или блок текста). Preload для критических ресурсов.', '2026-04-22 20:26:50.540705'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1136, 'CLS (сдвиг макета): резервируйте место под изображения (width/height), не вставляйте контент динамически выше существующего.', '2026-04-22 20:26:53.715799'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1137, 'Минификация CSS: purgecss удаляет неиспользуемые стили. В больших проектах экономит до 70% объёма.', '2026-04-22 20:26:56.887954'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1138, 'Шрифты: используйте font-display: swap, предзагружайте шрифты через preload, но не злоупотребляйте — лишние preload вредят.', '2026-04-22 20:27:00.077667'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1139, 'Service Worker для кеширования статики и стратегии stale-while-revalidate. PWA — не только оффлайн, но и скорость повторных визитов.', '2026-04-22 20:27:03.340254'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1140, 'Профилируйте в DevTools: вкладка Performance, запись загрузки страницы. Ищите долгие скрипты и пересчёты стилей.', '2026-04-22 20:27:06.414770'::timestamp, 183);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1141, 'Кнопка «Наверх» появляется через 500px скролла — исследование NNGroup показало, что пользователи ждут её не раньше.', '2026-04-22 20:27:10.305151'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1142, 'Цветовая контрастность: для основного текста минимум 4.5:1, для крупного (18pt+) — 3:1. Проверяйте в WebAIM Contrast Checker.', '2026-04-22 20:27:13.287688'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1143, 'Интерактивные элементы (кнопки, ссылки) должны быть не меньше 44x44 пикселей для тач-экранов. Apple и Google рекомендуют.', '2026-04-22 20:27:16.752431'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1144, 'Скелетон (skeleton screen) лучше спиннера. Показывает структуру, снижает воспринимаемое время загрузки. Используйте псевдоэлементы с анимацией shimmer.', '2026-04-22 20:27:19.536794'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1145, 'Карточки товаров должны содержать: изображение, название, цену, рейтинг. Кнопка «Купить» — только при наведении на десктопе, на мобиле всегда видна.', '2026-04-22 20:27:22.810488'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1146, 'Стилизация фокуса: не удаляйте outline, замените на более заметный стиль (box-shadow: 0 0 0 3px rgba(66,153,225,0.5)).', '2026-04-22 20:27:25.878076'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1147, 'Хлебные крошки полезны для глубоких сайтов (>3 уровня). Для плоских (до 2 уровней) достаточно ссылки «Назад».', '2026-04-22 20:27:29.246535'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1148, 'Модальные окна: при открытии фокус должен переходить внутрь модалки, а при закрытии — возвращаться на кнопку открытия.', '2026-04-22 20:27:32.114662'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1149, 'Пустые состояния (empty states) важны: показывайте иллюстрацию и подсказку, как заполнить контент. Не просто «Ничего нет».', '2026-04-22 20:27:35.814543'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1150, 'Анимация уведомлений: не дольше 300ms, с ease-out. Для пользователей с vestibular disorders отключайте через prefers-reduced-motion.', '2026-04-22 20:27:39.690793'::timestamp, 184);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1151, 'Семантическая вёрстка: <button> вместо <div> с кликом. Скринридеры не поймут див, даже с role=''button''.', '2026-04-22 20:27:43.274572'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1152, 'Атрибут aria-label нужен только когда текст визуально скрыт. Иначе скринридер прочитает дважды.', '2026-04-22 20:27:46.345688'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1153, 'Для скрытого контента: .sr-only { position: absolute; width: 1px; height: 1px; padding: 0; margin: -1px; overflow: hidden; }', '2026-04-22 20:27:49.316326'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1154, 'Проверка клавиатурной навигации: Tab, Shift+Tab, Enter, Space. Фокус должен быть видимым и логичным.', '2026-04-22 20:27:52.594040'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1155, 'ARIA live regions: role=''status'' или ''alert'' для динамического контента. Скринридер прочитает изменения.', '2026-04-22 20:27:55.767400'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1156, 'Цвет не должен быть единственным индикатором ошибки. Добавляйте иконки или текст (например, «Поле обязательно»).', '2026-04-22 20:27:59.043417'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1157, 'Изображения с пустым alt (alt='''') — декоративные. Если изображение информативное, alt должен описывать содержание.', '2026-04-22 20:28:02.321214'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1158, 'Пропорции текста: пользователь может увеличить шрифт до 200% без поломки макета. Проверяйте зум в браузере.', '2026-04-22 20:28:05.597508'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1159, 'Заголовки: h1 — главный, один на странице. h2-h6 — иерархия, нельзя пропускать уровни (с h2 на h4).', '2026-04-22 20:28:08.977893'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1160, 'Тестируйте a11y с axe DevTools, Lighthouse, и на реальном скринридере (NVDA, VoiceOver).', '2026-04-22 20:28:12.149804'::timestamp, 185);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1161, 'Webpack 5: module federation позволяет загружать модули из удалённых сборок. Микрофронтенд без iframe.', '2026-04-22 20:28:16.041049'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1162, 'Vite быстрее webpack в dev-режиме благодаря нативным ES модулям. Для сборки использует Rollup.', '2026-04-22 20:28:19.335974'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1163, 'ESBuild на Go — самый быстрый бандлер. Используется в Vite для предварительной сборки зависимостей.', '2026-04-22 20:28:22.594701'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1164, 'Babel всё ещё нужен для поддержки старых браузеров, но можно ограничиться browserslist и core-js.', '2026-04-22 20:28:25.666886'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1165, 'CSS-модули с postcss — автопрефиксер, минификация, импорты. Не надо CSS-in-JS.', '2026-04-22 20:28:28.841169'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1166, 'TypeScript: строгая настройка strict: true. noImplicitAny ловит много ошибок. Incremental сборка ускоряет повторные компиляции.', '2026-04-22 20:28:31.709161'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1167, 'Tree shaking работает с ES модулями. Не используйте CommonJS в библиотеках, если хотите удалить мёртвый код.', '2026-04-22 20:28:35.396969'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1168, 'Настройка path aliases в tsconfig (paths) и в сборщике. Упрощает импорты: @/components вместо ''../../components''.', '2026-04-22 20:28:38.470006'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1169, 'Среда разработки: Docker с hot-reload, volumes для node_modules. Избегайте проблем с версиями на разных ОС.', '2026-04-22 20:28:41.863474'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1170, 'Source maps в production: используйте ''hidden-source-map'' для отслеживания ошибок без полного исходника в браузере.', '2026-04-22 20:28:44.992294'::timestamp, 186);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1171, 'Feature-Sliced Design (FSD) — методология для крупных проектов. Слои: app, processes, pages, features, entities, shared.', '2026-04-22 20:28:48.091196'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1172, 'Атомный дизайн: атомы (кнопки), молекулы (форма), организмы (карточка), шаблоны, страницы. Помогает переиспользовать.', '2026-04-22 20:28:51.881635'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1173, 'Стейт-менеджмент: zustand для простых приложений, redux-toolkit для сложных. MobX — для реактивности, но осторожно с обёртками.', '2026-04-22 20:28:55.021042'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1174, 'Монорепозиторий: npm workspaces, yarn workspaces, Turborepo. Общий код между проектами без дублирования.', '2026-04-22 20:28:58.434573'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1175, 'Адаптивный дизайн: mobile-first подход, точки перелома через медиазапросы. Избегайте фиксированных ширин.', '2026-04-22 20:29:01.506126'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1176, 'Design tokens: переменные для цвета, шрифта, отступов. Единый источник правды для всех компонентов.', '2026-04-22 20:29:05.193615'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1177, 'Интернационализация (i18n): react-i18next, ключи в JSON. Плюс подгрузка языков по требованию.', '2026-04-22 20:29:09.100560'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1178, 'Обработка ошибок: ErrorBoundary в React, глобальный обработчик unhandledrejection, fallback UI.', '2026-04-22 20:29:11.855942'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1179, 'Гибридные приложения: WebView с мостом для нативных вызовов. Осторожно с производительностью анимаций.', '2026-04-22 20:29:15.022940'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1180, 'CI/CD для фронтенда: линтинг, тесты, сборка, деплой на S3/Netlify/Vercel. Preview деплой для каждого PR.', '2026-04-22 20:29:18.178245'::timestamp, 187);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1181, 'Jest + React Testing Library: тестируйте поведение, а не детали реализации. Не используйте snapshot для больших компонентов.', '2026-04-22 20:29:21.489759'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1182, 'Playwright лучше Puppeteer: автовейты, трассировка, тестирование в разных браузерах (Chromium, Firefox, WebKit).', '2026-04-22 20:29:24.853332'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1183, 'Unit тесты для утилит и хуков, интеграционные для компонентов, E2E для критических путей.', '2026-04-22 20:29:27.735798'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1184, 'Тестирование accessibility: jest-axe, axe-playwright. Находит нарушения ARIA, контрастности.', '2026-04-22 20:29:30.894755'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1185, 'Mock fetch: jest.spyOn(global, ''fetch''). Создайте утилиту для моков с разными сценариями (успех, ошибка).', '2026-04-22 20:29:33.734731'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1186, 'CI: запускайте тесты параллельно, используйте --shard для больших наборов. Кэшируйте node_modules.', '2026-04-22 20:29:36.736513'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1187, 'Тесты на производительность: Lighthouse CI, измерение времени рендеринга в Playwright.', '2026-04-22 20:29:40.316184'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1188, 'Снапшоты полезны только для статичных строк (например, сообщения об ошибках). Для UI — хрупкие.', '2026-04-22 20:29:43.284072'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1189, 'Покрытие кода не должно быть самоцелью. 80% покрытия достаточно, если покрыты критичные сценарии.', '2026-04-22 20:29:46.971215'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1190, 'Тест-дабл: stubs для возврата фиксированных значений, mocks для проверки вызовов.', '2026-04-22 20:29:49.939738'::timestamp, 188);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1191, 'Структурированные данные JSON-LD для товаров, статей, хлебных крошек. Гугл любит. Проверяйте в Rich Results Test.', '2026-04-22 20:29:53.744101'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1192, 'Канонические ссылки (rel=''canonical'') для страниц с дублирующимся контентом. Указывайте абсолютный URL.', '2026-04-22 20:29:56.905167'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1193, 'Динамический рендеринг для SPA: используйте prerender.io или серверный рендеринг (Next.js) для SEO.', '2026-04-22 20:29:59.975566'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1194, 'Мета-теги: title (50-60 символов), description (120-160). Уникальные для каждой страницы.', '2026-04-22 20:30:02.944871'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1195, 'Файл robots.txt: запрещайте индексацию служебных путей (/admin, /api). Но не блокируйте CSS/JS — они нужны для рендеринга.', '2026-04-22 20:30:06.342748'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1196, 'Карта сайта sitemap.xml, с приоритетами и частотой обновления. Отправляйте в Search Console.', '2026-04-22 20:30:09.514827'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1197, 'Open Graph и Twitter Cards для соцсетей: og:image, og:title, og:description. Улучшают шаринг.', '2026-04-22 20:30:12.774419'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1198, 'Скорость загрузки влияет на ранжирование. Оптимизируйте LCP, FID, CLS.', '2026-04-22 20:30:16.170150'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1199, 'Для Next.js: getStaticProps для статики, getServerSideProps для динамики. ISR (incremental static regeneration) — золотая середина.', '2026-04-22 20:30:19.941285'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1200, 'Мобильная версия: адаптивный дизайн, viewport meta, отсутствие горизонтального скролла на 320px.', '2026-04-22 20:30:23.320620'::timestamp, 189);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1201, 'Вкладка Performance: запись, выделение долгих задач (жёлтые и красные блоки). Ищите пересчёт стилей (Recalculate Style).', '2026-04-22 20:30:28.134153'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1202, 'Network: имитируйте медленные сети (3G, offline). Блокировка запросов, просмотр размера и времени загрузки.', '2026-04-22 20:30:31.718329'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1203, 'Вкладка Coverage: показывает, какой процент CSS/JS использован. Удаляйте неиспользуемый код.', '2026-04-22 20:30:35.098950'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1204, 'Сохранение логов: вкладка Console, настройка «Preserve log». Не теряются при навигации.', '2026-04-22 20:30:38.483341'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1205, 'Отладка React: расширение React DevTools. Профилирование рендеров, поиск компонентов, хуков.', '2026-04-22 20:30:41.445819'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1206, 'Вкладка Elements: инспекция стилей, добавление классов на лету, изменение псевдоклассов (:hover).', '2026-04-22 20:30:44.620332'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1207, 'Локальное переопределение (Overrides): изменяйте файлы прямо в DevTools, сохраняйте изменения для локальной отладки.', '2026-04-22 20:30:48.085273'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1208, 'JavaScript дебаггер: точки останова (breakpoints), условные breakpoints, логпойнты (console.log без изменения кода).', '2026-04-22 20:30:51.258322'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1209, 'Анализ памяти: вкладка Memory, снимки кучи (heap snapshot). Ищите утечки — увеличивающиеся объекты.', '2026-04-22 20:30:54.246028'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1210, 'Симуляция устройств: режим эмуляции мобильных устройств, сенсорных событий, геолокации, ориентации.', '2026-04-22 20:30:57.858132'::timestamp, 190);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1211, 'В 2023 году археологи обнаружили под Помпеями нетронутую гробницу с фресками, изображающими сцены из «Илиады». Возраст — около 2000 лет.', '2026-04-22 20:31:03.462989'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1212, 'Шумерская клинопись — древнейшая из известных систем письма. Самые ранние таблички датируются 3400 годом до н.э. и содержат хозяйственные записи.', '2026-04-22 20:31:06.442936'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1213, 'Египетская пирамида Джосера в Саккаре — первая каменная пирамида в истории. Построена архитектором Имхотепом около 2650 года до н.э.', '2026-04-22 20:31:09.914453'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1214, 'В 1974 году в Сиане (Китай) крестьяне нашли терракотовую армию императора Цинь Шихуанди. Более 8000 статуй, каждая с уникальным лицом.', '2026-04-22 20:31:13.293055'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1215, 'Римский акведук Aqua Claudia длиной 69 км построен при императоре Клавдии. Ежедневно подавал в Рим около 200 000 кубометров воды.', '2026-04-22 20:31:16.892053'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1216, 'Битва при Гавгамелах (331 г. до н.э.): Александр Македонский с 47 000 воинов разгромил армию Дария III, насчитывавшую до 100 000 человек.', '2026-04-22 20:31:20.460088'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1217, 'Древние греки использовали систему оптического телеграфа — гидравлос. Сигналы передавались на расстояние до 50 км с помощью факелов и воды.', '2026-04-22 20:31:24.161810'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1218, 'В 1901 году у берегов Греции найден Антикитерский механизм — аналоговый компьютер II века до н.э. Он вычислял положения небесных тел.', '2026-04-22 20:31:27.540744'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1219, 'Индейцы майя создали один из самых точных календарей. Их год составлял 365.2420 дней, погрешность — всего 0.0002 дня от современного.', '2026-04-22 20:31:31.212032'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1220, 'Храм Артемиды в Эфесе — одно из семи чудес света. Сгорел в 356 г. до н.э. в день рождения Александра Македонского, позже восстановлен.', '2026-04-22 20:31:34.797391'::timestamp, 191);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1221, 'Битва при Гастингсе 1066 года: нормандцы Вильгельма Завоевателя победили англосаксов. Решающим фактором стала ложная атака отступления.', '2026-04-22 20:31:38.629732'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1222, 'Король Ричард Львиное Сердце провёл в Англии всего 6 месяцев за 10 лет правления. Остальное время — в крестовых походах и плену.', '2026-04-22 20:31:42.067029'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1223, 'В 1215 году бароны вынудили короля Иоанна Безземельного подписать Великую хартию вольностей. Документ ограничил власть монарха впервые в Европе.', '2026-04-22 20:31:45.854312'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1224, 'Столетняя война (1337-1453) длилась 116 лет. В ней сменилось пять поколений. Жанна д''Арк появилась на поле боя через 92 года после начала.', '2026-04-22 20:31:49.133827'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1225, 'Чёрная смерть (1346-1353) убила от 30% до 60% населения Европы. В некоторых городах, например во Флоренции, умерло 80% жителей.', '2026-04-22 20:31:52.776437'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1226, 'Падение Константинополя в 1453 году положило конец Византийской империи. Османы использовали 70-тонные пушки, отлитые венгерским инженером Урбаном.', '2026-04-22 20:31:56.589521'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1227, 'Крестовые походы: Первый (1096-1099) завершился взятием Иерусалима. Из 30 000 участников до города дошли около 12 000.', '2026-04-22 20:31:59.986872'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1228, 'В 800 году папа Лев III короновал Карла Великого императором Запада. Это событие заложило основу Священной Римской империи.', '2026-04-22 20:32:03.892269'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1229, 'Киевская Русь приняла христианство в 988 году при князе Владимире. Крещение было выбрано после сравнения ислама, иудаизма и византийского обряда.', '2026-04-22 20:32:07.051366'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1230, 'Альбигойский крестовый поход (1209-1229) против катаров в Лангедоке уничтожил почти всё население города Безье — 20 000 человек за один день.', '2026-04-22 20:32:11.265972'::timestamp, 192);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1231, 'Леонардо да Винчи написал «Мону Лизу» в период с 1503 по 1519 год. Картина висит в Лувре за пуленепробиваемым стеклом после кражи 1911 года.', '2026-04-22 20:32:15.037453'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1232, 'Микеланджело расписывал Сикстинскую капеллу 4 года (1508-1512) лёжа на лесах. Он сам спроектировал конструкцию, чтобы не мешать службам.', '2026-04-22 20:32:18.315564'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1233, 'Гутенберг изобрёл книгопечатание около 1450 года. Первая напечатанная книга — Библия из 42 строк, тираж 180 экземпляров.', '2026-04-22 20:32:21.591325'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1234, 'Коперник опубликовал гелиоцентрическую систему «О вращениях небесных сфер» в год своей смерти (1543). Церковь запретила книгу через 73 года.', '2026-04-22 20:32:24.972022'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1235, 'Томас Мор написал «Утопию» в 1516 году. Термин стал нарицательным для идеального общества. Сам Мор был казнён за отказ признать Генриха VIII главой церкви.', '2026-04-22 20:32:28.149207'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1236, 'В 1492 году Христофор Колумб открыл Америку, ища морской путь в Индию. Он совершил 4 экспедиции, до смерти считая открытые земли Азией.', '2026-04-22 20:32:32.036307'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1237, 'Рафаэль Санти умер в 37 лет. Его последняя картина «Преображение» была завершена учениками после смерти мастера.', '2026-04-22 20:32:35.943826'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1238, 'Николай Кузанский в XV веке предположил, что Земля вращается вокруг Солнца и не является центром Вселенной — за 100 лет до Коперника.', '2026-04-22 20:32:39.716892'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1239, 'Альбрехт Дюрер создал гравюру «Меланхолия» в 1514 году. Магический квадрат 4х4 на ней содержит постоянную сумму 34 по всем направлениям.', '2026-04-22 20:32:44.033381'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1240, 'В 1453 году пал Константинополь, и греческие учёные бежали в Италию, привезя с собой античные манускрипты. Это ускорило Возрождение.', '2026-04-22 20:32:47.071332'::timestamp, 193);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1241, 'В 1494 году Тордесильясский договор разделил мир между Испанией и Португалией по меридиану в 370 лигах западнее Кабо-Верде.', '2026-04-22 20:32:50.791334'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1242, 'Британская Ост-Индская компания управляла Индией почти 100 лет (1757-1857), имея собственную армию в 200 000 человек — вдвое больше британской.', '2026-04-22 20:32:54.682317'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1243, 'Конкистадоры во главе с Кортесом завоевали империю ацтеков в 1519-1521 годах. 500 испанцев с союзниками-тлашкаланцами победили армию в сотни тысяч.', '2026-04-22 20:32:57.840576'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1244, 'Франция продала Луизиану США в 1803 году за 15 миллионов долларов. Площадь — 2,1 млн км² (примерно 1/3 современных США).', '2026-04-22 20:33:00.622044'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1245, 'В 1885 году на Берлинской конференции европейские державы разделили Африку, не пригласив ни одного африканского представителя.', '2026-04-22 20:33:04.001444'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1246, 'Португальцы начали вывоз рабов из Африки в 1441 году. За 400 лет трансатлантической работорговли было вывезено около 12 миллионов человек.', '2026-04-22 20:33:07.278218'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1247, 'Австралия стала британской колонией для ссыльных в 1788 году. Первый флот из 11 кораблей доставил 778 заключённых.', '2026-04-22 20:33:10.759781'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1248, 'Испанский флот (Непобедимая армада) в 1588 году потерпел поражение от Англии. Потеряв 67 кораблей из 130, Испания утратила морское господство.', '2026-04-22 20:33:14.137618'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1249, 'Колониальная империя Португалии просуществовала 584 года (1415-1999). Последняя колония — Макао возвращена Китаю.', '2026-04-22 20:33:17.398796'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1250, 'Битва при Плесси (1757) положила начало британскому владычеству в Индии. Роберт Клайв подкупил главнокомандующего бенгальской армии Мир Джафара.', '2026-04-22 20:33:20.589237'::timestamp, 194);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1251, 'Американская революция началась с «Бостонского чаепития» в 1773 году: колонисты выбросили в море 342 ящика чая в знак протеста против налогов.', '2026-04-22 20:33:24.261886'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1252, 'Французская революция 1789 года: взятие Бастилии 14 июля стало символом свержения абсолютизма. В крепости на тот момент было всего 7 заключённых.', '2026-04-22 20:33:27.538340'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1253, 'Декларация независимости США (1776) была написана Томасом Джефферсоном. 56 подписантов рисковали жизнью — Британия считала их государственными изменниками.', '2026-04-22 20:33:31.325004'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1254, 'В 1793 году Людовик XVI был казнён на гильотине. За его процесс проголосовали 387 депутатов из 721 — перевес всего в 26 голосов.', '2026-04-22 20:33:35.012263'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1255, 'Гаитянская революция (1791-1804) — единственное успешное восстание рабов в истории. Гаити стала первой чёрной республикой.', '2026-04-22 20:33:38.017302'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1256, 'Восстание декабристов в России (1825) произошло после смерти Александра I. 3000 солдат вышли на Сенатскую площадь, но восстание было подавлено.', '2026-04-22 20:33:41.257740'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1257, 'Европейские революции 1848 года охватили 50 стран. В Париже свергли короля Луи-Филиппа, во Франкфурте создали первый общегерманский парламент.', '2026-04-22 20:33:44.855865'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1258, 'Мексиканская революция (1910-1920) унесла около 2 миллионов жизней. Принятая в 1917 году конституция стала первой в мире, гарантировавшей социальные права.', '2026-04-22 20:33:48.219842'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1259, 'Февральская революция 1917 года в России свергла монархию. Николай II отрёкся от престола 2 марта. Через 8 месяцев большевики захватили власть.', '2026-04-22 20:33:51.513163'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1260, 'Американский лозунг «Нет налогам без представительства» возник из-за гербового сбора 1765 года. Колонисты не имели мест в британском парламенте.', '2026-04-22 20:33:54.339446'::timestamp, 195);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1261, 'Первая мировая война началась 28 июля 1914 года после убийства эрцгерцога Франца Фердинанда. За 4 года погибло около 20 миллионов человек.', '2026-04-22 20:33:57.452589'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1262, 'Верденская битва (1916) длилась 302 дня. Французские потери — 377 000, немецкие — 337 000. Девиз: «Они не пройдут».', '2026-04-22 20:34:00.816648'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1263, 'Вторая мировая война (1939-1945) — самый масштабный конфликт в истории. Участвовало 61 государство, мобилизовано 110 миллионов человек.', '2026-04-22 20:34:04.403287'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1264, 'Операция «Барбаросса» (22 июня 1941) — вторжение Германии в СССР. За первые 3 месяца вермахт продвинулся на 500 км, потеряв 400 000 солдат.', '2026-04-22 20:34:07.779289'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1265, 'День Д — 6 июня 1944 года: высадка союзников в Нормандии. 156 000 солдат, 5000 кораблей, 11 000 самолётов. В первый день погибло 4400 человек.', '2026-04-22 20:34:11.669634'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1266, 'Битва за Сталинград (1942-1943) длилась 200 дней. Потери с обеих сторон превысили 2 миллиона человек. 91 000 немецких солдат попали в плен.', '2026-04-22 20:34:15.457798'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1267, 'Хиросима и Нагасаки: атомные бомбардировки 6 и 9 августа 1945 года. В момент взрыва погибло 140 000 и 70 000 человек соответственно.', '2026-04-22 20:34:19.143590'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1268, 'Подводные лодки типа VII — самое массовое оружие Кригсмарине. Построено 703 единицы, потопили 3000 кораблей союзников.', '2026-04-22 20:34:23.210361'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1269, 'Курская битва (июль 1943) — крупнейшее танковое сражение в истории. С обеих сторон участвовало до 6000 танков и 2 млн человек.', '2026-04-22 20:34:26.908996'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1270, 'Атомные бомбардировки привели к капитуляции Японии 2 сентября 1945 года. Вторая мировая война завершилась через 6 лет и 1 день.', '2026-04-22 20:34:30.322711'::timestamp, 196);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1271, 'Берлинский кризис 1948-1949: СССР заблокировал наземные пути в Западный Берлин. Союзники 11 месяцев доставляли грузы по воздуху — 278 000 полётов.', '2026-04-22 20:34:33.993421'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1272, 'Карибский кризис 1962 года: советские ракеты на Кубе. Мир находился на грани ядерной войны 13 дней. Кризис разрешился тайными переговорами.', '2026-04-22 20:34:37.458947'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1273, 'Корейская война (1950-1953) унесла жизни 2,5 миллиона человек. Граница осталась на 38-й параллели, разделив Север и Юг.', '2026-04-22 20:34:40.751051'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1274, 'Вьетнамская война (1955-1975) закончилась падением Сайгона. США потеряли 58 000 военных, Вьетнам — до 3 миллионов гражданских.', '2026-04-22 20:34:44.145706'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1275, 'Строительство Берлинской стены началось 13 августа 1961 года. За 28 лет её пытались преодолеть более 5000 человек, 140 погибли.', '2026-04-22 20:34:47.508600'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1276, 'Гонка вооружений: к 1986 году в мире насчитывалось 70 000 ядерных боеголовок. Мощность арсеналов в 1 млн раз превысила бомбу Хиросимы.', '2026-04-22 20:34:51.204298'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1277, 'Программа «Аполлон» высадила человека на Луну в 1969 году. Это был ответ на советский спутник и полёт Гагарина.', '2026-04-22 20:34:54.679313'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1278, 'Афганская война (1979-1989) стоила СССР 15 000 погибшими, 35 000 ранеными. Моджахеды получили помощь от США через Пакистан.', '2026-04-22 20:34:58.158159'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1279, 'В 1991 году распался Советский Союз. 25 декабря М.С. Горбачёв ушёл в отставку. На карте появилось 15 новых независимых государств.', '2026-04-22 20:35:01.536924'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1280, 'В 1987 году Рейган и Горбачёв подписали Договор о ликвидации ракет средней и меньшей дальности. Уничтожено 2692 ракеты.', '2026-04-22 20:35:04.612175'::timestamp, 197);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1281, 'В 2001 году террористическая атака 11 сентября унесла жизни 2977 человек. Это привело к войне в Афганистане и созданию Департамента внутренней безопасности США.', '2026-04-22 20:35:08.193811'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1282, 'Европейский союз награждён Нобелевской премией мира в 2012 году за вклад в объединение континента после двух мировых войн.', '2026-04-22 20:35:11.793937'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1283, 'Китай стал второй экономикой мира в 2010 году, обогнав Японию. ВВП Китая вырос с 150 млрд долларов в 1980 до 18 трлн в 2023-м.', '2026-04-22 20:35:14.967893'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1284, 'Пандемия COVID-19 (2020-2023) затронула все страны. Зарегистрировано более 700 миллионов случаев, 7 миллионов смертей.', '2026-04-22 20:35:18.022662'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1285, 'В 2015 году в Париже принято климатическое соглашение. 196 стран обязались удерживать рост температуры ниже 2°C.', '2026-04-22 20:35:21.504390'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1286, 'Арабская весна (2010-2012) свергла режимы в Тунисе, Египте, Ливии, Йемене. В Сирии вспыхнула гражданская война, длящаяся до сих пор.', '2026-04-22 20:35:25.002226'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1287, 'В 2020 году Великобритания официально вышла из Европейского союза (Brexit). Переходный период завершился 31 декабря 2020 года.', '2026-04-22 20:35:28.161370'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1288, 'Цифровая революция: в 2024 году число пользователей интернета достигло 5,4 миллиарда (67% населения Земли).', '2026-04-22 20:35:31.146489'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1289, 'В 2011 году в Норвегии Андерс Брейвик убил 77 человек в теракте. Это самое массовое убийство в истории страны.', '2026-04-22 20:35:34.919733'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1290, 'Россия и Китай в 2023 году объявили о стратегическом партнёрстве без границ. Товарооборот достиг 240 млрд долларов.', '2026-04-22 20:35:38.417327'::timestamp, 198);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1291, 'Крещение Руси в 988 году князем Владимиром Святославичем объединило восточных славян под властью православия.', '2026-04-22 20:35:41.863058'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1292, 'Ледовое побоище 1242 года: войско Александра Невского разгромило немецких рыцарей на Чудском озере. Тевтонцы потеряли около 400 воинов.', '2026-04-22 20:35:45.173369'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1293, 'Куликовская битва (1380) стала первым крупным поражением Золотой Орды. Дмитрий Донской получил прозвище в честь победы.', '2026-04-22 20:35:48.742611'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1294, 'Иван Грозный в 1565 году ввёл опричнину — систему репрессий против бояр. За 7 лет казнено около 4000 человек.', '2026-04-22 20:35:51.917033'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1295, 'Пётр I основал Санкт-Петербург в 1703 году. Город строился на болотах силами крепостных — погибло до 100 000 человек.', '2026-04-22 20:35:54.892672'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1296, 'Отечественная война 1812 года: Наполеон вошёл в Москву, но оставил её через месяц. Из 600 000 солдат «Великой армии» вернулись 40 000.', '2026-04-22 20:35:58.384144'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1297, 'Отмена крепостного права в 1861 году освободила 23 миллиона крестьян. За землю они платили выкуп в течение 49 лет.', '2026-04-22 20:36:01.644992'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1298, 'Первая русская революция 1905 года началась с «Кровавого воскресенья» 9 января. Войска расстреляли мирное шествие к Зимнему дворцу.', '2026-04-22 20:36:04.734027'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1299, 'В 1918 году в Екатеринбурге расстреляна царская семья — Николай II, Александра Фёдоровна и пятеро детей.', '2026-04-22 20:36:08.063374'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1300, 'Битва под Москвой (1941) сорвала план блицкрига. Вермахт впервые потерпел крупное поражение, отступив на 100-250 км.', '2026-04-22 20:36:11.576758'::timestamp, 199);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1301, 'Великий шёлковый путь протяжённостью 10 000 км соединял Китай и Средиземноморье с II века до н.э. По нему везли шёлк, пряности, идеи.', '2026-04-22 20:36:15.060856'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1302, 'Империя Чингисхана в XIII веке стала крупнейшей в истории — 24 миллиона км². Монголы использовали скоростную конную почту «ям».', '2026-04-22 20:36:17.925245'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1303, 'Японский период Сэнгоку (1467-1615) — эпоха воюющих провинций. Самураи сражались за власть почти 150 лет.', '2026-04-22 20:36:21.203473'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1304, 'Китайский император Цинь Шихуанди (259-210 гг. до н.э.) объединил Китай, начал строить Великую стену и создал терракотовую армию.', '2026-04-22 20:36:24.786864'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1305, 'Индийская империя Маурьев при Ашоке (268-232 гг. до н.э.) охватывала почти весь субконтинент. После кровопролитной войны Ашока принял буддизм.', '2026-04-22 20:36:27.960693'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1306, 'Японское затворничество сакоку (1633-1853) длилось 220 лет. Выезжать из страны и возвращаться было запрещено под страхом смерти.', '2026-04-22 20:36:31.546396'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1307, 'Война Онин (1467-1477) в Японии уничтожила Киото. Сражения шли прямо на улицах города, население сократилось с 200 000 до 30 000.', '2026-04-22 20:36:35.046854'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1308, 'Китайская династия Тан (618-907) считается золотым веком. Чанган (совр. Сиань) был крупнейшим городом мира с населением 1 млн человек.', '2026-04-22 20:36:38.611246'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1309, 'Англо-китайские опиумные войны (1839-1842, 1856-1860) навязали Китаю неравноправные договоры. Гонконг перешёл Британии.', '2026-04-22 20:36:42.295969'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1310, 'В 1911 году Синьхайская революция свергла династию Цинь, правившую 268 лет. Китай стал республикой во главе с Сунь Ятсеном.', '2026-04-22 20:36:45.982472'::timestamp, 200);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1311, 'Заливка льда после матча — целое искусство. Температура воды 60°C, два слоя, и нельзя спешить, иначе пойдут трещины. Зато утром лёд как зеркало.', '2026-04-22 20:36:53.560052'::timestamp, 201);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1312, 'Самая частая поломка во дворце — борта. Игроки въезжают на скорости, крепления не выдерживают. Меняем по 5-6 секций за сезон.', '2026-04-22 20:36:56.735251'::timestamp, 201);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1313, 'Хоккейная коробка под открытым небом: осенью заливаем при -5°C, чистим каждые два часа. Когда приходят морозы -20, лёд становится твёрдым как бетон.', '2026-04-22 20:37:00.218306'::timestamp, 201);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1314, 'Почему на арене всегда холодно? Температура воздуха должна быть около +10°C, иначе лёд тает, а игроки задыхаются от жары.', '2026-04-22 20:37:03.493747'::timestamp, 201);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1315, 'Зрители не видят, как после матча мы два часа скребём и заливаем лёд заново. Но без этого завтрашняя игра превратится в болото.', '2026-04-22 20:37:06.872646'::timestamp, 201);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1316, 'Посетил 23 хоккейные арены в Европе. Лучшая атмосфера — в Чехии, на O2 Arena в Праге. Чешские болельщики поют весь матч, даже если их команда проигрывает 0:5.', '2026-04-22 20:37:10.369730'::timestamp, 202);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1317, 'Монреальский «Белл-центр» — храм хоккея. Там на стенах висят свитера всех легенд «Канадиенс». И тишина во время гимна Канады — мурашки по коже.', '2026-04-22 20:37:13.731852'::timestamp, 202);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1318, 'В Швеции на матчах SHL продают кофе с корицей и булочки. И болельщики спокойные, аплодируют хорошим действиям обеих команд. Непривычно после России.', '2026-04-22 20:37:16.738070'::timestamp, 202);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1319, 'Самая дешёвая хоккейная поездка была в Финляндию: билет на «Таппару» — 15 евро, пиво — 5 евро. Зато уровень — как в хорошей КХЛ.', '2026-04-22 20:37:19.575145'::timestamp, 202);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1320, 'Арена в Астане (Барыс) — ледовый дворец в степи. Снаружи —40°C, внутри — идеальный лёд и полные трибуны. Удивительное место.', '2026-04-22 20:37:22.660381'::timestamp, 202);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1321, 'Пять матчей подряд на ноль. Секрет? Не вратарь, а вся команда. Защитники блокируют броски, нападающие не дают контратаковать. Я просто замыкаю.', '2026-04-22 20:37:26.123167'::timestamp, 203);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1322, 'Самый сложный сэйв — не щелчок с синей, а добивание с пятака. Там нет времени на реакцию, только чтение игры и везение.', '2026-04-22 20:37:28.990348'::timestamp, 203);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1323, 'Психология вратаря: пропустил гол — забудь через секунду. Иначе следующий обязательно залетит. Тренирую это с детства.', '2026-04-22 20:37:32.062332'::timestamp, 203);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1324, 'Любимый вратарь детства — Доминик Гашек. Он вытворял такое ногами и ловушкой, что ломало все шаблоны. Гибкость и чутьё.', '2026-04-22 20:37:34.936708'::timestamp, 203);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1325, 'Совет молодым вратарям: не надевайте слишком свободную экипировку. Щитки должны сидеть плотно, иначе шайба найдёт щель.', '2026-04-22 20:37:37.837595'::timestamp, 203);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1326, 'В большинстве главное — движение шайбы. Стоячие нападающие — лёгкая цель для защиты. Каждые две секунды должна идти передача.', '2026-04-22 20:37:40.782748'::timestamp, 204);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1327, 'Любимая схема розыгрыша: 1-3-1. Один у ворот, три по линии, один на синей. Меняем местами, растягиваем защиту, ищем бросок со средней дистанции.', '2026-04-22 20:37:44.042534'::timestamp, 204);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1328, 'Забил 20 голов за сезон в большинстве. Секрет — бросок после паса поперёк площади ворот. Голкипер не успевает сместиться.', '2026-04-22 20:37:47.216970'::timestamp, 204);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1329, 'Слабое место розыгрыша — потеря шайбы на синей. Тогда убегают два в ноль. Поэтому крайний защитник всегда должен быть готов откатиться.', '2026-04-22 20:37:50.411969'::timestamp, 204);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1330, 'Когда соперник садится в коробочку (4-1), нужно бросать по воротам с любой позиции. Рикошеты и добивания — главное оружие.', '2026-04-22 20:37:53.462776'::timestamp, 204);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1331, 'Золотое правило защитника: держи клюшку на льду и оппонента спиной к воротам. Не давай развернуться и отдать пас на пятак.', '2026-04-22 20:37:56.725961'::timestamp, 205);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1332, 'Лучший защитник НХЛ текущего сезона — Кейл Макар. Он не только разрушает атаки, но и подключается вперёд как четвёртый нападающий.', '2026-04-22 20:37:59.402948'::timestamp, 205);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1333, 'Силовой приём в углу: нужно въехать не плечом, а бедром, и обязательно попасть в корпус, а не в голову. Иначе удаление и травма.', '2026-04-22 20:38:03.090354'::timestamp, 205);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1334, 'Игра в меньшинстве — выживание. Мы строим клин (два внизу, один наверху) и блокируем все броски. Боль за победу.', '2026-04-22 20:38:06.468760'::timestamp, 205);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1335, 'Защитник должен видеть поле на три хода вперёд. Отдал пас — уже катись в свободную зону, чтобы получить ответку.', '2026-04-22 20:38:09.849619'::timestamp, 205);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1336, 'Роллердром во дворе — наша Мекка. Играем до фонарей, счёт 10:9, без судей, без правил. Зато с драками и победными голами в последнюю секунду.', '2026-04-22 20:38:13.185526'::timestamp, 206);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1337, 'В уличном хоккее клюшка — продолжение рук. Половина пасов идёт не глядя, на звук. Кто дольше катался в детстве, тот и мастер.', '2026-04-22 20:38:16.409383'::timestamp, 206);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1338, 'Зимой заливаем каток во дворе сами. Вёдра, шланги, лопаты. Лёд кривой, но это не мешает забивать по десять штук за вечер.', '2026-04-22 20:38:19.386689'::timestamp, 206);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1339, 'Разница между уличным и профессиональным хоккеем? В уличном ты играешь, потому что любишь. А профессионалы иногда забывают эту любовь за деньгами.', '2026-04-22 20:38:22.953757'::timestamp, 206);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1340, 'Самый ценный трофей — банка пива после победы в ночном турнире на три двора. Остальное — суета.', '2026-04-22 20:38:25.989261'::timestamp, 206);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1341, 'Сектор активных болельщиков — это отдельный вид спорта. Кричать 60 минут, махать флагами, заводить песни. После матча голос пропадает на два дня.', '2026-04-22 20:38:29.261086'::timestamp, 207);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1342, 'Самая громкая игра, на которой был — финал КХЛ 2014, «Лев» против «Магнитки». Прага взрывалась после каждой шайбы. Жаль, что проиграли.', '2026-04-22 20:38:32.375181'::timestamp, 207);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1343, 'Выездные фанаты — особый народ. Ехать 20 часов на поезде, чтобы поддержать команду на чужой арене. И кричать громче домашних.', '2026-04-22 20:38:36.164990'::timestamp, 207);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1344, 'Традиция: перед плей-офф бреем голову налысо. Вместе с командой входим в режим войны. Работает — команда не проигрывала три года подряд.', '2026-04-22 20:38:39.653755'::timestamp, 207);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1345, 'Самый обидный матч: проигрыш 1:2 за 10 секунд до конца. Шайба залетела от клюшки своего же защитника. Домой шли молча.', '2026-04-22 20:38:42.408897'::timestamp, 207);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1346, 'Дети 7 лет не умеют кататься спиной вперёд. Начинаем с «ёлочки» и конькобежных упражнений. Через месяц уже бегают.', '2026-04-22 20:38:45.490697'::timestamp, 208);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1347, 'Главное в детском хоккее — не результат, а желание играть. Если ребёнок улыбается на льду — ты хороший тренер.', '2026-04-22 20:38:48.450080'::timestamp, 208);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1348, 'Родители — отдельная боль. Кричат с трибун «бросай», когда нужно пасовать. Провожу собрания, объясняю тактику. Бесполезно.', '2026-04-22 20:38:51.734926'::timestamp, 208);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1349, 'Наш лучший игрок в 10 лет — вратарь. Он тащит всё, но никогда не хвалится. Скромность и труд — вот что воспитываем.', '2026-04-22 20:38:54.799541'::timestamp, 208);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1350, 'Поражение 0:10 в турнире — не трагедия. Разобрали ошибки, почистили лёд, пошли тренироваться дальше. Через год выиграли этот же турнир.', '2026-04-22 20:38:57.564661'::timestamp, 208);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1351, 'В 80-х играли без шлемов, а клюшки были деревянные. Щелчок Могильного — 150 км/ч, и это сухим деревом. Страшно вспомнить.', '2026-04-22 20:39:00.944533'::timestamp, 209);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1352, 'Лучший матч в моей карьере — против сборной Канады 1987 года. Мы проиграли 3:4, но сражались как львы. После матча канадцы подошли пожать руки.', '2026-04-22 20:39:04.219783'::timestamp, 209);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1353, 'Сейчас хоккей быстрее, но жёстче? Раньше драки были каждый матч, и никто не прятал лицо за визором. Другое поколение.', '2026-04-22 20:39:07.395914'::timestamp, 209);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1354, 'Сборная СССР — это не просто команда, это школа. Тарасов придумал комбинации, которые до сих пор играют в НХЛ. Вечная память.', '2026-04-22 20:39:10.572828'::timestamp, 209);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1355, 'Ветераны собираемся раз в месяц, катаемся «тихим хоккеем». Без силовых, без борьбы, но с тем же азартом. Молодые приходят смотреть.', '2026-04-22 20:39:14.066143'::timestamp, 209);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1356, 'Клюшка — это продолжение рук. Изгиб крюка, жёсткость, баланс. Подбираю каждому игроку индивидуально, смотрю, как бросает.', '2026-04-22 20:39:17.736694'::timestamp, 210);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1357, 'НХЛ-овские профи используют 10-12 клюшек за сезон. Одна ломается, вторая теряет жёсткость. Я ремонтирую композит, вклеиваю новое древко.', '2026-04-22 20:39:21.948288'::timestamp, 210);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1358, 'Правильная длина клюшки: стоя на коньках, крюк должен доходить до подбородка. Короткая — хуже бросок, длинная — плохой контроль.', '2026-04-22 20:39:25.418231'::timestamp, 210);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1359, 'Самый дорогой заказ — копия клюшки Овечкина: изгиб с «лопатой», жёсткость 120. Не каждый форвард сможет таким бросить, а Ови — может.', '2026-04-22 20:39:28.401422'::timestamp, 210);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1360, 'Зимой клюшки мерзнут и становятся хрупкими. Хранить при комнатной температуре, сушить после игры. Иначе треснут на щелчке.', '2026-04-22 20:39:31.987033'::timestamp, 210);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1361, 'Регулировка льда — это химия. Температура плиты, влажность воздуха, количество солей в воде. Идеальный лёд — твёрдый, но не скользкий.', '2026-04-22 20:39:34.940199'::timestamp, 211);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1362, 'Утренняя заливка — ритуал. Я люблю одиночество на арене в 6 утра, только звук шланга и пар от воды. Медитация.', '2026-04-22 20:39:38.012259'::timestamp, 211);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1363, 'Трещины на льду заливаем горячей водой и замораживаем жидким азотом. За 5 минут — готово. Холодная вода не подходит, будет бугор.', '2026-04-22 20:39:41.224213'::timestamp, 211);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1364, 'Самый сложный лёд — для фигурного катания. Он должен быть мягче, чтобы фигурка оставляла след. А хоккеисты потом ругаются.', '2026-04-22 20:39:44.257438'::timestamp, 211);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1365, 'После концерта на арене лёд приходится перезаливать полностью. Пыль и грязь въедаются, шайба не скользит. Ужас.', '2026-04-22 20:39:47.126713'::timestamp, 211);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1366, 'Женский хоккей не уступает мужскому по самоотдаче. Мы так же блокируем броски, бьёмся у бортов и не жалуемся на синяки.', '2026-04-22 20:39:50.815757'::timestamp, 212);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1367, 'Олимпийский финал 2018: Канада — США. Мы проиграли в овертайме, но ту игру помню каждую секунду. Лучший матч в жизни.', '2026-04-22 20:39:54.500146'::timestamp, 212);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1368, 'Разница между мужским и женским хоккеем? У нас запрещены силовые приёмы в корпус. Но мы нашли другие способы бороться за шайбу.', '2026-04-22 20:39:57.569283'::timestamp, 212);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1369, 'Экипировка для женщин: шлемы и щитки те же, но коньки уже, а трусы короче. И обязательно — длинные волосы убирать в сетку.', '2026-04-22 20:40:00.747178'::timestamp, 212);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1370, 'Нас всё ещё меньше, чем мужчин. Но с каждым годом растёт число девчонок в хоккейных школах. Будущее за равноправием.', '2026-04-22 20:40:04.140577'::timestamp, 212);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1371, 'Организовать детский турнир на 20 команд — это логистический ад. Расписание, судьи, раздевалки, питание. Спим по 4 часа.', '2026-04-22 20:40:07.825176'::timestamp, 213);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1372, 'Самый провал: заказали автобусы для команд, а они не приехали. Пришлось такси за свой счёт, 60 тысяч рублей.', '2026-04-22 20:40:10.963941'::timestamp, 213);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1373, 'Хороший турнир узнаётся по мелочам: вовремя залитый лёд, работающий видеоповтор, тёплые раздевалки. Участники это ценят.', '2026-04-22 20:40:14.261068'::timestamp, 213);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1374, 'Призы — отдельная история. Команды любят не кубки, а подарки: клюшки, свитера, скидки в магазине. Прагматизм.', '2026-04-22 20:40:17.640256'::timestamp, 213);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1375, 'После турнира разбираю ошибки с судейской бригадой. Кто-то не засёк чистоту, кто-то пропустил нарушение. Учимся на своих косяках.', '2026-04-22 20:40:20.609617'::timestamp, 213);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1376, 'Капитан — не тот, кто забивает больше всех. А тот, кто в раздевалке скажет правильные слова после поражения. И поднимет команду.', '2026-04-22 20:40:23.680387'::timestamp, 214);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1377, 'У нас традиция: новичок должен спеть песню на первом выезде. Снимает напряжение и объединяет. Даже если он фальшивит.', '2026-04-22 20:40:27.265324'::timestamp, 214);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1378, 'Лучший момент в карьере: когда после трудного сезона команда выбрала меня капитаном. Голосование было единогласным.', '2026-04-22 20:40:30.545689'::timestamp, 214);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1379, 'В раздевалке перед седьмым матчем плей-офф я сказал: «Посмотрите друг на друга. Вы — семья. Семья не сдаётся». Выиграли 3:0.', '2026-04-22 20:40:33.738600'::timestamp, 214);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1380, 'Конфликт между звеньями решаю открытым разговором. Без криков, без обид. На льду мы одна команда, а не отдельные звёзды.', '2026-04-22 20:40:36.701875'::timestamp, 214);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1381, 'Талант видно с детства. Мальчик 8 лет катается как 12-летний, видит поле, отдаёт пас не глядя. Берём в академию.', '2026-04-22 20:40:40.285623'::timestamp, 215);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1382, 'Самый недооценённый навык — хоккейный интеллект. Игрок может быть не быстрым, но всегда оказываться в нужном месте. Это не учат, это врождённое.', '2026-04-22 20:40:43.822068'::timestamp, 215);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1383, 'Езжу по турнирам, смотрю сотни матчей. Иногда нахожу алмаз в региональной лиге, где его никто не заметил. Гордость.', '2026-04-22 20:40:46.918780'::timestamp, 215);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1384, 'Ошибка скаута: смотреть на габариты, а не на характер. Маленький игрок с большим сердцем обыграет великана с пустыми глазами.', '2026-04-22 20:40:50.012922'::timestamp, 215);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1385, 'Лучшее открытие за 10 лет — Никита Кучеров. В 17 лет он был незаметным, но его руки и чутье — элитные. Остальное — история.', '2026-04-22 20:40:53.069396'::timestamp, 215);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1386, 'Техника вратаря начинается с позиции «бабочка»: колени вместе, щитки в стороны, ловушка перед собой. Отрабатываем до автоматизма.', '2026-04-22 20:40:56.345733'::timestamp, 216);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1387, 'Самый сложный элемент — вставание после падения. Нужно опереться на клюшку и выбросить ногу вперёд, не теряя шайбу из виду.', '2026-04-22 20:40:59.342535'::timestamp, 216);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1388, 'Работа ног: вратарь должен скользить вдоль линии ворот, а не перебирать ногами. Длинные скольжения — спасение на дальних бросках.', '2026-04-22 20:41:02.592405'::timestamp, 216);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1389, 'Психология вратаря: как не сломаться после трёх голов подряд? Переключиться на следующую смену, забыть прошлое. Тренируем дыхательные техники.', '2026-04-22 20:41:06.279847'::timestamp, 216);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1390, 'Современный вратарь должен играть клюшкой — выбрасывать шайбу на пас, делать первый пас. Без этого не выжить в НХЛ.', '2026-04-22 20:41:09.674179'::timestamp, 216);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1391, 'Интервью после матча — жанр сам по себе. Игроки говорят клише («хорошая работа», «выполнили установку»), но иногда выдают искренние эмоции. Это мы и ловим.', '2026-04-22 20:41:12.934523'::timestamp, 217);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1392, 'Самый неудобный вопрос: «Почему проиграли?» Команда зла, тренер закрывается. Приходится спрашивать о тактике, чтобы разрядить обстановку.', '2026-04-22 20:41:16.108256'::timestamp, 217);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1393, 'Писать о хоккее 10 лет — видишь, как меняется игра. Раньше были драки и силовая борьба, теперь скорость и комбинации. И болельщики ностальгируют.', '2026-04-22 20:41:19.606615'::timestamp, 217);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1394, 'Лучший комментатор — тот, кто умеет молчать в паузах. Не надо заполнять каждую секунду пустой болтовнёй. Шум арены — тоже часть трансляции.', '2026-04-22 20:41:22.764340'::timestamp, 217);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1395, 'Освещаю МХЛ — лигу, где мало денег, но много страсти. Там играют не за контракты, а за мечту. Лучшие интервью и эмоции.', '2026-04-22 20:41:26.062241'::timestamp, 217);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1396, 'Ледовая подготовка: на коньках нужно делать те же упражнения, что и в зале. Приседания, выпады, прыжки. Только на льду они эффективнее.', '2026-04-22 20:41:29.730319'::timestamp, 218);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1397, 'Скоростная выносливость: интервалы 30 секунд спринта, 30 секунд отдыха. 10 повторений. Хоккеист должен взрываться каждую смену.', '2026-04-22 20:41:32.903742'::timestamp, 218);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1398, 'Травмы коленей — бич хоккея. Укрепляем мышцы вокруг колена: приседания на одной ноге, эксцентрическая нагрузка. Профилактика важнее лечения.', '2026-04-22 20:41:36.180111'::timestamp, 218);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1399, 'Питание в сезон: углеводы за 2 часа до матча (гречка, макароны), белок после. И никакого жирного — тяжесть в животе убивает скорость.', '2026-04-22 20:41:40.696228'::timestamp, 218);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1400, 'Восстановление после игры: контрастный душ, компрессионные гетры, сон не менее 8 часов. Мелочи дают 10% к готовности.', '2026-04-22 20:41:43.960313'::timestamp, 218);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1401, 'Учёба и хоккей — вечный баланс. Тренировки в 6 утра, пары до 14, потом лёд и домой в 22. На тусовки нет времени.', '2026-04-22 20:41:47.560255'::timestamp, 219);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1402, 'Студенческая лига США (NCAA) — лучший путь в НХЛ. Там сочетают жёсткие тренировки с академической нагрузкой. И бесплатное образование.', '2026-04-22 20:41:50.719264'::timestamp, 219);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1403, 'Моя стипендия покрывает всё: учёба, проживание, экипировка. За это я должен отдавать 100% на льду и в классе. Справедливо.', '2026-04-22 20:41:54.098071'::timestamp, 219);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1404, 'Самое большое достижение — выиграть чемпионат конференции. После финала мы плакали от счастья, а профессора поздравляли на парах.', '2026-04-22 20:41:57.479828'::timestamp, 219);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1405, 'Планирую закончить университет и попробовать себя в АХЛ. Но учёбу не брошу — диплом инженера пригодится в любой жизни.', '2026-04-22 20:42:00.564547'::timestamp, 219);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1406, 'Сборная России на Олимпиаде 2018 — лучшее воспоминание. Финал с немцами, гол Капризова в овертайме. Вся страна кричала у экранов.', '2026-04-22 20:42:04.252260'::timestamp, 220);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1407, 'Суперсерия 1972 — легенда. Наши парни играли против профи НХЛ и доказали, что советский хоккей — лучший. Вечная память тем ребятам.', '2026-04-22 20:42:07.615784'::timestamp, 220);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1408, 'Швеция — самая неудобная сборная. Они терпеливо ждут твоих ошибок и наказывают. Играть против них — как шахматная партия.', '2026-04-22 20:42:10.790787'::timestamp, 220);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1409, 'ЧМ-2021 — возвращение сборной России на вершину. Овечкин, Малкин, Панарин — золотое поколение. Жаль, что больше не соберутся вместе.', '2026-04-22 20:42:13.965055'::timestamp, 220);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1410, 'Надежда на молодёжку: Мичков, Яровой, Демидов. Они играют в умный хоккей. Через 5 лет будут громить канадцев.', '2026-04-22 20:42:17.666164'::timestamp, 220);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1411, 'В Непале я заблудился в горах. Телефон сел, еда кончилась. Местный старик нашёл меня по звуку моих проклятий. Напоил чаем и показал тропу. С тех пор вожу с собой компас и запасной повербанк.', '2026-04-22 20:42:24.115816'::timestamp, 221);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1412, 'Поезд в Индии. Ехал 28 часов в general class. Познакомился с семьёй, которая ехала на свадьбу. Они кормили меня самосой и научили играть в местную карточную игру. Никогда не чувствовал себя таким желанным гостем.', '2026-04-22 20:42:27.571231'::timestamp, 221);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1413, 'В Перу на рынке Куско пытался купить пончо. Продавец запросил 100 долларов. Я сказал, что у меня только 30. Он сделал вид, что оскорблён, потом через пять минут торговли продал за 35. Мы оба знали, что это игра.', '2026-04-22 20:42:30.717438'::timestamp, 221);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1414, 'Однажды во Вьетнаме у меня украли кошелёк. Я остался без денег и карт. Хостел, где я жил, позволил мне работать за еду — мыть полы и менять простыни. Две недели я был уборщиком. Теперь я никогда не смотрю свысока на тех, кто это делает.', '2026-04-22 20:42:34.341820'::timestamp, 221);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1415, 'В Исландии я решил искупаться в термальном источнике. Снял одежду, залез — вода идеальная. Через 10 минут приехал автобус с туристами. Пришлось сидеть по шею в воде, пока они фоткали пейзажи. Никогда не раздевайтесь вдали от машины.', '2026-04-22 20:42:37.310903'::timestamp, 221);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1416, 'Долгая история. В 2019 я полетел в Японию на фудзи-рок фестиваль. Потерял билет за день до концерта. Нашёл в ленте твиттера парня, который продавал лишний. Встретились в Токио у статуи Хатико. Он отдал билет за полцены, потому что «ты похож на меня в 20 лет». Мы подружились, до сих пор переписываемся. Фестиваль был невероятный.', '2026-04-22 20:42:40.486012'::timestamp, 221);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1417, 'В Марокко меня пытались развести на деньги «гиды». Один старик в Фесе просто сказал: «Иди туда, где много местных, а не туда, где много туристов». Следующие три дня я ел за 2 доллара и видел настоящую жизнь.', '2026-04-22 20:42:43.710735'::timestamp, 221);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1418, 'Мой трёхлетний сын вчера сказал: «Мама, я тебя не буду любить, если ты не дашь мне конфету». Через минуту пришёл обниматься. Дети — мастера манипуляции, но какие же они искренние.', '2026-04-22 20:42:47.056934'::timestamp, 222);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1419, 'Дочь принесла из школы рисунок «Моя семья». Папа нарисован с огромными ушами, я — с зелёным лицом, а брат — в виде монстра. Учительница сказала, что это творческое видение. Мы повесили на холодильник.', '2026-04-22 20:42:50.010405'::timestamp, 222);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1420, 'Первый раз оставила детей с няней на два часа. За это время успела выпить кофе горячим, сходить в туалет без зрителей и просто посмотреть в стену. Это был лучший отпуск в моей жизни.', '2026-04-22 20:42:52.976960'::timestamp, 222);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1421, 'Готовлю ужин, слышу грохот. Захожу в гостиную — годовалый сын высыпал весь корм для хомяка себе на голову и сидит счастливый. Хомяк бегает по дивану. В такие моменты я просто смеюсь, потому что плакать уже нет сил.', '2026-04-22 20:42:55.844412'::timestamp, 222);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1422, 'Когда я была беременна вторым, старший сказал: «Мама, а можно мы оставим ребёночка в роддоме? Он будет там спать, а мы будем к нему приходить в гости». Думал, что это игрушка, которую можно вернуть.', '2026-04-22 20:42:58.990173'::timestamp, 222);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1423, 'Муж попытался заменить мне подгузники, пока я была в командировке. Купил не тот размер. Пришлось звонить соседке в 11 ночи. Теперь он знает, что такое «размер 4» и «ночные». Герой.', '2026-04-22 20:43:01.784711'::timestamp, 222);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1424, 'Мы переехали в новый дом. В первую ночь дети боялись спать в своих комнатах. Все пятеро (включая мужа) улеглись в гостиной на матрасы. Смотрели «Шрека» до двух ночи. Это был хаос, но я запомню эту ночь навсегда.', '2026-04-22 20:43:05.075956'::timestamp, 222);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1425, 'На первом собеседовании мне сказали: «Ты слишком молод». Через год я пришёл в ту же компанию как консультант и учил их работать в CRM. Дверь, которая закрылась, иногда открывается с другой стороны.', '2026-04-22 20:43:08.542190'::timestamp, 223);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1426, 'Меня уволили с первой работы за «несоответствие корпоративной культуре». Я не ходил на пятничные пивасики, потому что хотел работать. Оказалось, важнее быть своим, чем эффективным. Теперь я ищу компании, где ценят результат, а не тусовки.', '2026-04-22 20:43:11.592127'::timestamp, 223);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1427, 'Шеф присвоил мой проект. Я промолчал, но начал вести учёт всех правок и писем. Через полгода он попросил меня обучить новичка — я передал новичку файл с историей проекта. Шефа повысили, но репутация треснула.', '2026-04-22 20:43:14.992370'::timestamp, 223);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1428, 'Я работал в стартапе 80 часов в неделю за еду. Владелец обещал долю. Когда стартап продали, он сказал: «Ты был наёмным сотрудником». С тех пор я всегда прошу всё в договоре, даже дружеские обещания.', '2026-04-22 20:43:17.961993'::timestamp, 223);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1429, 'Однажды я опоздал на важную презентацию из-за сломанного метро. Начальник устроил разнос. Я не оправдывался, а сказал: «Что я могу сделать сейчас, чтобы исправить?» Он дал мне второй шанс. Я выступил на следующий день, и клиент подписал контракт. Оправдания бесполезны — решения нужны.', '2026-04-22 20:43:20.964868'::timestamp, 223);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1430, 'В 25 лет я стал тимлидом. Моя команда состояла из людей, которые были старше на 15 лет. Они меня не слушали. Пришлось учиться не командовать, а спрашивать совета. «Как бы вы сделали?» — магическая фраза. Через месяц мы стали лучшим отделом.', '2026-04-22 20:43:23.735047'::timestamp, 223);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1431, 'Я ушёл из офиса в удалёнку, потому что не мог больше терпеть open space. Коллега слева постоянно жевал, справа — говорил по громкой связи. Дома я работаю в тишине и делаю в два раза больше. Никогда не вернусь.', '2026-04-22 20:43:27.180641'::timestamp, 223);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1432, 'Первый курс, сессия. Я не спал двое суток перед экзаменом по анатомии. На экзамене забыл всё, кроме строения уха. Преподаватель спросил: «Что вы можете сказать о нервной системе?» Я ответил: «Она соединяет ухо с мозгом?» Меня отправили пересдавать.', '2026-04-22 20:43:30.664176'::timestamp, 224);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1433, 'Стипендия 2000 рублей в месяц. На неё я покупал гречку, макароны и иногда курицу. Ходил в гости к другу, потому что у него дома были пельмени. Теперь я зарабатываю нормально, но до сих пор люблю гречку.', '2026-04-22 20:43:34.025608'::timestamp, 224);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1434, 'Мы с одногруппниками скинулись на пиццу перед зачётом. Заказали четыре огромные. Пришёл преподаватель, угостился и поставил автоматом всем зачёт. Лучшие инвестиции в жизни.', '2026-04-22 20:43:37.318784'::timestamp, 224);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1435, 'Я проспал пару по философии. Когда зашёл, преподаватель сказал: «Молодой человек, вы опоздали на 20 минут. Что скажете в своё оправдание?» Я ляпнул: «Время — иллюзия, сэр». Он засмеялся и поставил присутствие. Иногда наглость спасает.', '2026-04-22 20:43:40.799134'::timestamp, 224);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1436, 'В общежитии мы устроили тайную комнату в заброшенной кладовке. Поставили диван, торшер, купили чайник. Это был наш клуб. О нём знали только свои. Идеальное место для ночных разговоров.', '2026-04-22 20:43:43.884730'::timestamp, 224);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1437, 'На последнем курсе я защищал диплом. За минуту до выступления у меня оторвалась пуговица на штанах. Пришлось выходить, придерживая их рукой. Комиссия думала, что я так волнуюсь. Получил пятёрку.', '2026-04-22 20:43:47.142274'::timestamp, 224);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1438, 'Я подрабатывал курьером. Вёз заказ на другой конец города. Попал в аварию (меня подрезали). Пицца перевернулась. Заказчик сказал: «Главное, что вы живы. Пиццу я не оплачу, но и жалобу писать не буду». Спасибо, незнакомец.', '2026-04-22 20:43:50.175011'::timestamp, 224);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1439, 'Я проработал на заводе 40 лет. В день увольнения никто не сказал «спасибо». Просто выдали расчёт и пожелали удачи. Понял: работа — это обмен времени на деньги. Не ждите любви от работодателя.', '2026-04-22 20:43:53.723506'::timestamp, 225);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1440, 'Жена умерла пять лет назад. Я до сих пор иногда готовлю на двоих. Её любимое кресло стоит пустым. Молодым говорю: не ссорьтесь из-за ерунды, завтра может быть поздно.', '2026-04-22 20:43:56.734662'::timestamp, 225);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1441, 'Дети выросли и разъехались. Сначала было тихо и одиноко. Потом я завёл собаку, начал ходить на рыбалку. Тишина — это не пустота, а свобода делать что хочешь.', '2026-04-22 20:43:59.535600'::timestamp, 225);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1442, 'В 60 лет я выучил английский. Занимался по приложению каждый день по часу. Сейчас могу читать новости в оригинале и смотреть сериалы без перевода. Никогда не поздно.', '2026-04-22 20:44:02.813374'::timestamp, 225);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1443, 'Сосед попросил меня научить его играть в шахматы. Он оказался талантливым учеником — через год он меня обыгрывал. Я был горд, как отец. Передавать опыт — это тоже счастье.', '2026-04-22 20:44:06.601765'::timestamp, 225);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1444, 'Я пережил дефолт 1998 года, кризис 2008, пандемию. Все говорили, что это конец. Ничего, живём. Главное — не паниковать и иметь запас гречки.', '2026-04-22 20:44:09.689287'::timestamp, 225);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1445, 'Мой внук спросил: «Деда, а ты в детстве играл в айфон?» Я показал ему самодельную рогатку. Мы вместе запускали камни в банки. Ему понравилось больше, чем планшет.', '2026-04-22 20:44:12.452464'::timestamp, 225);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1446, 'Мою картину не взяли на выставку. Я обиделся и сжёг её. Через год тот же куратор позвонил и сказал: «У тебя есть что-то новое?» Я послал его. Гордость — плохой советчик, но иногда необходима.', '2026-04-22 20:44:16.037619'::timestamp, 226);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1447, 'Я рисовал портрет незнакомки в метро. Она заметила, подошла и попросила показать. Я боялся, что рассердится. А она сказала: «Ты сделал меня красивее, чем я есть. Можно забрать?» Я отдал. Мы вместе вышли на её станции.', '2026-04-22 20:44:19.196649'::timestamp, 226);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1448, 'В художественной школе меня ругали за «грязный цвет». Я пытался соответствовать. А потом понял: моя «грязь» — это моя палитра. Теперь я получаю заказы именно на тёмные, мрачные работы.', '2026-04-22 20:44:22.269307'::timestamp, 226);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1449, 'Я написал картину маслом за три часа. Потом переписывал её две недели. В итоге вернулся к первому варианту. Спонтанность часто лучше вымученности.', '2026-04-22 20:44:25.953807'::timestamp, 226);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1450, 'Однажды я продал картину за тысячу долларов. Купил на эти деньги холсты и краски на год. Не было чувства «я заработал». Было чувство «меня поняли».', '2026-04-22 20:44:29.528266'::timestamp, 226);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1451, 'В творческом кризисе я неделю ничего не делал. Смотрел в стену. А потом нарисовал эту стену — трещины, разводы, тени. Получилась лучшая работа года.', '2026-04-22 20:44:33.634475'::timestamp, 226);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1452, 'Мой сын сказал: «Папа, нарисуй мне дракона». Я рисовал час, дракон получился эпичным. Сын посмотрел и сказал: «А почему он не розовый?» Потом сам дорисовал розовые крылья. Теперь эта картина висит в гостиной.', '2026-04-22 20:44:36.550408'::timestamp, 226);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1453, 'Мне поставили диабет второго типа. Врач сказал: «Или вы меняете питание, или через 10 лет вас не будет». Я убрал сахар, хлеб, макароны. Через три месяца сахар пришёл в норму. Еда — это лекарство.', '2026-04-22 20:44:40.085734'::timestamp, 227);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1454, 'Я лежал в больнице с панкреатитом. Рядом умирал мужчина от рака поджелудочной. Он сказал: «Я курил и пил всю жизнь, думал, пронесёт. Не пронесло». Я бросил курить на следующий день.', '2026-04-22 20:44:43.259848'::timestamp, 227);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1455, 'Фитнес-трекер изменил мою жизнь. Я увидел, что сплю 5 часов, прохожу 3000 шагов и сижу 14 часов. Сейчас я сплю 7 часов, хожу 10000 шагов. Чувствую себя на 20 лет моложе.', '2026-04-22 20:44:46.538053'::timestamp, 227);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1456, 'Депрессия — это не слабость. Я лечился два года. Таблетки, психотерапия, поддержка жены. Сейчас я счастлив, но помню то состояние. Не бойтесь просить помощи.', '2026-04-22 20:44:49.813876'::timestamp, 227);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1457, 'Я сломал позвоночник в ДТП. Врачи сказали: «Будешь ходить? Неизвестно». Я занимался каждый день по 4 часа. Через год я пробежал марафон (медленно, но пробежал).', '2026-04-22 20:44:52.886134'::timestamp, 227);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1458, 'Аллергия на пыльцу. Раньше весна была адом. Я начал принимать антигистаминные за месяц до сезона, поставил очиститель воздуха. Теперь я люблю весну.', '2026-04-22 20:44:56.366899'::timestamp, 227);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1459, 'Геморрой — это не смешно. Я стеснялся идти к врачу, мучился год. Пришёл — вылечили за месяц. Не повторяйте моих ошибок, здоровье важнее стыда.', '2026-04-22 20:44:59.440207'::timestamp, 227);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1460, 'Я помню время, когда интернет включался по телефонной линии, а для входа в сеть нужно было ждать, пока модем пищит. Сегодня дети не знают, что такое «занято» в телефоне. Мы жили в другом мире.', '2026-04-22 20:45:02.921025'::timestamp, 228);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1461, 'Мой первый компьютер — ZX Spectrum с кассетным магнитофоном. Игры загружались по 15 минут и часто вылетали. Но я знал BASIC и мог сам написать простенькую игру. Сейчас дети не знают, как работают вещи под капотом.', '2026-04-22 20:45:06.914487'::timestamp, 228);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1462, 'Я удалил все соцсети, кроме телеграма. Потраченное время сократилось с 4 часов в день до 30 минут. Спать стал лучше, тревожность ушла. Цифровой детокс — это реально.', '2026-04-22 20:45:10.397006'::timestamp, 228);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1463, 'Мы купили робот-пылесос. Это устройство спасло наш брак. Раньше мы ругались из-за уборки каждое воскресенье. Теперь робот делает всё, а мы пьём кофе.', '2026-04-22 20:45:13.904000'::timestamp, 228);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1464, 'Я написал скрипт, который автоматически отвечает на письма клиентов. Экономит мне 10 часов в неделю. Начальник не знает. Технологии — это инструмент освобождения, если уметь их использовать.', '2026-04-22 20:45:17.255843'::timestamp, 228);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1465, 'В 2010 году я купил биткоины за 100 долларов, когда они стоили 10 центов. Продал, когда они выросли до 1 доллара, заработал 1000 долларов и был счастлив. Если бы я держал… Но тогда никто не знал.', '2026-04-22 20:45:20.841565'::timestamp, 228);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1466, 'У меня умный дом. Лампочки включаются по голосу, чайник греется к пробуждению. Гости думают, что я волшебник. На самом деле я просто ленивый и люблю автоматизацию.', '2026-04-22 20:45:24.015337'::timestamp, 228);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1467, 'Мы с другом не общались пять лет из-за глупой ссоры. Встретились на похоронах общего знакомого. Посмотрели друг на друга и обнялись. Время — плохой лекарь, оно не возвращает потерянные годы.', '2026-04-22 20:45:27.291707'::timestamp, 229);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1468, 'Мой лучший друг переехал в другую страну. Мы созваниваемся раз в месяц, но когда встречаемся раз в год — разговариваем как будто не расставались. Настоящая дружба не требует ежедневного присутствия.', '2026-04-22 20:45:30.471824'::timestamp, 229);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1469, 'Друг попросил в долг крупную сумму. Я отказал, объяснив, что не даю в долг, чтобы не потерять дружбу. Он обиделся. Через год его кинул другой «друг», который дал денег под проценты. Мы помирились.', '2026-04-22 20:45:33.948315'::timestamp, 229);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1470, 'Мы с друзьями каждый новый год отмечаем вместе уже 20 лет. Семьи менялись, города менялись, но эта традиция осталась. Ритуалы важнее обстоятельств.', '2026-04-22 20:45:37.023996'::timestamp, 229);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1471, 'Я предал друга ради карьеры. Дал негативный отзыв о нём начальнику. Получил повышение, а друга уволили. С тех пор я не сплю спокойно. Не повторяйте. Карьера стоит меньше, чем совесть.', '2026-04-22 20:45:40.209254'::timestamp, 229);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1472, 'У меня есть друг, с которым мы познакомились в очереди в туалете на концерте. Очередь была длинная, мы разговорились, оказалось, что у нас одинаковые музыкальные вкусы. Теперь мы ходим на концерты вместе.', '2026-04-22 20:45:43.643462'::timestamp, 229);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1473, 'Мой друг умер от рака. В последний месяц мы просто сидели молча и смотрели фильмы. Он сказал: «Не плачь, я прожил крутую жизнь». Теперь я живу так, чтобы он мной гордился.', '2026-04-22 20:45:46.968068'::timestamp, 229);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1474, 'Моя мама умерла, когда мне было 20. Я не успел сказать ей «спасибо». Каждый день я разговариваю с её фотографией. Горе не уходит, ты просто учишься жить с дырой в груди.', '2026-04-22 20:45:50.331129'::timestamp, 230);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1475, 'Я потерял ребёнка на пятом месяце беременности. Мы уже купили коляску, выбрали имя. Слёзы не помогли. Мы с женой поехали в путешествие, чтобы не сойти с ума. Сейчас у нас двое детей, но мы никогда не забыли того малыша.', '2026-04-22 20:45:54.049873'::timestamp, 230);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1476, 'Мой отец ушёл из семьи, когда мне было 10. Я ненавидел его 15 лет. Потом он позвонил и сказал, что болен раком. Я приехал проститься. Прощение освободило меня, а не его.', '2026-04-22 20:45:57.355763'::timestamp, 230);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1477, 'Я пережил пожар. Сгорел дом, всё имущество, фотографии, документы. Осталась только одежда на мне. Первую неделю я плакал. Потом понял: вещи — это всего лишь вещи, главное — я жив.', '2026-04-22 20:46:01.082752'::timestamp, 230);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1478, 'Моего лучшего друга убили в драке. Я был в ярости, хотел отомстить. Но адвокат сказал: «Ты сядешь, а ему ничего не будет». Я выбрал жизнь. Правосудие свершилось без меня.', '2026-04-22 20:46:04.362227'::timestamp, 230);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1479, 'Я развёлся после 15 лет брака. Думал, жизнь кончена. Через два года встретил новую любовь. Понял: некоторые двери закрываются, чтобы открылись другие.', '2026-04-22 20:46:07.636932'::timestamp, 230);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1480, 'Собака прожила со мной 14 лет. Когда она умерла, я выл в голос. Соседи стучали по батареям. Я похоронил её в лесу, где мы гуляли. Теперь у меня новая собака, но я до сих пор прихожу на ту могилу.', '2026-04-22 20:46:10.776992'::timestamp, 230);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1481, 'Я начал бизнес с 5000 рублей. Покупал на рынке китайские футболки и перепродавал в соцсетях. Первые три месяца не было ни одного заказа. На четвёртый пришёл первый клиент. Сейчас у меня сеть магазинов.', '2026-04-22 20:46:14.102054'::timestamp, 231);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1482, 'Меня уволили с работы. Я остался без денег, с кредитом и семьёй. Решил делать то, что умею лучше всего — программировать. Написал приложение за месяц, оно завирусилось. Иногда дно — это трамплин.', '2026-04-22 20:46:17.466473'::timestamp, 231);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1483, 'Я должен был выступить на конференции. За час до выступления потерял голос. Вышел, написал на доске маркером ключевые тезисы и показал жестами. Зал аплодировал стоя. Импровизация сильнее плана.', '2026-04-22 20:46:20.949329'::timestamp, 231);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1484, 'В 30 лет я бросил работу юриста и пошёл учиться на повара. Родители сказали, что я сошёл с ума. Сейчас я шеф-повар ресторана с мишленовской звездой. Следуйте за своим интересом, даже если все против.', '2026-04-22 20:46:24.240202'::timestamp, 231);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1485, 'Я три года пытался получить инвестиции. Мне отказали 127 раз. На 128-й сказали «да». Упорство побеждает талант, когда талант сдаётся.', '2026-04-22 20:46:27.503387'::timestamp, 231);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1486, 'Я создал продукт, который никто не хотел. Потратил год, сжёг 2 миллиона. Уволил команду. Через месяц пришёл клиент, которому это было нужно. Мы переписали продукт под него. Теперь мы лидеры в нише.', '2026-04-22 20:46:30.573682'::timestamp, 231);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1487, 'Моя первая сделка — продал парню на avito старую гитару. Он пришёл, попробовал, сказал: «Беру». Я заработал 3000 рублей. Это был лучший день.', '2026-04-22 20:46:34.118563'::timestamp, 231);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1488, 'Я прыгнул с тарзанки в Новой Зеландии. Сердце ушло в пятки. Трос оборвался? Нет, но в тот момент я был уверен, что всё. Страх — это просто химия. Через секунду после прыжка я смеялся.', '2026-04-22 20:46:37.674109'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1489, 'Мы сплавлялись по горной реке. Наш катамаран перевернулся. Я оказался под водой, меня крутило, не мог найти выход. Потом вынырнул в 50 метрах ниже. С тех пор я всегда надеваю шлем и жилет, даже если все смеются.', '2026-04-22 20:46:41.120140'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1490, 'В Турции я полетел на параплане. Пилот сказал: «Сейчас будет спираль». Я закричал. Он спросил: «Страшно?» Я сказал: «Нет, круто!» Потом мы приземлились, и я сразу захотел ещё.', '2026-04-22 20:46:44.498464'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1491, 'Я забрался на Эльбрус без гида. На высоте 5000 метров у меня началась горная болезнь. Каждый шаг был пыткой. Повернул назад. Успех — не только вершина, но и умение вовремя остановиться.', '2026-04-22 20:46:47.777073'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1492, 'Дайвинг с акулами в Египте. Инструктор сказал: «Не делайте резких движений». Я замер. Акула проплыла в метре. Я видел её глаз, она смотрела на меня как на еду, но не тронула. Адреналин зашкаливал.', '2026-04-22 20:46:51.054907'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1493, 'Я ночевал в палатке в лесу, и медведь обнюхивал её снаружи. Я сжался в комок, боялся дышать. Медведь ушёл через пять минут. Больше никогда не храню еду в палатке.', '2026-04-22 20:46:54.534655'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1494, 'Мы с друзьями решили пройти 100 км на велосипедах за день. На 80-м у меня свело ногу. Друзья уговорили закончить. Последние 20 км я ехал на одной ноге, матерясь сквозь зубы. Мы доехали. Гордость пересилила боль.', '2026-04-22 20:46:57.669457'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1495, 'Я начал бесплатно убирать мусор в соседнем парке. Сначала один. Потом пришли двое, потом десять. Теперь у нас волонтёрская группа из 50 человек. Маленькое действие может вырасти в движение.', '2026-04-22 20:47:01.499982'::timestamp, 233);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1496, 'Во время пандемии мы организовали доставку продуктов пенсионерам. 100 волонтёров, 3000 доставок. Старушка заплакала и сказала: «Вы мои ангелы». Слёзы чужих людей — лучшая награда.', '2026-04-22 20:47:05.083367'::timestamp, 233);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1497, 'Я создал чат соседей. Сначала ругались из-за парковки и шума. Потом договорились: один чат для конфликтов, другой — для помощи. Теперь мы даём друг другу соль, забираем посылки, сидим с детьми. Сообщество начинается с правил.', '2026-04-22 20:47:08.359243'::timestamp, 233);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1498, 'Мы отремонтировали подъезд своими силами. Купили краску, кисти, за выходные покрасили стены, заменили лампочки. Управляющая компания увидела и сказала: «Молодцы, с вас скидка 10%». Деньги не главное.', '2026-04-22 20:47:11.635821'::timestamp, 233);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1499, 'Я собрал деньги для детского дома на благотворительном концерте. Мы выступали бесплатно, принесли еду, собрали 150 тысяч. Дети пели нам песню в ответ. Слёзы.', '2026-04-22 20:47:15.014755'::timestamp, 233);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1500, 'Мы посадили 200 деревьев в городе. Чиновники не помогали. Мы сами выкопали ямы, привезли саженцы, поливали. Через пять лет в этом районе стало прохладнее и чище. Теперь чиновники говорят: «Это наша инициатива».', '2026-04-22 20:47:18.392659'::timestamp, 233);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1501, 'Я организовал бесплатные курсы английского для подростков из малообеспеченных семей. Многие не верили, что у них получится. Через год трое поступили в вузы на бюджет. Ради этого стоило стараться.', '2026-04-22 20:47:21.568615'::timestamp, 233);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1502, 'Я ушёл в 10-дневный ретрит по випассане. Молчание, медитация, никакой связи. На третий день я хотел сбежать. На пятый — понял, что мой ум — это сумасшедшая обезьяна. На десятый — договорился с обезьяной.', '2026-04-22 20:47:25.153830'::timestamp, 234);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1503, 'Я был атеистом. Потом умер мой отец. Я не знал, куда девать боль. Пошёл в церковь, поставил свечку. Не знаю, есть ли Бог, но ритуал помог. Иногда нам нужна структура, чтобы пережить хаос.', '2026-04-22 20:47:28.534025'::timestamp, 234);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1504, 'Я прочитал 100 книг по саморазвитию. Все они говорят одно: будьте в моменте. Но я понял это только когда сидел на берегу океана и просто смотрел на волны. Книги не заменяют опыт.', '2026-04-22 20:47:31.706405'::timestamp, 234);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1505, 'Психоделики? Однажды я попробовал ЛСД в контролируемой обстановке с ситтером. Я увидел, что я — не мои мысли, а тот, кто их наблюдает. Это изменило моё отношение к тревоге. Но это не для всех.', '2026-04-22 20:47:35.291787'::timestamp, 234);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1506, 'Йога — это не позы. Это способность сидеть в тишине и не двигаться. Я не мог 10 секунд. Через год практики — 30 минут. Медитация — это атлетика ума.', '2026-04-22 20:47:38.275254'::timestamp, 234);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1507, 'Я прошёл психотерапию. Два года разбирал детские травмы, отношения с матерью, чувство вины. Дорого, больно, эффективно. Психическое здоровье — это не слабость, это работа.', '2026-04-22 20:47:41.637821'::timestamp, 234);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1508, 'Я перестал врать себе. Признался, что моя работа не приносит счастья, брак развалился, друзья — не друзья. Разрушил всё. Потом построил заново. Честность с собой — самая трудная и самая освобождающая вещь.', '2026-04-22 20:47:45.135577'::timestamp, 234);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1509, 'Первый интернет-мем — смайлик :) предложил Скотт Фалман в 1982 году. До него использовали :-) и :-(, но именно этот стал стандартом.', '2026-04-22 20:47:50.855438'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1510, 'Мем «Pepe the Frog» прошёл путь от комикса до символа ненависти. Оригинальный автор устал, что его творение угнали.', '2026-04-22 20:47:53.824187'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1511, '«Лолка» (lol) появилась на BBS в 1980-х. Сейчас это уже архаизм, но без неё не было бы «лмао» и «кек».', '2026-04-22 20:47:56.652540'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1512, 'Вирус «Гангнам стайл» собрал 4 млрд просмотров в 2012 — первый YouTube-мем, который вышел за рамки интернета.', '2026-04-22 20:47:59.762447'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1513, 'Мем «Это фиаско, братан» пошёл из реалити-шоу «Пацанки». Героиня сказала фразу проигравшей — и понеслось.', '2026-04-22 20:48:04.082707'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1514, 'Интересно, что «Ждун» (Homunculus loxodontus) — это скульптура нидерландской художницы, а не фотошоп. В России его переосмыслили.', '2026-04-22 20:48:07.442763'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1515, 'История мема «Девушка vs кошка» (Woman yelling at cat) — два старых мема скрестили, и получился вирус. Настоящая магия.', '2026-04-22 20:48:10.721204'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1516, 'Мем «How dare you?» Греты Тунберг разлетелся за сутки. Политический мем — самый быстрый способ стать популярным.', '2026-04-22 20:48:13.995060'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1517, 'Первый мем на русском — «Превед, медвед» (2006). Это был форумный сленг, который породил целую субкультуру.', '2026-04-22 20:48:17.399047'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1518, 'ТикТок убил старые форматы мемов. Сейчас виральный тренд живёт 2-3 дня, а не месяц, как в 2015.', '2026-04-22 20:48:20.550424'::timestamp, 235);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1519, 'Данк-мем — это мем, который кажется глупым или оскорбительным, но именно поэтому он смешной. Пример: «Шрэк — это любовь, Шрэк — это жизнь».', '2026-04-22 20:48:24.235282'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1520, 'Чёрный юмор в мемах — граница, которую постоянно двигают. Мем про 9/11 стал нормой через 10 лет, про COVID — через год.', '2026-04-22 20:48:27.306310'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1521, 'Мем «Обезьяна смотрит в сторону» (Monkey looking away) — идеальный шаблон для выбора между двумя плохими вариантами.', '2026-04-22 20:48:30.281308'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1522, '«Грустный пепе» (Sad Pepe) — эволюция обычного Пепе. Выражает экзистенциальную тоску зумера.', '2026-04-22 20:48:33.872506'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1523, 'Мем с «Бутербродом, который упал маслом вниз» — классика физики и жизненной несправедливости.', '2026-04-22 20:48:36.523551'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1524, 'Почему данк-мемы нельзя объяснять? Объяснённый данк теряет магию. Если тебе надо объяснять — ты не целевая аудитория.', '2026-04-22 20:48:40.071570'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1525, 'Самый тёмный мем: «Два самолёта и небоскрёб» — некоторые шутят, я осуждаю, но факт: такие мемы живут на 4chan.', '2026-04-22 20:48:43.280108'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1526, 'Мем «Бернт Крис» (Chris Pratt испуган) — универсальный шаблон для любых неловких ситуаций.', '2026-04-22 20:48:46.193329'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1527, 'Формат «Nobody: …» задаёт абсурдный контекст. Пример: «Nobody: ... My brain: помнишь тот тупой момент 10 лет назад?»', '2026-04-22 20:48:49.618191'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1528, 'Коллекционирую мемы в папках по годам. 2016 — папка весит 10 ГБ, 2024 — 200 ГБ. Инфляция контента.', '2026-04-22 20:48:52.704210'::timestamp, 236);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1529, 'Мем с собакой, которая говорит «You''re doing great, sweetie» — всегда поднимает настроение.', '2026-04-22 20:48:55.681966'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1530, 'Кот, который обнимает кактус — про принятие колючих сторон себя. Неожиданно глубоко.', '2026-04-22 20:48:58.772156'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1531, 'Формат «Me and the boys» с улыбающимися друзьями — простая радость от компании.', '2026-04-22 20:49:01.818012'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1532, 'Мем с малышом Йодой, который пьёт суп — чистое умиротворение. Нет негатива, только покой.', '2026-04-22 20:49:05.092899'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1533, '«Wholesome Keanu Reeves» — Киану, который раздаёт еду бездомным, сидит в метро, улыбается. Человек-мем.', '2026-04-22 20:49:08.271568'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1534, 'Комикс про депрессивного ослика Иа, которого друзья вытаскивают гулять — доброта без пафоса.', '2026-04-22 20:49:11.338541'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1535, 'Мем «Два стула» (один с трудностями, другой с трудностями) — принятие жизненных выборов.', '2026-04-22 20:49:14.512521'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1536, 'Кошачьи лапки, которые мнут одеяло — «making biscuits». За этим можно наблюдать часами.', '2026-04-22 20:49:17.482676'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1537, '«Thank you, next» — не только песня Арианы, но и шаблон про отпускание обид.', '2026-04-22 20:49:20.450648'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1538, 'Формат «Expectation vs reality» часто грустный, но есть wholesome версия: ожидал дождь, а реальность — радуга.', '2026-04-22 20:49:23.523921'::timestamp, 237);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1539, 'Мем с бесконечным коридором и человеком, который несёт лопату — я не знаю, что это, но я это чувствую.', '2026-04-22 20:49:27.106806'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1540, '«We live in a society» — фраза, которую приписывают Джокеру, но в мемах она значит вообще всё и ничего.', '2026-04-22 20:49:30.589974'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1541, 'Формат «He is beginning to believe» из Матрицы — используется для момента просветления в абсурдных ситуациях.', '2026-04-22 20:49:33.660980'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1542, 'Мем с тремя панелями: первый — норма, второй — тревога, третий — абсолютный покой. Сюрреализм в структуре.', '2026-04-22 20:49:36.959847'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1543, '«Это слишком много, я иду домой» — картинка с пингвином, который уходит вдаль. Универсальный выход из любой ситуации.', '2026-04-22 20:49:39.702557'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1544, 'Мем с катящимся камнем, на котором написано «my sanity» — метафора жизни.', '2026-04-22 20:49:42.995737'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1545, 'Формат «Me explaining to my mom...» — диалог, где сын объясняет мемы, а мама не понимает, но поддерживает.', '2026-04-22 20:49:46.211359'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1546, 'Голубой и чёрный квадраты Малевича в мемах — когда пост имеет глубокий смысл, который никто не понял.', '2026-04-22 20:49:49.432467'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1547, '«This is fine» — собака в горящей комнате. Шедевр абсурда, который стал гимном нашего времени.', '2026-04-22 20:49:52.810077'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1548, 'Мем с бесконечным падением в колодец — вариация на тему «déjà vu». Не пугайтесь, это нормально.', '2026-04-22 20:49:55.881716'::timestamp, 238);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1549, '«Троллфейс» (Cool Story Bro) — 2008 год. Сейчас уже не смешно, но тогда это был пик интернет-юмора.', '2026-04-22 20:49:59.787199'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1550, '«Гиперсом» (Nyan Cat) — летающий кот с поп-тартом. Смотреть 10 часов подряд — ритуал посвящения.', '2026-04-22 20:50:02.965206'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1551, '«Rickroll» — Рик Эстли никогда не умирает. В 2021 его заслали на Super Bowl, 2023 — в TikTok.', '2026-04-22 20:50:06.838215'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1552, '«Bad Luck Brian» — парень в свитере, который всегда в проигрыше. Классика 2012.', '2026-04-22 20:50:09.807535'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1553, '«Over 9000» — крик Вегеты из Dragon Ball Z. Используется до сих пор для гипербол.', '2026-04-22 20:50:13.187005'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1554, '«One Does Not Simply Walk into Mordor» — Боромир стал шаблоном для любой сложной задачи.', '2026-04-22 20:50:16.261455'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1555, '«Yo Dawg, I heard you like...» — Xzibit и его мем про встраивание вещей друг в друга.', '2026-04-22 20:50:19.755429'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1556, '«Socially Awesome Awkward Penguin» — пингвин, который иллюстрирует разрыв между намерением и реальностью.', '2026-04-22 20:50:23.022466'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1557, '«Futurama Fry» — «Not sure if...» — шаблон для неуверенности. До сих пор актуален.', '2026-04-22 20:50:26.907518'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1558, 'Помните «Мою ленту»? Это был первый русский мем про ВК. В 2009 это было смешно, сейчас — ностальгия.', '2026-04-22 20:50:29.980062'::timestamp, 239);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1559, 'Мем — это единица культурной информации. Как ген, но распространяется не в ДНК, а в мозгах. Докинз придумал термин в 1976.', '2026-04-22 20:50:33.462763'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1560, 'Почему одни мемы живут годами, а другие умирают за день? Успешный мем должен быть: простым, копируемым, вариативным.', '2026-04-22 20:50:36.533646'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1561, 'Мем «Девушка vs кошка» — идеальный пример вирусности. Два самостоятельных мема дали третьего, который сильнее суммы.', '2026-04-22 20:50:39.810714'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1562, 'Глубокая мысль: мемы — это способ обработки коллективной травмы. Шутка про пандемию помогает пережить страх.', '2026-04-22 20:50:43.085498'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1563, 'Формат «POV» (точка зрения) — эволюция мема от третьего лица к первому. Мы теперь не наблюдатели, а участники.', '2026-04-22 20:50:46.071330'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1564, 'ТикТок-мемы строятся на звуке и повторяющихся движениях. Это возврат к ритуальным танцам.', '2026-04-22 20:50:49.025163'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1565, 'Мем «Сигма» (одинокий волк) — реакция на токсичную маскулинность альф. Новый архетип.', '2026-04-22 20:50:52.096803'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1566, 'Феномен «мем-эха»: одна картинка порождает тысячи вариаций, но оригинал забывается. Как устный фольклор.', '2026-04-22 20:50:55.169968'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1567, 'Мемы про работу из дома (WTF Zoom call) — как мы коллективно переживали карантин.', '2026-04-22 20:50:58.447281'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1568, 'Самый философский мем: «I''m in this photo and I don''t like it» — узнавание себя в смешном и грустном одновременно.', '2026-04-22 20:51:01.622484'::timestamp, 240);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1569, 'Кот с надписью «I should buy a boat» — что бы ни случилось, всегда есть оправдание купить лодку.', '2026-04-22 20:51:04.957869'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1570, '«Grumpy Cat» (Табби) — умерла в 2019, но её лицо «не люблю всё» живёт вечно.', '2026-04-22 20:51:08.279600'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1571, 'Кот, который орёт (Crying Cat) — формат для выражения любой боли, от драмы до упавшего бутерброда.', '2026-04-22 20:51:11.569120'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1572, '«Кот в сапогах» (Puss in Boots) с большими глазами — когда ты просишь что-то очень мило.', '2026-04-22 20:51:14.828613'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1573, 'Мем с двумя котами за обеденным столом: один белый, другой чёрный — дуализм добра и зла.', '2026-04-22 20:51:17.901786'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1574, 'Кот, который высовывает язык (blep) — не мем, а состояние души.', '2026-04-22 20:51:20.973600'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1575, '«Лил Буб» — ещё одна кошка-мем, которая тоже ушла, но её уникальный язык (висящий наружу) остался.', '2026-04-22 20:51:24.164363'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1576, 'Формат «Cat at the table» — изначально из мультфильма, а стал шаблоном про споры.', '2026-04-22 20:51:27.630270'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1577, 'Мем с котом, который нажимает на кнопку — «Do not push the red button».', '2026-04-22 20:51:31.331156'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1578, 'Мои три кота вдохновляют меня на мемы. Например, когда кот писает в тапок — это «expectation vs reality».', '2026-04-22 20:51:34.184122'::timestamp, 241);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1579, '«All your base are belong to us» — первый геймерский мем из игры Zero Wing. 2000 год, плохой перевод.', '2026-04-22 20:51:37.563552'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1580, '«Doom» запускают на всём: на банкомате, на калькуляторе, на тесте на беременность. Это уже мем-культ.', '2026-04-22 20:51:40.533364'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1581, '«Press F to pay respects» — из Call of Duty: Advanced Warfare. Теперь F — синоним соболезнований.', '2026-04-22 20:51:43.216997'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1582, '«The cake is a lie» — Portal, 2007. До сих пор используется для обманутых ожиданий.', '2026-04-22 20:51:46.573261'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1583, 'Мем «Surprised Pikachu» — шок от очевидных последствий своих действий.', '2026-04-22 20:51:50.261659'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1584, '«Легит или чит?» — русский геймерский мем про подозрительных соперников.', '2026-04-22 20:51:53.332134'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1585, '«Как тебе такое, Илон Маск?» — про игру в шахматы с голубями. Классика.', '2026-04-22 20:51:56.522276'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1586, '«Хантер из L4D2, который бьёт в лицо» — шаблон для внезапного поворота.', '2026-04-22 20:51:59.893622'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1587, '«У меня 300 FPS, но я всё равно лагаю» — вечная проблема геймеров.', '2026-04-22 20:52:03.061592'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1588, '«GG WP» — сокращение, которое стало мемом, когда игра была ужасной, но вежливость превыше всего.', '2026-04-22 20:52:06.303041'::timestamp, 242);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1589, '«У меня лапки» — цитата из «Масяни» (2000-е). Сейчас уже не все понимают, а тогда это был пик.', '2026-04-22 20:52:10.024368'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1590, 'Мем «Жирный кот» с усами из 2006. Был на каждом форуме. Сейчас его место заняли другие коты.', '2026-04-22 20:52:12.991247'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1591, '«Я не знаю, кто ты, но я найду тебя и спрошу» — фраза из старого треда Dota 2.', '2026-04-22 20:52:16.371856'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1592, '«Школьные годы чудесные» — картинка с толстым котом, который держит карандаш.', '2026-04-22 20:52:19.033436'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1593, '«Кто не спрятался — я не виноват» — мем из детской игры, который стал ностальгией по 90-м.', '2026-04-22 20:52:21.799033'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1594, '«Кушать подано» — кадр из советского фильма, который внезапно стал мемом в 2010.', '2026-04-22 20:52:24.870005'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1595, '«Остапа понесло» — из «12 стульев». Классика, которая живёт в интернете.', '2026-04-22 20:52:28.248841'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1596, 'Мем с «пушистым белым зайцем» — кто помнит? Это был старый смайл на башке.', '2026-04-22 20:52:31.321819'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1597, '«Сладкая парочка» — Колян и Светка из рекламы сока. Ретро-мем.', '2026-04-22 20:52:34.292049'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1598, 'Ностальгия по аське: статусы «Отошёл», «Не беспокоить», «Я в печали» — это были наши первые мемы.', '2026-04-22 20:52:37.290652'::timestamp, 243);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1599, '«Бабушка, блин, покурить» — классика рунета. Фраза, которую сказал внук, и она разлетелась.', '2026-04-22 20:52:40.640927'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1600, '«Давай, до свидания!» — из видео с тренером, который ругает спортсмена.', '2026-04-22 20:52:43.688857'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1601, '«Слушай, дед, а ты кто?» — из разговора с бабушкой, которая забыла внука.', '2026-04-22 20:52:46.681964'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1602, 'Мем с «жирным котом» и надписью «Я тебя не знаю, но я тебя люблю» — русский интернет-романтизм.', '2026-04-22 20:52:49.752991'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1603, '«А че сразу?» — универсальный ответ на любой вопрос. Родился на Pikabu.', '2026-04-22 20:52:52.943799'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1604, '«Заколебали, я устал, я ухожу» — из треда про работу, стал шаблоном.', '2026-04-22 20:52:56.204898'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1605, '«Саня, привет!» — голосовое сообщение, которое превратилось в мем.', '2026-04-22 20:52:59.379302'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1606, '«Маша, мы с тобой два сапога пара» — из фильма «Любовь и голуби». Цитируют все.', '2026-04-22 20:53:02.553492'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1607, '«Ну, ты лось!» — из рекламы пива. В народе — мягкое оскорбление.', '2026-04-22 20:53:05.318719'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1608, '«Дебил, что ли?» — самая частая фраза в комментариях, которая стала мемом.', '2026-04-22 20:53:08.498665'::timestamp, 244);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1609, 'Первый мотоцикл построил Даймлер в 1885 году — деревянная рама, одноцилиндровый двигатель 264 куб.см, 0.5 л.с. Максималка 11 км/ч.', '2026-04-22 20:53:14.124597'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1610, 'Harley-Davidson основали в 1903 году в сарае. Первый двигатель не мог выдать больше 3 л.с., но фирма выжила благодаря военным заказам в Первую мировую.', '2026-04-22 20:53:17.195302'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1611, 'Honda Super Cub — самый продаваемый мотоцикл в истории, более 100 миллионов штук. Простая конструкция, автоматическое сцепление, вечный двигатель.', '2026-04-22 20:53:20.575662'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1612, 'Suzuki GSX-R750 1985 года перевернул представление о спортбайках: алюминиевая рама, 17-дюймовые колёса, сухая масса 179 кг. С него началась эра литровых спортбайков.', '2026-04-22 20:53:23.954257'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1613, 'Байкерская культура возникла после Второй мировой войны. Демобилизованные лётчики покупали дешёвые армейские Harley и создавали первые мотоклубы. Фильм «Дикий ангел» 1953 года сделал образ байкера культовым.', '2026-04-22 20:53:27.436515'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1614, 'Итальянские мотоциклы: Moto Guzzi V8 1957 года имела 8 цилиндров V-образных и развивала 140 км/ч. Из-за сложности выпустили всего 8 штук.', '2026-04-22 20:53:31.429309'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1615, 'Yamaha V-Max 1985 года — дрэгстер от производителя. V4 1200 куб.см, 145 л.с., разгон до сотни за 3.5 секунды. Прозвище «Убийца Сузук» осталось в истории.', '2026-04-22 20:53:34.779131'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1616, 'BMW R32 1923 года ввёл оппозитный двигатель и карданный вал. Схема живёт до сих пор, и ни один байкер не перепутает звук боксёра.', '2026-04-22 20:53:38.231712'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1617, 'В 1970-х японские производители убили европейский мотоциклетный бизнес. Kawasaki Z1 1972 года — 903 куб.см, 82 л.с., четырёхцилиндровый. Triumph и Norton не выдержали конкуренции.', '2026-04-22 20:53:41.975237'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1618, 'Suzuki Hayabusa 1999 года ограничили 300 км/ч по джентльменскому соглашению. Самый быстрый серийный мотоцикл своего времени, до сих пор рекордсмен по аэродинамике.', '2026-04-22 20:53:45.049811'::timestamp, 245);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1619, 'Настоящий кафе-рейсер — это не просто стиль. Укороченный хвост, низкий руль, прямой бак. И обязательно шлифовка до алюминия.', '2026-04-22 20:53:48.530175'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1620, 'Постройка кастома из старого Honda CB750. Замена вилки на перевёрнутую, литьё вместо спиц, фальшбак из стекловолокна. Бюджет — 150 тысяч, сезон работы.', '2026-04-22 20:53:52.010520'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1621, 'Кожаный комбез и шлем-интеграл — мастхэв для кафе-рейсера. Открытое лицо красиво только на фото, в реальности камень в зуб — плохой опыт.', '2026-04-22 20:53:55.303282'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1622, 'Вместо спидометра ставлю GPS-логгер. Стрелочные приборы красивы, но точность — плюс-минус 10 км/ч. А на треке нужны цифры.', '2026-04-22 20:53:58.155677'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1623, 'Резина для кастомов: Avon Roadrider или Continental TKV. Классический рисунок, но современный состав. Держат дугу на мокром.', '2026-04-22 20:54:01.098998'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1624, 'Коленвал на CB550 родной, но поршневую заменил на кованую. Компрессия поднялась, двигатель стал злее, но вибрация убивает подушку сиденья.', '2026-04-22 20:54:04.504140'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1625, 'Ночная поездка по набережной на кафе-рейсере — особый кайф. Свет фар на старую брусчатку, и ты слышишь каждый камень. Город спит, а байк живёт.', '2026-04-22 20:54:07.371235'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1626, 'Коробка передач на старых Honda — нечёткая. Ставлю короткие кики, меняю масло на 10W-60, и переключения становятся мягче.', '2026-04-22 20:54:10.328274'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1627, 'Французская школа: гоночные мотоциклы 1970-х. Розетки в треке, седло-горб, выхлоп 4-в-1. Красота, за которую убьют на любом мотосборище.', '2026-04-22 20:54:13.619018'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1628, 'Бак с чеканкой — ручная работа. Рисунок «паутина» или «ромб» стоит от 30 тысяч. Но когда видишь результат, понимаешь, почему кастом — искусство.', '2026-04-22 20:54:16.894815'::timestamp, 246);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1629, 'За один сезон проехал 15 тысяч километров по России. Золотое кольцо, Карелия, Крымский мост. Самый тяжёлый участок — трасса М4 в дождь.', '2026-04-22 20:54:20.492994'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1630, 'Круиз-контроль и подогрев ручек — обязательны для туриста. Без них после 500 км кисти немеют, а пальцы отказываются жать сцепление.', '2026-04-22 20:54:23.977790'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1631, 'Шины Michelin Road 5 прошли 12 тысяч км по асфальту и грунтовке. Намокший грейдер держат отлично, а в лужах не аквапланируют.', '2026-04-22 20:54:26.929794'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1632, 'Однажды ночевал в палатке у обочины в Карелии. Утром комары съели, зато вид на озеро и восход — бесценны. Багаж должен быть водонепроницаемым.', '2026-04-22 20:54:30.103358'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1633, 'GPS-навигатор Garmin Zumo надёжнее телефона. Не боится вибрации, дождя, а пальцы в перчатках работают. Однажды телефон отвалился на кочке.', '2026-04-22 20:54:33.789928'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1634, 'Гидрокостюм с мембраной Gore-Tex — единственное спасение в затяжной ливень. Дешёвые дождевики рвутся на ветру, и ты мокрый за 10 минут.', '2026-04-22 20:54:36.964902'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1635, 'Оптимальная скорость для дальняка на Suzuki V-Strom 650 — 110 км/ч. Расход 4.5 литра, нет усталости, и можно любоваться пейзажами.', '2026-04-22 20:54:40.446644'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1636, 'Планируя маршрут, всегда закладываю 30% запаса по времени. Встречные ямы, ремонты дорог, жара — всё отнимает силы. Лучше приехать позже, чем в кювет.', '2026-04-22 20:54:44.950716'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1637, 'Самая красивая дорога — Чуйский тракт. От Бийска до границы с Монголией. Степь, горы, реки, и асфальт идеальный. Но бензина берите с собой.', '2026-04-22 20:54:48.345836'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1638, 'Мототуризм учит минимализму. В дороге нужны только карта, аптечка, тёплые вещи и деньги. Остальное — лишний вес, который ты будешь тащить 10 часов.', '2026-04-22 20:54:51.812738'::timestamp, 247);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1639, 'Реставрация Jawa 350/638: разобрал до винтика, перебрал двигатель, хромирование заняло 4 месяца. Первый запуск — слёзы на глазах.', '2026-04-22 20:54:55.459402'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1640, 'Оригинальные запчасти для старых мотоциклов — охота за сокровищами. Ebay, разборки в Чехии, японские аукционы. За пару рычагов сцепления на CB400F отдал 200 евро.', '2026-04-22 20:54:58.596236'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1641, 'Двигатель Jawa с двухтактным маслом — прелесть. Дым, запах, звук выхлопа. Ни один современный байк не даст такого настроения. Но смесь готовить строго 1:25.', '2026-04-22 20:55:02.053420'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1642, 'Урожай 1980-х: ИЖ Планета-5, Восход, Минск. Самый живучий — ИЖ, но тормозов нет, свет коптилка, зато чинится молотком и отвёрткой.', '2026-04-22 20:55:04.919079'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1643, 'Винтажный мотоцикл требует постоянного ухода. Регулировка клапанов каждые 3000 км, смазка тросов, затяжка спиц. Если не любишь возиться — бери современный.', '2026-04-22 20:55:08.707614'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1644, 'Бензин для старичков — только 95 без этанола. Современное топливо разъедает резиновые шланги и диафрагмы. Зимой сливаю карбюраторы, чтобы не закисли.', '2026-04-22 20:55:12.085156'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1645, 'С пробегом 45 лет на Jawa не гоняю, максимум 70-80 км/ч. Коллекционная ценность выше, чем адреналин. А на треке для скорости есть R1.', '2026-04-22 20:55:15.669560'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1646, 'Каждый год собираем слёт ретро-мотоциклов. Участники едут на Уралах, Днепрах, BMW R65. Главное не скорость, а чувство эпохи.', '2026-04-22 20:55:19.173616'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1647, 'Восстановить старый мотоцикл стоит как новый китайский 250 куб.см. Но когда ты его заводишь и едешь, понимаешь — это не про деньги.', '2026-04-22 20:55:22.327481'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1648, 'Запчасти на IZH Planeta 5 ещё можно найти на авторынках. Поршневую группы, сальники, прокладки — всё есть. А вот кузовные детали — только с рук.', '2026-04-22 20:55:25.707588'::timestamp, 248);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1649, 'На эндуро главное — ноги. Стоишь на подножках, колени сжимают бак, руки расслаблены. Если сесть в седло на кочках, позвоночник не выдержит.', '2026-04-22 20:55:29.296278'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1650, 'Грязь проходится на второй передаче, с постоянным газом. Резко открыл — задница уйдёт вбок. Сбросил — зароешься передним колесом.', '2026-04-22 20:55:32.771957'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1651, 'Резина Metzeler MC360 Mid Hard — зверь в лесу. Шипы крупные, самоочищается, но на асфальте гудит как трактор. Зато в грязи не буксует.', '2026-04-22 20:55:36.971301'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1652, 'Упал в болото, залил двигатель водой. Слил масло, продул цилиндры, поменял свечу. Завёлся с третьего кика. Эндуро должно быть ремонтопригодным.', '2026-04-22 20:55:40.568681'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1653, 'Перед выездом в лес обязательно смазываю цепь специальной смазкой-липучкой. Обычное масло смывается за 50 км грязи, а цепь потом менять.', '2026-04-22 20:55:43.932397'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1654, 'Шлем-кросс с козырём — обязателен. Солнце, ветки, грязь. В обычном шлеме без козыря через час ничего не видно.', '2026-04-22 20:55:47.005229'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1655, 'Самый сложный участок — корни деревьев после дождя. Мокрые, скользкие, как лёд. Нужно поднимать обороты и пропускать через заднее колесо.', '2026-04-22 20:55:50.178685'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1656, 'Эндуро-трасса — это не скорость, а выносливость. 100 км по лесу выматывают сильнее, чем 500 по шоссе. Руки отваливаются, но адреналин зашкаливает.', '2026-04-22 20:55:53.865251'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1657, 'Боты с защитой голени (кроссовые) спасли от перелома, когда нога попала между подножкой и землёй. Жёсткий пластик — лучше синяк, чем гипс.', '2026-04-22 20:55:57.450666'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1658, 'Лучшая эндуро-техника — смотреть туда, куда хочешь поехать. Если смотреть на дерево — в него и врежешься. Взгляд прокладывает путь.', '2026-04-22 20:56:02.161474'::timestamp, 249);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1659, 'Чоппер — это удлинённая вилка, откинутый назад руль, техасское седло и хром. Сделать из старого Honda Shadow можно за зиму в гараже.', '2026-04-22 20:56:05.861500'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1660, 'Кожаная жилетка с патчами — не просто одежда, а удостоверение личности. Каждый патч имеет значение, и носить чужие нельзя.', '2026-04-22 20:56:08.815357'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1661, 'Длинная вилка (6-8 дюймов) меняет геометрию. На малых скоростях руль тяжелый, зато на прямой едешь как по рельсам.', '2026-04-22 20:56:11.989501'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1662, 'Американский V-twin с громким выхлопом — душа чоппера. S&S Cycle, Ultima, RevTech. Звук такой, что собаки воют за квартал.', '2026-04-22 20:56:15.266447'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1663, 'Постройка чоппера своими руками — это 90% времени на поиск деталей. Бак от старого Харлея, седло заказывал у кожевника в Питере.', '2026-04-22 20:56:18.644469'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1664, 'Мотоклуб — семья. Вместе ездим на слёты, помогаем друг другу с ремонтом, отмечаем дни рождения. Одиночек среди чопперов почти нет.', '2026-04-22 20:56:22.142938'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1665, 'Краска-металлик с пейнт-пушкой — отдельное искусство. Плавные переходы, хромовые полосы, иногда аэрография. Цена покраски доходит до 100 тысяч.', '2026-04-22 20:56:25.522566'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1666, 'Посадка на чоппере расслабленная. Руки на широком руле, ноги вытянуты вперёд. Спина отдыхает, но кочки проходят через позвоночник.', '2026-04-22 20:56:28.476116'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1667, 'Рубашка-ковбойка, бандана, кожаные штаны — униформа. Шлем — только интеграл с открытым лицом. Полиция не любит, но это стиль.', '2026-04-22 20:56:32.163966'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1668, 'Harley-Davidson Softail Slim — современная классика. Скрытая задняя подвеска, V-twin 1690 куб.см, 85 ньютон-метров. Для города и шоссе идеал.', '2026-04-22 20:56:35.542119'::timestamp, 250);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1669, 'Зимой на мотоцикле главное — подогрев ручек и ладоней. Без них через 15 минут пальцы не чувствуют ни тормоз, ни сцепление.', '2026-04-22 20:56:39.038168'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1670, 'Лучший городской мотоцикл — 250-400 куб.см. Максимум до 120 км/ч, маневренный, расход 3 литра. В пробках между рядами как рыба.', '2026-04-22 20:56:42.300272'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1671, 'Правило левой полосы: всегда смотри в зеркало на 100 метров назад. Таксисты любят резко перестраиваться без поворотников.', '2026-04-22 20:56:45.268137'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1672, 'Дождь — не проблема, если есть качественный дождевик и резина с ламелями. А вот листья и дорожная разметка становятся скользкими, как лёд.', '2026-04-22 20:56:48.342466'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1673, 'Рюкзак с жёсткой спиной — спасение для спины. В обычном рюкзаке ноутбук давит на позвоночник, а за день это превращается в боль.', '2026-04-22 20:56:52.130490'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1674, 'Обогреваемые стельки в ботинках — мастхэв при температуре ниже +5°C. Дешёвые китайские за 500 рублей работают, но провода быстро перетираются.', '2026-04-22 20:56:55.920474'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1675, 'Мотокоммуникатор Cardo для связи с напарником. В пробках скучно, а голосовые подсказки навигатора через шлем — удобно.', '2026-04-22 20:56:58.888081'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1676, 'Ежедневная поездка на работу: 15 км, 30 минут вместо часа на маршрутке. Парковка во дворе офиса бесплатно. Экономия времени огромная.', '2026-04-22 20:57:02.371657'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1677, 'Летом в городе главное — потоотведение. Мотокуртка с сеткой и подкладкой-мембраной. Вентиляция в шлеме открыта, иначе закипишь на светофоре.', '2026-04-22 20:57:05.648342'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1678, 'За год проехал 12 тысяч по Москве. Поменял цепь, звёзды, колодки и масло 4 раза. Дешевле, чем ОСАГО и транспортный налог на машину.', '2026-04-22 20:57:08.775812'::timestamp, 251);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1679, 'Разгон до сотни за 3 секунды на Kawasaki ZX-10R — это наркотик. Адреналин зашкаливает, мозг не успевает обрабатывать картинку.', '2026-04-22 20:57:12.916468'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1680, 'Трек на спортбайке — это не просто катание, а спорт. Положение тела, торможение, траектория. Один лишний градус наклона — и улетаешь.', '2026-04-22 20:57:16.603407'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1681, 'Спортбайк не для города. Руки затекают, спина болит, коленки торчат, а в пробке перегрев. Но когда выезжаешь на пустое шоссе — забываешь обо всём.', '2026-04-22 20:57:20.188018'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1682, 'Ремень безопасности на мотоцикле не спасает. А вот подушка на баке (tank pad) и наколенники — обязательно.', '2026-04-22 20:57:23.055373'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1683, 'Регулировка подвески под свой вес меняет поведение байка на 100%. Если мягко — клюёт носом при торможении. Если жёстко — трясёт на неровностях.', '2026-04-22 20:57:26.128587'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1684, 'Первый раз на треке с упал из-за страха наклона. Мозг говорил: «Слишком низко!», я выпрямил байк, и улетел в траву. Надо доверять резине.', '2026-04-22 20:57:29.506100'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1685, 'Бензин 98 на спортбайке обязателен. Детонация на 95-м убьёт поршневую за сезон. К тому же мощность падает на 5-7 л.с.', '2026-04-22 20:57:32.884552'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1686, 'Спортбайк — это ещё и имидж. Но главное — не хром и наклейки, а умение ездить. На треке все равны, там не купишь секунды.', '2026-04-22 20:57:35.958311'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1687, 'После трёх часов активной езды на треке руки не слушаются. Делаю перерыв каждые 20 минут, пью воду, разминаю кисти. Иначе хватка пропадает.', '2026-04-22 20:57:39.456920'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1688, 'Тормозная жидкость RBF 600 меняется каждые 3 трек-дня. Если забыть — педаль тормоза станет ватной, и на выходе из прямой можно не вписаться.', '2026-04-22 20:57:42.921247'::timestamp, 252);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1689, 'Регулировка клапанов на 4-цилиндровом моторе — кропотливая работа. Щупы на 0.10-0.15 мм, затяжка с моментом. Перетянешь — сломаешь головку.', '2026-04-22 20:57:46.403424'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1690, 'Самая частая причина падения компрессии — прогоревший клапан или залегшие кольца. Диагностика компрессометром занимает 10 минут, а спасает от разборки.', '2026-04-22 20:57:49.680083'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1691, 'Карбюраторы Keihin CVK требуют синхронизации. Без vacuum-гайд-тубы четыре цилиндра работают вразнобой, мотоцикл троит и не едет.', '2026-04-22 20:57:53.055654'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1692, 'Масло в мотоцикле надо менять чаще, чем в машине. На спортах — каждые 3000 км, на туристах — 5000. Мотор крутится до 12000, нагрузка выше.', '2026-04-22 20:57:56.229928'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1693, 'Регулировка натяжения цепи: провис 25-35 мм на подвешенном заднем колесе. Если перетянуть — убиваешь подшипники вторичного вала и цепь рвётся.', '2026-04-22 20:57:59.507104'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1694, 'Перед заменой тормозных колодок проверяю состояние дисков. Биение более 0.2 мм — замена. Иначе новые колодки съедятся за месяц.', '2026-04-22 20:58:02.886516'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1695, 'Диагностика электроники: мультиметр, схема проводки и терпение. Часто проблема в массе — окислился контакт, и вся система глючит.', '2026-04-22 20:58:06.164170'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1696, 'Замена передней вилки: масло 10W, уровень отмеряю по мануалу. Если залить разное количество — вилка будет работать несимметрично.', '2026-04-22 20:58:09.647426'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1697, 'Обслуживание мотоцикла зимой — лучшее время. Снимаю аккумулятор, завожу раз в месяц, консервация топливной системы. Весной он как новый.', '2026-04-22 20:58:13.228289'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1698, 'Частая ошибка клиентов — экономия на расходниках. Дешёвая цепь рвётся через 5000 км, и вырывает картер. Результат — замена двигателя.', '2026-04-22 20:58:16.598584'::timestamp, 253);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1699, 'The Beatles перевернули звук в 1967-м. «Sgt. Pepper» показал, что студия может быть инструментом, а не просто местом записи.', '2026-04-22 20:58:23.572692'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1700, 'Led Zeppelin украли половину риффов у блюзовых музыкантов 20-х, но сделали это так гениально, что им всё простили.', '2026-04-22 20:58:26.539545'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1701, 'Кобейн ненавидел славу. «Nevermind» сделал его голосом поколения, а он просто хотел играть панк.', '2026-04-22 20:58:29.920764'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1702, 'Pink Floyd без Уотерса — это уже не Pink Floyd. «The Final Cut» — настоящий конец.', '2026-04-22 20:58:32.993724'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1703, 'Queen на Live Aid 1985 — лучшее живое выступление в истории. Фредди держал 70 тысяч в руках.', '2026-04-22 20:58:36.237054'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1704, 'Вуди Гатри писал песни про пыльные бури и голод. Его влияние на Боба Дилана и весь фолк-рок огромно.', '2026-04-22 20:58:39.647152'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1705, 'The Stooges придумали панк-рок за пять лет до Ramones. Игги Поп — безумный гений.', '2026-04-22 20:58:43.450137'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1706, 'Miles Davis записал «Kind of Blue» почти без репетиций. Просто пришёл, дал музыкантам гаммы и сказал: играйте.', '2026-04-22 20:58:46.815828'::timestamp, 255);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1707, 'Чарли Паркер мог сыграть 300 нот за минуту, но каждая имела значение. Бибоп не любят те, кто не успевает за мыслью.', '2026-04-22 20:58:50.008167'::timestamp, 255);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1708, 'John Coltrane — «A Love Supreme» как молитва. Четыре части, один порыв. Лучший джазовый альбом всех времён.', '2026-04-22 20:58:53.076585'::timestamp, 255);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1709, 'Nina Simone говорила: «Джаз — это не музыка, это способ существования». Её голос бил прямо в сердце.', '2026-04-22 20:58:56.230483'::timestamp, 255);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1710, 'Herbie Hancock в 70-х ушёл в электронику, и старые фанаты его проклинали. А он создал фанк-джаз.', '2026-04-22 20:58:59.514215'::timestamp, 255);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1711, 'Человек, который не слышал Chet Baker, не знает, что такое меланхолия. Его труба плачет.', '2026-04-22 20:59:02.687434'::timestamp, 255);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1712, 'Weather Report — фьюжн, который танцует. «Birdland» знает даже тот, кто не знает джаза.', '2026-04-22 20:59:05.774116'::timestamp, 255);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1713, 'Равель говорил: «Мой „Болеро“ — это оркестровое произведение без музыки». И всё равно это гениальное нарастание.', '2026-04-22 20:59:09.549471'::timestamp, 256);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1714, 'Шопен не любил играть для публики. 30 его концертов за всю жизнь — меньше, чем у современных поп-звёзд за месяц.', '2026-04-22 20:59:12.876338'::timestamp, 256);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1715, 'Бетховен писал Девятую симфонию уже глухим. Он не слышал аплодисментов после премьеры.', '2026-04-22 20:59:16.304652'::timestamp, 256);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1716, 'Гленн Гульд бросил концерты в 32 года. Сказал: «Сцена — это клетка». Ушёл в студию и записал лучшего Баха.', '2026-04-22 20:59:19.480076'::timestamp, 256);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1717, 'Моцарт писал музыку как дневник. Весёлые сонаты — когда деньги есть, грустные — когда долги.', '2026-04-22 20:59:22.551571'::timestamp, 256);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1718, 'Скрябин мечтал синтезировать цвета и звук. «Прометей» с партией света — опередил время на сто лет.', '2026-04-22 20:59:25.829153'::timestamp, 256);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1719, 'Лист изобрёл сольный концерт фортепиано. До него пианисты были просто аккомпаниаторами.', '2026-04-22 20:59:28.901025'::timestamp, 256);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1720, 'Kraftwerk в 1974-м использовали драм-машину, и весь мир зазвучал иначе. Транс, техно, хаус — всё оттуда.', '2026-04-22 20:59:32.143793'::timestamp, 257);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1721, 'Aphex Twin выпустил «Windowlicker» и сломал головы всем, кто думал, что электроника — это скучно.', '2026-04-22 20:59:35.044715'::timestamp, 257);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1722, 'Daft Punk создали альбом «Random Access Memories» без сэмплов — живыми музыкантами. И получили «Грэмми».', '2026-04-22 20:59:38.140606'::timestamp, 257);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1723, 'Brian Eno придумал термин «ambient». Его музыка для аэропортов — фон, который меняет пространство.', '2026-04-22 20:59:41.393390'::timestamp, 257);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1724, 'Пластик 80-х звучит дешёво, но без него не было бы synth-pop. Depeche Mode сделали моду на синтезаторы.', '2026-04-22 20:59:44.770772'::timestamp, 257);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1725, 'Мёртвые техно-продюсеры (Avicii, Кёльш, SOPHIE) уходят слишком рано. Грустно, когда тишина наступает на пике.', '2026-04-22 20:59:48.049048'::timestamp, 257);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1726, '«Selected Ambient Works 85-92» — лучший альбом для метро и долгой дороги. Ричард Д. Джеймс записал его в 14 лет.', '2026-04-22 20:59:51.304477'::timestamp, 257);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1727, 'Русская трёхрядка — гармонь, на которой плясали под «Барыню». Не путайте с баяном, у того клавиши как у пианино.', '2026-04-22 20:59:54.806699'::timestamp, 258);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1728, 'Ирландский джиг — 6/8, раз-два-три. Волынка Uilleann мягче шотландской, она не дует, а сжимается под мышкой.', '2026-04-22 20:59:58.201906'::timestamp, 258);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1729, 'Ойко — хорватское многоголосье. Включаешь и будто на камнях у моря стоишь.', '2026-04-22 21:00:01.872147'::timestamp, 258);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1730, 'Грузинское пение с квинтами и секундами — человеческий аккордеон. Ни один автотюн не повторит такую чистоту.', '2026-04-22 21:00:05.560011'::timestamp, 258);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1731, 'Кантеле — карело-финские гусли. Строй пентатоника, звук прозрачный как северное небо.', '2026-04-22 21:00:09.042244'::timestamp, 258);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1732, 'Сельская музыка Болгарии: нечётные размеры 5/8, 7/8, 9/8. Западный слух спотыкается, а балканцы танцуют.', '2026-04-22 21:00:12.315364'::timestamp, 258);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1733, 'Вьетнамский дан бау — однострунная скрипка с рычагом. Имитирует человеческий голос и крики птиц.', '2026-04-22 21:00:15.797240'::timestamp, 258);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1734, 'Biggie записал «Ready to Die» в подвале, будучи должником. Второй альбом уже делал при жизни королём.', '2026-04-22 21:00:19.278357'::timestamp, 259);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1735, 'Nas — «Illmatic» 1994. Короткий, злой, идеальный. Продюсеры как на подбор: Primo, Pete Rock, Q-Tip.', '2026-04-22 21:00:22.571283'::timestamp, 259);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1736, 'Tupac читал стихи Шекспира в тюрьме. Его текст «Dear Mama» — лучшее, что написано о матери в хип-хопе.', '2026-04-22 21:00:25.831400'::timestamp, 259);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1737, 'Wu-Tang Clan выпустили «Enter the Wu-Tang» и придумали свой алфавит. Метод Мэн умеет считать деньги.', '2026-04-22 21:00:29.011403'::timestamp, 259);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1738, 'Beastie Boys начинали как панк-группа. «Licensed to Ill» — это рэп для белых, но без фальши.', '2026-04-22 21:00:32.487827'::timestamp, 259);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1739, 'MF DOOM носил маску суперзлодея и читал про пончики и какао. Его рифмы как пазл, который собираешь с третьего раза.', '2026-04-22 21:00:35.767964'::timestamp, 259);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1740, 'Kendrick Lamar «To Pimp a Butterfly» — джаз-рэп о чёрной Америке. Продюсер Flying Lotus делал биты с дисторшном.', '2026-04-22 21:00:39.143834'::timestamp, 259);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1741, 'Black Sabbath придумали хэви-метал, когда Тони Айомми отрезал себе кончики пальцев и настроил гитару ниже.', '2026-04-22 21:00:42.729004'::timestamp, 260);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1742, 'Metallica «Master of Puppets» — идеальный трэш-альбом. Клифф Бертон погиб до релиза, так и не услышав его на сцене.', '2026-04-22 21:00:45.981273'::timestamp, 260);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1743, 'Iron Maiden играют на трёх гитарах. Гармонии как авиаэскадрилья, и Брюс Дикинсон ещё и самолёт водит.', '2026-04-22 21:00:49.282340'::timestamp, 260);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1744, 'Mayhem и норвежский блэк-метал: убийства, церкви в пепле, Евронимус и его трон из костей. Музыка тёмная, история мрачнее.', '2026-04-22 21:00:52.662262'::timestamp, 260);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1745, 'Slipknot пришли в масках, чтобы не быть узнанными. Теперь их маски узнают все. Ирония.', '2026-04-22 21:00:55.633450'::timestamp, 260);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1746, 'Opeth пишут 10-минутные песни, где есть и чистый вокал, и гроулинг. Прогрессив-дэт — это интеллектуальный метал.', '2026-04-22 21:00:58.824371'::timestamp, 260);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1747, 'Pantera «Vulgar Display of Power» — риффы как кувалда. Фил Ансельмо кричит так, что хочется крушить мебель.', '2026-04-22 21:01:02.289289'::timestamp, 260);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1748, 'Arcade Fire пришли на «Грэмми» в костюмах животных и выиграли. Инди-рок может быть большим.', '2026-04-22 21:01:05.566183'::timestamp, 261);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1749, 'The Smiths слушают те, кто не вписался в школьную тусовку. Моррисси плачет о любви, Марр берёт красивые аккорды.', '2026-04-22 21:01:08.846219'::timestamp, 261);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1750, 'Bon Iver записал «For Emma, Forever Ago» в хижине в лесу. Четыре месяца одиночества, гитара и микрофон.', '2026-04-22 21:01:11.910586'::timestamp, 261);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1751, 'Tame Impala — это один человек Кевин Паркер. Он играет всё сам, даже ударные. Психоделика для сноубордистов.', '2026-04-22 21:01:15.599504'::timestamp, 261);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1752, 'Vampire Weekend придумали афро-поп для выпускников университетов. Свитера, гребля и сёрф-гитара.', '2026-04-22 21:01:18.670655'::timestamp, 261);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1753, 'Sufjan Stevens написал песню про Иллинойс и штат, где ничего нет. А получилось грандиозно.', '2026-04-22 21:01:21.844308'::timestamp, 261);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1754, 'Neutral Milk Hotel — «In the Aeroplane Over the Sea». Единственный альбом, который слышат по ту сторону рая.', '2026-04-22 21:01:25.033508'::timestamp, 261);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1755, 'Оригинал «White Album» The Beatles с номером на обложке стоит до 5000$. У меня переиздание за 30$, но я счастлив.', '2026-04-22 21:01:28.706417'::timestamp, 262);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1756, 'Vinyl — это не тёплый ламповый звук. Это ритуал: достать, почистить, поставить иглу. Цифра удобна, аналог — душа.', '2026-04-22 21:01:31.880439'::timestamp, 262);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1757, '«The Dark Side of the Moon» на виниле звучит объёмнее. Спектроанализатор не покажет разницы, но уши слышат.', '2026-04-22 21:01:35.259229'::timestamp, 262);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1758, 'Коллекционировать пластинки — значит иногда покупать свинью. Я купил «Metal Machine Music» Лу Рида и до сих пор не понял, зачем.', '2026-04-22 21:01:38.741554'::timestamp, 262);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1759, 'Джаз на виниле: «Blue Train» Колтрейна — оригинал 1957 уйдёт за 20000$. Мой японец переиздание звучит почти как студия.', '2026-04-22 21:01:42.017470'::timestamp, 262);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1760, 'Грязная пластинка — треск и шипение. Но если почистить перед каждым проигрыванием, живёт вечно.', '2026-04-22 21:01:45.603216'::timestamp, 262);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1761, 'Первая пластинка, которую я купил — «London Calling» The Clash. Цена 1 фунт на блошином рынке. До сих пор играет без царапин.', '2026-04-22 21:01:48.980878'::timestamp, 262);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1762, 'Золотое правило: записывай тихий звук громким микрофоном, а громкий — тихим. Искажения — враг.', '2026-04-22 21:01:52.360689'::timestamp, 263);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1763, 'Phil Spector изобрёл «стену звука»: десятки музыкантов в одной комнате, эхо, реверберация. Битлз ненавидели этот метод.', '2026-04-22 21:01:55.638548'::timestamp, 263);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1764, 'Аналоговая плёнка 2 дюйма — 24 дорожки. Цифра Pro Tools — безграничные возможности, но нет того «тёплого» клиппинга.', '2026-04-22 21:01:59.508644'::timestamp, 263);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1765, 'Ошибка новичков: ставят компрессор на мастеринг и убивают динамику. Громкость решает не всё.', '2026-04-22 21:02:03.012518'::timestamp, 263);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1766, 'Руперт Нив создал лучшие предусилители. Neve 1073 — магия, превращающая скучный голос в бархат.', '2026-04-22 21:02:06.184493'::timestamp, 263);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1767, 'Работа с барабанами: три микрофона (бочка, малый, overhead) часто звучат лучше, чем десять.', '2026-04-22 21:02:09.870738'::timestamp, 263);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1768, 'Джордж Мартин был пятым битлом. Без его струнных аранжировок «Yesterday» была бы просто гитарой.', '2026-04-22 21:02:12.753611'::timestamp, 263);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1769, 'Роберт Джонсон продал душу дьяволу на перекрёстке. 29 песен, которые изменили рок-н-ролл.', '2026-04-22 21:02:17.447839'::timestamp, 264);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1770, 'B.B. King называл гитару Люсиль. Каждый бенд — как выдох, каждый вибрато — как слёзы.', '2026-04-22 21:02:20.639963'::timestamp, 264);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1771, 'Мадди Уотерс превратил дельту Миссисипи в чикагский блюз с электрогитарой. Хаулин Вулф рычал басом.', '2026-04-22 21:02:25.041476'::timestamp, 264);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1772, 'Стиви Рэй Вон умер в вертолёте после концерта. Его «Texas Flood» — лучший блюз 80-х.', '2026-04-22 21:02:28.522763'::timestamp, 264);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1773, 'Блюз — это пентатоника с блюзовыми нотами. Не надо играть много, надо играть с чувством.', '2026-04-22 21:02:32.090980'::timestamp, 264);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1774, 'Bessie Smith — императрица блюза. Голос, который разрывал палатки в 20-х. Умерла после аварии, потому что её не взяла белая больница.', '2026-04-22 21:02:35.163300'::timestamp, 264);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1775, 'Когда гитарист спрашивает «какой блюз играть?», ответ всегда — «E major, тоска и виски».', '2026-04-22 21:02:38.337921'::timestamp, 264);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1776, 'Майкл Джексон «Thriller» — самый продаваемый альбом, но его величие не в цифрах, а в клипе, который изменил формат.', '2026-04-22 21:02:41.835997'::timestamp, 265);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1777, 'Madonna умела шокировать и переизобретать себя. «Like a Prayer» с горящими крестами — икона богоборчества.', '2026-04-22 21:02:45.102332'::timestamp, 265);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1778, 'Britney Spears «Toxic» — идеальный поп-трек. Модуляции, струнные, сбитый ритм. Продюсеры поклонились.', '2026-04-22 21:02:48.781546'::timestamp, 265);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1779, 'Taylor Swift перезаписывает свои альбомы, чтобы владеть мастер-копиями. Битва артиста с лейблами важнее, чем хит-парады.', '2026-04-22 21:02:52.172111'::timestamp, 265);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1780, 'Beyoncé «Lemonade» — альбом-визуальный фильм о неверности и женской силе. Сделала поп-музыку искусством.', '2026-04-22 21:02:55.453906'::timestamp, 265);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1781, 'K-pop (BTS, Blackpink) — глобальный феномен, где танцы важнее вокала. Фанаты донаты на рекламные щиты как религию.', '2026-04-22 21:02:58.714733'::timestamp, 265);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1782, 'Леди Гага носила мясное платье, но она реально поёт. Джазовый альбом с Тони Беннеттом доказал это.', '2026-04-22 21:03:03.032517'::timestamp, 265);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1783, 'Фламенко: канте (пение), байле (танец), точе (гитара). В каждом аккорде — страсть и кровь цыган.', '2026-04-22 21:03:07.215002'::timestamp, 266);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1784, 'Индийская рага — не просто мелодия, а молитва времени суток. Утром играют одну рагу, вечером — другую.', '2026-04-22 21:03:10.903403'::timestamp, 266);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1785, 'Гамелан с Бали: оркестр из гонгов, металлофонов и барабанов. Звучит как инопланетный космос.', '2026-04-22 21:03:14.089593'::timestamp, 266);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1786, 'Кубинский сон — предок сальсы. Комплекс клаве Buena Vista Social Club оживил его в 90-х.', '2026-04-22 21:03:17.447782'::timestamp, 266);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1787, 'Тувинское горловое пение хоомей: один человек поёт две ноты одновременно. Басовый бурдон и свистящая мелодия.', '2026-04-22 21:03:20.753763'::timestamp, 266);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1788, 'Арабский уд — лютня без ладов. Макам — система микротонов, которую не взять на фортепиано.', '2026-04-22 21:03:24.313356'::timestamp, 266);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1789, 'Клезмер — музыка восточноевропейских евреев. Свадебные мелодии плачут и смеются одновременно.', '2026-04-22 21:03:27.487135'::timestamp, 266);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1790, 'Леонард Коэн писал «Hallelujah» пять лет. Перебрал 80 вариантов куплетов. Потом умер, зная, что это гимн.', '2026-04-22 21:03:30.764811'::timestamp, 267);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1791, 'Джони Митчелл «Both Sides Now» — гениальная простота. Облака, любовь, жизнь — всё иллюзия.', '2026-04-22 21:03:33.939048'::timestamp, 267);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1792, 'Пол Саймон всегда берёт чужие стили (регги, афробит) и делает их своими. Грейсленд — шедевр.', '2026-04-22 21:03:37.195621'::timestamp, 267);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1793, 'Плохой поэт пишет «я люблю тебя», хороший — «твоё имя выгравировано на моей рёбрах». Лана Дель Рей умеет.', '2026-04-22 21:03:40.390798'::timestamp, 267);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1794, 'Авторская песня: Высоцкий хрипел правду, Окуджава напевал надежду. ДДТ «Что такое осень» — уже классика.', '2026-04-22 21:03:43.558520'::timestamp, 267);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1795, 'Любэ не все любят, но «Комбат» — честный текст про войну без пафоса. Игорь Матвиенко знает ремесло.', '2026-04-22 21:03:46.807488'::timestamp, 267);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1796, 'Сергей Есенин написал «Письмо матери» в 27 лет. Каждое слово бьёт в сердце, если у тебя есть мама.', '2026-04-22 21:03:49.784118'::timestamp, 267);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1797, 'Темп 60-80 ударов в минуту синхронизируется с сердцем. Медленный ритм снижает тревожность.', '2026-04-22 21:03:53.094964'::timestamp, 268);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1798, 'Барабаны (шаманские, дарбука) используются при аутизме: ритм организует хаотичный мозг.', '2026-04-22 21:03:56.675669'::timestamp, 268);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1799, 'Моцарт не делает детей умнее, но его сонаты снимают стресс у недоношенных младенцев.', '2026-04-22 21:03:59.559491'::timestamp, 268);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1800, 'При инсульте пациенты не могут говорить, но могут петь. Музыкальная терапия восстанавливает речь через правое полушарие.', '2026-04-22 21:04:02.922027'::timestamp, 268);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1801, 'Громкий металл поднимает агрессию, но помогает выплеснуть гнев без насилия. Сессия с барабанами работает лучше психолога.', '2026-04-22 21:04:06.507861'::timestamp, 268);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1802, 'Пение в хоре повышает окситоцин — гормон доверия. Групповая терапия для подростков даёт эффект даже без слов.', '2026-04-22 21:04:09.455001'::timestamp, 268);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1803, 'Белый шум (шум дождя, вентилятора) — не музыка, но лечит бессонницу. Звук маскирует триггеры.', '2026-04-22 21:04:13.059582'::timestamp, 268);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1804, 'В сосновом лесу после дождя воздух пахнет смолой и хвоей. Грибы появляются на третий день, если температура не ниже +10.', '2026-04-22 21:04:20.333959'::timestamp, 269);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1805, 'Старые берёзы часто имеют дупла — в них селятся совы и летяги. Если увидите опилки под дуплом, значит, там кто-то живёт.', '2026-04-22 21:04:23.202536'::timestamp, 269);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1806, 'Черника лучше растёт в полутени ельников. Ягоды начинают поспевать в конце июля, но самые сладкие — после первых заморозков.', '2026-04-22 21:04:26.749630'::timestamp, 269);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1807, 'Следы лося легко отличить от кабаньих: у лося копыта широкие, раздвоенные, а кабан оставляет более округлый отпечаток с боковыми пальцами.', '2026-04-22 21:04:29.682814'::timestamp, 269);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1808, 'Заповедник «Кивач» известен своим водопадом, но мало кто знает, что там растёт редкая карельская берёза — её древесина с мраморным рисунком.', '2026-04-22 21:04:33.748813'::timestamp, 269);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1809, 'Снимать лис лучше всего на рассвете. Они выходят кормиться, когда солнце только начинает золотить траву, и не так пугливы.', '2026-04-22 21:04:37.334424'::timestamp, 270);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1810, 'Выдр увидеть трудно, но можно по следам на снегу: они перекатываются с горки в воду, оставляя длинные борозды.', '2026-04-22 21:04:40.431500'::timestamp, 270);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1811, 'Медведь на Кольском полуострове не боится человека, но и не нападает первым. Главное — не бежать и не смотреть в глаза.', '2026-04-22 21:04:43.585645'::timestamp, 270);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1812, 'Самая фотогеничная птица России — зимородок. Ярко-синяя спинка и рыжая грудка, но чтобы его снять, нужно часами сидеть у воды.', '2026-04-22 21:04:47.578436'::timestamp, 270);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1813, 'Рысь заметить почти невозможно — она сливается с корой деревьев. Мой лучший кадр получился, когда она вышла на тропу в сумерках.', '2026-04-22 21:04:51.161811'::timestamp, 270);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1814, 'На Эльбрусе на высоте 4000 метров уже чувствуется нехватка кислорода. Акклиматизация должна идти постепенно: подъём на 500 метров, ночёвка ниже.', '2026-04-22 21:04:54.951063'::timestamp, 271);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1815, 'В горах Урала есть плато Маньпупунёр — семь каменных столбов выветривания высотой до 40 метров. Летом там туманы, создающие мистическую атмосферу.', '2026-04-22 21:04:57.916862'::timestamp, 271);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1816, 'Самый опасный период в горах — не зима, а весна. Мокрый снег сходит лавинами, а лёд на тропах делает каждый шаг рискованным.', '2026-04-22 21:05:01.305392'::timestamp, 271);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1817, 'Альпинистское правило: на подъём трать треть времени и сил, на спуск — две трети. Люди чаще гибнут на спуске, когда устали и потеряли бдительность.', '2026-04-22 21:05:04.580927'::timestamp, 271);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1818, 'В Алтайских горах живут аргали — горные бараны с огромными рогами. Их популяция восстановилась благодаря заповедникам, но встретить всё равно редкость.', '2026-04-22 21:05:08.178557'::timestamp, 271);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1819, 'Клёст выводит птенцов зимой, потому что питается семенами шишек, которые созревают к холодам. Температура до -30°C не мешает насиживанию.', '2026-04-22 21:05:11.562818'::timestamp, 272);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1820, 'Орлан-белохвост гнездится на Камчатке. Размах крыльев до 2.5 метров. Увидеть его можно на скалах у моря — он высматривает рыбу.', '2026-04-22 21:05:14.721104'::timestamp, 272);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1821, 'Свиристели налетают на рябину огромными стаями и съедают все ягоды за день. Их прилёт — верная примета скорых заморозков.', '2026-04-22 21:05:17.691675'::timestamp, 272);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1822, 'Удод узнаваем по хохолку и клюву-пинцету. Он ищет насекомых в навозе и земле, поэтому часто селится рядом с фермами.', '2026-04-22 21:05:20.576555'::timestamp, 272);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1823, 'Филин — самая крупная сова в России. Его крик слышен за 3 км, а лапы сжимаются с силой 30 кг. Полевки и крысы не спасаются.', '2026-04-22 21:05:23.835037'::timestamp, 272);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1824, 'В Белом море водятся гренландские тюлени. Детёныши (бельки) рождаются на льду и первую неделю совершенно белые — маскировка.', '2026-04-22 21:05:27.315768'::timestamp, 273);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1825, 'Каспийское море — это озеро, но его фауна уникальна: каспийская нерпа (единственный тюлень в закрытом водоёме) и осётр на грани исчезновения.', '2026-04-22 21:05:30.612047'::timestamp, 273);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1826, 'В Чёрном море на глубине более 150 метров нет жизни из-за сероводорода. Зато в прибрежной зоне можно увидеть дельфинов-афалин.', '2026-04-22 21:05:34.194873'::timestamp, 273);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1827, 'Берингово море — одно из самых штормовых. Волны достигают 15 метров. Но там самая богатая рыбная фауна: треска, камбала, лосось.', '2026-04-22 21:05:37.150226'::timestamp, 273);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1828, 'В Охотском море обитают киты-горбачи. Их песни слышны за сотни километров, а каждый год они придумывают новые мелодии.', '2026-04-22 21:05:40.377614'::timestamp, 273);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1829, 'Венерин башмачок — орхидея наших лесов. Цветёт раз в году, но если сорвать, следующее цветение наступит только через 10 лет. Охраняется.', '2026-04-22 21:05:43.627774'::timestamp, 274);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1830, 'Папоротник орляк не размножается спорами, а разрастается корневищем. Одно растение может занимать площадь до 100 кв. метров.', '2026-04-22 21:05:46.778227'::timestamp, 274);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1831, 'Берёза карельская имеет древесину с волнистой текстурой из-за генетической мутации. Она не растёт прямой — всегда искривлена.', '2026-04-22 21:05:49.848228'::timestamp, 274);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1832, 'Росянка — хищное растение болот. Её листья покрыты клейкими каплями, которые привлекают и переваривают насекомых. Цветки белые, невзрачные.', '2026-04-22 21:05:53.023370'::timestamp, 274);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1833, 'В Сибири растёт лиственница, которая живёт до 800 лет. Её древесина не гниёт, поэтому её использовали для строительства мостов и настилов.', '2026-04-22 21:05:56.610163'::timestamp, 274);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1834, 'Почему осенью листья желтеют? Хлорофилл разрушается, и проявляются каротиноиды (жёлтые) и антоцианы (красные). Холодная ночь усиливает красный.', '2026-04-22 21:05:59.796631'::timestamp, 275);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1835, 'Муравейник — сложная вентиляция. Муравьи строят купол так, чтобы тёплый воздух поднимался кверху, а свежий заходил снизу. Температура внутри стабильна.', '2026-04-22 21:06:02.960954'::timestamp, 275);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1836, 'Сфагновые болота консервируют всё, что в них падает. Найдены тела людей возрастом 2000 лет с сохранившейся кожей — из-за кислой среды и отсутствия кислорода.', '2026-04-22 21:06:06.557937'::timestamp, 275);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1837, 'Лось способен нырять за водными растениями на глубину до 5 метров и задерживать дыхание на минуту. Под водой он щиплет кувшинки.', '2026-04-22 21:06:09.473078'::timestamp, 275);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1838, 'В тайге деревья выделяют фитонциды, убивающие бактерии. В сосновом лесу воздух практически стерилен — поэтому там строят туберкулёзные санатории.', '2026-04-22 21:06:12.502969'::timestamp, 275);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1839, 'Тропа Дючесс в Приэльбрусье — 40 км через ледники и морены. Лучшее время — август, когда реки не разлились и нет лавин.', '2026-04-22 21:06:15.656973'::timestamp, 276);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1840, 'Одежда в поход: никакого хлопка, только мембрана и флис. Хлопок намокает и не сохнет, в горах это гарантия переохлаждения.', '2026-04-22 21:06:19.258742'::timestamp, 276);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1841, 'На Байкале есть маршрут «Большая Байкальская тропа» — 500 км вдоль побережья. Часть проходит по диким местам, где живут медведи и нерпы.', '2026-04-22 21:06:22.332552'::timestamp, 276);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1842, 'Запас еды: бери на 20% больше, чем планируешь. Энергозатраты в горах выше, плюс можно задержаться из-за погоды.', '2026-04-22 21:06:25.714583'::timestamp, 276);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1843, 'Лучшие треккинговые палки — с фиксацией twist-lock. Они надёжнее защёлок, особенно в грязь и мороз. Вес одной палки не более 300 граммов.', '2026-04-22 21:06:28.781184'::timestamp, 276);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1844, 'Облака-башенки (кучево-дождевые) — признак грозы. Если они растут вертикально за час — через 2-3 часа жди ливня и молний.', '2026-04-22 21:06:32.043536'::timestamp, 277);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1845, 'Зимой давление падает перед снегопадом. Если барометр резко идёт вниз — в течение 12 часов пойдёт снег, и ветер усилится.', '2026-04-22 21:06:35.116448'::timestamp, 277);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1846, 'Румб — направление ветра по сторонам света. Северный ветер несёт холод и ясное небо, южный — тепло и осадки.', '2026-04-22 21:06:38.705326'::timestamp, 277);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1847, 'Туман образуется ночью при ясном небе и влажности выше 90%. Радиационный туман — самый плотный, рассеивается после восхода.', '2026-04-22 21:06:41.568658'::timestamp, 277);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1848, 'Радуга утром — к дождю, вечером — к хорошей погоде. Утренняя радуга бывает на западе, где ещё идут осадки.', '2026-04-22 21:06:44.760690'::timestamp, 277);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1849, 'Сортировка мусора: пластик с маркировкой 1 (ПЭТ) и 2 (HDPE) перерабатывается лучше всего. 5 (PP) тоже можно, но реже.', '2026-04-22 21:06:48.138654'::timestamp, 278);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1850, 'Энергия ветра в России: самые ветреные места — побережье Охотского моря и Калмыкия. Ветряк на 1 МВт окупается за 5-7 лет.', '2026-04-22 21:06:51.195940'::timestamp, 278);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1851, 'Лесные пожары чаще всего возникают из-за человека: брошенный окурок или стекло, которое фокусирует лучи. Кострище тушите водой и засыпайте землёй.', '2026-04-22 21:06:54.466675'::timestamp, 278);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1852, 'Средний срок разложения: бумага — 2 месяца, окурок — 5 лет, пластиковый пакет — 20 лет, батарейка — 100 лет. Батарейки нельзя выбрасывать в мусор.', '2026-04-22 21:06:57.855402'::timestamp, 278);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1853, 'Восстановление торфяников после пожаров идёт 20 лет. Осушать болота ради торфа — экологическая катастрофа, они перестают поглощать CO2.', '2026-04-22 21:07:01.045094'::timestamp, 278);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1854, 'Шмель может летать при температуре +4°C, потому что разогревает грудные мышцы вибрацией. Пчёлы при такой температуре уже не вылетают.', '2026-04-22 21:07:04.612580'::timestamp, 279);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1855, 'Жук-плавунец — подводный хищник. Он запасает воздух под надкрыльями и может находиться под водой до 20 минут. Личинка ещё опаснее — кусает мальков.', '2026-04-22 21:07:07.685114'::timestamp, 279);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1856, 'Клоп-солдатик (пожарник) не вредит растениям, питается соками мёртвых насекомых. Его яркая окраска предупреждает птиц о неприятном вкусе.', '2026-04-22 21:07:10.983739'::timestamp, 279);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1857, 'Пауки-скакунчики видят в 5 раз лучше человека. Они прыгают на добычу с расстояния 20 своих длин и перед прыжком прикрепляют страховочную нить.', '2026-04-22 21:07:14.260830'::timestamp, 279);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1858, 'Муравей-жнец собирает семена и перемалывает их своими огромными челюстями. Муравьиная кислота не вырабатывается — они безвредны для человека.', '2026-04-22 21:07:17.109634'::timestamp, 279);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1859, 'Бобры строят плотины, чтобы поднять уровень воды и обезопасить вход в хатку. Длина плотины может достигать 100 метров, а возраст — 10 лет.', '2026-04-22 21:07:20.386588'::timestamp, 280);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1860, 'Ручьевая форель живёт только в чистой холодной воде с температурой не выше 20°C. Если вода теплеет — рыба уходит в верховья.', '2026-04-22 21:07:23.371890'::timestamp, 280);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1861, 'Купаться в реке после ливня опасно: смываются удобрения с полей и бактерии. Уровень кишечной палочки может превышать норму в 100 раз.', '2026-04-22 21:07:26.223080'::timestamp, 280);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1862, 'Река Вуокса в Ленобласти знаменита своими каменистыми порогами. Там водится сиг и хариус — индикаторы чистой воды.', '2026-04-22 21:07:29.504021'::timestamp, 280);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1863, 'Заиливание реки происходит из-за вырубки лесов по берегам. Корни деревьев укрепляли грунт, без них берег осыпается и вода мутнеет.', '2026-04-22 21:07:32.676059'::timestamp, 280);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1864, 'Древесина лиственницы настолько плотная, что тонет в воде. Поэтому из неё делают сваи для мостов и набережных — Венеция стоит на лиственничных сваях.', '2026-04-22 21:07:36.076211'::timestamp, 281);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1865, 'В Карелии есть лес, который рос на месте древнего вулкана. Почва содержит много железа, и берёзы там имеют красноватый ствол.', '2026-04-22 21:07:39.585175'::timestamp, 281);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1866, 'Сосна может расти на скалах, выпуская корни в трещины на десятки метров. Такие деревья называются «корабельные» — они дают идеально ровную древесину.', '2026-04-22 21:07:42.627794'::timestamp, 281);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1867, 'Тополь быстро растёт, но живёт всего 50-70 лет. Старые тополя опасны: внутри они часто гнилые, но снаружи выглядят здоровыми.', '2026-04-22 21:07:45.484072'::timestamp, 281);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1868, 'В заповеднике «Брянский лес» растут дубы возрастом 400 лет. Диаметр ствола достигает 2 метров, а крона закрывает 30 метров в диаметре.', '2026-04-22 21:07:48.652374'::timestamp, 281);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1869, 'Первоцветы — сон-трава и ветреница — появляются, когда снег только сошёл. У них есть защита: в тканях содержатся ядовитые вещества.', '2026-04-22 21:07:51.622611'::timestamp, 282);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1870, 'Осина трепещет листьями из-за сплющенных черешков. Это помогает дереву выживать при сильном ветре — лист не рвётся, а колеблется.', '2026-04-22 21:07:54.797319'::timestamp, 282);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1871, 'Следы куницы на снегу — две параллельные полоски от лап, прыжки по 30-40 см. Охотится на белок и бурундуков, может залезть в дупло.', '2026-04-22 21:07:58.075626'::timestamp, 282);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1872, 'Весенний разлив рек — важное событие для нереста щуки. Она мечет икру на затопленных лугах, где нет хищников.', '2026-04-22 21:08:01.784059'::timestamp, 282);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1873, 'Кедровка (птица) запоминает места, где спрятала кедровые орехи. Одна птица делает до 60 тысяч запасов, часть забывает — так кедр размножается.', '2026-04-22 21:08:05.058275'::timestamp, 282);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1874, 'Зубры в национальном парке «Орловское полесье» — восстановленная популяция. Их кормят сеном зимой и следят, чтобы не было близкородственного скрещивания.', '2026-04-22 21:08:09.136308'::timestamp, 283);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1875, 'Амурский тигр занесён в Красную книгу. На воле осталось около 500 особей. Основная угроза — браконьерство и вырубка лесов.', '2026-04-22 21:08:12.326713'::timestamp, 283);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1876, 'Снежный барс (ирбис) живёт в горах Алтая. Его редко видят, но зимой можно найти следы — широкие подушечки лап, чтобы не проваливаться в снег.', '2026-04-22 21:08:15.410293'::timestamp, 283);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1877, 'Белуха — полярный дельфин. В Белом море летом они собираются стадами до 100 особей, чтобы линять — трутся о гальку и сдирают старую кожу.', '2026-04-22 21:08:19.070744'::timestamp, 283);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1878, 'Степной орёл гнездится на земле, а не на деревьях. Из-за распашки степей их численность сократилась в 5 раз за 30 лет.', '2026-04-22 21:08:22.451079'::timestamp, 283);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1879, 'Яшма на Урале бывает красной, зелёной, жёлтой. Это кремнистая порода с примесями оксидов железа и марганца — каждое месторождение уникально.', '2026-04-22 21:08:26.138283'::timestamp, 284);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1880, 'Мрамор на Алтае имеет серые и белые тона с чёрными прожилками. Его добывают в горах, блоки вырезают алмазными канатами.', '2026-04-22 21:08:29.313789'::timestamp, 284);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1881, 'Кварцит — очень твёрдая порода, звенит при ударе. Из него делают футеровку шаровых мельниц, потому что он износостойкий.', '2026-04-22 21:08:32.719034'::timestamp, 284);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1882, 'Окаменелое дерево в Забайкалье — это ископаемая древесина, в которой кремний заместил органику. Срез показывает годовые кольца из агата.', '2026-04-22 21:08:35.985970'::timestamp, 284);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1883, 'Горный хрусталь — бесцветный кварц. В Субполярном Урале находят кристаллы длиной до метра. Раньше из них делали линзы.', '2026-04-22 21:08:39.366374'::timestamp, 284);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1884, 'Млечный путь лучше всего виден в августе с 1 до 3 часов ночи, если уехать от города за 50 км. Яркая полоса — миллиарды звёзд.', '2026-04-22 21:08:42.744597'::timestamp, 285);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1885, 'Полярное сияние на Кольском полуострове бывает с сентября по март. Зелёное свечение — ионизированный кислород, красное — азот.', '2026-04-22 21:08:45.920175'::timestamp, 285);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1886, 'Падающие звёзды — метеоры. Они сгорают на высоте 80-100 км. Самый яркий поток — Персеиды (август), до 100 метеоров в час.', '2026-04-22 21:08:49.079361'::timestamp, 285);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1887, 'Комета NEOWISE в 2020 году была видна невооружённым глазом. У неё два хвоста: пылевой (жёлтый) и ионный (голубой).', '2026-04-22 21:08:52.489020'::timestamp, 285);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1888, 'Телескоп с апертурой 100 мм позволяет увидеть кольца Сатурна и спутники Юпитера. Главное — устойчивый штатив и отсутствие засветки.', '2026-04-22 21:08:55.736584'::timestamp, 285);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1889, 'Почему помидоры трескаются? Из-за неравномерного полива. После засухи резкий полив заставляет плоды набирать воду, кожица не выдерживает.', '2026-04-22 21:08:59.014350'::timestamp, 286);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1890, 'Посадка бархатцев между грядками отпугивает тлю и нематод. Корни выделяют вещества, которые не любят почвенные вредители.', '2026-04-22 21:09:02.397477'::timestamp, 286);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1891, 'Клубнику лучше мульчировать соломой — ягоды не лежат на земле, меньше гниют. Солома подкисляет почву, что полезно для клубники.', '2026-04-22 21:09:05.466323'::timestamp, 286);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1892, 'Соседство лука и моркови взаимовыгодно: лук отпугивает морковную муху, а морковь — луковую. Сажайте рядами через один.', '2026-04-22 21:09:08.948829'::timestamp, 286);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1893, 'Формирование огурцов: прищипывайте верхушку после 5-го листа, чтобы росли боковые плети — на них больше женских цветков.', '2026-04-22 21:09:12.436784'::timestamp, 286);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1894, 'Белый гриб растёт в сосновых и еловых лесах. Ищите на полянах, у тропинок, во мху. Если нашёл один — вокруг могут быть ещё.', '2026-04-22 21:09:15.912833'::timestamp, 287);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1895, 'Лисички никогда не червивеют из-за вещества хиноманноза, которое убивает паразитов. Их легко чистить — достаточно промыть.', '2026-04-22 21:09:19.307694'::timestamp, 287);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1896, 'Сморчки появляются в апреле. Их обязательно нужно отваривать 15 минут и сливать воду — иначе можно отравиться гиромитрином.', '2026-04-22 21:09:22.472358'::timestamp, 287);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1897, 'Грузди солят только холодным способом, вымачивая 3 дня в холодной воде. Горячая засолка делает их резиновыми.', '2026-04-22 21:09:25.659067'::timestamp, 287);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1898, 'Мухомор красный ядовит, но лось его ест — помогает избавляться от глистов. Для человека даже прикосновение может вызвать раздражение.', '2026-04-22 21:09:28.818139'::timestamp, 287);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1899, 'Субботник на озере Байкал: волонтёры собирают пластик и стекло с пляжей. За один сезон вывозят до 10 тонн мусора.', '2026-04-22 21:09:32.198058'::timestamp, 288);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1900, 'Раздельный сбор в Москве: контейнеры для пластика, стекла и бумаги. Но пластик нужно мыть — иначе его не переработают.', '2026-04-22 21:09:35.782373'::timestamp, 288);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1901, 'Посадка леса весной: саженцы сосны и ели высаживают на гарях. Норма — 2 тысячи деревьев на гектар, выживаемость 70%.', '2026-04-22 21:09:39.419941'::timestamp, 288);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1902, 'Чистка родников: волонтёры углубляют дно, убирают ил и ставят срубы. После этого вода становится чище и не застаивается.', '2026-04-22 21:09:42.679203'::timestamp, 288);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1903, 'Эко-марафон «Сдай батарейку»: за год собирают 20 тонн отработанных элементов. Из них извлекают цинк, марганец и медь.', '2026-04-22 21:09:46.127052'::timestamp, 288);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1904, 'Госдума приняла в первом чтении поправки о порядке формирования избирательных комиссий. Законопроект предполагает увеличение доли партийных представителей.', '2026-04-22 21:09:52.788058'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1905, 'Переговоры России и Китая по газовому контракту «Сила Сибири-2» перешли в практическую плоскость. Стороны обсуждают ценовые параметры.', '2026-04-22 21:09:56.061384'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1906, 'В пяти регионах пройдут экспериментальные электронные выборы с использованием блокчейн-технологий. ЦИК обещает полностью прозрачную систему.', '2026-04-22 21:09:59.315352'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1907, 'Парламент Казахстана одобрил поправки о расширении полномочий маслихатов. Местные представительные органы получат контроль над бюджетом районов.', '2026-04-22 21:10:03.245937'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1908, 'МИД Франции вызвал посла РФ из-за предполагаемого вмешательства в выборы. Москва отвергает обвинения и называет их бездоказательными.', '2026-04-22 21:10:06.405982'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1909, 'Совет Федерации рекомендовал правительству пересмотреть методику расчёта прожиточного минимума. Новая модель может быть внедрена с 2026 года.', '2026-04-22 21:10:09.989896'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1910, 'Компания «Яндекс» представила новую нейросеть YandexGPT-4 с открытым исходным кодом. Модель доступна для некоммерческого использования.', '2026-04-22 21:10:13.999472'::timestamp, 290);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1911, 'Российские учёные разработали прототип фотонного процессора для задач искусственного интеллекта. Энергопотребление в 100 раз ниже кремниевых аналогов.', '2026-04-22 21:10:17.486994'::timestamp, 290);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1912, 'Apple объявила о прекращении выпуска iPhone SE третьего поколения. Новый бюджетный смартфон выйдет не раньше 2026 года.', '2026-04-22 21:10:21.176283'::timestamp, 290);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1913, 'Запущен первый частный спутник для мониторинга лесных пожаров. Данные будут передаваться в МЧС в режиме реального времени.', '2026-04-22 21:10:24.651373'::timestamp, 290);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1914, 'Госдума приняла закон о маркировке голосовых помощников. Владельцы колонок смогут идентифицировать искусственный интеллект по специальному сигналу.', '2026-04-22 21:10:27.915223'::timestamp, 290);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1915, 'Китайские инженеры испытали квантовый компьютер на 500 кубитах. Машина решила задачу оптимизации за 200 секунд — классическому суперкомпьютеру потребовались бы тысячи лет.', '2026-04-22 21:10:33.357495'::timestamp, 290);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1916, 'Центробанк сохранил ключевую ставку на уровне 16%. Регулятор отметил замедление инфляции до 7,2% в годовом выражении.', '2026-04-22 21:10:37.044034'::timestamp, 291);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1917, 'Мировой рынок нефти: Brent торгуется выше 85 долларов за баррель на фоне сокращения добычи ОПЕК+. Аналитики ждут роста до 90 к концу квартала.', '2026-04-22 21:10:40.512645'::timestamp, 291);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1918, 'Рубль укрепился до 90 за доллар на фоне высоких цен на энергоносители и продажи валютной выручки экспортёрами.', '2026-04-22 21:10:43.779638'::timestamp, 291);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1919, 'ВВП России вырос на 3,6% по итогам первого полугодия, сообщил Росстат. Основной вклад внесли обрабатывающая промышленность и строительство.', '2026-04-22 21:10:47.271415'::timestamp, 291);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1920, 'Еврокомиссия ввела пошлины на импорт электромобилей из Китая. Ставка составит от 17% до 38% в зависимости от производителя.', '2026-04-22 21:10:50.768162'::timestamp, 291);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1921, 'Банк Японии впервые за 17 лет повысил ключевую ставку — до 0,25%. Иена отреагировала укреплением на 2% к доллару.', '2026-04-22 21:10:53.940470'::timestamp, 291);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1922, 'В Третьяковской галерее открылась выставка авангардистов 1920-х годов. В экспозиции представлены работы Малевича, Кандинского и Родченко.', '2026-04-22 21:10:57.541683'::timestamp, 292);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1923, 'Фильм Звягинцева «Нелюбовь» вошёл в лонг-лист премии «Оскар» от России. Картина рассказывает о семейной драме в провинциальном городке.', '2026-04-22 21:11:01.016770'::timestamp, 292);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1924, 'Большой театр представит премьеру балета «Мастер и Маргарита» в постановке Юрия Посохова. Хореограф использовал музыку Шнитке и Десятникова.', '2026-04-22 21:11:04.886232'::timestamp, 292);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1925, 'Эрмитаж запустил виртуальные туры с разрешением 8K. Онлайн-посетители могут рассмотреть детали картин с увеличением до 1000%.', '2026-04-22 21:11:07.964022'::timestamp, 292);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1926, 'В Санкт-Петербурге пройдёт XII Международный культурный форум. Участники обсудят цифровизацию музеев и сохранение памятников архитектуры.', '2026-04-22 21:11:11.341829'::timestamp, 292);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1927, 'Умер народный артист России, режиссёр Александр Сокуров. Ему было 72 года. Прощание пройдёт в Концертном зале Мариинского театра.', '2026-04-22 21:11:14.412054'::timestamp, 292);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1928, 'Сборная России по футболу провела товарищеский матч с Вьетнамом и выиграла со счётом 3:0. Голы забили Чалов, Обляков и Миранчук.', '2026-04-22 21:11:18.225038'::timestamp, 293);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1929, 'Олимпийский комитет России объявил о переходе на азиатскую систему лицензирования. Спортсмены смогут отбираться на Игры-2026 через квалификации в Китае.', '2026-04-22 21:11:21.272878'::timestamp, 293);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1930, 'Фигуристка Камила Валиева вернулась на лёд после дисквалификации. На контрольных прокатах она чисто исполнила четверной тулуп.', '2026-04-22 21:11:24.260420'::timestamp, 293);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1931, 'Российские хоккеисты выиграли Кубок Первого канала, обыграв сборную Беларуси в овертайме — 4:3. Победную шайбу забросил Кирилл Марченко.', '2026-04-22 21:11:27.573290'::timestamp, 293);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1932, 'Легкоатлетка Мария Ласицкене объявила о завершении карьеры. Трёхкратная чемпионка мира планирует заняться тренерской деятельностью.', '2026-04-22 21:11:31.003367'::timestamp, 293);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1933, 'ФИФА смягчила санкции в отношении российского футбола. Допуск юношеских сборных к международным турнирам может быть восстановлен в 2025 году.', '2026-04-22 21:11:34.486787'::timestamp, 293);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1934, 'В Париже прошла акция протеста фермеров против соглашения ЕС с МЕРКОСУР. Демонстранты перекрыли трассы и вылили молоко на улицы.', '2026-04-22 21:11:38.119057'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1935, 'Землетрясение магнитудой 6,2 произошло в центральной части Японии. Жертв нет, но повреждены несколько десятков домов, прервано движение поездов.', '2026-04-22 21:11:41.769567'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1936, 'Совет Безопасности ООН принял резолюцию о гуманитарных паузах в Газе. Документ поддержали 14 стран, воздержались США.', '2026-04-22 21:11:45.258269'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1937, 'В Индии открылся самый длинный в мире железнодорожный тоннель под водой — 12 километров. Он соединит Мумбаи с пригородом через залив.', '2026-04-22 21:11:48.311410'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1938, 'Президент Бразилии объявил о вступлении страны в ОПЕК+. Бразилия станет 24-м участником соглашения с 1 января 2025 года.', '2026-04-22 21:11:51.794583'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1939, 'Великобритания и Германия подписали двустороннее соглашение о борьбе с нелегальной миграцией. Лондон обязался выплатить Берлину 500 млн евро.', '2026-04-22 21:11:54.993057'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1940, 'Биологи МГУ расшифровали геном сибирского шелкопряда. Открытие поможет в создании биопестицидов для защиты лесов.', '2026-04-22 21:11:58.555146'::timestamp, 295);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1941, 'Миссия «Луна-27» стартует в декабре 2025 года. Посадочный модуль доставит буровую установку для поиска водяного льда на южном полюсе спутника.', '2026-04-22 21:12:01.934513'::timestamp, 295);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1942, 'Физики из Новосибирска создали сверхпроводник, работающий при температуре -20°C. Разработка может применяться в квантовых компьютерах.', '2026-04-22 21:12:05.313180'::timestamp, 295);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1943, 'Археологи нашли в Хакасии нетронутое курганное захоронение скифского времени. В погребальной камере обнаружены золотые украшения и оружие.', '2026-04-22 21:12:08.166495'::timestamp, 295);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1944, 'Учёные СПбГУ запатентовали способ переработки пластика с помощью бактерий. Микроорганизмы разлагают ПЭТ-бутылки за 10 дней.', '2026-04-22 21:12:11.151064'::timestamp, 295);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1945, 'Телескоп «Джеймс Уэбб» обнаружил в атмосфере экзопланеты K2-18b признаки диметилсульфида — газа, который на Земле производят только микроорганизмы.', '2026-04-22 21:12:14.325822'::timestamp, 295);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1946, 'Минздрав утвердил новый порядок диспансеризации: добавлены скрининг на гепатит С и тест на ВИЧ для всех взрослых раз в три года.', '2026-04-22 21:12:18.013676'::timestamp, 296);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1947, 'В десяти регионах запустят программу бесплатного переобучения предпенсионеров. Курсы по IT и менеджменту будут длиться до 6 месяцев.', '2026-04-22 21:12:20.983118'::timestamp, 296);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1948, 'Росстат: естественная убыль населения сократилась на 12% по сравнению с прошлым годом. Рост рождаемости отмечен в 14 субъектах.', '2026-04-22 21:12:23.850562'::timestamp, 296);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1949, 'Минпросвещения ввело новый предмет «Семьеведение» в старших классах. Курс будет включать основы психологии и бюджетирования.', '2026-04-22 21:12:26.923092'::timestamp, 296);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1950, 'В Москве открылся первый в России хоспис для детей с онкологическими заболеваниями. Центр рассчитан на 60 коек с паллиативной помощью.', '2026-04-22 21:12:30.320250'::timestamp, 296);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1951, 'Пенсионный фонд начал проактивно назначать выплаты по инвалидности без заявления. Данные поступают из медицинских учреждений автоматически.', '2026-04-22 21:12:33.888230'::timestamp, 296);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1952, 'Роснефть начала бурение новой скважины на месторождении им. Требса и Титова. Запасы оцениваются в 20 млн тонн нефти.', '2026-04-22 21:12:37.576097'::timestamp, 297);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1953, 'Евросоюз сократил импорт российского СПГ на 25% за последние полгода. Альтернативой стал газ из Катара и США, но он на 40% дороже.', '2026-04-22 21:12:40.749822'::timestamp, 297);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1954, 'Запущена первая очередь ветропарка в Калмыкии мощностью 100 МВт. Проект реализован при поддержке «Росатома».', '2026-04-22 21:12:44.334169'::timestamp, 297);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1955, 'Правительство утвердило энергостратегию до 2040 года с акцентом на ВИЭ и атомную энергетику. Доля безуглеродной генерации вырастет до 40%.', '2026-04-22 21:12:48.027747'::timestamp, 297);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1956, 'Китай и Россия обсуждают строительство гидроаккумулирующей станции в Приамурье. Проект поможет балансировать энергосистемы двух стран.', '2026-04-22 21:12:51.813221'::timestamp, 297);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1957, 'МЭА прогнозирует пик спроса на нефть в 2028 году. Далее начнётся постепенное снижение из-за перехода на электромобили и возобновляемую энергетику.', '2026-04-22 21:12:54.985543'::timestamp, 297);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1958, 'В Москве запустили бесплатные автобусы до строящихся станций БКЛ. Маршруты синхронизированы с графиком закрытия участков метро.', '2026-04-22 21:12:58.470066'::timestamp, 298);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1959, 'Мэрия Казани представила проект велодорожек на набережной протяжённостью 22 км. Строительство завершится к лету 2025 года.', '2026-04-22 21:13:02.170304'::timestamp, 298);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1960, 'Петербург утвердил программу реновации пяти хрущёвок на Васильевском острове. Жильцов переселят в новый микрорайон с паркингом.', '2026-04-22 21:13:05.660837'::timestamp, 298);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1961, 'В Новосибирске заработал первый в Сибири трамвай на водородных топливных элементах. Запас хода — 250 км, заправка занимает 5 минут.', '2026-04-22 21:13:09.348468'::timestamp, 298);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1962, 'Красноярск вошёл в число городов — участников федерального проекта «Умный город». Планируется внедрение систем учёта ресурсов и видеонаблюдения.', '2026-04-22 21:13:12.295764'::timestamp, 298);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1963, 'Минстрой предложил обязать застройщиков устанавливать зарядные станции для электромобилей во всех новых ЖК. Норма начнёт действовать с 1 июля 2025 года.', '2026-04-22 21:13:15.674621'::timestamp, 298);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1964, 'Минобороны получило первую партию истребителей Су-57 с новым двигателем «Изделие 30». Машины поступят в авиаполк Южного военного округа.', '2026-04-22 21:13:18.848770'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1965, 'Армия США испытала гиперзвуковую ракету AGM-183A ARRW. Изделие достигло скорости 6 Махов на высоте 30 км.', '2026-04-22 21:13:22.537140'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1966, 'В Каспийском море прошли совместные учения ВМФ России, Ирана и Азербайджана. Отработана оборона нефтяных платформ.', '2026-04-22 21:13:25.908649'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1967, 'Разработан новый бронежилет «Оберег» для военной полиции. Он защищает от ножа и автоматной очереди на дистанции 10 метров.', '2026-04-22 21:13:29.311203'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1968, 'Шойгу анонсировал серийное производство беспилотников «Ланцет-3» с дальностью 100 км. Устройства оснащены системой искусственного интеллекта.', '2026-04-22 21:13:32.983924'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1969, 'Пентагон разместит ракеты средней дальности в Германии с 2026 года. Москва заявила об ответных мерах, включая размещение «Искандеров» в Калининграде.', '2026-04-22 21:13:36.466144'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1970, 'Росприроднадзор оштрафовал завод «Норникель» на 10 млрд рублей за разлив топлива в Норильске. Деньги направят на очистку рек.', '2026-04-22 21:13:39.759079'::timestamp, 300);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1971, 'В Баренцевом море стартовала программа по восстановлению популяции трески. За пять лет планируется выпустить 50 млн мальков.', '2026-04-22 21:13:43.432239'::timestamp, 300);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1972, 'Минприроды создаст национальный парк «Кузнецкий Алатау» для защиты сибирского кедра и снежного барса. Площадь — 500 тыс. гектаров.', '2026-04-22 21:13:47.014260'::timestamp, 300);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1973, 'Уровень загрязнения воздуха в Красноярске снизился на 20% после запуска программы «Чистый воздух». Основной эффект дал перевод ТЭЦ на газ.', '2026-04-22 21:13:50.397440'::timestamp, 300);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1974, 'США и Канада договорились ограничить вылов лосося в Тихом океане. Квоты сократят на 15% для сохранения популяции.', '2026-04-22 21:13:53.469152'::timestamp, 300);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1975, 'Гринпис опубликовал отчёт о загрязнении Волги микропластиком. В пробах воды из 20 городов найдены частицы в концентрации до 10 частиц на литр.', '2026-04-22 21:13:56.744755'::timestamp, 300);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1976, 'Telegram ввёл платную подписку «Premium+» за 799 рублей в месяц. Абоненты получат расширенный доступ к управлению каналами и ускоренное модерарование.', '2026-04-22 21:14:00.124769'::timestamp, 301);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1977, 'Роскомнадзор включил видеохостинг Vimeo в реестр нарушителей. Сервис ограничат за отказ удалять запрещённый контент.', '2026-04-22 21:14:03.436364'::timestamp, 301);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1978, 'Первый канал объявил о запуске онлайн-кинотеатра с отечественными фильмами. Библиотека включает 5000 наименований, цена подписки — 399 руб.', '2026-04-22 21:14:06.879848'::timestamp, 301);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1979, 'Совет по правам человека при ООН призвал Meta* (*признана экстремистской в РФ) обеспечить прозрачность модерации в российском сегменте.', '2026-04-22 21:14:09.855409'::timestamp, 301);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1980, 'Рейтинг самых цитируемых СМИ за май: ТАСС, «РИА Новости» и «Коммерсантъ» сохранили лидерство. Упоминаемость выросла на 12% из-за выборов.', '2026-04-22 21:14:12.720371'::timestamp, 301);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1981, 'YouTube запустил функцию автоматического перевода субтитров на 50 языков, включая русский. Пока тестируется на обучающих каналах.', '2026-04-22 21:14:15.895823'::timestamp, 301);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1982, 'Верховный суд разъяснил правила признания сделок с недвижимостью недействительными при банкротстве физлиц. Акцент сделан на добросовестность покупателя.', '2026-04-22 21:14:20.401813'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1983, 'Госдума приняла закон об ужесточении наказания за повторную езду в нетрезвом виде. Максимальный срок увеличивается до 3 лет лишения свободы.', '2026-04-22 21:14:23.474630'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1984, 'Минюст зарегистрировал поправки о внесудебном блокировании сайтов с фейками о ветеранах. Решение будет принимать генпрокурор или его замы.', '2026-04-22 21:14:26.931233'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1985, 'Конституционный суд признал законным досудебное изъятие имущества по делам о коррупции. Имущество можно вернуть только через суд после оправдания.', '2026-04-22 21:14:29.987409'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1986, 'ЕСПЧ присудил 50 тыс. евро российскому активисту за незаконное административное задержание. Решение вступило в силу, исполнение под вопросом.', '2026-04-22 21:14:33.306849'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1987, 'В Арбитражный процессуальный кодекс внесены изменения о дистанционных заседаниях. Стороны смогут участвовать через Госуслуги с биометрией.', '2026-04-22 21:14:36.932047'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1988, 'Россия и Китай запускают безвизовый режим для туристических групп от трёх человек. Срок пребывания — до 15 дней.', '2026-04-22 21:14:40.170489'::timestamp, 303);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1989, 'Авиакомпания «Россия» открыла прямые рейсы из Москвы в Хабаровск на Superjet-100. Полёт займёт 7 часов 20 минут.', '2026-04-22 21:14:43.548745'::timestamp, 303);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1990, 'В Карелии открылся круглогодичный курорт «Белые скалы» с термальными источниками. Инвестиции в проект составили 2 млрд рублей.', '2026-04-22 21:14:46.799399'::timestamp, 303);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1991, 'Ростуризм предложил субсидировать внутренние туры для пенсионеров. Компенсация может достигать 50% стоимости путёвки.', '2026-04-22 21:14:49.908524'::timestamp, 303);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1992, 'Поезд «Сапсан» начал курсировать между Петербургом и Выборгом. Время в пути — 1 час 15 минут, цена билета от 600 рублей.', '2026-04-22 21:14:53.381224'::timestamp, 303);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1993, 'Турция возобновила авиасообщение с 20 российскими городами, включая Новосибирск, Казань и Екатеринбург. Туристов ждут 90 отелей по системе «всё включено».', '2026-04-22 21:14:56.453786'::timestamp, 303);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1994, 'Выборы в местные советы показали явку 34% — это новый антирекорд. Люди устали от однотипных программ и обещаний, которые никто не выполняет.', '2026-04-22 21:15:02.803597'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1995, 'Почему кандидат Петров проиграл в своём округе? Потому что его штаб сделал ставку на грязный пиар вместо реальных встреч с людьми. Электорат чувствует фальшь.', '2026-04-22 21:15:05.994858'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1996, 'Сравниваю предвыборные программы трёх основных партий. Различия только в цветах брошюр, экономические пункты списаны с одного документа под копирку.', '2026-04-22 21:15:08.949404'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1997, 'Закон о лоббизме предлагают принять уже 15 лет. Ни одна фракция не заинтересована в прозрачности, потому что все получают деньги от крупного бизнеса.', '2026-04-22 21:15:12.243753'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1998, 'Интересный феномен: в соцсетях политики пишут одно, на встречах с избирателями — другое, а в кулуарах — третье. Запоминается только последнее, но до него никто не докопается.', '2026-04-22 21:15:16.016572'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (1999, 'Рейтинг президента упал на 7% за квартал. Причина не в оппозиции, а в том, что люди не видят улучшения в своих кошельках и больницах.', '2026-04-22 21:15:19.190375'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2000, 'Дебаты на федеральном канале превратились в шоу. Вместо аргументов — оскорбления, вместо фактов — крики. Зрители выключают телевизор через 10 минут.', '2026-04-22 21:15:22.786644'::timestamp, 289);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2001, 'Миротворцы ООН в Конго выводятся после 20 лет присутствия. Ситуация не стабилизировалась, просто у мирового сообщества закончились деньги и интерес.', '2026-04-22 21:15:26.564826'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2002, 'Гуманитарный коридор в Газе работает с перебоями: за неделю пропустили только 20% обещанной помощи. Люди умирают от голода, пока дипломаты спорят о формулировках.', '2026-04-22 21:15:29.842239'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2003, 'Саммит БРИКС в этом году: 5 новых стран подали заявки. Западные санкции только ускорили создание альтернативных центров силы.', '2026-04-22 21:15:32.812916'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2004, 'Беженцы из Судана: 8 миллионов человек покинули дома за полгода. Соседние страны не справляются, лагеря переполнены, антисанитария.', '2026-04-22 21:15:36.193680'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2005, 'Интервью с командиром добровольческого батальона на Украине: «Нам не хватает дронов и шифровальной связи. Волонтёры закрывают 40% потребностей».', '2026-04-22 21:15:39.360673'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2006, 'Почему Европа не может отказаться от российского газа полностью? Потому что СПГ из США на 30% дороже, а регазификационные терминалы строятся годами.', '2026-04-22 21:15:42.541662'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2007, 'Дипломатический скандал: посла Франции отозвали из Нигера после того, как местные военные обвинили его в подкупе депутатов. Африка устала от неоколониализма.', '2026-04-22 21:15:45.445392'::timestamp, 294);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2008, 'Новый российский дрон «Охотник» прошел испытания: дальность 6000 км, скорость до 1000 км/ч, боевая нагрузка 2 тонны. Беспилотная авиация меняет правила войны.', '2026-04-22 21:15:50.120751'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2009, 'Расходы НАТО на оборону: 2% ВВП теперь недостаточно. Генсек требует 3%, но страны Балтии и так едва сводят концы с концами.', '2026-04-22 21:15:53.539661'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2010, 'Военный переворот в Габоне: французский легион выведен из страны. Африканские режимы больше не хотят содержать иностранные базы на своей территории.', '2026-04-22 21:15:56.881578'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2011, 'Анализ потерь бронетехники в текущем конфликте: танки без защиты от дронов становятся просто дорогими мишенями. Нужны новые концепции.', '2026-04-22 21:15:59.925930'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2012, 'Корабли Черноморского флота: 5 единиц выведены из Севастополя в Новороссийск после атак безэкипажных катеров. Бухта больше не является безопасной гаванью.', '2026-04-22 21:16:03.555418'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2013, 'США передают Тайваню ракеты Harpoon. Китай проводит военные учения вокруг острова. Эскалация в Азии набирает обороты.', '2026-04-22 21:16:07.035654'::timestamp, 299);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2014, 'Верховный суд разрешил изымать земельные участки для госнужд по цене в 2 раза ниже рыночной. Малый бизнес разорён.', '2026-04-22 21:16:10.712090'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2015, 'Поправки в УК: статья о «фейках» теперь грозит сроком до 15 лет. Адвокаты говорят о расплывчатых формулировках — под статью можно подвести любую критику.', '2026-04-22 21:16:13.781959'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2016, 'Закон о домашнем насилии снова отложен. В комитете посчитали, что «вмешательство в семью» недопустимо, несмотря на тысячи погибших женщин.', '2026-04-22 21:16:16.852599'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2017, 'Госдума приняла в первом чтении закон о цифровом профиле. Все данные граждан — от паспорта до медицинских анализов — будут в одной базе. Эксперты бьют тревогу об утечках.', '2026-04-22 21:16:20.337050'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2018, 'ЕСПЧ присудил компенсацию российским активистам: 300 тысяч евро за незаконные обыски. Россия заявила, что решение не будет исполнено.', '2026-04-22 21:16:23.716770'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2019, 'Судебные приставы начали блокировать банковские счета за долги по ЖКХ без предупреждения. Люди узнают об этом, когда карта не проходит в магазине.', '2026-04-22 21:16:27.109522'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2020, 'Новый КоАП: штраф за пропаганду «нетрадиционных ценностей» увеличен до 200 тысяч рублей. ЛГБТ-сообщество уходит в глубокое подполье.', '2026-04-22 21:16:30.269534'::timestamp, 302);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2021, 'Переговоры по Карабаху зашли в тупик. Азербайджан требует полного вывода армянских войск, Армения — международных гарантий. Париж и Вашингтон бессильны.', '2026-04-22 21:16:33.724932'::timestamp, 304);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2022, 'Саммит G20 в Дели: итоговая декларация принята без осуждения России. Страны Глобального Юга отказались от антироссийских формулировок.', '2026-04-22 21:16:36.824228'::timestamp, 304);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2023, 'Визит Эрдогана в Сочи: обсуждали зерновую сделку и газовый хаб. Турецкий лидер пытается играть роль посредника между Москвой и Киевом.', '2026-04-22 21:16:40.425291'::timestamp, 304);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2024, 'Китай и Афганистан: Пекин официально признал талибов. Взамен — доступ к редкоземельным металлам, которых в Афганистане на триллионы долларов.', '2026-04-22 21:16:44.025012'::timestamp, 304);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2025, 'Посол США в ООН заявила о «решительной поддержке» Украины. Но пакет помощи в 60 миллиардов долларов до сих пор не одобрен Конгрессом.', '2026-04-22 21:16:46.966362'::timestamp, 304);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2026, 'Минские соглашения: экс-канцлер Германии признал, что они были нужны только для того, чтобы выиграть время для укрепления Украины. Дипломатия как оружие.', '2026-04-22 21:16:50.036035'::timestamp, 304);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2027, 'Северная Корея закрыла свои посольства в 10 странах. Денег на дипломатов нет — всё уходит на ракетную программу.', '2026-04-22 21:16:53.417195'::timestamp, 304);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2028, 'Депутаты от «Единой России» внесли законопроект о QR-кодах. Общественная приёмная партии завалена гневными письмами — люди не хотят цифровых паспортов.', '2026-04-22 21:16:57.942470'::timestamp, 305);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2029, 'В Госдуме прошёл круглый стол по демографии. Пришли 12 депутатов из 450. Остальные были в регионах или на больничном — тема никому не интересна.', '2026-04-22 21:17:00.994569'::timestamp, 305);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2030, 'Фракция КПРФ потребовала вернуть советскую систему распределения выпускников вузов. «Это решит проблему кадрового голода», — заявил Зюганов.', '2026-04-22 21:17:04.173209'::timestamp, 305);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2031, 'Спикер парламента запретил журналистам снимать в зале заседаний. Теперь мы можем писать только текст по пресс-релизам — никаких живых эмоций.', '2026-04-22 21:17:07.771033'::timestamp, 305);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2032, 'Закон о QR-кодах отозван после массовых протестов. Депутаты испугались потерять рейтинги перед выборами. Народная воля сработала.', '2026-04-22 21:17:11.031756'::timestamp, 305);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2033, 'Парламентские слушания по пенсионной реформе: выступали 3 часа, изменений ноль. Пенсионный возраст повысили, а накопления заморозили до 2030 года.', '2026-04-22 21:17:14.412067'::timestamp, 305);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2034, 'Новый депутат от «Новых людей» предложил блокчейн для голосования. Старожилы засмеяли — им проще работать с бумажными бюллетенями и ручками.', '2026-04-22 21:17:17.381644'::timestamp, 305);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2035, 'Муниципальные выборы в 10 регионах: зафиксировано 300 жалоб на вбросы. ЦИК признал обоснованными 15. Остальные отклонили «за недостаточностью доказательств».', '2026-04-22 21:17:20.776564'::timestamp, 306);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2036, 'Явка на довыборах в Госдуму по одномандатному округу № 44 — 27%. Самый низкий показатель за 10 лет. Избиратели демонстрируют бойкот.', '2026-04-22 21:17:24.038560'::timestamp, 306);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2037, 'Электронное голосование в Москве: система дала сбой на 2 часа. Многие бюллетени ушли в «спецпапку». Наблюдатели не смогли проверить протоколы.', '2026-04-22 21:17:27.418661'::timestamp, 306);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2038, 'Опрос ВЦИОМ: 68% граждан хотят сменяемости власти, но только 12% верят, что выборы честные. Парадокс легитимности.', '2026-04-22 21:17:30.711988'::timestamp, 306);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2039, 'Партия «Яблоко» собрала подписи для участия в выборах в Петербурге. Избирком забраковал 40% из-за ошибок в оформлении — стандартная практика.', '2026-04-22 21:17:33.666195'::timestamp, 306);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2040, 'Технология «карусели» на выборах в Башкирии: автобусы с бюджетниками возили по 5-6 участкам. Зафиксировано на видео, но дела не завели.', '2026-04-22 21:17:37.740556'::timestamp, 306);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2041, 'Экзит-поллы независимых социологов разошлись с официальными результатами на 15-20%. Разрыв увеличивается от региона к региону.', '2026-04-22 21:17:40.734169'::timestamp, 306);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2042, 'Реформа местного самоуправления: глав городов больше не будут выбирать — назначать станет губернатор. Люди потеряют последнюю возможность влиять на власть.', '2026-04-22 21:17:44.346312'::timestamp, 307);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2043, 'Национальный проект «Образование»: деньги выделены, но школы в сёлах закрываются. 200 школ за год — это победа оптимизации над здравым смыслом.', '2026-04-22 21:17:47.557599'::timestamp, 307);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2044, 'Правительство обсуждает повышение НДФЛ до 18% для всех, а не только для богатых. Минфин ищет деньги, а бизнес уходит в тень.', '2026-04-22 21:17:50.770080'::timestamp, 307);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2045, 'Минздрав отчитался о снижении смертности. Независимые демографы говорят о манипуляции статистикой: из расчёта убрали ковидные смерти.', '2026-04-22 21:17:53.767426'::timestamp, 307);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2046, 'Государственная программа переселения соотечественников: за 5 лет приехало 200 тысяч, обещали 5 миллионов. Ни жилья, ни работы.', '2026-04-22 21:17:57.215393'::timestamp, 307);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2047, 'Цифровая экономика: 500 миллиардов рублей на IT-инфраструктуру. Деньги освоены, но «Госуслуги» до сих пор падают в первый час пиковых нагрузок.', '2026-04-22 21:18:00.566297'::timestamp, 307);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2048, 'Стратегия пространственного развития: Москва получит ещё 10% федеральных дотаций, а депрессивные моногорода — только обещания.', '2026-04-22 21:18:03.984330'::timestamp, 307);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2049, 'Китай и Россия провели совместные военные учения в Японском море. Япония выразила протест — Курилы снова стали точкой напряжения.', '2026-04-22 21:18:07.516313'::timestamp, 308);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2050, 'Индия закупает нефть у России по дисконту 30%, одновременно продавая оружие Тайваню. Искусство баланса в большом стиле.', '2026-04-22 21:18:10.626935'::timestamp, 308);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2051, 'США и Иран обменялись заключёнными. Сделка стала возможна после размораживания 6 миллиардов иранских активов. Дипломатия, а не бомбёжки.', '2026-04-22 21:18:14.058467'::timestamp, 308);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2052, 'Европа создаёт систему быстрого реагирования без США. Макрон и Шольц хотят стратегической автономии, но Боррель сомневается в финансировании.', '2026-04-22 21:18:17.502763'::timestamp, 308);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2053, 'Турция заблокировала вступление Швеции в НАТО после сожжения Корана в Стокгольме. Эрдоган использует любую возможность для торга.', '2026-04-22 21:18:20.739111'::timestamp, 308);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2054, 'Пакистан закупил у России нефть за рупии — обход доллара. Китай, Россия и Пакистан создают альтернативную финансовую систему.', '2026-04-22 21:18:24.062917'::timestamp, 308);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2055, 'Белоруссия разместила тактическое ядерное оружие. Польша требует пересмотра границ. Ситуация напоминает Карибский кризис, только в Европе.', '2026-04-22 21:18:27.311331'::timestamp, 308);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2056, 'Акция в поддержку Навального в 30 городах. Задержано 500 человек. Люди выходят, несмотря на уголовные статьи и огромные штрафы.', '2026-04-22 21:18:30.509877'::timestamp, 309);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2057, 'Либертарианская партия собрала 100 тысяч подписей за отмену QR-кодов. Власти проигнорировали петицию, сославшись на технический сбой.', '2026-04-22 21:18:33.997734'::timestamp, 309);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2058, 'В Петербурге задержали активистку, которая вывесила флаг Украины на Невском. Ей грозит до 5 лет по статье о дискредитации.', '2026-04-22 21:18:37.076679'::timestamp, 309);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2059, 'Протесты в Башкирии против мусорного полигона: силовики применили дубинки. Десятки пострадавших, местные жители требуют отставки чиновников.', '2026-04-22 21:18:40.049748'::timestamp, 309);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2060, 'Эко-активисты в Норильске перекрыли дорогу к комбинату. Их требования — закрыть опасное производство. Ответ властей — уголовные дела о хулиганстве.', '2026-04-22 21:18:43.226024'::timestamp, 309);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2061, 'Студенты МГУ вышли на митинг против платного образования. Администрация пообещала отчислить зачинщиков. Свобода слова только в учебниках.', '2026-04-22 21:18:46.399065'::timestamp, 309);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2062, 'Женщины-жены мобилизованных пикетируют Кремль: «Верните мужей с границы». Их не показывают по ТВ, но одиночные пикеты продолжаются месяцами.', '2026-04-22 21:18:49.664167'::timestamp, 309);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2063, 'Внутрипартийные выборы в «Единой России»: побеждают те, кто принёс больше денег в кассу. Демократия внутри партии давно умерла.', '2026-04-22 21:18:53.039821'::timestamp, 310);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2064, 'КПРФ раскололась на два крыла: старое (Зюганов) и новое (Грудинин). Спорят о возврате советской плановой экономики, но ни у кого нет реальной программы.', '2026-04-22 21:18:56.317668'::timestamp, 310);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2065, 'ЛДПР после смерти Жириновского потеряла 30% электората. Слуцкий не харизматичен, партия идёт к маргинализации.', '2026-04-22 21:18:59.493301'::timestamp, 310);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2066, '«Новые люди» пробуют занять нишу правого либерализма. Их спонсоры — IT-бизнесмены, которые хотят налоговых льгот и дешёвых кадров.', '2026-04-22 21:19:02.672976'::timestamp, 310);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2067, 'Справедливая Россия объединилась с «Патриотами». Результат — 3% в опросах. Объединение слабых не создало сильного игрока.', '2026-04-22 21:19:05.454573'::timestamp, 310);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2068, 'Партия «Яблоко» решила не участвовать в федеральных выборах — не хватает денег на агитацию. Региональное присутствие сокращается.', '2026-04-22 21:19:08.611921'::timestamp, 310);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2069, 'Монархическая партия подала заявку на регистрацию. Эксперты уверены, что это кремлёвский проект для отъема голосов у националистов.', '2026-04-22 21:19:11.696519'::timestamp, 310);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2070, 'Расследование о хищениях при строительстве космодрома Восточный: 10 миллиардов рублей разворованы. Уголовное дело закрыли за истечением срока.', '2026-04-22 21:19:15.162716'::timestamp, 311);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2071, 'Заместитель министра обороны задержан с 2 миллионами долларов в чемодане. В суде заявил, что это «подарок от друзей». Отпущен под подписку.', '2026-04-22 21:19:18.235375'::timestamp, 311);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2072, 'Госзакупки по нацпроекту «Здравоохранение»: томографы за 50 миллионов, рыночная цена — 15. Разница ушла в офшоры подставных фирм.', '2026-04-22 21:19:21.615592'::timestamp, 311);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2073, 'Схема с землёй в Подмосковье: чиновники вывели 500 гектаров леса, продав его под коттеджи. Ущерб бюджету — 3 миллиарда.', '2026-04-22 21:19:25.508260'::timestamp, 311);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2074, 'Росгвардия закупила бронежилеты, которые не держат пули. Экспертиза показала подделку. Деньги вернули, но поставщик исчез за границей.', '2026-04-22 21:19:29.296402'::timestamp, 311);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2075, 'Декларации госслужащих: у 300 человек доходы выросли в 10 раз за год, хотя зарплаты индексировали на 4%. Ни одного запроса в прокуратуру.', '2026-04-22 21:19:32.474793'::timestamp, 311);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2076, 'Фонд «Сколково»: 15 миллиардов выделено на инновации, 14 ушли на зарплаты топ-менеджерам и «консалтинг» аффилированным фирмам.', '2026-04-22 21:19:36.261688'::timestamp, 311);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2077, 'Путин объявил о «традиционных ценностях» как основе государства. Что это значит на практике? Уголовные статьи за ЛГБТ и доносы на учителей.', '2026-04-22 21:19:39.468575'::timestamp, 312);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2078, 'Идеология «русского мира» в школах: новый учебник истории говорит о «воссоединении» Крыма и «защите соотечественников». Любая критика вне закона.', '2026-04-22 21:19:42.407058'::timestamp, 312);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2079, 'Консервативный поворот: РПЦ получила право veto на школьные учебники. Эволюцию заменили «Божьим промыслом», астрономию убрали.', '2026-04-22 21:19:45.361621'::timestamp, 312);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2080, 'Молодёжные движения: «Юнармия» и «Волонтёры Победы» воспитывают патриотов. Вместо дискуссий — строевая подготовка и портреты Сталина.', '2026-04-22 21:19:49.108743'::timestamp, 312);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2081, 'Почему либерализм в России непопулярен? Потому что 90-е ассоциируются с грабежом и беспределом. Народ хочет стабильности, даже ценой свободы.', '2026-04-22 21:19:52.034024'::timestamp, 312);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2082, 'Евразийство как альтернатива западному глобализму. Дугин и его последователи предлагают «особый путь» — изоляцию и мобилизационную экономику.', '2026-04-22 21:19:55.412691'::timestamp, 312);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2083, 'Коммунистическая идеология возвращается: 30% молодых людей положительно относятся к Сталину. Школы и ТВ создали культ личности заново.', '2026-04-22 21:19:58.297760'::timestamp, 312);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2084, '11-й пакет санкций ЕС: запрет на экспорт станков с ЧПУ и подшипников. Россия переходит на китайские аналоги, но качество ниже.', '2026-04-22 21:20:01.661619'::timestamp, 313);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2085, 'Россия запустила параллельный импорт: товары везут через Казахстан и Армению. Таможенные пошлины выросли, дефицита нет, но цены выше на 20%.', '2026-04-22 21:20:04.735714'::timestamp, 313);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2086, 'США ввели санкции против 12 российских банков. МИД России назвал это «актом экономической агрессии». Китай не присоединился.', '2026-04-22 21:20:07.808108'::timestamp, 313);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2087, 'Турецкий бизнес уходит из России под давлением американских вторичных санкций. Строительные контракты заморожены, заводы остановлены.', '2026-04-22 21:20:10.572748'::timestamp, 313);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2088, 'Эффект санкций: импорт в Россию упал на 40%, но внутреннее производство выросло лишь на 5%. Качество товаров снизилось, ассортимент обеднел.', '2026-04-22 21:20:13.618136'::timestamp, 313);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2089, 'Южная Корея запретила поставки чипов в Россию. «Микрон» пытается освоить 65-нм технологию — отставание от мира на 15 лет.', '2026-04-22 21:20:16.409059'::timestamp, 313);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2090, 'Заморозка золотовалютных резервов на 300 миллиардов долларов. Россия судится в Европейском суде, но шансы близки к нулю.', '2026-04-22 21:20:19.481349'::timestamp, 313);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2091, 'Закон о суверенном рунете: Роскомнадзор может отключать страну от глобальной сети. Тестирование прошло успешно, но интернет замедлился на 30%.', '2026-04-22 21:20:22.965850'::timestamp, 314);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2092, 'Выход из Совета Европы: Россия больше не связана решениями ЕСПЧ. Правозащитники бьют тревогу — власть получила карт-бланш.', '2026-04-22 21:20:26.343721'::timestamp, 314);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2093, 'Собственные платёжные системы: МИР и СПФС. Транзакции внутри страны идут, но за границей карты МИР перестали работать с 2024 года.', '2026-04-22 21:20:29.519918'::timestamp, 314);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2094, 'Импортозамещение в авиации: Суперджет-100 теперь на 60% из российских деталей. Но двигатель ПД-14 всё ещё требует доработок.', '2026-04-22 21:20:33.102193'::timestamp, 314);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2095, 'Продовольственная безопасность: Россия закрыла импорт овощей и фруктов из Европы. Своих теплиц не хватает, цены на помидоры выросли вдвое.', '2026-04-22 21:20:36.380507'::timestamp, 314);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2096, 'Военный суверенитет: производство дронов и боеприпасов наращено в 10 раз. Но станки и микрочипы всё ещё импортные — уязвимость сохраняется.', '2026-04-22 21:20:40.172621'::timestamp, 314);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2097, 'Культурный суверенитет: западные фильмы и музыку запрещают, заменяя на отечественные. Молодёжь переходит на пиратские сайты и VPN.', '2026-04-22 21:20:43.447920'::timestamp, 314);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2098, 'Billboard Hot 100 на этой неделе: Тейлор Свифт снова на вершине, 12-я неделя подряд. Рекорд для артистки 2020-х.', '2026-04-22 21:20:50.208525'::timestamp, 315);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2099, 'Spotify удалил 7% треков из-за накрутки стримов. Независимые исполнители теряют до 40% доходов — платформа борется с ботоводством.', '2026-04-22 21:20:53.792083'::timestamp, 315);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2100, 'Почему песни стали короче? Средняя длина хита упала с 4:30 до 2:45 за 10 лет. TikTok диктует: припев должен начинаться через 15 секунд.', '2026-04-22 21:20:56.977823'::timestamp, 315);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2101, 'Сравниваю последние альбомы Дуа Липы и Оливии Родриго. У Дуа — танцевальный фьюжн, у Оливии — эмоциональный поп-панк. Оба в топе, но аудитория почти не пересекается.', '2026-04-22 21:20:59.936014'::timestamp, 315);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2102, 'Тренд года: AI-вокал в поп-музыке. Голосовые модели Гранде и Уикенда уже используют без разрешения. Лейблы в панике, суды неизбежны.', '2026-04-22 21:21:04.034065'::timestamp, 315);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2103, 'Ремикс на сингл Билли Айлиш от Charli XCX взорвал тикток. 50 миллионов просмотров за 3 дня. Старая школа не верит, но алгоритмы любят коллаборации.', '2026-04-22 21:21:06.900219'::timestamp, 315);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2104, 'Кантри-поп возвращается: Beyoncé выпустила Texas Hold ''Em, и это лучший её трек за 5 лет. Кроссовер жанров — новая ниша для чартов.', '2026-04-22 21:21:10.179985'::timestamp, 315);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2105, 'Вокал в современном попе: автотюн уже не эффект, а норма. Адель и Сэм Смит — редкие исключения, которые поют живьём без поправок.', '2026-04-22 21:21:13.673479'::timestamp, 316);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2106, 'Разбираю припев ''Flowers'' Майли Сайрус. Простая мелодия на пяти нотах, но запоминается с первого раза. Гениально для радиоформата.', '2026-04-22 21:21:16.936622'::timestamp, 316);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2107, 'Почему у The Weeknd такой уникальный тембр? Он использует фальцет в 70% партий и добавляет лёгкую дисторсию. Результат — звук, который не спутаешь.', '2026-04-22 21:21:20.110333'::timestamp, 316);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2108, 'Оливия Родриго поёт с надрывом, как будто ей 15 и ей разбили сердце. Это работает, потому что она искренна. Молодёжь чувствует фальшь за версту.', '2026-04-22 21:21:23.594626'::timestamp, 316);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2109, 'Гармонии в песнях Little Mix — лучшие в поп-группах после Destiny''s Child. Их менеджмент разругался, но музыка останется.', '2026-04-22 21:21:27.081309'::timestamp, 316);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2110, 'Ариана Гранде расширила диапазон на альбоме ''Eternal Sunshine''. Теперь она берёт ноты второй октавы — раньше держалась в третьей-четвёртой. Взросление вокалистки.', '2026-04-22 21:21:30.666975'::timestamp, 316);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2111, 'Джастин Бибер поёт с носовым резонатором, и это его фишка. Без неё он был бы обычным тенором.', '2026-04-22 21:21:33.731915'::timestamp, 316);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2112, 'Глобальный стриминг вырос на 12% за квартал. Латинская поп-музыка (Bad Bunny, Karol G) дала 40% прироста — англоязычный рынок стагнирует.', '2026-04-22 21:21:37.010805'::timestamp, 317);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2113, 'Billboard изменил правила: теперь 1000 премиум-стримов = 1 продажа. Инди-артисты в шоке: их рейтинг упал на 30 позиций за ночь.', '2026-04-22 21:21:40.287053'::timestamp, 317);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2114, 'K-pop доминирует в YouTube: 8 из 10 самых просматриваемых видео за месяц — клипы BTS, Blackpink, NewJeans. Фанаты организовали массовый стриминг.', '2026-04-22 21:21:43.577784'::timestamp, 317);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2115, 'Чарты Apple Music в России: INSTASAMKA и Anna Asti вытеснили Моргенштерна. Текст на русском с элементами трэпа — новый мейнстрим.', '2026-04-22 21:21:46.847502'::timestamp, 317);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2116, 'UK Singles Chart: 5 песен в топ-10 — это ремиксы старых хитов. Кризис идей? Или ностальгия стала прибыльнее инноваций.', '2026-04-22 21:21:49.912546'::timestamp, 317);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2117, 'Стриминговая инфляция: за неделю можно набрать 10 миллионов прослушиваний, если твой трек попал в плейлист ''Today''s Top Hits''. Вопрос денег, а не качества.', '2026-04-22 21:21:53.394362'::timestamp, 317);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2118, 'Как сделан бит ''Blinding Lights''? Синтезатор с эффектом хоруса, драм-машина LinnDrum и бас-линия на аналоговом Moog. Весь секрет в компрессии.', '2026-04-22 21:21:56.979360'::timestamp, 318);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2119, 'Сведение вокала в песнях Дуа Липы: двойной трек, лёгкий реверб и де-эссер на 6 кГц. Голос становится объёмным, но не резким.', '2026-04-22 21:22:00.051528'::timestamp, 318);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2120, 'Почему все хэйтеры говорят, что ''минусовка под фонограмму''? Потому что сцена не подготовлена: мониторы кривые, звукорежиссёр спит.', '2026-04-22 21:22:03.943786'::timestamp, 318);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2121, 'Мастеринг для Spotify: нужно оставлять -1 dB TP, иначе платформа режет пики и звук становится плоским. Многие артисты об этом не знают.', '2026-04-22 21:22:07.528332'::timestamp, 318);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2122, 'Sidechain-компрессия в танцевальной поп-музыке: когда бас «качает» под кик. Делает трек энергичным, но на дешёвых колонках теряется.', '2026-04-22 21:22:11.828128'::timestamp, 318);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2123, 'Использование вокодера у Daft Punk и у Kanye West — небо и земля. У первых он мягкий, у второго агрессивный. Техника одна, контекст решает.', '2026-04-22 21:22:14.916057'::timestamp, 318);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2124, 'Лимитер на шине делает громкость, но убивает динамику. Современный поп сжат до 6 LUFS — это предел для человеческого уха.', '2026-04-22 21:22:18.382434'::timestamp, 318);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2125, 'Тейлор Свифт заработала 200 миллионов долларов за тур ''Eras''. Билеты проданы на год вперёд. Вторичный рынок продаёт места по 5000 долларов.', '2026-04-22 21:22:21.659936'::timestamp, 319);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2126, 'Скандал: менеджер Дуа Липы требовал 50% за организацию встреч с фанатами. Артистка уволила его после слива переписки.', '2026-04-22 21:22:25.452633'::timestamp, 319);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2127, 'Почему звёзды 2000-х (Бритни, Кристина) не могут повторить успех? Индустрия стала другой: сейчас нужен не голос, а образ в TikTok.', '2026-04-22 21:22:28.791748'::timestamp, 319);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2128, 'Эд Ширан написал 30 песен за 2 месяца в карантине. 10 из них стали хитами. Секрет: ежедневный челлендж — написать куплет до завтрака.', '2026-04-22 21:22:32.004282'::timestamp, 319);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2129, 'Канье Уэст снова в центре скандала: его лейбл отказывается выпускать альбом из-за антисемитских строчек. Артист грозит судом.', '2026-04-22 21:22:35.077566'::timestamp, 319);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2130, 'Леди Гага после роли в ''Joker 2'' призналась, что принимает антидепрессанты. Слава — это не только красные дорожки, но и панические атаки.', '2026-04-22 21:22:38.561501'::timestamp, 319);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2131, 'Шон Мендес и Камила Кабельо расстались, но продолжают выпускать дуэты. Фанаты в шоке: это пиар или настоящая дружба?', '2026-04-22 21:22:42.477032'::timestamp, 319);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2132, 'Мадонна в 40 лет записала ''Hung Up'' — лучший танцевальный хит десятилетия. Сейчас 65-летняя певица всё ещё на сцене, но уже без былой формы.', '2026-04-22 21:22:46.151973'::timestamp, 320);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2133, 'Влияние Майкла Джексона на современный поп: от бита в ''Billie Jean'' до вокальных приёмов The Weeknd. Его звук живёт в каждом артисте.', '2026-04-22 21:22:49.723286'::timestamp, 320);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2134, 'Почему 80-е снова в моде? Синтвейв и ретро-поп захватили чарты. Dua Lipa, The Weeknd, Bruno Mars — все оглядываются назад.', '2026-04-22 21:22:52.897082'::timestamp, 320);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2135, 'Группа ABBA распалась в 1982 году, а в 2021 выпустила альбом ''Voyage''. И он стал платиновым. Возвращение легенд — тренд десятилетия.', '2026-04-22 21:22:55.968161'::timestamp, 320);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2136, 'Джордж Майкл был поп-иконой, но умер в одиночестве. Его ''Careless Whisper'' до сих пор самая заказываемая песня на радио.', '2026-04-22 21:22:59.466755'::timestamp, 320);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2137, 'Бойз-бенды 90-х: Backstreet Boys и NSYNC. У них были вокальные аранжировки, которые современные группы не могут повторить.', '2026-04-22 21:23:02.845494'::timestamp, 320);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2138, 'Стиви Уандер подарил поп-музыке хроматическую гармонию. Без него не было бы ''Isn''t She Lovely'' и половины соула.', '2026-04-22 21:23:06.533714'::timestamp, 320);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2139, 'BTS приостановили групповую деятельность ради сольников. Акции их лейбла HYBE упали на 30% за день — фанаты в истерике.', '2026-04-22 21:23:09.693690'::timestamp, 321);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2140, 'NewJeans — новый феномен K-pop: их песни длятся 2 минуты, нет припева в привычном смысле. И это работает, зумеры обожают.', '2026-04-22 21:23:12.764095'::timestamp, 321);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2141, 'Blackpink установили рекорд: их тур собрал 300 миллионов долларов. Четыре девушки принесли больше, чем некоторые рок-фестивали.', '2026-04-22 21:23:15.836334'::timestamp, 321);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2142, 'SM Entertainment внедряет AI-трене для айдолов: нейросеть анализирует танец и голос, подсказывает ошибки. Человеческих учителей уволят?', '2026-04-22 21:23:19.128943'::timestamp, 321);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2143, 'Почему J-pop не взлетел глобально? Потому что японские лейблы блокируют YouTube и Spotify. Корейцы, наоборот, открыли всё.', '2026-04-22 21:23:22.697715'::timestamp, 321);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2144, 'Токийский фестиваль Summer Sonic: на одной сцене выступают Stray Kids и Аврил Лавин. Кроссовер культур — залог успеха K-pop на Западе.', '2026-04-22 21:23:25.777029'::timestamp, 321);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2145, 'Лирика Тейлор Свифт: она пишет про бывших так подробно, что фанаты вычисляют их по датам и деталям. Искусство мести.', '2026-04-22 21:23:29.354969'::timestamp, 322);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2146, 'Песня ''Drivers License'' Оливии Родриго: текст написан от первого лица, каждая строчка — конкретный эпизод из её жизни. Поэтому так больно.', '2026-04-22 21:23:32.837063'::timestamp, 322);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2147, 'У Эда Ширана есть правило: не использовать слова ''love'', ''heart'', ''baby'' в припеве. Так он заставляет себя искать свежие метафоры.', '2026-04-22 21:23:35.709416'::timestamp, 322);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2148, 'Самый глупый текст в поп-музыке: ''Gucci Gang'' Лил Пампа. 50 повторений одного слова. Но это стало мемом и принесло миллионы.', '2026-04-22 21:23:39.173841'::timestamp, 322);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2149, 'Лана Дель Рей пишет как поэт-символист: ''My pussy tastes like Pepsi Cola'' — это не про колу, а про американскую мечту. Не все понимают.', '2026-04-22 21:23:42.669340'::timestamp, 322);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2150, 'Сравнение текстов Адель и Арианы Гранде. Адель — про боль и принятие, Ариана — про власть и удовольствие. Разные поколения, разные ценности.', '2026-04-22 21:23:45.742126'::timestamp, 322);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2151, 'Гарри Стайлс поёт ''Watermelon Sugar'' — бессмыслица, но британцы обожают абсурд. Иногда важен не смысл, а настроение.', '2026-04-22 21:23:48.711318'::timestamp, 322);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2152, 'Сценический костюм Бейонсе для Renaissance тура весит 15 кг, расшит стразами Сваровски вручную. За кулисами её переодевают 12 человек.', '2026-04-22 21:23:52.501620'::timestamp, 323);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2153, 'Модный тренд 2024: корсеты поверх платьев. Увидели у Дуа Липы, теперь все копируют. Инстаграм завален DIY-уроками.', '2026-04-22 21:23:55.470951'::timestamp, 323);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2154, 'Билли Айлиш отказалась от мешковатой одежды и вышла в платье от Gucci. Фанаты в шоке: ''Ты предала эстетику''. Но стиль эволюционирует.', '2026-04-22 21:23:58.748366'::timestamp, 323);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2155, 'Канье Уэст выпустил новую коллекцию Yeezy: серые балахоны без формы. Цена 800 долларов за кусок ткани. Фанаты раскупили за час.', '2026-04-22 21:24:01.980815'::timestamp, 323);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2156, 'Розовые волосы Лиззо стали её фишкой. Краситель приходится обновлять каждые 10 дней, иначе корни портят вид на сцене.', '2026-04-22 21:24:05.591183'::timestamp, 323);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2157, 'На красной дорожке Грэмми 2024 все в чёрном. Так артисты выражают протест против войны. Стиль как политическое высказывание.', '2026-04-22 21:24:08.712353'::timestamp, 323);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2158, 'Сникерсы от Balenciaga за 1200 долларов — это поп-культура. Носишь такую обувь — ты в тренде, даже если не слушаешь музыку.', '2026-04-22 21:24:11.958659'::timestamp, 323);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2159, 'Коачелла 2024: хедлайнеры — Bad Bunny, Blackpink, Фрэнк Оушен. Билеты взлетели до 2000 долларов за три дня. Пустыня станет бетонным полем.', '2026-04-22 21:24:15.544451'::timestamp, 324);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2160, 'Гластонбери в этом году побил рекорд: 250 тысяч зрителей. Организаторы увеличили количество туалетов в 2 раза, но очереди всё равно по часу.', '2026-04-22 21:24:19.024927'::timestamp, 324);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2161, 'Lollapalooza Индия: первый раз за пределами США. Местные власти выделили 50 миллионов на инфраструктуру. Надеются, что это поднимет туризм.', '2026-04-22 21:24:22.302418'::timestamp, 324);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2162, 'Трагедия на фестивале Astroworld: суд обязал Трэвиса Скотта выплатить компенсации 10 семей. С тех пор его концерты охраняют как президентские.', '2026-04-22 21:24:26.094408'::timestamp, 324);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2163, 'Tomorrowland построил новую сцену высотой с 10-этажный дом. Пиротехника на 2 миллиона евро. Электронная поп-музыка превратилась в цирк.', '2026-04-22 21:24:29.071019'::timestamp, 324);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2164, 'Фестиваль «Нашествие» в России: запрещены треки с ненормативной лексикой. Исполнители переписывают тексты прямо перед выходом на сцену.', '2026-04-22 21:24:32.441617'::timestamp, 324);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2165, 'Новичок Рене Рэпп выпустила дебютный сингл ''Snow Angel'' — и он сразу в топ-10. Её голос сравнивают с Леди Гагой в молодости.', '2026-04-22 21:24:36.028349'::timestamp, 325);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2166, 'Как стать популярным в TikTok: сними 30 секунд под бит, добавь трендовый танец. PinkPantheress так и сделала — теперь у неё миллионы стримов.', '2026-04-22 21:24:39.450610'::timestamp, 325);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2167, 'Первый альбом GAYLE ''abcdefu'' разошёлся тиражом в 500 тысяч копий. Ей всего 19 лет. Лейблы ищут следующую ''злую девочку''.', '2026-04-22 21:24:42.902121'::timestamp, 325);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2168, 'Платформа Bandcamp позволяет артистам зарабатывать напрямую, без посредников. Но инди-музыканты жалуются: трудно пробиться без плейлистов.', '2026-04-22 21:24:46.371114'::timestamp, 325);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2169, 'Студия звукозаписи для новичков в Москве стоит 3000 рублей в час. За 10 часов можно записать сингл, но сведение и мастеринг — отдельно.', '2026-04-22 21:24:49.853874'::timestamp, 325);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2170, 'Самый популярный способ раскрутки сейчас — коллаборация с блогером-миллионником. Один пост в Instagram стоит 20 тысяч долларов.', '2026-04-22 21:24:52.924583'::timestamp, 325);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2171, 'Битмейкинг в стиле тин-поп: драм-машина Roland TR-808, синтезатор Serum и сэмплы из старых записей. Джастин Бибер так сделал ''Sorry''.', '2026-04-22 21:24:56.303100'::timestamp, 326);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2172, 'Танцевальная поп-музыка 2024: темп 120-130 BPM, бас на каждой четверти, фортепиано в припеве. Dua Lipa и Ava Max используют один шаблон.', '2026-04-22 21:24:59.580834'::timestamp, 326);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2173, 'Диджейский сет на радио: нужно удержать слушателя 3 минуты. Поэтому треки сокращают до 2:30, убирая длинные интро и аутро.', '2026-04-22 21:25:02.653649'::timestamp, 326);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2174, 'Секвенсор Ableton Live — стандарт для продюсеров. Его session view позволяет экспериментировать с аранжировкой в реальном времени.', '2026-04-22 21:25:05.931166'::timestamp, 326);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2175, 'Ремикс на ''Unholy'' от Sam Smith сделал диджей Крис Лейк. Он добавил техно-бас, и трек зазвучал агрессивнее, чем оригинал.', '2026-04-22 21:25:09.002647'::timestamp, 326);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2176, 'Клубная поп-музыка сейчас — это смесь хауса и латино. Bad Bunny задал тренд, теперь все его копируют, но без души.', '2026-04-22 21:25:12.500246'::timestamp, 326);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2177, 'Коллаборация The Weeknd и Арианы Гранде ''Save Your Tears'' собрала миллиард стримов. Их голоса идеально сливаются в унисон на припеве.', '2026-04-22 21:25:16.393249'::timestamp, 327);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2178, 'Дуэт Шакиры и Карди Би ''Puntería'' — неожиданный хит. Латино и рэп перемешались в одном треке, и это работает.', '2026-04-22 21:25:20.370069'::timestamp, 327);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2179, 'Почему совместные альбомы редко бывают удачными? ''Everything Is Love'' Бейонсе и Jay-Z — исключение. Они женаты, поэтому искренни.', '2026-04-22 21:25:23.253988'::timestamp, 327);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2180, 'Elton John и Дуа Липа записали ''Cold Heart'' — ремейк его старой песни. 80-летний певец актуален, потому что выбирает правильных партнёров.', '2026-04-22 21:25:26.413940'::timestamp, 327);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2181, 'Самый неудачный дуэт: Канье и Тейлор на сцене VMA 2009. Они не пели вместе, но конфликт стал самым обсуждаемым событием года.', '2026-04-22 21:25:29.997123'::timestamp, 327);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2182, 'Билли Айлиш отказывается от дуэтов: ''Мой голос слишком специфичен''. Но спела с Labrinth — и получился хит. Значит, можно, если подобрать материал.', '2026-04-22 21:25:33.069606'::timestamp, 327);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2183, 'Универсальному лейблу принадлежит 30% мирового каталога поп-музыки. Антимонопольные иски не помогают — они выкупают конкурентов.', '2026-04-22 21:25:36.422796'::timestamp, 328);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2184, 'Артисты получают 12-16% от стримов. Остальное забирают лейбл, дистрибьютор и платформа. Инди-музыканты имеют 80% — но без раскрутки.', '2026-04-22 21:25:39.598642'::timestamp, 328);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2185, 'Spotify платит $0.003 - $0.005 за стрим. Чтобы заработать минимальную зарплату в США, нужно 6 миллионов прослушиваний в месяц.', '2026-04-22 21:25:43.105527'::timestamp, 328);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2186, 'Контракт 360: лейбл получает процент с туров, мерча и даже рекламных контрактов. Такой подписал Джастин Бибер в 17 лет — и потерял миллионы.', '2026-04-22 21:25:46.910907'::timestamp, 328);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2187, 'Блокчейн и NFT в музыке: попытка дать артистам прямой доход. Пока провал — фанаты не хотят покупать цифровые токены за 100 долларов.', '2026-04-22 21:25:50.069801'::timestamp, 328);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2188, 'Китайский рынок (Tencent Music) платит в 10 раз больше за стрим, чем Spotify. Западные лейблы активно подписывают китайских исполнителей.', '2026-04-22 21:25:53.356283'::timestamp, 328);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2189, 'Грэмми 2024: Тейлор Свифт получила ''Альбом года'' в 4-й раз — рекорд. Она обошла Фрэнка Синатру и Стиви Уандера.', '2026-04-22 21:25:56.845176'::timestamp, 329);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2190, 'BRIT Awards в этом году вручили награду ''Лучшему международному артисту'' Бейонсе, но она не приехала — была в туре. Скандал.', '2026-04-22 21:25:59.902628'::timestamp, 329);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2191, 'MTV VMA: лучший клип года — ''Flowers'' Майли Сайрус. Режиссёр снимал его одним дублем на iPhone. Бюджет 5000 долларов.', '2026-04-22 21:26:03.076377'::timestamp, 329);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2192, 'Премия ''Eurovision 2024'' прошла в Швеции. Победила группа из Финляндии с песней про троллей. Европа любит абсурд.', '2026-04-22 21:26:06.885309'::timestamp, 329);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2193, 'Вручение наград "Золотой граммофон" в Москве: Лобода и Киркоров получили статуэтки, хотя их треки не звучали на радио — куплено.', '2026-04-22 21:26:10.772633'::timestamp, 329);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2194, 'Премия Polar Music Prize присуждена 83-летнему Полу Саймону за вклад в поп-музыку. Он спел ''The Sound of Silence'' — зал плакал.', '2026-04-22 21:26:14.090533'::timestamp, 329);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2195, 'Третью неделю в зале. Научился не краснеть при виде гантелей. Прогресс?', '2026-04-22 21:26:20.258497'::timestamp, 330);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2196, 'Спросил у тренера, как качать пресс. Он сказал: «Начни с диеты». Больно, но честно.', '2026-04-22 21:26:22.841921'::timestamp, 330);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2197, 'Почему никто не предупредил, что после приседаний ноги не сгибаются два дня?', '2026-04-22 21:26:25.917256'::timestamp, 330);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2198, 'Жим лёжа 40 кг — мой личный рекорд. Через год будет 100, я верю.', '2026-04-22 21:26:28.986568'::timestamp, 330);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2199, 'В зале увидел мужика, который делает становую с весом как я. Он даже не вспотел. Куда я лезу?', '2026-04-22 21:26:32.161261'::timestamp, 330);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2200, 'Тренировка ног: сегодня попробовал выпады с гантелями. Теперь хожу как робот.', '2026-04-22 21:26:35.134106'::timestamp, 330);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2201, 'Заметил, что после тренировки сплю как убитый. И есть хочется постоянно. Норма?', '2026-04-22 21:26:38.306313'::timestamp, 330);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2202, '10 лет в зале. Понял главное: прогрессия нагрузок и сон важнее любых добавок.', '2026-04-22 21:26:41.585160'::timestamp, 331);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2203, 'Раньше гнался за весом на штанге. Сейчас — за качеством повторений. Разница колоссальная.', '2026-04-22 21:26:44.859915'::timestamp, 331);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2204, 'Спина — фундамент. Тренируй тяги, не забрасывай. Грудью качать легко, а спину — каждый ленится.', '2026-04-22 21:26:47.933024'::timestamp, 331);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2205, 'Подсушка перед летом: минус 8 кг за 3 месяца. Жир ушёл, сила почти не упала. Кето + дефицит.', '2026-04-22 21:26:51.520307'::timestamp, 331);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2206, 'Травма плеча год назад научила: разминка и мобильность — не для слабаков, а для умных.', '2026-04-22 21:26:54.490748'::timestamp, 331);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2207, 'Самый недооценённый снаряд в зале — эспандер для кистей. Хват становится стальным через месяц.', '2026-04-22 21:26:57.969158'::timestamp, 331);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2208, 'Совет новичкам: не копируйте программу профи. База 3 раза в неделю и сон — ваше всё.', '2026-04-22 21:27:00.954575'::timestamp, 331);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2209, 'Сегодня присел 200 кг на 5 раз. До соревнований осталось 6 недель, идём по плану.', '2026-04-22 21:27:04.318674'::timestamp, 332);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2210, 'Становая 240 — взял легко, но техника хромает. Спина округляется, надо работать над кором.', '2026-04-22 21:27:07.493706'::timestamp, 332);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2211, 'День жима: 140 на 3 раза. Застрял в середине, помог страховочный. Без понтов.', '2026-04-22 21:27:10.481030'::timestamp, 332);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2212, 'Травма приводящей мышцы — полгода восстановления. Теперь делаю гиперэкстензию и адукцию обязательно.', '2026-04-22 21:27:13.449493'::timestamp, 332);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2213, 'Экипировка: бинты на колени добавляют 15-20 кг к приседу. Но без них колени болят.', '2026-04-22 21:27:17.018245'::timestamp, 332);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2214, 'Соревновательный цикл: первая неделя — объём, вторая — интенсивность, третья — пик, четвёртая — разгрузка.', '2026-04-22 21:27:20.090296'::timestamp, 332);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2215, 'Лучший друг пауэрлифтера — массажный валик и поход к остеопату раз в месяц.', '2026-04-22 21:27:23.382462'::timestamp, 332);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2216, 'Люблю функционалку с собственным весом. Отжимания, выпады, бёрпи — и жир тает.', '2026-04-22 21:27:26.648494'::timestamp, 333);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2217, 'Раньше боялась брать гантели больше 5 кг. Оказалось, что 8 кг — это нормально, руки не станут мужскими.', '2026-04-22 21:27:29.820168'::timestamp, 333);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2218, 'Кардио после силовой — лучший жиросжигатель. 20 минут на беговой дорожке в наклоне творят чудеса.', '2026-04-22 21:27:33.317865'::timestamp, 333);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2219, 'Заметила, что когда тренируюсь утром до завтрака — энергия на весь день. Вечером уже не та активность.', '2026-04-22 21:27:36.375123'::timestamp, 333);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2220, 'Ягодичный мост с 40 кг — моя гордость. Форма попы меняется на глазах за 2 месяца.', '2026-04-22 21:27:39.447267'::timestamp, 333);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2221, 'Фитнес-бикини: сушка — это адский голод. Но когда видишь рельеф пресса, понимаешь, что оно того стоило.', '2026-04-22 21:27:42.621144'::timestamp, 333);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2222, 'Самый кайф — когда после тренировки мышцы приятно горят, и ты знаешь, что не зря встала в 6 утра.', '2026-04-22 21:27:45.708587'::timestamp, 333);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2223, 'Как тренер, чаще всего вижу ошибку: новички берут слишком большой вес и делают упражнения рывками. Техника важнее.', '2026-04-22 21:27:49.790143'::timestamp, 334);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2224, 'Совет клиентам: если у вас болит спина на следующий день после становой — вы делали её не спиной, а поясницей.', '2026-04-22 21:27:53.169922'::timestamp, 334);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2225, 'Программа для новичка на 3 месяца: база (жим, присед, тяга), 2-3 подхода, 8-12 повторений. Вес добавлять, когда легко.', '2026-04-22 21:27:56.242413'::timestamp, 334);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2226, 'Клиент пришёл с запросом «убрать живот». Объяснил, что локальное жиросжигание не работает. Нужен дефицит калорий.', '2026-04-22 21:27:59.420802'::timestamp, 334);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2227, 'Самое сложное — не составить программу, а заставить клиента спать 8 часов и есть белок.', '2026-04-22 21:28:03.016854'::timestamp, 334);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2228, 'Вижу, как парни делают бицепс с весом тела, раскачиваясь. Говорю: «Убери 20 кг и делай чисто». Обижаются.', '2026-04-22 21:28:06.075549'::timestamp, 334);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2229, 'Моя философия: зал — это не место для эго, а место для работы над собой. Оставьте понты за дверью.', '2026-04-22 21:28:09.456009'::timestamp, 334);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2230, 'Сегодня WOD: 21-15-9 бёрпи, становой тяги 100 кг и подтягиваний. Закончил за 14 минут, лёгкие горят.', '2026-04-22 21:28:12.831782'::timestamp, 335);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2231, 'Фран — это классика. 21-15-9 бёрпи и подъёмов гири 35 кг. Мой рекорд 4:30. Есть куда расти.', '2026-04-22 21:28:16.844109'::timestamp, 335);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2232, 'Двойные прыжки на скакалке научился только через месяц. Теперь это моё любимое кардио.', '2026-04-22 21:28:19.695277'::timestamp, 335);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2233, 'Кроссфит травмоопасен, если не следить за техникой. Особенно рывок и толчок. Много часов с палкой.', '2026-04-22 21:28:22.562596'::timestamp, 335);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2234, 'Отдых между раундами — не более 2 минут. Иначе теряется эффект функционального тренинга.', '2026-04-22 21:28:25.326838'::timestamp, 335);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2235, 'После открытого чемпионата мира по кроссфиту понял: моя слабость — гимнастика (выход силой, стойка на руках).', '2026-04-22 21:28:28.399092'::timestamp, 335);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2236, 'Самое крутое в кроссфите — дух сообщества. Все болеют за тебя, даже если ты последний.', '2026-04-22 21:28:31.166015'::timestamp, 335);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2237, 'Минус 15 кг за 5 месяцев. Рецепт: дефицит 500 ккал, 3 силовые в неделю и 10 тыс шагов.', '2026-04-22 21:28:34.442401'::timestamp, 336);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2238, 'Раньше ненавидел беговую дорожку. Теперь слушаю подкаст и бегаю 40 минут — кайф.', '2026-04-22 21:28:37.104706'::timestamp, 336);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2239, 'Первое время после похудения кожа обвисла. Но через полгода подтянулась, помогли упражнения на пресс.', '2026-04-22 21:28:39.973666'::timestamp, 336);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2240, 'Срыв на сладкое бывает. Главное — не винить себя и продолжить на следующий день. Один пирожное не решит всё.', '2026-04-22 21:28:42.941985'::timestamp, 336);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2241, 'Вода — недооценённый помощник. Пью 2.5 литра в день, аппетит стал меньше.', '2026-04-22 21:28:46.116257'::timestamp, 336);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2242, 'Вес встал плато на месяц. Увеличил кардио и убрал 100 ккал из рациона — пошёл снова.', '2026-04-22 21:28:49.190173'::timestamp, 336);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2243, 'Самый сложный этап — удержать результат после похудения. Тренировки теперь навсегда.', '2026-04-22 21:28:52.382827'::timestamp, 336);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2244, 'Массанабор: +5 кг за 3 месяца. Атлеты, не забывайте про спину и ноги, а не только грудью и бицепсом.', '2026-04-22 21:28:55.250940'::timestamp, 337);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2245, 'Питание на массе: 2 г белка на кг веса, 5 г углеводов, остальное жиры. Без этого мышцы не растут.', '2026-04-22 21:28:58.201477'::timestamp, 337);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2246, 'Креатин реально работает. После месяца приёма на жиме добавил 5 кг. Вода в мышцах, зато сила.', '2026-04-22 21:29:01.274735'::timestamp, 337);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2247, 'Периодизация: делаю 4 недели объёмного тренинга (12-15 повторов), потом 2 недели силового (5-8). Прогресс не стоит.', '2026-04-22 21:29:05.063325'::timestamp, 337);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2248, 'Руки выросли с 38 до 42 см за полгода. Секрет: базовые упражнения (тяга, жим, подтягивания), а не изоляция.', '2026-04-22 21:29:08.240726'::timestamp, 337);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2249, 'Тренируюсь 4 раза в неделю: грудь+трицепс, спина+бицепс, ноги, плечи+живот. Такой сплит уже 2 года.', '2026-04-22 21:29:11.310398'::timestamp, 337);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2250, 'Главное для роста — не только тренировки, но и сон. Если сплю 6 часов вместо 8 — результата нет.', '2026-04-22 21:29:14.295708'::timestamp, 337);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2251, 'Бегаю полумарафон. Силовые в зале 2 раза в неделю помогли укрепить кор и убрать боли в коленях.', '2026-04-22 21:29:17.455235'::timestamp, 338);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2252, 'Интервалы на беговой дорожке: 1 минута бег в темпе 5 мин/км, 2 минуты трусцой. Повторить 8 раз. Выносливость растёт.', '2026-04-22 21:29:20.803020'::timestamp, 338);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2253, 'Велотренировки 3 часа в зоне 2 пульса — лучшее жиросжигание и развитие капилляров.', '2026-04-22 21:29:24.009180'::timestamp, 338);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2254, 'Плавание после бега восстанавливает лучше, чем полный отдых. Активная регенерация.', '2026-04-22 21:29:26.980342'::timestamp, 338);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2255, 'Моя слабость — гибкость. Добавил 15 минут растяжки после каждой тренировки, колени и тазобедренные стали благодарить.', '2026-04-22 21:29:30.154672'::timestamp, 338);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2256, 'Экипировка для бега — не понты. Правильные кроссовки снимают нагрузку с позвоночника.', '2026-04-22 21:29:33.330405'::timestamp, 338);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2257, 'Темперамент выносливого атлета: не рвать с места, а держать ровный пульс и терпеть, когда хочется остановиться.', '2026-04-22 21:29:37.200102'::timestamp, 338);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2258, 'Гантели с дисками — классика. Регулируемые удобны, но со временем люфт. Лучше набор немых.', '2026-04-22 21:29:39.989883'::timestamp, 339);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2259, 'Тренажёр Смита — зло для приседаний. Фиксированная траектория не учитывает анатомию, травмирует колени.', '2026-04-22 21:29:42.853591'::timestamp, 339);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2260, 'Резиновые петли (TRX) — гениально для тренировки корпуса и подтягиваний, если нет турника.', '2026-04-22 21:29:45.721572'::timestamp, 339);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2261, 'Плиточный блин 20 кг должен иметь диаметр 450 мм. Китайские часто меньше — неудобно для становой.', '2026-04-22 21:29:48.998353'::timestamp, 339);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2262, 'Магнезия — дешёвое спасение для хвата. Без неё тяжёлая становая выскальзывает из рук.', '2026-04-22 21:29:52.192221'::timestamp, 339);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2263, 'Фитнес-браслеты врут на 15-20% по пульсу. Если нужна точность — нагрудный датчик.', '2026-04-22 21:29:55.658973'::timestamp, 339);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2264, 'Скамья для жима с регулировкой наклона — мастхэв для дома. Иначе плечи быстро убьёшь.', '2026-04-22 21:29:58.523011'::timestamp, 339);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2265, 'Разрыв мениска: полгода без приседаний. Теперь делаю выпады и присед с резиной — колено терпит.', '2026-04-22 21:30:01.800023'::timestamp, 340);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2266, 'Восстановление после эпикондилита (локоть теннисиста) заняло 4 месяца. Плавание и массаж, потом изометрические упражнения.', '2026-04-22 21:30:04.872328'::timestamp, 340);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2267, 'Травма поясницы: гиперэкстензия без веса, планка, подъёмы ног лёжа. Никакой становой полгода.', '2026-04-22 21:30:08.062595'::timestamp, 340);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2268, 'Самое сложное — не сорваться и не начать тренироваться через боль. Рецидив отбрасывает на месяцы.', '2026-04-22 21:30:11.442204'::timestamp, 340);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2269, 'Физиотерапевт сказал: «Слабые ягодицы — причина болей в пояснице». Работаю над ними каждый день.', '2026-04-22 21:30:14.805448'::timestamp, 340);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2270, 'Лед после тренировки снимает воспаление. 15 минут на больное место — и легче.', '2026-04-22 21:30:18.188282'::timestamp, 340);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2271, 'Возвращение к становой: начал с пустого грифа и делал по 10 повторений с идеальной техникой. Прибавлял по 5 кг в неделю.', '2026-04-22 21:30:21.873224'::timestamp, 340);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2272, 'До соревнований 8 недель. Сушка в самом разгаре: 1800 ккал, 200 г белка, углеводы только вокруг тренировки.', '2026-04-22 21:30:25.049528'::timestamp, 341);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2273, 'Поза вчера на протоколе: бицепс бедра всё ещё жидковат. Добавил сгибания ног лёжа и румынскую тягу.', '2026-04-22 21:30:28.135624'::timestamp, 341);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2274, 'Тренировки на рельеф: многоповторка (15-20) с малым отдыхом (30-45 сек). Жжение невыносимое, но это то что надо.', '2026-04-22 21:30:31.809300'::timestamp, 341);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2275, 'В день соревнований: нагрев, пампинг, углеводная загрузка за 2 часа. Креатин и кофеин за 30 минут.', '2026-04-22 21:30:34.779072'::timestamp, 341);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2276, 'Сценический загар — целое искусство. Второй слой наносим за 3 часа до выхода, третий — за час.', '2026-04-22 21:30:38.260432'::timestamp, 341);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2277, 'Психологически самое тяжелое — последние 2 недели, когда устал и голоден, а ещё надо улыбаться на сцене.', '2026-04-22 21:30:41.842861'::timestamp, 341);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2278, 'После соревнований — отрыв на 2 недели. Бургеры, мороженое и полный отдых. Затем снова в работу.', '2026-04-22 21:30:44.809373'::timestamp, 341);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2279, 'Ты можешь. Просто приди сегодня в зал. Даже 20 минут — уже победа.', '2026-04-22 21:30:48.105970'::timestamp, 342);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2280, 'Не сравнивай своё начало с чужим опытом. У того мужика за плечами 10 лет тренировок.', '2026-04-22 21:30:51.265739'::timestamp, 342);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2281, 'Пропустил неделю? Не корить себя. Просто вернись завтра и продолжай.', '2026-04-22 21:30:54.439867'::timestamp, 342);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2282, 'Мотивация приходит и уходит. Дисциплина — вот что работает.', '2026-04-22 21:30:58.229179'::timestamp, 342);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2283, 'Результат не виден сразу. Дай себе хотя бы 3 месяца, прежде чем судить.', '2026-04-22 21:31:01.507386'::timestamp, 342);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2284, 'Помни: тело не обманешь. Каждый подход, каждый повтор — это вклад в будущее.', '2026-04-22 21:31:04.476292'::timestamp, 342);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2285, 'Зал — это место, где ты борешься только с собой. И это прекрасно.', '2026-04-22 21:31:07.670749'::timestamp, 342);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2286, 'Белок: 1.6-2.2 г на кг веса. Разносите на 4-5 приёмов. Лучшие источники: курица, рыба, творог, яйца.', '2026-04-22 21:31:10.724251'::timestamp, 343);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2287, 'Углеводы: до тренировки — медленные (овсянка, гречка), после — быстрые (банан, рис) для восстановления.', '2026-04-22 21:31:13.900007'::timestamp, 343);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2288, 'Жиры: 0.8-1 г на кг. Омега-3 (рыбий жир, льняное масло) обязательно для гормонов.', '2026-04-22 21:31:16.766626'::timestamp, 343);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2289, 'Питьевой режим: 30 мл на кг веса. Во время тренировки маленькими глотками по 100-150 мл каждые 20 минут.', '2026-04-22 21:31:19.751698'::timestamp, 343);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2290, 'BCAA не нужны, если вы едите достаточно белка. Креатин и протеин — да, остальное маркетинг.', '2026-04-22 21:31:22.605072'::timestamp, 343);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2291, 'Голод после тренировки — сигнал: нужно поесть в течение 1.5 часов. Иначе мышцы будут разрушаться.', '2026-04-22 21:31:25.895398'::timestamp, 343);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2292, 'Планируйте питание на неделю вперёд. Тогда не сорвётесь на фастфуде.', '2026-04-22 21:31:29.236448'::timestamp, 343);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2293, 'Хожу на йогу 3 раза в неделю. Гибкость выросла невероятно, спина перестала болеть.', '2026-04-22 21:31:32.143813'::timestamp, 344);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2294, 'Пилатес укрепил кор — теперь становая не кажется опасной. Рекомендую всем, кто поднимает тяжести.', '2026-04-22 21:31:35.303440'::timestamp, 344);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2295, 'Зумба — мой антидепрессант. После работы идёшь и просто танцуешь, забывая о проблемах.', '2026-04-22 21:31:38.477350'::timestamp, 344);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2296, 'Стретчинг после силовой — обязательно. 10 минут на группе, и на следующий день мышцы болят меньше.', '2026-04-22 21:31:42.183699'::timestamp, 344);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2297, 'Пробовала кроссфит, но травмировала плечо. Вернулась к пилатесу и аквааэробике — безопасно и эффективно.', '2026-04-22 21:31:45.235993'::timestamp, 344);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2298, 'Групповые занятия помогают не пропускать: жалко подвести группу и тренера.', '2026-04-22 21:31:48.308330'::timestamp, 344);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2299, 'Самое классное в группе — энергия. Когда все вокруг стараются, ты тоже выкладываешься на 100%.', '2026-04-22 21:31:51.073380'::timestamp, 344);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2300, 'Белка на завтрак нужно не меньше 20 г, чтобы стабилизировать сахар и избежать срывов на сладкое через два часа. Яйца, творог, протеин.', '2026-04-22 21:31:57.526348'::timestamp, 345);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2301, 'Дефицит витамина D есть у 80% жителей северных широт. Добавки нужны с октября по апрель, дозировку подбирает врач по анализу крови.', '2026-04-22 21:32:00.495315'::timestamp, 345);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2302, 'Почему диеты не работают? Потому что жёсткие ограничения ведут к срывам. Лучше добавить полезное, чем запрещать любимое.', '2026-04-22 21:32:03.568187'::timestamp, 345);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2303, 'Интервальное голодание 16/8 помогает снизить калорийность, но подходит не всем. При проблемах с желчным пузырём и гастрите — противопоказано.', '2026-04-22 21:32:06.759273'::timestamp, 345);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2304, 'Съедайте 500 г овощей и фруктов в день. Это 5 порций. Зелень, капуста, огурцы — основа. Фрукты лучше в первой половине дня.', '2026-04-22 21:32:10.020127'::timestamp, 345);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2305, 'Омега-3 из рыбы усваивается лучше, чем из льна. Нужно 2 порции жирной морской рыбы в неделю (лосось, скумбрия, сардины).', '2026-04-22 21:32:12.696783'::timestamp, 345);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2306, 'Вода — основа метаболизма. Формула: 30 мл на кг веса. Если мало пьёте, обмен веществ замедляется, появляются отёки.', '2026-04-22 21:32:15.659100'::timestamp, 345);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2307, 'Авокадо не надо запекать — горчит. Лучше добавлять в салаты сырым или делать гуакамоле с лаймом и кинзой.', '2026-04-22 21:32:19.031904'::timestamp, 346);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2308, 'Правильная варка гречки: залить кипятком 1:2, укутать на час. Никакой соли в процессе — добавить в готовую.', '2026-04-22 21:32:22.719309'::timestamp, 346);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2309, 'Салат из свеклы с чесноком и грецким орехом: свеклу запечь, натереть, добавить давленый чеснок, орехи, йогурт вместо майонеза.', '2026-04-22 21:32:25.808660'::timestamp, 346);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2310, 'Овсянка не полезна, если это быстрые хлопья. Берите цельную или резаную, варите 15-20 минут, добавляйте ягоды и орехи.', '2026-04-22 21:32:28.983034'::timestamp, 346);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2311, 'Тыквенные семечки обжарьте на сухой сковороде 3 минуты — станут хрустящими и ароматными. Отлично к салатам и кашам.', '2026-04-22 21:32:32.671954'::timestamp, 346);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2312, 'Куриную грудку не пересушивайте: замаринуйте в йогурте с горчицей на час, запекайте при 180°C 25 минут под фольгой.', '2026-04-22 21:32:36.033808'::timestamp, 346);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2313, 'Запечённые овощи: баклажаны, цукини, перец, лук нарезать крупно, сбрызнуть маслом, посыпать тимьяном, 200°C 30 минут.', '2026-04-22 21:32:39.412628'::timestamp, 346);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2314, 'Осознанное питание: положите телефон, жуйте медленно, ощущайте вкус. Насыщение наступает через 20 минут после начала еды.', '2026-04-22 21:32:43.201456'::timestamp, 347);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2315, 'Эмоциональный голод наступает внезапно, требует конкретной еды (шоколад, чипсы) и не проходит после обычной еды. Отличите от физического.', '2026-04-22 21:32:46.581936'::timestamp, 347);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2316, 'Практика «тарелка здорового питания»: половина — овощи, четверть — белок, четверть — сложные углеводы. Работает без подсчёта калорий.', '2026-04-22 21:32:49.756051'::timestamp, 347);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2317, 'Почему мы переедаем вечером? Потому что днём недоедаем. Плотный обед с белком и клетчаткой снижает вечерний жор.', '2026-04-22 21:32:52.933811'::timestamp, 347);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2318, 'Дневник питания помогает увидеть реальную картину. Записывайте всё, что съели за 3 дня — удивитесь, сколько «незаметных» калорий.', '2026-04-22 21:32:56.327681'::timestamp, 347);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2319, 'Не запрещайте сладкое, а договаривайтесь: один десерт в день после полноценного приёма пищи. Срывы уйдут.', '2026-04-22 21:32:59.797129'::timestamp, 347);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2320, 'Голодная злость — признак нехватки углеводов. Быстрые углеводы (фрукты, хлеб) быстро поднимут сахар и настроение.', '2026-04-22 21:33:02.864883'::timestamp, 347);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2321, 'После тренировки нужны белки и углеводы в соотношении 1:2. Например, протеиновый коктейль с бананом — для восстановления мышц.', '2026-04-22 21:33:06.046217'::timestamp, 348);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2322, 'Креатин — самая изученная добавка. 5 г в день повышает силу и выносливость. Подходит и мужчинам, и женщинам.', '2026-04-22 21:33:09.318826'::timestamp, 348);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2323, 'BCAA не нужны, если вы едите достаточно белка. В цельном белке все аминокислоты есть, BCAA — пустая трата денег.', '2026-04-22 21:33:12.286751'::timestamp, 348);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2324, 'Жиросжигатели (L-карнитин, кофеин, синефрин) работают только при дефиците калорий. Сами по себе они не сжигают жир.', '2026-04-22 21:33:15.870761'::timestamp, 348);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2325, 'Протеин лучше из сыворотки: быстро усваивается, идеален после тренировки. Казеин — на ночь, для медленного питания.', '2026-04-22 21:33:18.957759'::timestamp, 348);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2326, 'Пейте воду во время тренировки: по 100-150 мл каждые 15-20 минут. Обезвоживание снижает силу на 20%.', '2026-04-22 21:33:22.221649'::timestamp, 348);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2327, 'Углеводное окно — миф. Загружаться углеводами нужно в течение 2-3 часов после тренировки, а не первых 30 минут.', '2026-04-22 21:33:25.310397'::timestamp, 348);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2328, 'Организм очищает себя сам через печень и почки. Никакие «детокс-соки» и клизмы не нужны, а иногда и опасны.', '2026-04-22 21:33:28.878235'::timestamp, 349);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2329, 'Свежевыжатый сок утром натощак — удар по поджелудочной. Клетчатка удалена, сахар в крови резко скачет.', '2026-04-22 21:33:31.862094'::timestamp, 349);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2330, 'Лимонная вода не «ощелачивает» организм — pH крови строго регулируется. Но утренняя вода с лимоном полезна для гидратации.', '2026-04-22 21:33:34.613010'::timestamp, 349);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2331, 'Активированный уголь для «очищения» не работает: он адсорбирует всё подряд, включая лекарства и витамины.', '2026-04-22 21:33:37.882450'::timestamp, 349);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2332, 'Зелёные смузи с сельдереем и шпинатом — хороший способ съесть больше зелени, но не детокс. Добавляйте белок для сытости.', '2026-04-22 21:33:40.980289'::timestamp, 349);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2333, 'Солевые промывания и слабительные для «очищения» вымывают электролиты и нарушают микрофлору кишечника.', '2026-04-22 21:33:44.024691'::timestamp, 349);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2334, 'Питьевая диета на соках ведёт к потере мышечной массы, замедлению метаболизма и возврату веса с избытком.', '2026-04-22 21:33:47.209256'::timestamp, 349);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2335, 'Изжога после еды — не норма. Частая причина — слабость нижнего пищеводного сфинктера. Не ложитесь после еды 2 часа.', '2026-04-22 21:33:50.385164'::timestamp, 350);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2336, 'Вздутие после бобовых и капусты — нормально. Но если вздутие после всего — проверьтесь на СИБР (избыточный бактериальный рост).', '2026-04-22 21:33:53.662655'::timestamp, 350);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2337, 'Клетчатка бывает растворимой (овёс, яблоки) и нерастворимой (отруби, капуста). При синдроме раздражённого кишечника нерастворимая может усиливать симптомы.', '2026-04-22 21:33:57.143849'::timestamp, 350);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2338, 'Пробиотики полезны после антибиотиков, но штамм Lactobacillus rhamnosus GG — один из самых изученных. Курс 2-4 недели.', '2026-04-22 21:34:00.831381'::timestamp, 350);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2339, 'Глютен вреден только при целиакии и чувствительности к глютену. Остальным безглютеновая диета не нужна и даже вредна.', '2026-04-22 21:34:04.432654'::timestamp, 350);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2340, 'Переедание и быстрая еда — основная причина ГЭРБ и холецистита. Жуйте медленно, не отвлекайтесь на гаджеты.', '2026-04-22 21:34:07.679278'::timestamp, 350);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2341, 'Кофе натощак стимулирует выработку соляной кислоты. При гастрите с повышенной кислотностью — противопоказан.', '2026-04-22 21:34:10.623947'::timestamp, 350);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2342, 'Веганство требует контроля B12. Дефицит приводит к анемии и неврологическим нарушениям. Принимайте добавки или ешьте обогащённые продукты.', '2026-04-22 21:34:14.076810'::timestamp, 351);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2343, 'Железо из растений (негемовое) усваивается хуже. Сочетайте с витамином С: шпинат с лимоном, гречка с киви.', '2026-04-22 21:34:16.909039'::timestamp, 351);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2344, 'Тофу — не сыр, а соевый творог. Содержит 10 г белка на 100 г, мало жира. Замаринуйте в соевом соусе и обжарьте.', '2026-04-22 21:34:20.186230'::timestamp, 351);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2345, 'Нутовый хумус — идеальный перекус: белок, клетчатка, полезные жиры из тахини. Готовьте сами, в магазинном много масла.', '2026-04-22 21:34:23.464932'::timestamp, 351);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2346, 'Семена чиа набухают в жидкости, давая чувство сытости. 2 ст. ложки залить кокосовым молоком на ночь — пудинг готов.', '2026-04-22 21:34:27.213554'::timestamp, 351);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2347, 'Киноа — псевдозерно, содержащее все незаменимые аминокислоты. Варите как кашу или добавляйте в салаты.', '2026-04-22 21:34:30.223424'::timestamp, 351);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2348, 'Нормы белка для веганов выше на 20-30% из-за худшей усвояемости растительного белка. Ориентир 1.2-1.5 г на кг веса.', '2026-04-22 21:34:33.297365'::timestamp, 351);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2349, 'Белки: 1.5-2 г на кг веса для активно тренирующихся. Для обычного человека — 1 г на кг. Жиры: 0.8-1 г на кг. Углеводы: остальное.', '2026-04-22 21:34:36.509207'::timestamp, 352);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2350, 'Макронутриенты не нужно считать всю жизнь. Пару недель — чтобы понять реальные порции. Глазомер быстро настраивается.', '2026-04-22 21:34:39.441407'::timestamp, 352);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2351, 'Углеводы не враги. 3-5 г на кг веса для поддержания, 5-7 г — для набора мышечной массы. Полностью убирать нельзя.', '2026-04-22 21:34:42.614473'::timestamp, 352);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2352, 'Жиры ниже 0.5 г на кг веса приводят к гормональным сбоям. У женщин — нарушение цикла, у мужчин — падение тестостерона.', '2026-04-22 21:34:45.584954'::timestamp, 352);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2353, 'Дефицит калорий для похудения — не более 20% от нормы. Больше — потеря мышц, замедление метаболизма, срывы.', '2026-04-22 21:34:49.329271'::timestamp, 352);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2354, 'Норму калорий считайте по формуле Миффлина-Сан-Жеора. Для женщин: (10 × вес) + (6.25 × рост) − (5 × возраст) − 161.', '2026-04-22 21:34:52.569485'::timestamp, 352);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2355, 'Рефиды — один день с повышенными углеводами на дефиците. Помогают психике и гормонам, не мешают жиросжиганию.', '2026-04-22 21:34:55.826935'::timestamp, 352);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2356, '«Органические» продукты не всегда полезнее обычных. Разница в содержании пестицидов, но не в витаминах. Мойте обычные овощи.', '2026-04-22 21:34:59.110957'::timestamp, 353);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2357, 'Фермерское молоко не пастеризовано — риск сальмонеллы и туберкулёза. Покупайте только у проверенных, кипятите.', '2026-04-22 21:35:02.661428'::timestamp, 353);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2358, 'Яйца с фермы имеют более яркий желток из-за каротиноидов в корме. По питательности разница с магазинными минимальна.', '2026-04-22 21:35:05.658617'::timestamp, 353);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2359, 'Картофель с рыхлой кожурой содержит меньше соланина. Зелёные пятна и ростки — вырезайте или выкидывайте.', '2026-04-22 21:35:08.851601'::timestamp, 353);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2360, 'Замороженные овощи и ягоды сохраняют больше витаминов, чем свежие после недели хранения. Особенно это касается брокколи и черники.', '2026-04-22 21:35:12.006425'::timestamp, 353);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2361, 'Мёд не пастеризуют, поэтому в нём могут быть бактерии. Детям до года давать нельзя из-за риска ботулизма.', '2026-04-22 21:35:14.977861'::timestamp, 353);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2362, 'Красная рыба дикая, а не фермерская, имеет более насыщенный цвет и меньше антибиотиков. Но дороже.', '2026-04-22 21:35:18.270402'::timestamp, 353);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2363, 'Готовьте на неделю в воскресенье. Отварите крупы, запеките курицу, нарежьте овощи — сборка обеда занимает 5 минут.', '2026-04-22 21:35:21.637804'::timestamp, 354);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2364, 'Контейнеры разделяйте на секции. Порции должны быть сбалансированы: половина — овощи, четверть — белок, четверть — гарнир.', '2026-04-22 21:35:24.708068'::timestamp, 354);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2365, 'Салаты не заправляйте заранее — листья вянут. Соус отдельно в маленькой баночке, смешивайте перед едой.', '2026-04-22 21:35:27.749144'::timestamp, 354);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2366, 'Рис и гречку храните в холодильнике до 5 дней. Разогревайте с парой ложек воды — вернётся свежесть.', '2026-04-22 21:35:31.060959'::timestamp, 354);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2367, 'Завтрак приготовьте с вечера: overnight oats (овсянка, молоко, йогурт, семена чиа, ягоды) — утром готово.', '2026-04-22 21:35:34.231754'::timestamp, 354);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2368, 'Перекусы на работу: яблоко, горсть орехов, морковные палочки, варёное яйцо. Никаких печенек и батончиков.', '2026-04-22 21:35:37.821357'::timestamp, 354);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2369, 'Заморозка порционная: супы, рагу, котлеты. Размораживайте в холодильнике за ночь, не в микроволновке.', '2026-04-22 21:35:41.297204'::timestamp, 354);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2370, 'Компульсивное переедание часто связано с запретами. Разрешите себе любую еду без чувства вины — уйдёт цикл «ограничение-срыв».', '2026-04-22 21:35:44.848583'::timestamp, 355);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2371, 'Интуитивное питание не работает при эмоциональных проблемах. Сначала разберитесь с причиной, потом с едой.', '2026-04-22 21:35:48.158792'::timestamp, 355);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2372, 'РПП (анорексия, булимия) — это психические расстройства, а не образ жизни. Лечит психиатр, а не диетолог.', '2026-04-22 21:35:51.554275'::timestamp, 355);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2373, 'Орторексия — навязчивое стремление к «правильной» еде. Люди исключают всё больше продуктов, страдает качество жизни.', '2026-04-22 21:35:55.123793'::timestamp, 355);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2374, 'Почему мы едим перед телевизором? Потому что отвлекаемся от сигналов насыщения. Уберите гаджеты за едой.', '2026-04-22 21:35:58.415822'::timestamp, 355);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2375, 'Дневная норма шагов (10000) не работает для всех. Слушайте тело: если устали — отдохните, если бодры — двигайтесь.', '2026-04-22 21:36:01.986514'::timestamp, 355);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2376, 'Стресс повышает кортизол, который стимулирует аппетит и откладывание жира на животе. Управление стрессом — часть диеты.', '2026-04-22 21:36:05.057096'::timestamp, 355);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2377, 'Кето-диета: менее 20 г углеводов в день, умеренный белок (1.5 г на кг), остальное жиры. Переход занимает 2-4 недели.', '2026-04-22 21:36:08.847880'::timestamp, 356);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2378, 'Кетогрипп — слабость, головная боль, раздражительность в первые дни. Пройдёт через неделю. Пейте воду с солью.', '2026-04-22 21:36:13.060738'::timestamp, 356);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2379, 'МТС масло (среднецепочечные триглицериды) ускоряет переход в кетоз. 1-2 столовые ложки в день с кофе или салатом.', '2026-04-22 21:36:16.321740'::timestamp, 356);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2380, 'На кето нельзя есть бобовые, злаки, фрукты (кроме ягод), сахар, крахмалистые овощи. Основа — мясо, рыба, яйца, авокадо, листовая зелень.', '2026-04-22 21:36:19.906976'::timestamp, 356);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2381, 'Кетодиета противопоказана при диабете 1 типа, панкреатите, заболеваниях печени и почек, беременности.', '2026-04-22 21:36:23.081471'::timestamp, 356);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2382, 'Измеряйте кетоны в крови, а не в моче (моча показывает только ацетоацетат, который уходит через 2 недели).', '2026-04-22 21:36:26.373266'::timestamp, 356);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2383, 'Долгосрочное кето может снизить уровень гормонов щитовидной железы. Делайте углеводные загрузки раз в 2 недели.', '2026-04-22 21:36:29.329571'::timestamp, 356);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2384, 'Детям до 3 лет не добавляйте сахар и соль. Их вкусовые рецепторы чувствительнее, а привычка к сладкому формируется на всю жизнь.', '2026-04-22 21:36:32.620906'::timestamp, 357);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2385, 'Прикорм: овощи (кабачок, брокколи) лучше фруктов, чтобы ребёнок не привык к сладкому. С 6 месяцев.', '2026-04-22 21:36:35.883845'::timestamp, 357);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2386, 'Школьный перекус: яблоко, сыр, хлебец, морковь. Исключите соки в пакетах — сахар и кислоты вредят зубам.', '2026-04-22 21:36:39.160176'::timestamp, 357);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2387, 'Семейный ужин за общим столом снижает риск ожирения у детей. Готовьте вместе, обсуждайте еду.', '2026-04-22 21:36:42.452094'::timestamp, 357);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2388, 'Пищевая аллергия у детей: вводите новые продукты по одному, ждите 3 дня. Мёд, орехи, морепродукты — после 3 лет.', '2026-04-22 21:36:45.513949'::timestamp, 357);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2389, 'Жирные кисломолочные продукты (творог 5%, йогурт 3.2%) полезнее обезжиренных — в них лучше усваивается кальций.', '2026-04-22 21:36:48.906747'::timestamp, 357);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2390, 'Детское ожирение в 80% случаев переходит во взрослое. Учите детей есть медленно, без телевизора.', '2026-04-22 21:36:51.961876'::timestamp, 357);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2391, 'Метаанализ 2023 года: средиземноморская диета снижает риск сердечно-сосудистых заболеваний на 30%. Оливковое масло, орехи, рыба.', '2026-04-22 21:36:55.137254'::timestamp, 358);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2392, 'Кокосовое масло содержит 90% насыщенных жиров, повышает ЛПНП (плохой холестерин) сильнее сливочного. Не суперфуд.', '2026-04-22 21:36:59.642963'::timestamp, 358);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2393, 'Интервальное голодание не улучшает метаболизм без дефицита калорий. Потеря веса — только из-за меньшего количества еды.', '2026-04-22 21:37:03.227008'::timestamp, 358);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2394, 'Добавки витамина D в дозе 2000 МЕ в день снижают риск ОРВИ на 20%, но не защищают от COVID. Доказано в РКИ.', '2026-04-22 21:37:06.607216'::timestamp, 358);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2395, 'Клетчатка снижает риск рака толстой кишки. Механизм: связывает канцерогены и ускоряет транзит. Норма 25-30 г в день.', '2026-04-22 21:37:09.884664'::timestamp, 358);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2396, 'Эритрит (сахарозаменитель) в больших дозах связан с тромбозами. Не превышайте 30 г в день, лучше стевия.', '2026-04-22 21:37:13.570808'::timestamp, 358);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2397, 'Мясо повышает риск диабета 2 типа не из-за жира, а из-за гема железа. Замена на птицу и рыбу снижает риск на 25%.', '2026-04-22 21:37:16.643223'::timestamp, 358);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2398, 'Микробиом кишечника весит 1.5-2 кг. Пребиотики (пища для бактерий) — чеснок, лук, бананы, овёс, бобовые.', '2026-04-22 21:37:20.229124'::timestamp, 359);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2399, 'Пробиотики с штаммом Bifidobacterium longum улучшают настроение и снижают тревожность. Кишечно-мозговая ось работает.', '2026-04-22 21:37:23.622216'::timestamp, 359);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2400, 'Ферментированные продукты: квашеная капуста, кимчи, кефир, йогурт без сахара. Натуральные пробиотики.', '2026-04-22 21:37:26.950959'::timestamp, 359);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2401, 'Синдром дырявого кишечника не признан официальной медициной. Маркеры зонулин и LBP не имеют доказательной базы.', '2026-04-22 21:37:30.383227'::timestamp, 359);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2402, 'FODMAP-диета при СРК: исключение бродильных углеводов на 4-6 недель, затем постепенное введение. Работает у 70%.', '2026-04-22 21:37:33.541296'::timestamp, 359);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2403, 'Глютен не повреждает кишечник без целиакии. Но пшеница содержит FODMAP (фруктаны), которые могут вызывать вздутие.', '2026-04-22 21:37:36.793451'::timestamp, 359);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2404, 'Искусственные подсластители (аспартам, сукралоза) изменяют состав микробиоты у мышей. У человека данные неоднозначны.', '2026-04-22 21:37:40.111483'::timestamp, 359);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2405, 'Тревога — это не враг. Это сигнал, что что-то важно для вас. Игнорируя тревогу, вы теряете связь с собой. Научитесь её слышать, а не заглушать.', '2026-04-22 21:37:45.318685'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2406, 'Выгорание не лечится отпуском за две недели. Нужно менять образ жизни, учиться говорить «нет» и пересматривать свои ценности. Иначе через месяц всё вернётся.', '2026-04-22 21:37:48.306232'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2407, 'Самый частый запрос в терапии: «Почему я не могу себя заставить?». Ответ — вы не на связи со своими истинными желаниями. Вы живёте чужими долженствованиями.', '2026-04-22 21:37:51.462872'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2408, 'Границы — это не про эгоизм. Это про уважение к себе. Если вы боитесь кого-то расстроить отказом, вы расстраиваете себя. Каждый день.', '2026-04-22 21:37:54.756655'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2409, 'Когнитивная переоценка: вместо «Я провалил презентацию, я ничтожество» попробуйте «Я не учел несколько моментов, в следующий раз сделаю лучше». Звучит просто, но требует тренировки.', '2026-04-22 21:37:58.227284'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2410, 'Эмоции живут около 90 секунд. Всё, что дольше — это уже ваши мысли, подогревающие эмоцию. Учитесь просто наблюдать, не накручивая.', '2026-04-22 21:38:00.845964'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2411, 'Паническая атака не опасна для жизни. Сердце не остановится, дыхание восстановится. Страх перед страхом — вот что её закрепляет. Разрешите себе испугаться, и она пройдёт быстрее.', '2026-04-22 21:38:03.974079'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2412, 'Почему люди остаются в абьюзивных отношениях? Не потому что слабые. А потому что абьюзер чередует насилие с «мёдом», создавая химическую зависимость. Выход есть, но нужна поддержка.', '2026-04-22 21:38:07.234891'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2413, 'Перфекционизм — это не стремление к лучшему, а страх оказаться недостаточно хорошим. Он парализует действие. Лучшее — враг хорошего, помните?', '2026-04-22 21:38:10.526632'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2414, 'Терапия работает не потому, что психолог даёт советы. А потому что вы впервые говорите правду о себе и чувствуете, что вас принимают без условий.', '2026-04-22 21:38:13.803776'::timestamp, 360);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2415, 'Детские травмы не обязательно определяют всю жизнь. Мозг пластичен. Но для этого нужно осознать свои автоматические реакции и начать их переписывать. Никогда не поздно.', '2026-04-22 21:38:17.475980'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2416, 'Подростковый бунт — это не «испорченность». Это сепарация. Ребёнок отделяется от родителей, чтобы стать собой. Если запрещать бунт, он уйдёт в депрессию или зависимость.', '2026-04-22 21:38:20.444603'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2417, 'Игры с младенцем в прятки учат постоянству объекта — мама не исчезает навсегда, она возвращается. Это основа базового доверия к миру.', '2026-04-22 21:38:23.824269'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2418, 'Авторитетный стиль воспитания (тёплый, но с границами) даёт лучшие результаты. Авторитарный (холодный, жёсткий) — тревожных детей. Попустительский — эгоцентричных.', '2026-04-22 21:38:26.891000'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2419, 'Кричать на ребёнка за двойку — учить его, что ошибки недопустимы. Тогда он вырастет в перфекциониста, который боится пробовать новое. Лучше разобрать тему вместе.', '2026-04-22 21:38:30.070830'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2420, 'Эгоцентризм дошкольника — норма. Ребёнок не может встать на чужую точку зрения до 6-7 лет. Бесполезно говорить «посмотри, как обижается брат» — он не понимает.', '2026-04-22 21:38:33.143144'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2421, 'В кризисе 3 лет «я сам» — важнейший этап. Если подавлять и делать всё за него, ребёнок вырастет с чувством, что он некомпетентен. Пусть пачкает, но учится.', '2026-04-22 21:38:36.524442'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2422, 'Песочная терапия работает не только с детьми. Проекция внутреннего мира на фигурки и песок помогает выразить то, для чего нет слов.', '2026-04-22 21:38:39.493050'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2423, 'Привязанность к маме формируется в первые 2 года. Если мама недоступна эмоционально, ребёнок вырастает либо тревожно-избегающим, либо тревожно-амбивалентным. Потом это влияет на все отношения.', '2026-04-22 21:38:42.666457'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2424, 'Сравнивать ребёнка с другими нельзя. Только с ним самим вчерашним. «Сегодня ты написал аккуратнее, чем вчера» — это мотивирует. «А Петя лучше» — убивает самооценку.', '2026-04-22 21:38:45.841380'::timestamp, 361);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2425, 'Ложная память — реальность. Каждый раз, вспоминая событие, вы перезаписываете его с учётом текущих эмоций и убеждений. Так свидетели искренне ошибаются в суде.', '2026-04-22 21:38:49.221129'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2426, 'Эффект Даннинга-Крюгера: некомпетентные люди уверены в себе, потому что не знают, чего не знают. А эксперты сомневаются, потому что видят всю сложность.', '2026-04-22 21:38:52.394292'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2427, 'Ваш мозг не различает реальную угрозу и воображаемую. Вот почему визуализация успеха работает — нейроны активируются так же, как при реальном действии.', '2026-04-22 21:38:55.517408'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2428, 'Когнитивное искажение «черно-белое мышление» — это ловушка. Мир не делится на успех/провал, добро/зло. Тренируйтесь видеть оттенки серого, и тревога снизится.', '2026-04-22 21:38:58.438390'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2429, 'Метод локомоции: если не можете начать дело, скажите себе: «Я просто сделаю один маленький шаг и посмотрю, что будет». Сопротивление падает, потому что нет обязательства делать всё идеально.', '2026-04-22 21:39:02.534954'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2430, 'Почему мы переоцениваем то, что имеем, и обесцениваем недоступное? Теория когнитивного диссонанса: «лиса и виноград» — защита самооценки.', '2026-04-22 21:39:05.505681'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2431, 'Наш мозг экономит энергию через эвристики (мыслительные shortcuts). Они полезны в быту, но в важных решениях ведут к ошибкам. Включайте медленное мышление.', '2026-04-22 21:39:08.852011'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2432, 'Прокрастинация — не лень. Это проблема регуляции эмоций. Вы откладываете задачу, потому что она вызывает тревогу, скуку или неуверенность. Решение — признать эти чувства.', '2026-04-22 21:39:11.751311'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2433, 'Эффект плацебо работает даже если вы знаете, что это плацебо. Просто ритуал и ожидание активируют дофаминовые пути. Ваше тело верит в исцеление.', '2026-04-22 21:39:14.720291'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2434, 'Якорение: первая цифра, которую вы слышите, влияет на все последующие оценки. Продавцы этим пользуются: показывают завышенную цену, а потом «скидку».', '2026-04-22 21:39:18.099286'::timestamp, 362);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2435, 'Главный убийца отношений — не измены, а презрение. Когда один партнёр смотрит на другого свысока, высмеивает его потребности — это конец. Не лечится.', '2026-04-22 21:39:21.273980'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2436, 'Конфликт — это не враг. Врагом является избегание конфликта. Пары, которые копят обиды, разводятся чаще тех, кто ссорится, но потом мирится конструктивно.', '2026-04-22 21:39:24.567013'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2437, 'Активное слушание: перефразируйте то, что сказал партнёр, и спросите «я правильно понял?». Это дешевле, чем ходить к психологу, и работает мгновенно.', '2026-04-22 21:39:28.048824'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2438, 'Любовь — это не только чувство, но и действие. Чувство может угасать, но если вы продолжаете заботиться, уважать, проводить время — чувство возвращается.', '2026-04-22 21:39:31.311183'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2439, 'Треугольник Карпмана: жертва, спасатель, агрессор. Если вы застряли в этих ролях — вы не в отношениях, вы в игре. Выход — отказаться от любой из ролей.', '2026-04-22 21:39:34.401325'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2440, 'Газлайтинг: «Ты выдумываешь», «Тебе показалось», «Ты слишком чувствительна». Это манипуляция, заставляющая жертву сомневаться в своей адекватности. Бегите от такого партнёра.', '2026-04-22 21:39:37.456379'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2441, 'Привязанность во взрослом возрасте: тревожный тип боится, что его бросят; избегающий боится близости. Проблемные пары часто состоят из тревожного и избегающего. Можно работать над собой.', '2026-04-22 21:39:40.742741'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2442, 'Деньги — частая причина разводов. Но не из-за их количества, а из-за разных ценностей: один копит, другой тратит на впечатления. Важно договориться о бюджете, а не оцифровывать любовь.', '2026-04-22 21:39:43.804531'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2443, 'Эмпатия ≠ симпатия. Симпатия — «мне жаль тебя». Эмпатия — «я слышу твою боль и рядом». В конфликте партнёру нужна эмпатия, а не советы.', '2026-04-22 21:39:47.081234'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2444, 'Семейные ритуалы (совместный ужин, прогулка по воскресеньям) создают чувство «мы». Это защищает от разрыва сильнее, чем страстный секс.', '2026-04-22 21:39:50.153630'::timestamp, 363);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2445, 'Техника 5-4-3-2-1 при панике: назовите 5 вещей, которые видите, 4 — которые можете потрогать, 3 — слышите, 2 — чувствуете запах, 1 — вкус. Возвращает в реальность.', '2026-04-22 21:39:54.013021'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2446, 'Социальная тревога лечится не избеганием, а постепенным погружением. Начните с малого: спросите время у прохожего. Потом — короткий диалог. Мозг переучится.', '2026-04-22 21:39:57.118491'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2447, 'Генерализованное тревожное расстройство — это как фоновая музыка катастроф. Лечение: выписывать страхи на бумагу и проверять, сколько из них сбылось. Оказывается, 95% не сбываются.', '2026-04-22 21:40:00.293785'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2448, 'Дыхание квадратом: вдох 4 с, задержка 4 с, выдох 4 с, задержка 4 с. Активирует парасимпатику через 2-3 минуты. Работает лучше валидола.', '2026-04-22 21:40:03.570340'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2449, 'Обсессивно-компульсивное расстройство — это не «люблю порядок». Это ритуалы, которые снижают невыносимую тревогу. Лечение — не делать ритуал и выдерживать тревогу, пока она не схлынет.', '2026-04-22 21:40:06.854842'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2450, 'Фобия — это условный рефлекс. Один раз испугались собаки, и теперь любая собака вызывает панику. Лечение — контролируемое столкновение с безопасным раздражителем.', '2026-04-22 21:40:09.920648'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2451, 'Тревожные люди часто гиперответственны. Они верят, что если они не проконтролируют всё, случится катастрофа. Разрешите себе нести ответственность только за свои действия, не за весь мир.', '2026-04-22 21:40:13.210594'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2452, 'Кошмары при ПТСР — это попытка мозга переработать травму. Техника репетиции образа: перепишите концовку кошмара на позитивную и прокручивайте днём. Снижает частоту.', '2026-04-22 21:40:16.472889'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2453, 'Синдром самозванца — форма социальной тревоги. Человек боится, что его разоблачат. Помогает список реальных достижений и признание: «да, я иногда ошибаюсь, это нормально».', '2026-04-22 21:40:19.970794'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2454, 'Агорафобия — страх открытых пространств, но на самом деле страх паники в месте, откуда трудно уйти. Лечение — маленькие шаги с безопасным человеком, постепенно расширяя зону.', '2026-04-22 21:40:23.744232'::timestamp, 364);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2455, 'Мотивация приходит после действия, а не до. Не ждите вдохновения. Сделайте первый крошечный шаг — и появятся силы для второго.', '2026-04-22 21:40:27.432477'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2456, 'Правило двух минут: если задача занимает меньше двух минут — делайте её сразу. Остальное — в список. Убирает прокрастинацию по мелочам.', '2026-04-22 21:40:30.606171'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2457, 'Постановка целей по SMART — это база. Но главное — разбить большую цель на ежедневные микро-действия. «Написать книгу» -> «написать 100 слов сегодня».', '2026-04-22 21:40:33.985967'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2458, 'Прокрастинация часто вызвана страхом несовершенства. Разрешите себе сделать «плохой первый вариант». Его можно исправить, а пустой лист — нет.', '2026-04-22 21:40:36.971476'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2459, 'Дофаминовое голодание: один день без соцсетей, еды, музыки, разговоров. Сбрасывает дофаминовые рецепторы, возвращает радость к простым вещам и мотивацию к работе.', '2026-04-22 21:40:39.730877'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2460, 'Метод Pomodoro: 25 минут работы, 5 минут отдыха. Мозг легче входит в поток, когда знает, что перерыв близко. Для прокрастинаторов — спасение.', '2026-04-22 21:40:42.689967'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2461, 'Не ждите, что мотивация будет всегда. Дисциплина — это когда делаете, несмотря на её отсутствие. Тренируйте дисциплину как мышцу.', '2026-04-22 21:40:45.864040'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2462, 'Визуализация прогресса: зачеркивайте дни в календаре, когда сделали нужное действие. Цепочка не должна прерываться. Это мощный якорь.', '2026-04-22 21:40:48.834257'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2463, 'Если не можете начать, используйте технику «Анти-расписание»: запланируйте наоборот все удовольствия (кино, прогулки), а работу втискивайте в оставшиеся окна. Срабатывает чувство дефицита.', '2026-04-22 21:40:52.227023'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2464, 'Почему новогодние обещания не работают? Потому что нет системы. Вместо «бегать по утрам» -> «в 7:00 надеть кроссовки и выйти из дома». Конкретный триггер.', '2026-04-22 21:40:55.491833'::timestamp, 365);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2465, 'Медитация — это не «отключить мысли». Это научиться наблюдать мысли, не цепляясь за них. Представьте, что мысли — это облака, плывущие по небу сознания.', '2026-04-22 21:40:58.767578'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2466, 'Телесное сканирование за 10 минут снижает кортизол. Лягте, проведите внимание от пальцев ног до макушки. Где напряжение? Не исправляйте, просто замечайте.', '2026-04-22 21:41:02.762831'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2467, 'Осознанное питание: один приём пищи без телефона, без книг. Чувствуйте вкус, текстуру, жевайте медленно. Увидите, что насыщаетесь меньшим количеством.', '2026-04-22 21:41:06.039484'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2468, 'Руминация (мысленная жвачка) — это не решение проблем. Это бег по кругу. Когда ловите себя на руминации, скажите: «Стоп. Что я могу сделать прямо сейчас?»', '2026-04-22 21:41:09.316353'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2469, 'Практика благодарности: каждый вечер записывайте 3 вещи, за которые вы благодарны. Даже «вкусный кофе» и «солнце за окном». Через месяц уровень счастья растёт.', '2026-04-22 21:41:12.491833'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2470, 'Техника STOP: Stop (остановись), Take a breath (вдохни), Observe (заметь, что внутри), Proceed (действуй осознанно). Для автоматических реакций гнева/тревоги.', '2026-04-22 21:41:15.884729'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2471, 'Mindfulness не о счастье, а о присутствии. Вы можете быть осознанны в горе, в боли. Это не избавит от страданий, но уберёт лишнее «страдание из-за страдания».', '2026-04-22 21:41:19.044246'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2472, 'Стресс на работе можно снизить 3-минутной паузой. Закройте глаза, сосредоточьтесь на дыхании, затем на ощущениях в теле, затем на звуках. Отключает автопилот.', '2026-04-22 21:41:22.018465'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2473, 'Исследования показывают: 8 недель практики майндфулнес увеличивают плотность серого вещества в гиппокампе (память) и уменьшают в миндалевидном теле (страх).', '2026-04-22 21:41:25.087802'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2474, 'Не осуждайте себя за то, что отвлеклись на медитации. Отвлечение — это норма. Важно заметить его и мягко вернуть внимание. Это и есть тренировка.', '2026-04-22 21:41:28.279190'::timestamp, 366);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2475, 'Феномен свидетеля: чем больше людей вокруг, тем меньше вероятность, что кто-то поможет. Каждый думает: «кто-то другой уже вызвал помощь». Если нужна помощь — обратитесь к конкретному человеку.', '2026-04-22 21:41:31.741117'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2476, 'Стэнфордский тюремный эксперимент показал: хорошие люди могут стать жестокими, если им дать власть и униформу. Ситуация сильнее личности, помните это.', '2026-04-22 21:41:34.509732'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2477, 'Когнитивный диссонанс: если вы вынуждены делать что-то противное вашим убеждениям, вы меняете убеждения, чтобы снизить дискомфорт. Так лояльные сотрудники становятся фанатами.', '2026-04-22 21:41:37.785478'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2478, 'Эффект ореола: если человек красив, мы приписываем ему ум, доброту и честность, даже не зная его. Работает в найме, суде, знакомствах.', '2026-04-22 21:41:40.858923'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2479, 'Групповое мышление: в сплочённой группе люди подавляют сомнения ради консенсуса. Это привело к катастрофе «Челленджера» — инженеры молчали, боясь нарушить единство.', '2026-04-22 21:41:44.066514'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2480, 'Зона комфорта не всегда полезна. Теория социального сравнения: мы оцениваем себя, сравнивая с другими. Вверх — вдохновляет или угнетает, вниз — повышает самооценку.', '2026-04-22 21:41:47.207131'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2481, 'Стереотипы экономят энергию мозга, но ведут к предрассудкам. Автоматическое активирование стереотипа можно затормозить, если сознательно думать о контр-примерах.', '2026-04-22 21:41:50.386197'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2482, 'Эффект Рингельмана: в группе люди работают менее усердно, чем в одиночку (социальная леность). Особенно если вклад не виден. Решение — персональная ответственность.', '2026-04-22 21:41:53.659129'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2483, 'Конформизм Аша: даже если очевидно, что линии равны, 75% поддаются мнению группы и ошибаются. Мы боимся выделяться больше, чем ошибаться.', '2026-04-22 21:41:56.543395'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2484, 'Проекция: мы приписываем другим свои собственные неприемлемые черты. Если вы кого-то бесит жадность — проверьте, не жаден ли вы сами, но отрицаете это.', '2026-04-22 21:41:59.614128'::timestamp, 367);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2485, 'EMDR (десенсибилизация движениями глаз) помогает переработать травму. Мозг, следуя за движением, «перезаписывает» воспоминание, отделяя эмоцию от факта.', '2026-04-22 21:42:02.978244'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2486, 'Посттравматический рост — реальность. Многие после травмы становятся сильнее, ценят жизнь, меняют приоритеты. Травма не только разрушает, но и может трансформировать.', '2026-04-22 21:42:05.845614'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2487, 'Диссоциация — это защита психики. Когда боль невыносима, вы словно смотрите на себя со стороны. Это спасло в момент травмы, но потом мешает жить. Интеграция — путь.', '2026-04-22 21:42:09.019955'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2488, 'Телесные проявления травмы: хроническое напряжение, боли, нарушение сна. Травма живёт не только в памяти, но и в теле. Соматическая терапия работает через дыхание и движение.', '2026-04-22 21:42:12.215991'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2489, 'Триггеры травмы: запах, звук, поза могут вернуть вас в прошлое. Важно распознавать их и использовать grounding (опору на стул, стопы, дыхание), чтобы вернуться в настоящее.', '2026-04-22 21:42:15.574236'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2490, 'Комплексное ПТСР отличается от простого: травма была длительной, повторяющейся (насилие в детстве). Симптомы: стыд, вина, проблемы с регуляцией эмоций, нарушенное чувство себя.', '2026-04-22 21:42:19.055679'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2491, 'Флешбэки — это не воспоминание, а переживание. Вы не помните, вы там. Учитесь говорить: «Сейчас 2025 год, я в безопасном месте, это эхо прошлого». Требует времени.', '2026-04-22 21:42:22.537382'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2492, 'Терапия травмы не стирает память. Но она лишает воспоминание заряда. Вы помните, что случилось, но тело больше не реагирует паникой, сердце не колотится.', '2026-04-22 21:42:25.611085'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2493, 'Стыд — самая токсичная эмоция после травмы. «Это я виноват». Работа: разделить ответственность — вы не могли контролировать действия обидчика, вы выжили.', '2026-04-22 21:42:29.194388'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2494, 'Группы поддержки для переживших травму снижают изоляцию. Услышать «со мной было похожее» нормализует реакцию. Вы не сумасшедший, вы травмированы.', '2026-04-22 21:42:32.383812'::timestamp, 368);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2495, 'Счастье на 50% определяется генетикой, на 10% — обстоятельствами, на 40% — нашими действиями. Значит, многое в ваших руках. Вопрос: что вы делаете для этих 40%?', '2026-04-22 21:42:35.442007'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2496, 'Три хорошие вещи в день: каждый вечер записывайте 3 позитивных события и почему они произошли. Это тренирует мозг замечать хорошее. Эффект через 2 недели.', '2026-04-22 21:42:38.617973'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2497, 'Самоэффективность — вера в свои силы — предсказывает успех лучше, чем талант. Её можно развить: маленькие победы, наблюдение за похожими людьми, поддержка.', '2026-04-22 21:42:42.365652'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2498, 'Цветочная терапия: живые растения в офисе повышают продуктивность на 15% и снижают стресс. Не обязательно дорогой ремонт, достаточно одного горшка на стол.', '2026-04-22 21:42:45.649608'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2499, 'Добрые дела увеличивают счастье больше, чем получение подарков. Купите кофе незнакомцу, напишите благодарственное письмо. Эффект длится несколько дней.', '2026-04-22 21:42:48.973816'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2500, 'Поток — состояние полной поглощённости делом. Условия: ясная цель, немедленная обратная связь, баланс сложности и навыков. Находите свой поток ежедневно.', '2026-04-22 21:42:52.237404'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2501, 'Сравнение с собой вчерашним, а не с соседом. Прогресс — главный источник дофамина. Ведите дневник достижений, даже мелких. «Сегодня я встал на 5 минут раньше» — победа.', '2026-04-22 21:42:55.209052'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2502, 'Самостоятельность (автономия) важнее денег для ощущения благополучия. Люди, которые чувствуют контроль над своей жизнью, счастливее богатых, но зависимых.', '2026-04-22 21:42:58.296680'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2503, 'Исследования показали: один разговор с близким другом в день снижает уровень кортизола так же, как медитация. Инвестируйте в общение.', '2026-04-22 21:43:01.760215'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2504, 'Празднование успехов — недооценённый навык. Мы быстро привыкаем к победам. Устройте ритуал: после завершения проекта — прогулка, ужин, похвала себе. Это продлевает радость.', '2026-04-22 21:43:05.033214'::timestamp, 369);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2505, 'Black Sabbath придумали металл, когда Тони Айомми потерял кончики пальцев на производстве. Он настроил гитару на полтона ниже, чтобы струны не резали — родился downtuned sound.', '2026-04-22 21:43:10.992570'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2506, 'Metallica записывали «Master of Puppets» за 4 месяца, а Cliff Burton погиб через год. Ему было 24. Альбом стал памятником.', '2026-04-22 21:43:14.372804'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2507, 'Вокалист Judas Priest Роб Хэлфорд выходил на сцену в кожаных штанах и с цепями — в 1970-х это было вызовом всем консерваторам.', '2026-04-22 21:43:17.649516'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2508, 'Slayer использовали трезвучия, которые джазовые музыканты считают ошибкой. Это дало их звуку хаотичную, режущую ухо агрессию.', '2026-04-22 21:43:20.736989'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2509, 'Mayhem из Норвегии сожгли церкви, убили гитариста и сделали депрессивный блэк-метал. Их альбом «De Mysteriis Dom Sathanas» — шедевр и криминальная хроника.', '2026-04-22 21:43:23.880573'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2510, 'Iron Maiden возят с собой 12 тонн оборудования. Брюс Дикинсон, кроме вокала, управляет самолётом группы. Настоящий авиатор.', '2026-04-22 21:43:27.569510'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2511, 'Meshuggah придумали джентовый ритм — полиритмию, где гитары играют в одном размере, а барабаны в другом. Мозг ломается, качаешь шеей.', '2026-04-22 21:43:30.847005'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2512, 'Dio изобрёл знак «коза» — жест, который его бабушка использовала для защиты от сглаза. Теперь это символ всего метала.', '2026-04-22 21:43:34.019994'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2513, 'В 1992 году на концерте Guns N'' Roses в Монреале Metallica осталась без Джеймса Хэтфилда (ожог), а Эксл Роуз устроил бунт, уйдя со сцены. Город разгромили фанаты.', '2026-04-22 21:43:37.193999'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2514, 'Cannibal Corpse запретили в Германии исполнять песни с первых альбомов из-за текстов. Группа просто играет инструменталы, а публика поёт сама.', '2026-04-22 21:43:40.375061'::timestamp, 370);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2515, '«Close to the Edge» Yes — 18 минут, 3 части, 20 смен тактовых размеров. Музыка для тех, кто считает, что рок — это не только куплет-припев.', '2026-04-22 21:43:44.402251'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2516, 'Genesis с Питером Гэбриэлом выходил на сцену в костюме лиса, цветка и даже в платье с лысиной. Шоу длилось 3 часа, никто не уходил.', '2026-04-22 21:43:47.640586'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2517, 'King Crimson придумали диссонанс в роке. Их «21st Century Schizoid Man» звучит так, будто мир сошёл с ума. Так оно и есть.', '2026-04-22 21:43:50.610350'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2518, 'Rush — три человека, которые играют сложнее многих групп с гитаристами. Нил Пирт писал тексты про Айн Рэнд и чёрные дыры.', '2026-04-22 21:43:53.960534'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2519, 'Tool выпускают альбомы раз в 10 лет. В 2019 году «Fear Inoculum» вышел через 13 лет после предыдущего. Платина за месяц.', '2026-04-22 21:43:56.815450'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2520, '«Supper''s Ready» Genesis длится 23 минуты. Там есть и баллада, и марш, и джазовый фьюжн. После такого прослушивания ты уже не тот.', '2026-04-22 21:44:00.648036'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2521, 'Emerson, Lake & Palmer использовали синтезатор Moog на сцене, когда он весил 50 кг и постоянно разряжался. Кейт Эмерсон бил клавиши ножами.', '2026-04-22 21:44:03.633406'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2522, 'Dream Theater написали «The Dance of Eternity» со 128 сменами размера за 6 минут. Барабанщик Майк Портной считал, что это весело.', '2026-04-22 21:44:06.895179'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2523, 'Почему прог не для всех? Потому что нужно внимание, терпение и хотя бы базовое чувство ритма. Но те, кто врубается, уже не вылезают.', '2026-04-22 21:44:09.878751'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2524, 'Последний альбом Gentle Giant «The Missing Piece» провалился, потому что фанаты сказали: слишком просто. А критики — слишком сложно. Идеальный провал.', '2026-04-22 21:44:13.169979'::timestamp, 371);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2525, 'Джимми Хендрикс играл на гитаре, перевёрнутой для левши, и использовал струны для правшей — так его звук отличался от всех.', '2026-04-22 21:44:17.030072'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2526, 'Рифф «Back in Black» Энгус Янг сыграл на Gibson SG, подключённой к вампу через одну педаль. Три ноты — и ты уже в раю.', '2026-04-22 21:44:20.017564'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2527, 'Эрик Клэптон записал соло «While My Guitar Gently Weeps» за один дубль. Джордж Харрисон сидел и слушал, не веря своим ушам.', '2026-04-22 21:44:23.805715'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2528, 'Дэвид Гилмор не пользуется медиатором — только пальцами. Его легато и бенды создают тот самый плачущий звук Pink Floyd.', '2026-04-22 21:44:26.760210'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2529, 'Ричи Блэкмор играл в Deep Purple с такой скоростью, что ломал струны на сцене. Тогда он просто продолжал играть на пяти струнах.', '2026-04-22 21:44:30.141482'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2530, 'Эдди Ван Хален прикрутил тремоло к стратокастеру и начал давить рычаг во время бендов — родился дайв-бомб.', '2026-04-22 21:44:33.417484'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2531, 'Стив Рэй Вон пережил авиакатастрофу, упал в реку, но спас гитару. На следующее утро он уже репетировал.', '2026-04-22 21:44:37.213003'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2532, 'Почему соло «Comfortably Numb» считается лучшим? Потому что оно не про скорость, а про то, как выжать из ноты всю боль.', '2026-04-22 21:44:40.506131'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2533, 'Брайан Мэй построил свою гитару Red Special из каминной доски и мотоциклетных пружин вместе с отцом. До сих пор на ней играет.', '2026-04-22 21:44:43.671364'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2534, 'Самый недооценённый рифф: «Money» Pink Floyd. Семь ударов в такте, записанных с помощью кассовых аппаратов и звонков монет.', '2026-04-22 21:44:46.641009'::timestamp, 372);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2535, 'The Ramones придумали панк за 2000 долларов и 3 аккорда. Джонни Рамон не умел играть соло — и не надо, это было бунтом против прог-виртуозов.', '2026-04-22 21:44:50.102475'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2536, 'Sex Pistols наняли Сида Вишеса за то, что он выглядел как панк, хотя играть не умел. На записи бас партии исполнял Глен Мэтлок.', '2026-04-22 21:44:53.795121'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2537, 'Dead Kennedys выпустили «Too Drunk to Fuck» — Би-би-си запретила песню, но она стала культовой. Политический панк рулит.', '2026-04-22 21:44:58.505645'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2538, 'У Clash был контракт с CBS за 100 000 фунтов. Они купили оборудование и раздали остатки фанатам. Первый и последний рок-коммунизм.', '2026-04-22 21:45:02.091559'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2539, 'Black Flag гастролировали на раздолбанном фургоне, спали на полу и играли где угодно. Именно так выживал американский хардкор.', '2026-04-22 21:45:05.367764'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2540, 'Bad Religion все участники — университетские профессора или учёные. Их тексты умнее, чем у 90% метал-групп.', '2026-04-22 21:45:08.339375'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2541, 'Панк-фестиваль в Сан-Бернардино 1980 года: 10 000 панков, полиция в броне, аресты, а Minor Threat играют «Straight Edge» и никто не пьёт.', '2026-04-22 21:45:11.733692'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2542, 'Когда Green Day подписались на мейджор-лейбл, их назвали предателями. А они продали 10 миллионов «Dookie» и показали, что панк может быть массовым.', '2026-04-22 21:45:15.303117'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2543, 'Почему панк не умер? Потому что каждый подросток с гитарой за 50 долларов может выйти на сцену и орать про систему. Три аккорда — и ты революционер.', '2026-04-22 21:45:18.680592'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2544, 'Лучший панк-альбом 2023 года? «The Record» Boygenius — три девушки поют о тревожности и дружбе под электрогитары. Панк изменился, но бунт остался.', '2026-04-22 21:45:22.769065'::timestamp, 373);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2545, 'Radiohead записали «OK Computer» в особняке 16 века. Том Йорк пел в темноте при свечах, а продюсер сказал: «Это звучит как будущее».', '2026-04-22 21:45:26.155535'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2546, 'The Smashing Pumpkins «Mellon Collie» — двойной альбом на 2 часа. Билли Корган написал 56 песен, а после тура группа почти распалась из-за наркотиков.', '2026-04-22 21:45:29.537281'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2547, 'Nirvana ненавидели свою славу, но «Nevermind» убил глэм-метал. Курт Кобейн считал альбом слишком попсовым, особенно «Polly».', '2026-04-22 21:45:32.726758'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2548, 'PJ Harvey записала «Rid of Me» за 3 дня с продюсером Стивом Альбини. Звук — сырой, агрессивный, почти невыносимый. Гениальный.', '2026-04-22 21:45:35.888832'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2549, 'Neutral Milk Hotel записали «In the Aeroplane Over the Sea» в студии с плохой звукоизоляцией — слышно поезда. Это добавило альбому магии.', '2026-04-22 21:45:39.592511'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2550, 'Fiona Apple назвала свой альбом «When the Pawn...» с длинным названием из 90 слов. Это был ответ на сексистскую критику.', '2026-04-22 21:45:42.455806'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2551, 'The White Stripes — только гитара и барабаны. Ни баса, ни клавиш. И это звучало тяжелее, чем половина метал-групп нулевых.', '2026-04-22 21:45:45.715782'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2552, 'Arcade Fire записывали «Funeral» после смерти нескольких родственников участников. Альбом — плач и праздник одновременно.', '2026-04-22 21:45:48.481124'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2553, 'Sonic Youth настраивали гитары в 50 разных открытых строев, просто чтобы звук был «не как у всех».', '2026-04-22 21:45:51.552680'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2554, 'Jeff Buckley утонул, записав только один альбом «Grace». Его кавер на «Hallelujah» считается лучшим в истории.', '2026-04-22 21:45:54.619730'::timestamp, 374);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2555, 'Kurt Cobain пришёл на прослушивание в Nirvana с гитарой, на которой было написано «Fuck off». Продюсер понял: это то, что нужно.', '2026-04-22 21:45:57.869941'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2556, 'Soundgarden написали «Black Hole Sun» за 15 минут. Крис Корнелл сказал, что это был сюрреалистический сон, превращённый в песню.', '2026-04-22 21:46:00.681266'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2557, 'Pearl Jam боролись с Ticketmaster за цены на билеты. Проиграли, но фанаты запомнили.', '2026-04-22 21:46:03.740412'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2558, 'Альбом «Dirt» Alice in Chains написан под кокаином и героином. Лейн Стейли умер от передоза через 8 лет. Музыка осталась.', '2026-04-22 21:46:06.567760'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2559, 'В 1992 году Nirvana на MTV вышли в костюмах и сыграли попсу. Они троллили индустрию. Фанаты не поняли, но сейчас это легенда.', '2026-04-22 21:46:09.586086'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2560, 'Hole — не просто «группа Курта». Кортни Лав написала «Live Through This» через 4 дня после смерти Кобейна. Альбом — крик.', '2026-04-22 21:46:12.751243'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2561, 'Stone Temple Pilots обвиняли в том, что они копируют Pearl Jam. А они просто играли гранж по-своему. «Plush» — хит на века.', '2026-04-22 21:46:15.823784'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2562, 'Chris Cornell, Layne Staley, Kurt Cobain, Scott Weiland — 27 клуб. Четверо великих ушли слишком рано. Гранж проклят?', '2026-04-22 21:46:18.895954'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2563, 'Гранж-туса 1991 года в Сиэтле: на сцене Nirvana, Pearl Jam, Soundgarden, Alice in Chains. Билет стоил 10 долларов.', '2026-04-22 21:46:22.276212'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2564, 'Почему гранж умер? Потому что мейджоры выпустили сотни клонов, а оригиналы сгорели. Но без них не было бы альтернативы и инди.', '2026-04-22 21:46:26.067287'::timestamp, 375);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2565, 'The Beatles никогда не играли «Yesterday» на концертах — Пол Маккартни стеснялся её. А это самая кавер-версия песня в истории.', '2026-04-22 21:46:29.342613'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2566, 'Джим Моррисон из The Doors был арестован на сцене в Майами за непристойное поведение. Его посадили, а группа развалилась.', '2026-04-22 21:46:32.721932'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2567, 'Rolling Stones записали «(I Can''t Get No) Satisfaction» во сне. Кит Ричардс проснулся, включил кассетник, сыграл рифф и отрубился.', '2026-04-22 21:46:36.408440'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2568, 'The Who разогнали фестиваль в Вудстоке в 5 утра. Пит Таунсенд разбил гитару, а Кит Мун упал за барабаны — и это был эпик.', '2026-04-22 21:46:39.497937'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2569, 'Дженис Джоплин выпила бутылку виски перед каждым выходом. Голос — хриплый, надрывный, настоящий. Умерла в 27.', '2026-04-22 21:46:42.670988'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2570, 'AC/DC записали «Back in Black» через 5 месяцев после смерти Бона Скотта. Брайан Джонсон выучил тексты за одну ночь.', '2026-04-22 21:46:45.898322'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2571, 'Queen на концерте в Рио 1985 года собрали 300 000 человек. Фредди бегал по сцене в кожаных штанах, хотя уже знал о ВИЧ.', '2026-04-22 21:46:49.516183'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2572, 'The Kinks запретили выступать в США на 4 года из-за буйного поведения. За это время они написали «Waterloo Sunset» — шедевр.', '2026-04-22 21:46:52.914537'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2573, 'Легенда: когда Дэвид Боуи выпустил «Ziggy Stardust», лейбл думал, что он сумасшедший. А он создал рок-миф, который живёт до сих пор.', '2026-04-22 21:46:56.061506'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2574, 'Лучший рок-альбом 1971 года? «Who''s Next», «Led Zeppelin IV» или «Imagine»? Спорим вечно, но слушаем все три.', '2026-04-22 21:46:59.449852'::timestamp, 376);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2575, 'Джон Пол Джонс из Led Zeppelin сыграл бас в «Ramble On» смычком. Никто до него не додумался.', '2026-04-22 21:47:02.844927'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2576, 'Geddy Lee из Rush играет на басу, поёт и нажимает на педали синтезатора ногами. Человек-оркестр.', '2026-04-22 21:47:06.331941'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2577, 'Бас-партия «Billie Jean» не Майкла Джексона, а Луи Джонсона. Он сыграл её на Yamaha и создал самый копируемый ритм в поп-музыке.', '2026-04-22 21:47:09.503196'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2578, 'Flea из Red Hot Chili Peppers перед выходом на сцену делает 100 отжиманий и прыгает. Его энергия питает весь концерт.', '2026-04-22 21:47:12.147925'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2579, 'Почему бас незаметен? Потому что он не для ушей, а для живота. Убери бас — и песня станет плоской.', '2026-04-22 21:47:14.914066'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2580, 'Cliff Burton из Metallica использовал дисторшн на басу иwah-wah. Его соло в «Anesthesia» — одна из лучших записей живого баса.', '2026-04-22 21:47:17.902265'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2581, 'Поль Маккартни играл на басу Höfner, потому что он симметричный и подходит левше. А его мелодичные партии изменили роль баса.', '2026-04-22 21:47:21.774350'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2582, 'Лемми из Motörhead никогда не пользовался медиатором — только пальцами. Его бас звучал как ломовая лошадь.', '2026-04-22 21:47:24.642639'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2583, 'Самый сложный бас в роке? «YYZ» Rush — ритмические рисунки и синкопы, которые обычный человек не повторит.', '2026-04-22 21:47:27.816886'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2584, 'Басисты — самые недооценённые музыканты. Мы держим ритм, гармонию и при этом стоим в тени гитаристов. Но без нас вы бы танцевали под метроном.', '2026-04-22 21:47:30.992110'::timestamp, 377);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2585, 'Фестиваль Donington 1984: 70 000 металхедов, ливень, Van Halen играют, а в поле — море грязи. Люди катаются по ней голыми.', '2026-04-22 21:47:34.064951'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2586, 'Концерт Queen в Будапеште 1986 года — первый рок-концерт за железным занавесом. 80 000 венгров рыдали от счастья.', '2026-04-22 21:47:37.238693'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2587, 'Pink Floyd шоу «The Wall» в Берлине 1990 года — 300 000 человек, стена высотой 25 метров, и её рушат под «Another Brick in the Wall».', '2026-04-22 21:47:40.020111'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2588, 'Foo Fighters в 2011 году сыграли 3.5 часа, потому что Дэйв Грол сломал ногу, но не хотел уходить. Забил гипс и продолжил.', '2026-04-22 21:47:43.296537'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2589, 'Lollapalooza 1992: Red Hot Chili Peppers, Soundgarden, Pearl Jam. Энтони Кидис вышел в одном носке. Толпа обезумела.', '2026-04-22 21:47:46.456622'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2590, 'Когда Rage Against the Machine играли на Democratic Convention 2000, их отключили через 3 песни. Задроты спустились в толпу и продолжили акустикой.', '2026-04-22 21:47:49.646311'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2591, 'Гластонбери 2000: Дэвид Боуи вышел в пиджаке и спел «Heroes». 150 000 человек плакали. Это был его последний фестиваль.', '2026-04-22 21:47:53.009311'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2592, 'Я видел, как барабанщик Tool играл 15-минутное соло, а гитарист в это время молча стоял. Зал не аплодировал — все просто смотрели с открытыми ртами.', '2026-04-22 21:47:56.407831'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2593, 'Лучшее живое выступление 2024 года? IDLES в крошечном клубе на 300 человек. Энергия такая, что стены потели.', '2026-04-22 21:47:59.359427'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2594, 'Концерт — это не музыка. Это когда свет, запах пота и крик толпы превращают тебя в кого-то другого на 2 часа. Живой рок никогда не умрёт.', '2026-04-22 21:48:02.345232'::timestamp, 378);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2595, 'Чёрная дыра в центре Млечного Пути Sgr A* в 4 миллиона раз тяжелее Солнца. Мы получили её фото только в 2022 году, хотя знали о ней 50 лет.', '2026-04-22 21:48:09.696713'::timestamp, 379);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2596, 'Когда звезда массивнее 8 солнечных масс взрывается сверхновой, её ядро коллапсирует в нейтронную звезду или чёрную дыру. Тяжелее — только чёрная дыра.', '2026-04-22 21:48:12.876651'::timestamp, 379);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2597, 'Гамма-всплески — самые энергичные события после Большого взрыва. За секунду выделяется энергии больше, чем Солнце за 10 миллиардов лет.', '2026-04-22 21:48:16.436239'::timestamp, 379);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2598, 'Почему горизонт событий чёрной дыры называется «горизонтом»? Потому что оттуда нельзя вернуться — даже свет. И мы не знаем, что внутри.', '2026-04-22 21:48:19.738617'::timestamp, 379);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2599, 'Тёмная материя не взаимодействует со светом, но её в 5 раз больше, чем обычной. Мы видим её только по гравитационному линзированию и скоростям звёзд.', '2026-04-22 21:48:23.323101'::timestamp, 379);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2600, 'Квантовая суперпозиция: кубит может быть 0 и 1 одновременно. Пока не измеришь. Это не магия, а математика — гильбертово пространство.', '2026-04-22 21:48:26.908094'::timestamp, 380);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2601, 'В квантовой запутанности частицы связаны так, что измерение одной мгновенно определяет состояние другой, даже на расстоянии. Эйнштейн называл это «жутким действием на расстоянии».', '2026-04-22 21:48:30.184969'::timestamp, 380);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2602, 'Квантовые компьютеры решают задачи в секунды, на которые классическим нужны тысячи лет. Например, факторизация больших чисел для взлома RSA.', '2026-04-22 21:48:33.373579'::timestamp, 380);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2603, 'Принцип неопределённости Гейзенберга: нельзя одновременно точно знать положение и импульс частицы. Δx·Δp ≥ ħ/2. Это не погрешность прибора, а свойство природы.', '2026-04-22 21:48:37.660866'::timestamp, 380);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2604, 'Декогеренция — главная проблема кубитов. Любое взаимодействие с окружающей средой разрушает квантовое состояние. Поэтому квантовые процессоры работают при температуре близкой к абсолютному нулю.', '2026-04-22 21:48:40.939346'::timestamp, 380);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2605, 'Луис и Мэри Лики нашли останки австралопитека Люси в 1974 году. Ей 3.2 миллиона лет, и она ходила на двух ногах. Прямой предок человека?', '2026-04-22 21:48:44.214187'::timestamp, 381);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2606, 'Горизонтальный перенос генов у бактерий — почему антибиотики перестают работать. Бактерии обмениваются плазмидами с генами устойчивости, даже разных видов.', '2026-04-22 21:48:47.879772'::timestamp, 381);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2607, 'Рудименты: аппендикс, копчик, третье веко. У китов есть кости задних конечностей. Эволюция не переписывает код заново — она модифицирует старое.', '2026-04-22 21:48:51.383572'::timestamp, 381);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2608, 'Естественный отбор не «заставляет» виды становиться сложнее. Он просто отсеивает менее приспособленных. Адаптация — локальная штука, не абсолютная.', '2026-04-22 21:48:54.368024'::timestamp, 381);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2609, 'Эволюция человека не остановилась. Ген устойчивости к ВИЧ CCR5-Δ32 распространился в Европе за последние 700 лет — возможно, из-за эпидемий чумы.', '2026-04-22 21:48:57.322200'::timestamp, 381);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2610, 'Нейроны передают сигнал со скоростью до 120 м/с. Потенциал действия возникает, когда мембранный потенциал достигает порога -55 мВ.', '2026-04-22 21:49:00.496816'::timestamp, 382);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2611, 'Гиппокамп отвечает за память. У лондонских таксистов, которые учат карту города, его объём физически больше. Нейропластичность в действии.', '2026-04-22 21:49:03.568876'::timestamp, 382);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2612, 'Дофамин — не «гормон счастья», а нейромедиатор предвкушения. Он выделяется, когда вы ждёте награду, а не когда получаете. Отсюда зависимость от соцсетей.', '2026-04-22 21:49:06.663969'::timestamp, 382);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2613, 'Зеркальные нейроны активируются и когда вы сами что-то делаете, и когда видите действие другого. Считается, что это основа эмпатии и обучения через подражание.', '2026-04-22 21:49:09.918620'::timestamp, 382);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2614, 'Миелиновая оболочка изолирует аксон и ускоряет проведение импульса. При рассеянном склерозе она разрушается — сигналы затухают, возникают проблемы с движением.', '2026-04-22 21:49:13.195091'::timestamp, 382);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2615, 'Содержание CO₂ в атмосфере сейчас 420 ppm — выше, чем за последние 800 000 лет. До индустриальной революции было 280 ppm.', '2026-04-22 21:49:16.369678'::timestamp, 383);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2616, 'Средняя температура Земли выросла на 1.2°C с конца XIX века. Кажется немного, но энергия этого нагрева эквивалентна 4 взрывам Хиросимы каждую секунду.', '2026-04-22 21:49:19.749632'::timestamp, 383);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2617, 'Таяние Гренландии: 270 миллиардов тонн льда в год. Если растает вся Гренландия — уровень моря поднимется на 7 метров. Утонут все прибрежные города.', '2026-04-22 21:49:23.246012'::timestamp, 383);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2618, 'Океан поглощает 25% CO₂, который выбрасывает человек. Это замедляет потепление, но приводит к закислению воды — кораллы и моллюски не могут строить раковины.', '2026-04-22 21:49:27.429531'::timestamp, 383);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2619, 'Парниковый эффект: без него средняя температура на Земле была бы -18°C. Проблема не в парниковых газах как таковых, а в их резком росте за 150 лет.', '2026-04-22 21:49:30.399703'::timestamp, 383);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2620, 'Графен — двумерный материал толщиной в один атом, в 200 раз прочнее стали и проводит электричество лучше меди. Но массового производства до сих пор нет.', '2026-04-22 21:49:34.394497'::timestamp, 384);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2621, 'Память формы: сплавы никелида титана (нитинол) «запоминают» форму. Деформируйте, нагрейте — вернётся в исходное состояние. Сосуды-стенты в медицине.', '2026-04-22 21:49:37.773941'::timestamp, 384);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2622, 'Сверхгидрофобные поверхности — эффект лотоса. Микроструктура из воска и бугорков отталкивает воду. На таких поверхностях капли скатываются, смывая грязь.', '2026-04-22 21:49:41.124609'::timestamp, 384);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2623, 'Пьезоэлектрики — кварц, титанат бария. При сжатии возникает напряжение. Зажигалка для газа, кварцевый резонатор в часах.', '2026-04-22 21:49:45.044499'::timestamp, 384);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2624, 'Фотокатализ на диоксиде титана: под УФ-светом он разлагает органику. Самоочищающиеся стёкла и бетон, которые борются с загрязнением воздуха.', '2026-04-22 21:49:48.423392'::timestamp, 384);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2625, 'Лист Мёбиуса имеет одну сторону и один край. Вы можете сделать его из полоски бумаги, склеив концы после полуоборота. Неориентируемая поверхность.', '2026-04-22 21:49:51.921488'::timestamp, 385);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2626, 'Четырёхцветная теорема: любую карту на плоскости можно раскрасить в 4 цвета так, что соседние страны будут разными. Доказано перебором 2000 конфигураций на компьютере.', '2026-04-22 21:49:55.505991'::timestamp, 385);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2627, 'Бутылка Клейна — поверхность, у которой нет ни внутренности, ни наружности. Её нельзя вложить в трёхмерное пространство без самопересечений.', '2026-04-22 21:49:58.261207'::timestamp, 385);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2628, 'Проблема тысячи чертей: сколько цветов нужно, чтобы раскрасить граф без пересечений? В 2018 году доказали, что для любых карт хватает 5 цветов, но пример с 5 — построен.', '2026-04-22 21:50:02.248601'::timestamp, 385);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2629, 'Гомотопия: круг можно стянуть в точку, а сферу — нельзя, если точка не на сфере. Это инвариант — фундаментальная группа π₁. Топологи ищут «форму пространства».', '2026-04-22 21:50:05.440314'::timestamp, 385);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2630, 'Тираннозавр рекс жил 68-66 млн лет назад. Он не бегал, как в «Парке Юрского периода», — его скорость была 25 км/ч. Но зато у него было самое сильное укусное усилие среди наземных животных.', '2026-04-22 21:50:09.315076'::timestamp, 386);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2631, 'Археоптерикс — переходная форма между динозаврами и птицами. У него были перья, но и зубы, и длинный костный хвост. Жил 150 млн лет назад.', '2026-04-22 21:50:12.591356'::timestamp, 386);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2632, 'Трилобиты господствовали в морях 270 млн лет. У них было фасеточное зрение из кальцита — каждая линза была кристаллом. Исчезли в пермском вымирании.', '2026-04-22 21:50:15.971095'::timestamp, 386);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2633, 'Шерстистый мамонт не был просто лохматым слоном. У него были маленькие уши (чтобы не обмораживать), горб жира на загривке и бивни до 4 метров.', '2026-04-22 21:50:19.044346'::timestamp, 386);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2634, 'Ихтиозавры — морские рептилии, которые выглядели как дельфины, но произошли от сухопутных предков. Живородящие — найден скелет самки с эмбрионом внутри.', '2026-04-22 21:50:22.525808'::timestamp, 386);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2635, 'CRISPR-Cas9 — ножницы для ДНК, которые бактерии используют против вирусов. Сейчас мы умеем программировать их, чтобы вырезать и вставлять гены.', '2026-04-22 21:50:26.110032'::timestamp, 387);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2636, 'Геном человека содержит 3 миллиарда пар оснований, но только 1.5% кодируют белки. Остальное — регуляторные последовательности и «мёртвые» вирусы.', '2026-04-22 21:50:29.710297'::timestamp, 387);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2637, 'Мутация в гене CCR5 делает человека устойчивым к ВИЧ. «Берлинский пациент» вылечился после пересадки костного мозга от такого донора.', '2026-04-22 21:50:32.986729'::timestamp, 387);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2638, 'Эпигенетика: метилирование ДНК и модификация гистонов меняют активность генов без изменения последовательности. Голод в Нидерландах в 1944-45 изменил метилирование у внуков.', '2026-04-22 21:50:36.575394'::timestamp, 387);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2639, 'Митохондриальная ДНК передаётся только от матери. У всех людей есть общая «митохондриальная Ева», которая жила в Африке 150 000 лет назад.', '2026-04-22 21:50:40.009567'::timestamp, 387);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2640, 'Марианская впадина — глубина 11 км. Давление в 1100 раз выше атмосферного. Там живут рыбы-психролюты, которые не имеют чешуи и имеют студенистое тело.', '2026-04-22 21:50:43.622361'::timestamp, 388);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2641, 'Гидротермальные источники на дне океана — чёрные курильщики. Температура воды +400°C, но она не кипит из-за давления. Экосистемы без солнечного света, на хемосинтезе.', '2026-04-22 21:50:46.899174'::timestamp, 388);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2642, 'Кальмар-вампир (Vampyroteuthis) живёт на глубине 600-900 метров. Защищается биолюминесцентными «огненными шоу» — светящимися облаками.', '2026-04-22 21:50:50.792781'::timestamp, 388);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2643, 'Китовый фекальный насос: киты питаются в глубине, всплывают и выделяют фекалии, богатые железом. Это удобряет фитопланктон, который поглощает CO₂.', '2026-04-22 21:50:54.579481'::timestamp, 388);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2644, 'Зона сумерек (200-1000 м) — самая большая экосистема на Земле. Там живут рыбы с собственными фонариками (фотофоры) для привлечения добычи и маскировки.', '2026-04-22 21:50:58.163593'::timestamp, 388);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2645, 'Бозон Хиггса — частица, отвечающая за массу. Открыта на БАК в 2012 году. Без неё все частицы летали бы со скоростью света.', '2026-04-22 21:51:02.012281'::timestamp, 389);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2646, 'Нейтрино — самые лёгкие и неуловимые частицы. Через каждый квадратный сантиметр Земли каждую секунду проходит 65 миллиардов солнечных нейтрино, и вы этого не замечаете.', '2026-04-22 21:51:05.230465'::timestamp, 389);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2647, 'Кварки никогда не встречаются в одиночку. В адронах (протоны, нейтроны) они связаны сильным взаимодействием. Попробуйте разорвать — энергия создаст новые кварки.', '2026-04-22 21:51:08.830130'::timestamp, 389);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2648, 'Антиматерия: у каждой частицы есть античастица с противоположным зарядом. При аннигиляции выделяется энергия по формуле E=mc². Но почему Вселенная состоит из материи, а не антиматерии?', '2026-04-22 21:51:11.886286'::timestamp, 389);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2649, 'Большой адронный коллайдер разгоняет протоны до 99.999999% скорости света. Энергия пучка — 6.5 ТэВ. Магниты охлаждаются жидким гелием до -271°C.', '2026-04-22 21:51:15.368145'::timestamp, 389);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2650, 'В кишечнике человека живёт 100 триллионов бактерий — в 10 раз больше, чем наших собственных клеток. Их геном (микробиом) в 100 раз больше человеческого.', '2026-04-22 21:51:18.337974'::timestamp, 390);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2651, 'Бактерии в кишечнике синтезируют витамины K, B12, а также нейромедиаторы — серотонин (90% всего серотонина организма) и дофамин.', '2026-04-22 21:51:21.637551'::timestamp, 390);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2652, 'Кесарево сечение меняет микробиом младенца: вместо бактерий из родовых путей он получает кожную флору матери. Это связано с повышенным риском аллергий и ожирения.', '2026-04-22 21:51:25.405651'::timestamp, 390);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2653, 'Фекальная трансплантация — введение кала здорового донора пациенту с Clostridium difficile. Эффективность — 90%, это золотой стандарт при рецидивах.', '2026-04-22 21:51:28.783843'::timestamp, 390);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2654, 'Пребиотики (клетчатка) и пробиотики (живые бактерии). Клетчатка — еда для полезных бифидо- и лактобактерий. Без неё они голодают.', '2026-04-22 21:51:32.282017'::timestamp, 390);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2655, 'Марсоход Curiosity обнаружил на Марсе органические молекулы и метан. Метан быстро разрушается под УФ, значит, он постоянно выделяется — возможно, из-за микробов?', '2026-04-22 21:51:35.749639'::timestamp, 391);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2656, 'Экзопланета TRAPPIST-1e находится в обитаемой зоне. У неё размер как у Земли, и она получает от своей звезды столько же света, сколько Земля от Солнца.', '2026-04-22 21:51:39.325547'::timestamp, 391);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2657, 'Титан — спутник Сатурна с атмосферой из азота и озёрами жидкого метана. Температура -179°C. Возможна ли жизнь на метановой основе?', '2026-04-22 21:51:42.318491'::timestamp, 391);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2658, 'Европа — спутник Юпитера с подлёдным океаном. Под ледяной корой глубиной 10-30 км — океан жидкой воды. Гидротермальные источники как на Земле?', '2026-04-22 21:51:45.784228'::timestamp, 391);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2659, 'Космический телескоп Джеймса Уэбба видит первые галактики, которые сформировались через 300 миллионов лет после Большого взрыва. Свет идёт 13.5 миллиардов лет.', '2026-04-22 21:51:49.375139'::timestamp, 391);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2660, 'GPT-4 имеет 1.7 триллиона параметров. Это не интеллект, а статистическое моделирование языка. Он не понимает смысла, но выдаёт правдоподобные тексты.', '2026-04-22 21:51:53.715224'::timestamp, 392);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2661, 'Свёрточные нейронные сети распознают образы не хуже человека. Они учатся находить края, формы, части объектов, а затем собирают их в целое.', '2026-04-22 21:51:57.341879'::timestamp, 392);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2662, 'Обучение с подкреплением: AlphaGo обыграл чемпиона мира в го. Алгоритм играл миллионы партий сам с собой, оптимизируя награду за выигрыш.', '2026-04-22 21:52:00.802692'::timestamp, 392);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2663, 'Проблема «чёрного ящика»: нейросети решают задачи, но мы не можем объяснить, как именно. Это критично для медицины и беспилотных авто.', '2026-04-22 21:52:04.233956'::timestamp, 392);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2664, 'Искусственный общий интеллект (AGI) пока не создан. Современные модели — узкий ИИ, они превосходят человека только в одной области.', '2026-04-22 21:52:07.202908'::timestamp, 392);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2665, 'Литосферные плиты движутся со скоростью 2-15 см в год — как рост ногтей. Землетрясения и вулканы происходят на границах плит.', '2026-04-22 21:52:10.259858'::timestamp, 393);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2666, 'Магнитное поле Земли создаётся жидким внешним ядром из железа и никеля. Оно защищает нас от солнечного ветра. Каждые 500 000 лет поле инвертируется.', '2026-04-22 21:52:13.740281'::timestamp, 393);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2667, 'Землетрясение магнитудой 9.0 в Японии 2011 года сдвинуло остров Хонсю на 2.4 метра и ускорило вращение Земли на 1.8 микросекунды.', '2026-04-22 21:52:17.018333'::timestamp, 393);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2668, 'Горячая точка Гавайев — мантийный плюм, который «прожигает» тихоокеанскую плиту. Цепь вулканов показывает направление движения плиты.', '2026-04-22 21:52:19.885926'::timestamp, 393);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2669, 'Радиоактивный распад урана, тория и калия внутри Земли выделяет 47 тераватт тепла — половина от общего теплового потока. Остальное — остаточное от формирования планеты.', '2026-04-22 21:52:22.973672'::timestamp, 393);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2670, 'Вирусы не живые — у них нет метаболизма, они не размножаются вне клетки. Но их геномы эволюционируют, и они захватывают клеточные механизмы.', '2026-04-22 21:52:26.541418'::timestamp, 394);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2671, 'РНК-вирусы, такие как ВИЧ и коронавирус, мутируют быстрее из-за отсутствия коррекции ошибок при копировании. Отсюда новые штаммы.', '2026-04-22 21:52:29.922359'::timestamp, 394);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2672, 'Бактериофаги — вирусы, убивающие бактерий. Их открыл Феликс Д’Эррель в 1917 году. Сейчас фаговая терапия — альтернатива антибиотикам при резистентности.', '2026-04-22 21:52:33.608229'::timestamp, 394);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2673, 'Вирусные векторы используются в генной терапии. Аденовирусы и AAV доставляют здоровые копии генов при наследственных болезнях, например, при СМА.', '2026-04-22 21:52:37.192714'::timestamp, 394);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2674, 'Вакцинация работает, потому что создаёт иммунную память. После встречи с убитым или ослабленным вирусом образуются В-клетки памяти, которые быстро реагируют при реальной инфекции.', '2026-04-22 21:52:40.382965'::timestamp, 394);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2675, 'Boston Dynamics Atlas прыгает, делает сальто и бегает по пересечённой местности. Использует гидравлику и лидар для балансировки в реальном времени.', '2026-04-22 21:52:43.950971'::timestamp, 395);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2676, 'Промышленные роботы на заводах автомобилей — точность позиционирования 0.02 мм. Они работают 24/7 и никогда не ошибаются (если правильно запрограммированы).', '2026-04-22 21:52:47.433952'::timestamp, 395);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2677, 'Мягкая роботика: силиконовые манипуляторы для захвата нежных объектов (помидоры, яйца). Без обратной связи по силе они просто обтекают предмет.', '2026-04-22 21:52:50.828228'::timestamp, 395);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2678, 'Ошибка 90% парней: покупают кроссовки под любой аутфит. Нет, под классические брюки нужны минималистичные кеды или лоферы, а не громоздкие белые «кирпичи».', '2026-04-23 11:16:44.118066'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2679, 'Уличный стиль последних двух сезонов — это oversize поверх oversize. Но чтобы не выглядеть как мешок, один слой должен быть приталенным.', '2026-04-23 11:16:46.653853'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2680, 'Тренд, который я ненавижу: джинсы с дырками на коленях зимой. Ноги мёрзнут, а вид — будто тебя собака покусала.', '2026-04-23 11:16:49.594082'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2681, 'Самая частая проблема мужского гардероба: чёрные джинсы, чёрные кроссовки, чёрная футболка. Это не стиль, это траур. Добавьте хотя бы один светлый акцент — сумку, ремень, носки.', '2026-04-23 11:16:52.261828'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2682, 'Носки с сандалиями больше не мем. Если вы носите сандалии с носками в городе — вы либо немецкий турист, либо фанат Балкан. Остановитесь.', '2026-04-23 11:16:54.573948'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2683, 'Штаны карго вернулись, но не те, в которых вы ходили в 2005. Сейчас они — зауженные к низу, без огромных накладных карманов, из плотного хлопка.', '2026-04-23 11:16:56.659690'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2684, 'Пальто-оверсайз смотрится круто только если у вас рост от 175. На низком росте оно превращает в гриб.', '2026-04-23 11:16:58.794033'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2685, 'Что купить весной 2025: ветровку-анорак нейтрального цвета, мешковатые джинсы, кожаные лоферы на толстой подошве. И никаких логотипов.', '2026-04-23 11:17:01.370892'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2686, 'Базовый гардероб: две футболки (белая и чёрная), два свитера (серый и бежевый), две пары джинс (синие и чёрные), кеды, лоферы, ботинки. Всё остальное — акценты.', '2026-04-23 11:17:03.624042'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2687, 'Главное правило уличного стиля: несочетаемое сочетать. Но для этого нужно чувство меры, а не просто надеть всё подряд.', '2026-04-23 11:17:05.875265'::timestamp, 399);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2688, 'Капсула из 10 вещей: белая рубашка, чёрные брюки, бежевый свитер, джинсы, блейзер, платье-футляр, тренч, лодочки, кроссовки, сумка-тоут. Всё комбинируется.', '2026-04-23 11:17:08.848092'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2689, 'Чёрный цвет стройнит, но если вы одеты во всё чёрное, добавьте текстуру: кожа, хлопок, шерсть, кашемир. Иначе выглядит плоско.', '2026-04-23 11:17:11.100050'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2690, 'Почему я выбрасываю вещи с логотипами? Потому что я хочу, чтобы люди смотрели на меня, а не на бренд.', '2026-04-23 11:17:13.353114'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2691, 'Мои инвестиции: хорошее пальто, сумка из натуральной кожи, часы. Всё остальное можно купить в масс-маркете, если знать, как сочетать.', '2026-04-23 11:17:15.706258'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2692, 'Базовый свитер из мериноса служит 5 лет. Из акрила — 2 стирки, и он катышками. Экономия на качестве выходит боком.', '2026-04-23 11:17:18.164261'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2693, 'Белая футболка — святое. Но только из 100% хлопка, плотная, с двойной строчкой на плечах. Такая стоит 2000-3000, не 500.', '2026-04-23 11:17:20.418459'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2694, 'Самый недооценённый предмет гардероба — жилет. Поверх рубашки, под пиджак, с джинсами. Добавляет слоёв и структуры.', '2026-04-23 11:17:22.464621'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2695, 'Почему унисекс-одежда так популярна? Потому что женщины устали от розового и кружев. Мужской крой даёт свободу и удобство.', '2026-04-23 11:17:24.819795'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2696, 'Не покупайте вещь, если она требует специального ухода. Если на этикетке «только химчистка» — вы будете носить её два раза в год.', '2026-04-23 11:17:27.177921'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2697, 'Минимализм — это не пустой шкаф, а гардероб, где каждая вещь имеет свою роль. Если вы сомневаетесь, зачем она вам — выкиньте.', '2026-04-23 11:17:29.398020'::timestamp, 400);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2698, 'Нашёл на блошином рынке левисы 80-х за 15 евро. Джинса плотная, как броня, потёртости настоящие. Такие сейчас стоят 15 000.', '2026-04-23 11:17:32.091248'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2699, 'Винтажный Levi''s Type III джинсовый пиджак 70-х. Поношенный, с дыркой на локте. Это не дефект, это история.', '2026-04-23 11:17:34.446440'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2700, 'Платье 60-х в цветочек за 10 долларов в благотворительном магазине. Посадка идеальная, ткань — хлопок с вискозой, на новые так не шьют.', '2026-04-23 11:17:37.009385'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2701, 'Совет: ищите винтаж по составам. 100% шерсть, хлопок, лён, шёлк — современные вещи с таким составом стоят бешено, а на секонд-хенде копейки.', '2026-04-23 11:17:39.773189'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2702, 'Ремень 50-х с пряжкой в виде орла. Кожа до сих пор мягкая, а металл не потемнел. Качество, которого уже нет.', '2026-04-23 11:17:42.684354'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2703, 'Ботинки Grinders 90-х. Сделаны в Англии, кожа 3 мм толщиной. Проходят ещё 20 лет. Нынешние Grinders — китайский пластик.', '2026-04-23 11:17:45.609999'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2704, 'Чем отличается настоящий винтаж от стилизации? Настоящий пахнет нафталином и пылью, у него неравномерный цвет, и он часто маломерка.', '2026-04-23 11:17:49.015225'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2705, 'Мой лайфхак: искать в мужских отделах. Женские платья и блузки 70-80х часто в идеальном состоянии — их редко носили.', '2026-04-23 11:17:51.341671'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2706, 'Винтаж не обязательно про ретро. Смешайте винтажный пиджак с новыми джинсами и кроссовками — получите современный аутфит.', '2026-04-23 11:17:53.593468'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2707, 'В 2025 тренд на upcycling. Перешиваю старые джинсы в юбку, а рубашку в топ. Это и экологично, и уникально.', '2026-04-23 11:17:55.641132'::timestamp, 401);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2708, 'Сочетание красного и розового больше не табу. Главное — один цвет должен быть ярким, другой приглушённым. Красный свитер + розовые брюки-пыль? Да.', '2026-04-23 11:17:58.408578'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2709, 'Правило трёх цветов: основной (60%), вторичный (30%), акцент (10%). Не нарушайте, пока не научитесь чувствовать баланс.', '2026-04-23 11:18:00.763002'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2710, 'Синий и зелёный — соседи по цветовому кругу. Идеальное спокойное сочетание: оливковые брюки + синий джемпер.', '2026-04-23 11:18:03.015418'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2711, 'Жёлтый — самый сложный цвет. Если не хотите выглядеть как такси, берите горчичный или охра, а не кислотный.', '2026-04-23 11:18:05.168036'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2712, 'Монохромный образ в бежевом — скучно? Нет, если смешать оттенки от песочного до кофейного. И добавить текстуру.', '2026-04-23 11:18:07.316997'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2713, 'Фиолетовый с оранжевым — адское сочетание для большинства. Но если взять лавандовый и терракотовый, это очень мягко.', '2026-04-23 11:18:09.568582'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2714, 'Чёрный + белый + красный — вечная классика. Красная сумка или туфли превращают чёрно-белый образ в вечерний.', '2026-04-23 11:18:11.946812'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2715, 'Цвет года 2025 по версии Pantone — Mocha Mousse. Нежно-коричневый, телесный. Сочетается с бежевым, серым, зелёным.', '2026-04-23 11:18:14.281329'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2716, 'Как носить неон? Одну деталь. Розовая неоновая сумка к полностью чёрному луку — да. Розовые неоновые штаны — нет.', '2026-04-23 11:18:16.746833'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2717, 'Пастельные тона: мятный, лавандовый, персиковый. Они работают только в плотных тканях. В тонком трикотаже выглядят дёшево.', '2026-04-23 11:18:19.097568'::timestamp, 402);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2718, 'Хлопок — дышит, мнётся. Лён — мнётся ещё сильнее, но очень благородно. Полиэстер — не мнётся, но вы будете потеть.', '2026-04-23 11:18:21.868862'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2719, 'Кашемир — мягче мериноса, но требует бережной стирки и ухода от моли. Один кашемировый свитер может стоить 10 акриловых, но прослужит дольше.', '2026-04-23 11:18:24.416271'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2720, 'Шерсть альпака не колется, теплее овечьей и не скатывается. Идеальный выбор для свитера, если у вас чувствительная кожа.', '2026-04-23 11:18:26.674868'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2721, 'Вискоза — это дерево, переработанное химией. Она мягкая и приятная, но после стирки может сесть на 5-10%.', '2026-04-23 11:18:29.025810'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2722, 'Натуральный шёлк не скользит, в отличие от искусственного. Проверить можно: настоящий шёлк при горении пахнет жжёными волосами, синтетика — пластиком.', '2026-04-23 11:18:31.386797'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2723, 'Твид — шерстяная ткань с пупырышками. Идеален для пиджаков и пальто. Не мнётся, держит форму, но тяжёлый.', '2026-04-23 11:18:33.633531'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2724, 'Флис — синтетика, но очень тёплая и быстросохнущая. Для активного отдыха лучше шерсти, для города — нет.', '2026-04-23 11:18:35.782562'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2725, 'Бамбуковая вискоза: мягкая, антибактериальная, но в производстве химия. Не верьте в «эко» — это маркетинг.', '2026-04-23 11:18:37.940111'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2726, 'Кожа: растительное дубление — экологично, но дорого. Хромовое дубление — быстро, дешево, но опасно для рабочих на фабриках.', '2026-04-23 11:18:40.292431'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2727, 'Самый недооценённый материал: хлопковый вельвет. Плотный, тёплый, с интересной фактурой. Отлично смотрится в брюках и пиджаках.', '2026-04-23 11:18:43.303920'::timestamp, 403);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2728, 'Пиджак сидит идеально, если плечевой шов заканчивается там, где заканчивается ваше плечо. Свисает — велик, топорщится — мал.', '2026-04-23 11:18:46.398565'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2729, 'Длина брюк: классика — одна складка на ботинке. Современный стиль — чуть выше щиколотки (но не как капри).', '2026-04-23 11:18:50.835064'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2730, 'Посадка пиджака: пуговица должна застёгиваться без натяжения, но и не болтаться. Между тканью и животом проходит ладонь.', '2026-04-23 11:18:52.994177'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2731, 'Укоротить рукав пиджака так, чтобы из-под него выглядывал манжет рубашки на 1-1.5 см. Это визуально удлиняет руки.', '2026-04-23 11:18:55.464795'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2732, 'Брюки со стрелками стройнят, но только если они сидят на талии, а не на бёдрах. Иначе стрелки расходятся.', '2026-04-23 11:18:57.593242'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2733, 'Пальто должно быть на размер больше, чем пиджак, чтобы не сковывать движения и надеваться поверх свитера.', '2026-04-23 11:18:59.952060'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2734, 'Ремень выбирайте под обувь. Коричневые туфли — коричневый ремень. Чёрные — чёрный. Кожа ремня должна быть как у обуви.', '2026-04-23 11:19:02.412952'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2735, 'Воротник рубашки: должен плотно облегать шею, но не душить. Палец между шеей и воротником проходит свободно.', '2026-04-23 11:19:04.870117'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2736, 'Если у вас узкие плечи, выбирайте пиджаки с мягким плечом (без наплечников) и с вертикальными полосками.', '2026-04-23 11:19:07.116913'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2737, 'Большинство проблем посадки решает портной. Купить вещь на размер больше и ушить стоит 1000-2000 рублей. Лучше, чем искать идеальную с первого раза.', '2026-04-23 11:19:09.580117'::timestamp, 404);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2738, 'Офисный код больше не требует пиджака каждый день. Но джинсы и худи — всё ещё нет. Замените худи на кардиган или джемпер.', '2026-04-23 11:19:12.339548'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2739, 'Белая рубашка — must have. Но она должна быть выглажена. Мятая рубашка убивает любой образ, даже с дорогими часами.', '2026-04-23 11:19:14.488657'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2740, 'Блейзер в клетку — спасение. Его можно носить и с брюками, и с джинсами, и поверх платья.', '2026-04-23 11:19:16.843372'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2741, 'Спортивные кроссовки в офис? Только если у вас стартап. В нормальной компании — лоферы, оксфорды, дерби.', '2026-04-23 11:19:19.303272'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2742, 'Чёрные брюки и чёрная рубашка — не офисный стиль, а официант. Разбавляйте цветом: синий пиджак, бежевый свитер.', '2026-04-23 11:19:21.660457'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2743, 'Лучший выбор на лето: льняная рубашка с длинным рукавом (закатать) и хлопковые чиносы. Дышит, не жарко, солидно.', '2026-04-23 11:19:24.012099'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2744, 'Зимний офисный лук: кашемировый свитер-водолазка, брюки из шерстяной фланели, ботинки. Тепло и элегантно.', '2026-04-23 11:19:26.325381'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2745, 'Аксессуары в офисе: часы, ремень, сумка-портфель. Броские носки или запонки — для смелых.', '2026-04-23 11:19:28.826372'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2746, 'Что я никогда не надену в офис: шорты, сланцы, футболку с принтом, рваные джинсы, спортивный костюм.', '2026-04-23 11:19:31.179504'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2747, 'Секрет стильного офисного образа: верх на размер больше, низ в обтяжку (или наоборот). Не делайте всё облегающим.', '2026-04-23 11:19:33.203265'::timestamp, 405);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2748, 'Часы определяют статус. Не обязательно Rolex, но качественный кварц за 10 000 смотрится лучше, чем подделка за 2000.', '2026-04-23 11:19:35.890615'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2749, 'Ремень должен совпадать по цвету с обувью. Это простое правило работает всегда.', '2026-04-23 11:19:38.144555'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2750, 'Носки — не для того, чтобы их не было видно. Носки с принтом — акцент. Но только если штаны не чёрные, а джинсы подвернуты.', '2026-04-23 11:19:40.601428'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2751, 'Сумка через плечо (сac) — тренд последних лет. И она удобна: телефон, кошелёк, ключи — не в карманах.', '2026-04-23 11:19:43.678455'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2752, 'Шарф из кашемира или мериноса — инвестиция. Он не колется, согревает и добавляет текстуру. А синтетический шарф — зло.', '2026-04-23 11:19:46.440161'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2753, 'Кожаный браслет или цепочка — тонкий намёк на характер. Но не носите их с часами на той же руке — царапают.', '2026-04-23 11:19:49.305293'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2754, 'Очки в роговой оправе делают лицо умнее. Солнцезащитные очки — не только от солнца, но и чтобы скрыть усталость.', '2026-04-23 11:19:52.287521'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2755, 'Головные уборы: бейсболка — для парка, кепка-восьмиклинка — для города, панама — для пляжа. Не путайте.', '2026-04-23 11:19:54.425421'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2756, 'Платок в нагрудном кармане пиджака. Не обязательно треугольником. Просто квадратом — уже элегантно.', '2026-04-23 11:19:56.780735'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2757, 'Умные часы — это удобно, но с костюмом они выглядят как спортивный элемент. Для деловых встреч наденьте классику.', '2026-04-23 11:19:58.936861'::timestamp, 406);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2758, 'Я не покупаю новую одежду 3 года. Только секонд-хенд, обмен с подругами, ремонт старой. Сэкономила 150 000 рублей.', '2026-04-23 11:20:01.899987'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2759, 'Самый экологичный гардероб — тот, который вы носите годами. Покупайте качество, а не количество.', '2026-04-23 11:20:04.256188'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2760, 'Как починить дырку на джинсах красиво? Заплатка из другой ткани в контрастном цвете. Японская техника сашико.', '2026-04-23 11:20:06.611737'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2761, 'Fast fashion производит 10% мировых выбросов CO2. Каждая вторая вещь оказывается на свалке через год. Не кормите эту систему.', '2026-04-23 11:20:08.971620'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2762, 'Шерсть не нужно стирать часто. Достаточно проветрить на балконе. Одно стирка в сезон — норма.', '2026-04-23 11:20:11.219389'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2763, 'Перекрасить чёрную выцветшую футболку можно специальной краской за 300 рублей. Зачем покупать новую?', '2026-04-23 11:20:13.679092'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2764, 'Обувь на толстой подошве служит дольше — подошва не стирается. Заодно трендово.', '2026-04-23 11:20:16.035608'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2765, 'Вторсырьё: из старых джинсов шьют сумки, из футболок — коврики, из свитеров — шапки. Гуглите upcycling мастер-классы.', '2026-04-23 11:20:18.490154'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2766, 'Что я никогда не покупаю: синтетику, вещи с пайетками (микропластик в океан), дешёвую обувь (через месяц на свалку).', '2026-04-23 11:20:20.844337'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2767, 'Осознанный шоппинг: задайте себе вопрос — надену ли я это 30 раз? Если нет — не берите.', '2026-04-23 11:20:23.406745'::timestamp, 407);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2768, 'Француженки говорят: перед выходом снимите одну вещь. Правило работает. Меньше аксессуаров — элегантнее.', '2026-04-23 11:20:26.172901'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2769, 'Белая рубашка с джинсами и балетками — никогда не промах. Добавьте красную помаду — уже вечерний выход.', '2026-04-23 11:20:28.803296'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2770, 'Тренч Burberry — классика. Но носите его не только с брюками, но и поверх платья, с джинсами, с юбкой.', '2026-04-23 11:20:31.390834'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2771, 'Приталенный жакет, свободные брюки, туфли-лодочки. Идеальный баланс женственного и строгого.', '2026-04-23 11:20:33.743972'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2772, 'Шёлковый платок в волосах или на сумке добавляет лёгкости даже самому скучному образу.', '2026-04-23 11:20:36.204960'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2773, 'Почему я люблю балетки? Удобно, женственно, подходит под 90% гардероба. Но не надевайте их с носками.', '2026-04-23 11:20:38.457338'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2774, 'Кардиган — лучший друг ленивого стилиста. Накинул поверх майки — и ты выглядишь собранно.', '2026-04-23 11:20:42.042173'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2775, 'Свитер оверсайз, заправленный спереди в джинсы, создаёт силуэт «песочные часы» без утягивания.', '2026-04-23 11:20:45.129532'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2776, 'Главное в элегантности — осанка. Одна и та же вещь сидит по-разному на сутулом и на прямом человеке.', '2026-04-23 11:20:47.677421'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2777, 'Классика: маленькое чёрное платье, жемчуг, лодочки. Коко Шанель знала толк.', '2026-04-23 11:20:51.343625'::timestamp, 408);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2778, 'Starship от SpaceX весит 5000 тонн на старте. Двигатели Raptor 2 развивают тягу 230 тонн каждый. 33 двигателя — это 7590 тонн, хватит, чтобы утащить на орбиту целый автобус.', '2026-04-23 11:21:55.768139'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2779, 'Квантовые компьютеры Google Sycamore решили задачу за 200 секунд, на которую суперкомпьютеру потребовалось бы 10 000 лет. Правда, задача была очень специфическая, но всё равно.', '2026-04-23 11:21:58.430376'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2780, 'Дрон Matrice 350 RTK от DJI работает при -20°C и ветре до 15 м/с. С шестью аккумуляторами может зависать в воздухе 4 часа. Спасение в горах теперь выглядит иначе.', '2026-04-23 11:22:00.799105'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2781, 'Процессор NVIDIA H100 содержит 80 миллиардов транзисторов. Для сравнения, Intel 4004 (1971) — 2300. Разница в 35 миллионов раз.', '2026-04-23 11:22:03.246220'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2783, 'Робот-собака Boston Dynamics Spot стоит $75 000. За эти деньги вы получаете открытый API, сменные блоки и способность подниматься по лестнице быстрее человека.', '2026-04-23 11:22:08.036024'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2784, 'Беспилотные такси Waymo в Сан-Франциско проехали 20 миллионов миль без смертельных ДТП. Всё благодаря лидару, камерам и нейросетям.', '2026-04-23 11:22:10.412395'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2785, 'Edge computing в промышленности: задержка обработки данных упала с 50 мс (облако) до 5 мс. Для роботизированной руки это разница между попаданием в гайку и мимо.', '2026-04-23 11:22:12.664346'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2786, 'Солнечные панели на МКС генерируют 120 кВт. Этого хватает на работу всех систем и ещё на подзарядку аккумуляторов. КПД всего 20%, но в космосе солнце светит всегда.', '2026-04-23 11:22:14.916959'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2787, 'Самый быстрый суперкомпьютер Frontier (США) — 1.1 экзафлопса. Он занимает площадь двух баскетбольных площадок и потребляет 30 мегаватт.', '2026-04-23 11:22:17.524606'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2788, 'Китай посадил зонд на обратную сторону Луны и доставил грунт. Это удалось только им. Почему? Потому что нужен спутник-ретранслятор, и его не у кого было купить.', '2026-04-23 11:22:20.344239'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2789, 'Топливо для ракет — жидкий водород и кислород. Плотность водорода 0.07 г/см³, его приходится охлаждать до -253°C. Бак для него весит больше, чем сам водород.', '2026-04-23 11:22:22.807349'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2790, 'Спутник «Ресурс-П» может снимать Землю с разрешением 0.7 метра. С высоты 500 км это значит, что он различит автомобиль, но не номер. Для шпионажа маловато.', '2026-04-23 11:22:25.469648'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2791, 'Космический мусор: на орбите 130 миллионов частиц от 1 мм до 1 см. Они летят со скоростью 7 км/с, и даже маленький винтик пробьёт корпус МКС.', '2026-04-23 11:22:27.819031'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2792, 'Ядерный реактор на спутнике «Космос-954» упал в Канаде в 1978 году. Радиоактивные обломки разбросало на 600 км. Канада выставила счёт СССР на $6 млн, его оплатили.', '2026-04-23 11:22:30.176829'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2793, 'Посадка марсохода Perseverance: «семь минут ужаса» — радиосигнал с Марса идёт 11 минут, так что посадка происходит полностью автоматически. Парашют, ракетные двигатели, небесный кран.', '2026-04-23 11:22:32.736440'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2794, 'Солнечный парус «LightSail 2» использовал фотоны для разгона. Давление света ничтожное, но за месяц орбита поднялась на 2 км. Технология для межзвёздных зондов.', '2026-04-23 11:22:35.091879'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2795, 'Запуск «Джеймса Уэбба» стоил $10 млрд. Телескоп сложили в 48 раз, чтобы влезть в ракету. Развернулся идеально на расстоянии 1.5 млн км от Земли.', '2026-04-23 11:22:37.547747'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2796, 'Венера: давление у поверхности 92 атмосферы, температура 460°C. Советский аппарат «Венера-13» проработал 127 минут. Никто больше не пытался сажать на Венеру с 1980-х.', '2026-04-23 11:22:39.904212'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2797, 'Китайская станция «Тяньгун» весит 100 тонн, как советский «Мир». Россияне могут летать туда, американцам запрещено. Новая космическая гонка.', '2026-04-23 11:22:43.575762'::timestamp, 410);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2798, 'Робот-сортировщик Stretch от Boston Dynamics берёт коробки до 25 кг и кладёт на полку со скоростью 800 коробок в час. Складские работники не нужны.', '2026-04-23 11:22:46.937327'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2799, 'Дрон-опылитель от японцев имитирует пчёл: на 4 пропеллерах, с щетинками из конского волоса. Опыляет 40% цветка за раз. Пчёлы лучше, но дронов не жалко.', '2026-04-23 11:22:49.732792'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2801, 'Хирургический робот da Vinci делает операции через проколы 8 мм. У него 3D-камера с 10-кратным увеличением и руки, которые не дрожат. Рак простаты удаляется за 2 часа.', '2026-04-23 11:22:55.164317'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2802, 'RoboBee — дрон размером с монету, весит 80 мг. Пока летает только привязанным к проводу, но может садиться на цветок. Разведка в будущем будет за ними.', '2026-04-23 11:22:57.823657'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2803, 'Промышленные экзоскелеты EksoVest снимают нагрузку с рук при работе над головой. Рабочие на складах Amazon носят их и поднимают грузы до 15 кг без усилий.', '2026-04-23 11:23:00.498324'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2804, 'Дрон-подводник Hydrolight может погружаться на 150 метров и снимать 4K. Нефтяники используют для осмотра труб. Вместо водолаза — дрон.', '2026-04-23 11:23:02.941917'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2805, 'Робот-сварщик ArcMate с лазерным сканером сам находит шов и варит с точностью до 0.1 мм. Заменяет трёх сварщиков в цеху.', '2026-04-23 11:23:05.448625'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2806, 'Погрузчик с автопилотом от Caterpillar водит сам по карьеру. GPS + лидар + радар — и 100-тонный грузовик едет без водителя 24/7.', '2026-04-23 11:23:07.960885'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2807, 'Boston Dynamics Atlas делает сальто назад. Гидравлика, 28 гидроприводов, 500 кг веса. Зачем? Чтобы однажды заменить людей в опасных зонах.', '2026-04-23 11:23:10.214524'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2808, 'AWS вырубился в 2017 году на 5 часов из-за опечатки: инженер удалил не тот сервер. Убытки интернет-компаний — $150 млн. С тех пор облачные гиганты внедрили «удаление с подтверждением».', '2026-04-23 11:23:13.080132'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2809, 'Облачный гейминг от NVIDIA GeForce Now позволяет играть в Cyberpunk 2077 на слабом ноутбуке. Пинг до дата-центра 10 мс — незаметно. Главное, чтобы интернет был от 50 Мбит.', '2026-04-23 11:23:15.441484'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2810, 'Edge-серверы от Cloudflare расположены в 300 городах мира. Время отклика DNS — 1 мс. Это потому, что сервер в вашем городе, а не в далёком дата-центре.', '2026-04-23 11:23:17.697182'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2811, 'Google Cloud предлагает холодное хранилище: $0.00099 за ГБ в месяц. Но если вам нужно восстановить данные, ждите 12 часов — ленты перематываются.', '2026-04-23 11:23:19.947775'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2812, 'Azure OpenAI интегрирован с офисными приложениями. Word пишет отчёты сам, а Excel прогнозирует продажи. Сотрудникам остаётся только нажать «Согласиться».', '2026-04-23 11:23:22.406401'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2813, 'Облачные базы данных Snowflake отделяют хранение от вычислений. Вы платите за то и другое отдельно. Мега-корпорации сэкономили миллионы, отключив неиспользуемые мощности.', '2026-04-23 11:23:24.958510'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2814, 'Green cloud — центры обработки данных на гидроэлектроэнергии. Google в Финляндии охлаждается морской водой. PUE (эффективность) — 1.1 против обычных 1.5.', '2026-04-23 11:23:27.418219'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2815, 'Kubernetes — оркестрация контейнеров. Позволяет масштабироваться с 1 до 1000 подов за минуту. Если ваш сайт переживает хайп, вы не упадёте.', '2026-04-23 11:23:29.976334'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2816, 'Серверы на ARM (Graviton) от Amazon на 40% дешевле и экономичнее Intel. Netflix переехал на них и сэкономил $100 млн в год.', '2026-04-23 11:23:32.342204'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2817, 'Суперкомпьютер в облаке: AWS P5 — 8 чипов H100, сеть 3200 Гбит/с. Аренда $32 в час за инстанс. Любой стартап может посчитать нейросеть, как Google.', '2026-04-23 11:23:34.671939'::timestamp, 412);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2818, 'FPV-дрон на LiPo аккумуляторе выдаёт 130 А пикового тока. Провода греются так, что за 3 минуты полёта можно яйцо сварить. Потому и летаем быстро.', '2026-04-23 11:23:37.420556'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2819, 'Гоночный дрон DRL Racer X разгоняется до 200 км/ч за секунду. Перегрузки — 12G. Пилоты тренируются на симуляторах, потому что в реальности не вывозят.', '2026-04-23 11:23:39.974782'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2820, 'Сельскохозяйственный дрон Agras T40 весит 40 кг без удобрений. Разбрызгивает 30 литров в минуту на 10 метров ширины. Обработать 100 гектаров за день — легко.', '2026-04-23 11:23:42.419277'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2821, 'Картографический дрон WingtraOne генерирует карту с точностью 1 см на 1 км. Геодезисты теперь не ходят с тахеометрами, а запускают дрон и пьют кофе.', '2026-04-23 11:23:44.925612'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2822, 'Дрон-спасатель с тепловизором замечает человека с высоты 200 метров даже в полной темноте. За 5 минут облетает лес, который спасатели проходили бы 2 часа.', '2026-04-23 11:23:48.198064'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2823, 'Аэрофотосъёмка для кино: дрон на RED 8K с карбоновыми пропеллерами и системой гашения вибраций. Плавный кадр с высоты 50 метров стоит $5000 за съёмочный день.', '2026-04-23 11:23:50.784217'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2824, 'Шерифы в Техасе используют дроны с громкоговорителем для переговоров с преступниками. Дрон висит 40 минут, транслирует «Сдавайтесь!», а полиция сидит в машине.', '2026-04-23 11:23:53.117403'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2825, 'Проверка ЛЭП дроном с LiDAR: за день дрон облетает 20 км линий, а нейросеть находит обледенение и коррозию. Раньше альпинисты лазили неделями.', '2026-04-23 11:23:55.267739'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2826, 'Дрон-аккумуляторщик: когда сел основной, подлетает запасной, цепляется магнитом и передаёт энергию. Пока заряжается, дрон висит на втором. Бесконечный полёт.', '2026-04-23 11:23:57.728540'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2827, 'DJI Avata с очками goggles 2 — ощущение полного погружения. Ты не управляешь, ты летишь. Один из моих заказчиков купил, а потом продал — укачало в первый же день.', '2026-04-23 11:24:00.184628'::timestamp, 413);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2828, 'Samsung Galaxy S23 Ultra имеет 200 Мп камеру. Размер пикселя — 0.6 мкм, но алгоритмы объединяют 16 пикселей в один — получается 12.5 Мп с отличным шумоподавлением.', '2026-04-23 11:24:03.034361'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2829, 'iPhone 15 Pro Max чип A17 Pro — 3 нм техпроцесс. 19 миллиардов транзисторов. Для сравнения, Intel Pentium 4 — 125 миллионов. Сейчас мощность игровой приставки в кармане.', '2026-04-23 11:24:05.412537'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2832, 'Беспроводная зарядка 50 Вт на OnePlus 11. Заряжает 5000 мАч за 30 минут. Но только с фирменным зарядным кобельком. Иначе — 10 Вт, как у всех.', '2026-04-23 11:24:12.169216'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2833, 'Samsung Galaxy Z Fold 5 стоит $1800. Складывается 200 000 раз (гарантия). В день вы откроете его 30 раз — хватит на 18 лет. Дорого, но перестали бояться.', '2026-04-23 11:24:14.416410'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2834, 'Сенсор отпечатка пальца под экраном (ультразвук) на Galaxy S24. Работает даже мокрой рукой и на плёнке. Оптический не работает.', '2026-04-23 11:24:16.874845'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2835, 'Смартфон с проектором — LG G8X? Нет, Motorola Moto Z с модулем InstaShare. Кино на стену 100 дюймов с яркостью 50 люмен. Темнота обязательна, но весело.', '2026-04-23 11:24:19.126416'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2836, 'Защита от воды IP68 — 1.5 метра на 30 минут. Но солёная вода убьёт любую защиту, так как соль проводит ток. Не купайтесь в море.', '2026-04-23 11:24:21.384131'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2837, 'Самый дешёвый 5G смартфон — Poco M6 Pro за $200. Чип MediaTek Dimensity 6100+, поддержка 5G есть, камера на троечку, но интернет летает.', '2026-04-23 11:24:23.636847'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2838, 'Нейросеть Stable Diffusion генерирует изображение за 2 секунды на RTX 4090. Модель обучена на 2 миллиардах картинок. Но она не понимает, что у человека 5 пальцев, если не поправить.', '2026-04-23 11:24:26.398570'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2839, 'LLaMA 3 от Meta — 70 миллиардов параметров. Работает на одном сервере с 2 GPU. Ответы почти как у GPT-4, но бесплатно и без цензуры.', '2026-04-23 11:24:28.651022'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2840, 'AlphaFold 2 от DeepMind предсказал структуру 200 миллионов белков. На это потребовалось 2 года. Раньше на один белок уходил год экспериментов.', '2026-04-23 11:24:30.906660'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2841, 'Tesla FSD (Full Self-Driving) использует нейросеть, обученную на 3 миллиардах километров видео. 8 камер, 1 млн строк кода, и всё равно иногда едет на красный.', '2026-04-23 11:24:33.360665'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2842, 'Генеративный AI для кода — GitHub Copilot пишет 40% кода в местах, где его используют. Ошибки? Да, но средний разработчик их ловит за 10 секунд.', '2026-04-23 11:24:35.752030'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2843, 'Midjourney v6 понимает «стиль 1980х» и «киберпанк» как художник. Но если вы попросите «кошку с рожками» — может нарисовать кошку с торчащими из ушей рогами.', '2026-04-23 11:24:38.175967'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2844, 'AI для диагностики рака кожи от Google Health. Точность 95% против 85% у дерматологов. Уже применяют в США, но только как второе мнение.', '2026-04-23 11:24:41.043443'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2845, 'Робот-хирург с ИИ от Johnson & Johnson сам планирует разрезы. Учит на 10 000 операций. Время операции сократилось на 20%, кровопотеря — на 30%.', '2026-04-23 11:24:44.734660'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2847, 'Sora от OpenAI — видео по тексту. 60 секунд с камерой и сменой ракурсов. Пока недоступна, но демки впечатляют: бегущая мамонт в снегу выглядит реально.', '2026-04-23 11:24:49.946989'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2848, 'AMD Ryzen 9 7950X3D имеет 3D V-Cache — 128 МБ кэша против обычных 64. В играх прирост 15-20% только за счёт большего объёма.', '2026-04-23 11:24:52.609389'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2849, 'Видеокарта NVIDIA RTX 4090 потребляет 450 Вт под нагрузкой. Для неё нужен блок питания на 1000 Вт и охлаждение, иначе чип греется до 85°C.', '2026-04-23 11:24:54.970459'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2850, 'SSD Samsung 990 Pro достигает скорости чтения 7450 МБ/с. Это 7.45 гигабайта в секунду. Windows загружается за 8 секунд.', '2026-04-23 11:24:57.319701'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2851, 'Оперативная память DDR5 работает на частоте 6400 МГц, но задержки CL32 — выше, чем у DDR4 (CL16). Для игр разница 2-5%.', '2026-04-23 11:24:59.574396'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2852, 'Материнская плата ASUS ROG Maximus Z790 Hero имеет 24 фазы питания по 105 ампер. Это запас для разгона i9 до 6 ГГц.', '2026-04-23 11:25:01.827483'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2853, 'Кулер Noctua NH-D15 — воздушный гигант весом 1.3 кг. Охлаждает 250 Вт и тише большинства водянок. В корпус нужно 165 мм высоты.', '2026-04-23 11:25:04.188267'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2854, 'Корпус Fractal Torrent имеет два 180-мм вентилятора спереди. Воздушный поток 150 CFM. Видеокарта при этом холоднее на 10°C.', '2026-04-23 11:25:06.539323'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2855, 'Монитор с OLED-панелью LG 27GR95QE: время отклика 0.03 мс. Выцветание пикселей есть, но не критично при работе.', '2026-04-23 11:25:08.996498'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2856, 'Источник бесперебойного питания APC Back-UPS 1500VA держит ПК с RTX 4090 5 минут. Этого хватит, чтобы сохранить документы.', '2026-04-23 11:25:11.455397'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2857, 'Мышь Logitech G Pro X Superlight весит 63 грамма. Сенсор HERO 25K, батареи хватает на 70 часов. Профессионалы в киберспорте её боготворят.', '2026-04-23 11:25:13.706959'::timestamp, 416);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2858, 'Хакеры взломали спутник ESA в 2020 году через уязвимость в прошивке. Смогли перехватить управление на 20 минут. С тех пор шифрование каналов связи ужесточили.', '2026-04-23 11:25:16.573370'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2859, 'Уязвимость в дронах DJI: исследователи подменили GPS-сигнал и увели дрон в другую точку. DJI выпустила патч через неделю. Летайте с обновлениями.', '2026-04-23 11:25:18.799804'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2860, 'Вредоносное ПО для смартфонов Pegasus читает всё: сообщения, микрофон, камеру, геолокацию. Оно не оставляет следов, и обнаружить его почти невозможно.', '2026-04-23 11:25:21.183405'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2861, 'Wi-Fi Deauth атака: хакер отправляет пакеты на отключение от сети. Ваш ноутбук теряет связь. Защита — WPA3, но он не везде.', '2026-04-23 11:25:23.638029'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2862, 'Подмена MAC-адреса: хакер может притвориться вашим устройством в общественной сети. Чтобы защититься, используйте VPN и никогда не отключайте HTTPS.', '2026-04-23 11:25:25.999064'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2863, 'Беспилотные автомобили уязвимы для фальшивых дорожных знаков. Наклейка «STOP» на картонке — и Tesla может резко затормозить. Протоколы распознавания всё ещё сырые.', '2026-04-23 11:25:28.455053'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2864, 'Атака на умный дом: через лампочку Philips Hue, подключённую к Zigbee, хакеры проникли в домашнюю сеть. Сегментируйте IoT на отдельный VLAN.', '2026-04-23 11:25:30.809574'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2866, 'Уязвимость в Bluetooth: BlueBorne позволяет заразить устройство без парынга. Отключайте Bluetooth, когда не пользуетесь.', '2026-04-23 11:25:35.826753'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2867, 'Deepfake голоса: злоумышленник позвонил директору фирмы голосом его начальника и перевёл $250 000. Нужно правило: никаких переводов по телефону.', '2026-04-23 11:25:38.181067'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2868, 'Колонизация Марса: Илон Маск планирует город на миллион человек к 2050 году. Starship будет летать каждые 26 месяцев (когда Марс близко). Стоимость билета — $500 000.', '2026-04-23 11:25:40.931426'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2869, 'Умные дороги: в Китае построили участок шоссе с зарядкой для электромобилей под асфальтом. Индукционные катушки заряжают на ходу. Больше не нужно останавливаться.', '2026-04-23 11:25:43.198605'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2870, 'Вертикальные фермы AeroFarms дают урожай в 100 раз больше на квадратный метр, чем поле. LED-лампы 24/7, гидропоника, без пестицидов. Еда в пустыне — реально.', '2026-04-23 11:25:46.089755'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2871, 'Город NEOM в Саудовской Аравии: зеркальная стена высотой 500 метров и длиной 170 км. Внутри — климат-контроль, роботы-доставщики и нет автомобилей. Сюрреализм.', '2026-04-23 11:25:49.097260'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2872, 'Электролёты с вертикальным взлётом: Joby Aviation сертифицирует модель с дальностью 240 км и скоростью 320 км/ч. Такси в небе обойдётся в $3 за километр.', '2026-04-23 11:25:51.900488'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2873, 'Термоядерный реактор ITER запустят в 2035 году. Он должен дать 500 МВт тепла, из которых 200 МВт электричества. Токамак весит 23 000 тонн.', '2026-04-23 11:25:54.153516'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2874, 'Квантовый интернет: в Китае передали квантовое состояние на 1200 км через спутник. Перехватить невозможно — изменится состояние фотона. Идеальная защита.', '2026-04-23 11:25:56.514540'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2875, 'Роботы-хирурги с телемедициной: хирург из Нью-Йорка оперирует пациента в Индии с задержкой 50 мс. Уже есть успешные операции на желчном пузыре.', '2026-04-23 11:25:58.825295'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2876, 'Искусственные листья: устройство из перовскита превращает солнечный свет и CO2 в синтез-газ (CO+H2). Из него можно делать топливо. КПД 10%.', '2026-04-23 11:26:01.321848'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2877, 'Генетически модифицированные комары от Oxitec уничтожили 95% популяции Aedes aegypti в Бразилии. Комары не переносят лихорадку Зика. Этика? Зато люди живы.', '2026-04-23 11:26:03.881410'::timestamp, 418);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2878, 'Заменил масло в двигателе своего JD 8330 через 400 моточасов вместо рекомендованных 500. Двигатель стал тише, а расход упал на 3%. Окупилось.', '2026-04-23 11:26:26.410340'::timestamp, 419);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2879, 'Сегодня пахал целину — старый MTZ-82 с новыми плугами не справился, пришлось брать New Holland T7.315. Мощность решает, когда земля тяжёлая.', '2026-04-23 11:26:28.662720'::timestamp, 419);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2880, 'Поставил систему автовождения Trimble на свой трактор. Теперь можно смотреть Netflix, пока он сам ведёт по полю. Шутка. Но спину разгрузило.', '2026-04-23 11:26:31.119625'::timestamp, 419);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2881, 'Ошибка новичков: экономят на противооткатных башмаках при работе на склонах. У соседа трактор перевернулся — еле выжил. Не рискуйте.', '2026-04-23 11:26:33.577835'::timestamp, 419);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2882, 'Расход топлива на вспашке: Fendt 936 показал 18 л/га, а старый Case Magnum — 24. Технологии экономят дизель, но стоят как космический корабль.', '2026-04-23 11:26:35.831205'::timestamp, 419);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2883, 'Почему выходят из строя форсунки Common Rail? 90% случаев — грязное топливо. Поставьте дополнительный фильтр и меняйте каждые 250 моточасов.', '2026-04-23 11:26:38.799834'::timestamp, 420);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2884, 'Клиент жаловался на чёрный дым на John Deere. Причина — забитый воздушный фильтр. Меняйте вовремя, не продувайте сжатым воздухом.', '2026-04-23 11:26:41.724504'::timestamp, 420);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2885, 'Турбина на тракторе любит плавный разгон и охлаждение перед глушением. Хочешь убить — работай на максимальных оборотах и глуши сразу.', '2026-04-23 11:26:45.676462'::timestamp, 420);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2886, 'Зимний запуск: аккумуляторы должны быть мощными, а свечи накала — исправными. Масло 5W-30 вместо 10W-40 даёт гарантию пуска до -25.', '2026-04-23 11:26:48.836619'::timestamp, 420);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2887, 'Восстановил двигатель ЯМЗ-236 на МТЗ-82 после перегрева. Причина — порванный ремень вентилятора и забывчивый механизатор. Следите за ремнями.', '2026-04-23 11:26:51.291313'::timestamp, 420);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2888, 'Система контроля высева точного земледелия окупается за 2 сезона. Пропуски и двойные засевы — прошлый век.', '2026-04-23 11:27:00.406757'::timestamp, 421);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2889, 'Почему прицепное орудие идёт неровно? Проверьте длину центральной тяги и раскосы навески. Банальная регулировка творит чудеса.', '2026-04-23 11:27:02.669329'::timestamp, 421);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2890, 'Пневматические тормоза на тракторном поезде: влагомаслоотделитель надо сливать каждый день. Вода замёрзнет — тормозов не будет.', '2026-04-23 11:27:05.014356'::timestamp, 421);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2891, 'Измерение буксования колёс: если колёса проскальзывают более 15% на пахоте — увеличивайте сцепной вес или снижайте скорость.', '2026-04-23 11:27:07.471461'::timestamp, 421);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2892, 'Зерноуборочный комбайн Lexion 770 — это космический корабль. 40 тонн зерна в час, кабина с кондиционером и автопилотом. Цена как у самолёта.', '2026-04-23 11:27:10.442075'::timestamp, 422);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2893, 'Жатка для кукурузы должна быть с автовысотой. Иначе камни летят в молотилку. Ремонт дешевле не будет.', '2026-04-23 11:27:12.592296'::timestamp, 422);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2894, 'Перед уборкой проверьте ремни вариатора. Один порванный ремень останавливает всё хозяйство на сутки.', '2026-04-23 11:27:14.945227'::timestamp, 422);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2895, 'Соломотряс забивается во влажную погоду. Увеличьте частоту вращения очистки и уменьшите подачу массы. Опыт, а не кнопки.', '2026-04-23 11:27:17.403610'::timestamp, 422);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2896, 'Система картирования урожайности в реальном времени показывает, где поле родило, а где нет. На следующий год удобряем дифференцированно.', '2026-04-23 11:27:20.170920'::timestamp, 422);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2897, 'Восстановил ДТ-54 1954 года. Двигатель пускается с пускача, гусеницы родные. Езжу по праздникам — соседи завидуют.', '2026-04-23 11:27:22.934258'::timestamp, 423);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2898, 'Фордзон-Путиловец 1924 года выпуска — первый массовый трактор СССР. У меня сохранился, работает до сих пор. Гордость коллекции.', '2026-04-23 11:27:25.494984'::timestamp, 423);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2899, 'Нашёл в поле заброшенный МТЗ-50. Двигатель в масле, коробка жива. Через месяц поехал. Технику прошлых лет делали на совесть.', '2026-04-23 11:27:27.950861'::timestamp, 423);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2900, 'Колёсные тракторы 1960-х: Беларусь МТЗ-5, ЮМЗ-6. У них нет гидроусилителя руля, зато починить можно кувалдой и сваркой.', '2026-04-23 11:27:30.510546'::timestamp, 423);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2901, 'Ретро-трактор на выставке: Ferguson TE20 — маленький, но легендарный. Именно он начал эру универсальных тракторов после войны.', '2026-04-23 11:27:33.072891'::timestamp, 423);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2902, 'Автономный трактор без кабины: уже тестируем. Он выезжает по заданию, пашет, возвращается на базу. Оператор только наблюдает.', '2026-04-23 11:27:35.939283'::timestamp, 424);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2903, 'Использование дронов для мониторинга полей: отправляю дрон, получаю карту NDVI, загружаю в автопилот трактора. Удобрения точно в цель.', '2026-04-23 11:27:38.504498'::timestamp, 424);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2904, 'Электрический трактор на аккумуляторах: 4 часа работы, потом 2 часа зарядки. Пока только для лёгких работ. Тихий, без выхлопа.', '2026-04-23 11:27:41.060081'::timestamp, 424);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2906, 'Интернет вещей на тракторе: датчики температуры масла, давления в шинах, загрузки двигателя — всё на смартфон. Уведомление о поломке за 100 км.', '2026-04-23 11:27:46.779703'::timestamp, 424);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2907, 'Первый паровой трактор построил в 1868 году Джон Фрулих. Он весил 15 тонн и пахал со скоростью 1 км/ч.', '2026-04-23 11:27:50.052506'::timestamp, 425);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2908, 'Fordson Model F 1917 года — трактор, который поставил сельское хозяйство на колёса. Выпущено более 700 000 штук.', '2026-04-23 11:27:52.495769'::timestamp, 425);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2909, 'В СССР в 1930-х на Челябинском тракторном заводе выпускали С-60 на керосине. Заводился зимой только с паяльной лампой.', '2026-04-23 11:27:54.984635'::timestamp, 425);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2910, 'История Минского тракторного завода: МТЗ-2 выпускали по лицензии американского Minneapolis-Moline. Белорусы сделали его легендой.', '2026-04-23 11:27:57.351412'::timestamp, 425);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2912, 'На тракторе слабое звено — насос гидравлики. Если руль тяжелый или навеска не поднимает, проверяйте сначала насос, а не масло.', '2026-04-23 11:28:02.460959'::timestamp, 426);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2913, 'Гидрораспределитель с электроуправлением на современных тракторах: одна ошибка в проводке — и сегмент не работает. Ищите обрыв.', '2026-04-23 11:28:05.020583'::timestamp, 426);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2914, 'Протекают уплотнения штоков цилиндров — меняйте сразу, не доливайте масло. С грязью в системе придётся менять весь насос.', '2026-04-23 11:28:07.379277'::timestamp, 426);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2915, 'Правильная регулировка предохранительного клапана: давление не должно превышать 180-200 бар, иначе разорвёт рукава.', '2026-04-23 11:28:10.140684'::timestamp, 426);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2916, 'Масло для гидравлики должно быть одно и то же. Смешивание разных спецификаций убивает уплотнения за месяц.', '2026-04-23 11:28:12.494188'::timestamp, 426);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2917, 'Вариатор CVT на тракторах Fendt — бесступенчатый, удобный. Но при пробеге 5000 моточасов требует замены подшипников вариатора.', '2026-04-23 11:28:15.463919'::timestamp, 427);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2918, 'КПП Powershift (Zf) на John Deere: 16 передач без сцепления. Неисправность чаще всего в соленоидах — промывка и замена решают 70% проблем.', '2026-04-23 11:28:17.919263'::timestamp, 427);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2919, 'Механическая коробка МТЗ-82 — легендарная 9-ступка. Двойное сцепление, синхронизаторы только на 4-5 передачах. Рвутся вилки включения.', '2026-04-23 11:28:20.305922'::timestamp, 427);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2920, 'Робот на Massey Ferguson: два сцепления, переключение за миллисекунды. Но боится грязного масла. Меняйте масло каждые 1000 моточасов.', '2026-04-23 11:28:22.736344'::timestamp, 427);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2921, 'Если на тракторе буксует муфта сцепления при трогании, не пробуксовывайте — горелые диски гарантированы. Лучше сразу регулировка.', '2026-04-23 11:28:25.283158'::timestamp, 427);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2922, 'Правильное давление в шинах: на поле — 0.8-1.2 бар, на асфальте — 1.6-2.0. Недокачка убивает боковины, перекачка — центры.', '2026-04-23 11:28:28.168979'::timestamp, 428);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2923, 'Шины с переменным давлением (IF/VF) позволяют нести бОльшую нагрузку при меньшем давлении. Дорогие, но меньше уплотняют почву.', '2026-04-23 11:28:30.779874'::timestamp, 428);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2924, 'Перед установкой шипов на колёса трактора: шиповка нужна только для работы на льду и гололеде. На асфальте шипы вырывает.', '2026-04-23 11:28:33.179448'::timestamp, 428);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2925, 'Качество ремонта шины: горячая вулканизация лучше холодной. Но если каркас повреждён — только замена.', '2026-04-23 11:28:35.538878'::timestamp, 428);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2926, 'Снижение давления в шинах на 20% увеличивает сцепление на 15%, но повышает расход топлива на 8%. Компромисс.', '2026-04-23 11:28:37.803760'::timestamp, 428);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2927, 'Система автопилота RTK с базовой станцией даёт точность 2 см. Сублимационная поправка через интернет — 10 см. Выбирайте по задачам.', '2026-04-23 11:28:40.872578'::timestamp, 429);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2928, 'Настройка автовождения: обязательно откалибруйте компас и гироскоп перед началом сезона. Иначе ряды будут кривыми.', '2026-04-23 11:28:43.842689'::timestamp, 429);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2929, 'Экономия от автопилота: перекрытия сокращаются с 10% до 2% — экономия семян, удобрений и топлива до 8%.', '2026-04-23 11:28:46.606814'::timestamp, 429);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2931, 'Ошибка: забыли скорректировать уход автопилота на склоне. Трактор съезжает вниз — задайте поправку на уклон.', '2026-04-23 11:28:53.396974'::timestamp, 429);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2932, 'Для 20 гектаров оптимальный трактор — 80-100 л.с. Брал Kubota M7-102, маловат для плуга, хорош для дискатора.', '2026-04-23 11:28:56.219515'::timestamp, 430);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2933, 'Взял трактор с кабиной — не пожалел. Полевая пыль и дождь больше не проблема. Комфорт повышает производительность.', '2026-04-23 11:28:58.553644'::timestamp, 430);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2934, 'Б/у трактор: осматривайте раму на предмет трещин, проверяйте гидравлику на горячую. На холодную все работают.', '2026-04-23 11:29:00.929088'::timestamp, 430);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2935, 'Самые надёжные бюджетные тракторы: JCB Fastrac (подвеска всех колёс), Claas Axion (экономичный дизель), но дороги в обслуживании.', '2026-04-23 11:29:03.182123'::timestamp, 430);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2936, 'Лучший вариант для малого фермера — МТЗ-82 с кондиционером и усиленным передним мостом. Дёшево, сердито, запчасти везде.', '2026-04-23 11:29:05.435969'::timestamp, 430);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2937, 'Тестировал новый Fendt 1160 Vario — 517 л.с., максимальная скорость 60 км/ч. Кабина как в бизнес-джете, но цена 550 000 евро.', '2026-04-23 11:29:08.098900'::timestamp, 431);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2938, 'Case IH Magnum 380 — отличная управляемость на поле, но подвеска переднего моста слишком мягкая. На асфальте раскачка.', '2026-04-23 11:29:10.462800'::timestamp, 431);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2939, 'Китайский Lovol 454: за 20 000$ — тягач для 50 л.с. Мотор Perkins, коробка китайская. Собрано грубо, но работает.', '2026-04-23 11:29:12.706875'::timestamp, 431);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2940, 'John Deere 8R 410: мощность 410 л.с., расход дизеля на пахоте 45 л/га. Много, но тяга бешеная.', '2026-04-23 11:29:15.162599'::timestamp, 431);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2941, 'Электрический трактор Monarch MK-V: 70 л.с., запас хода 4 часа. Бесшумный, но для серьёзного поля не годится.', '2026-04-23 11:29:17.633484'::timestamp, 431);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2942, 'Дизельные тракторы с сажевым фильтром требуют регенерации каждые 50 моточасов. Если регенерация не запускается — снижается мощность.', '2026-04-23 11:29:20.589980'::timestamp, 432);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2943, 'Биодизель из рапса: эмиссия CO2 ниже на 50%, но коррозия топливной системы. Подходит только старым тракторам с насосами Bosch.', '2026-04-23 11:29:23.048163'::timestamp, 432);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2944, 'AdBlue (мочевина) снижает выбросы NOx до 90%. Но если закончился — двигатель уходит в ограничение мощности. Всегда имейте запас.', '2026-04-23 11:29:25.616164'::timestamp, 432);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2945, 'Евро-5 на тракторах: EGR + DPF + SCR — целая химическая лаборатория на борту. Но дышать в поле стало легче.', '2026-04-23 11:29:28.070697'::timestamp, 432);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2946, 'Переход на газ (метан) для тракторов: New Holland T6 Methane — 180 л.с., запас хода 300 км. Пока дорого и инфраструктуры нет.', '2026-04-23 11:29:30.320281'::timestamp, 432);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2947, 'Гусеничный трактор не уплотняет почву, как колёсный. Идеален для рисовых полей и слабых грунтов.', '2026-04-23 11:29:32.982964'::timestamp, 433);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2948, 'Caterpillar D6 — классика. Двигатель C9.3, мощность 200 л.с., ресурс гусеницы 10 000 моточасов.', '2026-04-23 11:29:35.336212'::timestamp, 433);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2949, 'Болотоход на базе гусеничного трактора: широкие гусеницы (900 мм) позволяют работать на торфяниках, где колёсный утонет.', '2026-04-23 11:29:37.795759'::timestamp, 433);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2950, 'Челябинский Т-170 — легенда. Модернизированный дизель, усиленная трансмиссия. Используется в строительстве и сельском хозяйстве.', '2026-04-23 11:29:40.252573'::timestamp, 433);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2951, 'Гусеничный трактор требует постоянной натяжки гусениц. Ослабла — сойдёт с катков. Перетянул — ускоренный износ.', '2026-04-23 11:29:43.103176'::timestamp, 433);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2952, 'Для садов и виноградников нужен узкий трактор шириной до 1.5 м. Antonio Carraro — итальянцы делают отличные.', '2026-04-23 11:29:46.292357'::timestamp, 434);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2953, 'Трактор с шарнирно-сочленённой рамой поворачивается на месте, не давит кусты. Goldoni — лучший вариант.', '2026-04-23 11:29:49.367489'::timestamp, 434);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2954, 'Высокий клиренс (до 80 см) позволяет работать под кронами деревьев. Pasquali 997 — отличный выбор.', '2026-04-23 11:29:52.233770'::timestamp, 434);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2955, 'Фронтальный погрузчик на садовом тракторе должен быть быстросъёмным. Иначе будете врезаться в ветки.', '2026-04-23 11:29:54.701779'::timestamp, 434);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2957, 'Восстановил МТЗ-50 1978 года. Двигатель расточил до 1 ремонта, коробку перебрал. Теперь как новый.', '2026-04-23 11:29:59.706992'::timestamp, 435);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2958, 'Ржавый бак очищают электролизом: карбонат натрия, вода, плюс на бак, минус на электрод. За сутки — чистота.', '2026-04-23 11:30:02.065381'::timestamp, 435);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2959, 'Труднее всего найти оригинальные панели приборов. Заказываю с разборок в Беларуси.', '2026-04-23 11:30:04.827162'::timestamp, 435);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2960, 'Покраска трактора: двухкомпонентная эпоксидная грунтовка, потом полиуретановая эмаль. Держится 10 лет.', '2026-04-23 11:30:07.185299'::timestamp, 435);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2961, 'Восстановил легендарный ЛТЗ-60 — малютка с двухцилиндровым дизелем. Завёлся с пол-оборота, даже не верилось.', '2026-04-23 11:30:09.761542'::timestamp, 435);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2962, 'Тракторный поезд: трактор + две тележки. Длина до 30 метров. Нужны усиленные тормоза и световая сигнализация.', '2026-04-23 11:30:13.019424'::timestamp, 436);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2963, 'Перевозка трактора на низкорамном прицепе: обязательно закрепите ремнями и поставьте башмаки под колёса. Штраф 50 000 за падение.', '2026-04-23 11:30:15.372528'::timestamp, 436);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2964, 'Грузоподъёмность тележки зависит от шин. На 500/50-17 можно везти 8 тонн, на 600/55-22.5 — 12 тонн.', '2026-04-23 11:30:17.932388'::timestamp, 436);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2965, 'Топливная логистика: бензовоз с дизелем на поле. Лучше иметь запас на 3 дня работы.', '2026-04-23 11:30:20.392157'::timestamp, 436);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2966, 'Склад запчастей: самые ходовые — фильтры, ремни, сальники колёс. Держите их на базе, не ждите поставку.', '2026-04-23 11:30:22.747970'::timestamp, 436);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2967, 'Каркас безопасности (ROPS) и ремень спасают жизнь при опрокидывании. На старых тракторах каркас дорабатывайте.', '2026-04-23 11:30:25.715504'::timestamp, 437);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2968, 'Запрещено перевозить людей на прицепе или ковше. Каждую осень слышу о трагедиях. Не рискуйте.', '2026-04-23 11:30:28.069142'::timestamp, 437);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2969, 'При работе с ВОМ обязательно закрывайте щитком. Намотка одежды на кардан — почти всегда смертельно.', '2026-04-23 11:30:30.426982'::timestamp, 437);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2970, 'Заправка трактора: двигатель заглушить, не курить. Статика — повесьте заземление на бак.', '2026-04-23 11:30:32.987552'::timestamp, 437);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2971, 'Обучение механизаторов: каждый год повторять технику безопасности. Скоростной режим на поворотах — не более 10 км/ч.', '2026-04-23 11:30:35.449323'::timestamp, 437);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2972, 'Автономный трактор-робот без кабины уже в поле. Питание от водородных топливных элементов. Заправка 5 минут, работа 8 часов.', '2026-04-23 11:30:38.209520'::timestamp, 438);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2973, 'Трактор-дрон: несколько маленьких машин 50 л.с. вместо одного гиганта. Меньше уплотнение почвы, резервирование.', '2026-04-23 11:30:40.569731'::timestamp, 438);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2974, 'Искусственный интеллект на тракторе сам определяет болезни растений и даёт команду на обработку пестицидами.', '2026-04-23 11:30:44.139722'::timestamp, 438);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2975, 'Электрический трактор с быстрой заменой аккумуляторов (как на вилочных погрузчиках). Смена батареи за 10 минут.', '2026-04-23 11:30:46.810018'::timestamp, 438);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2976, '5G на поле: управление трактором с центрального пункта, видео с камер в реальном времени. Один оператор ведёт 5 машин.', '2026-04-23 11:30:49.126280'::timestamp, 438);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2977, 'Венеция летом — это ад: очереди по часу, море пота и голуби, норовящие нагадить в еду. Приезжайте в ноябре — вода поднимается, зато туристов в десять раз меньше.', '2026-04-23 11:31:08.928010'::timestamp, 439);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2978, 'Лучший завтрак в Париже — не круассаны в туристическом кафе, а багет с сыром из ближайшей пекарни и вид на Сену с набережной. Стоит 5 евро, впечатлений на миллион.', '2026-04-23 11:31:11.171621'::timestamp, 439);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2979, 'Исландия: не берите с собой зонт — бесполезно. Ветер его вывернет наизнанку за секунду. Лучше непромокаемая куртка с капюшоном и трекинговые штаны.', '2026-04-23 11:31:14.766229'::timestamp, 439);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2980, 'Поезд Берлин — Прага: купите билет за 2 недели до поездки за 19 евро вместо 80. А в поезде сядьте справа по ходу движения — через час откроются Саксонская Швейцария и обрывы Эльбы.', '2026-04-23 11:31:17.635319'::timestamp, 439);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2983, 'Вьетнам: мопеды повсюду, чтобы перейти дорогу — просто идите медленно, не меняя скорости. Водители объедут. Главное не бежать и не паниковать.', '2026-04-23 11:31:25.013829'::timestamp, 440);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2984, 'Трекинг в Непале к базовому лагерю Эвереста: не берите гида — тропа отмечена, чайные домики каждые 2-3 км. Сэкономленные 500 долларов потратьте на кислород в Лукле.', '2026-04-23 11:31:27.468392'::timestamp, 440);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2985, 'Япония: купите JR Pass до поездки. Без него поездка Токио-Киото-Осака обойдется в 30 000 йен, с пассом — 20 000 за неделю безлимита. И бронируйте места на синкансене.', '2026-04-23 11:31:29.792716'::timestamp, 440);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2986, 'Индия: носите с собой туалетную бумагу и антисептик. И запомните — «no» значит «maybe», а «maybe» значит «yes». Не торгуйтесь до копейки, 50 рупий не сделают вас беднее.', '2026-04-23 11:31:32.380954'::timestamp, 440);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2987, 'Сафари в Танзании: берите джип с поднятым верхом. В закрытом автомобиле вы ничего не увидите, кроме пыли на стеклах. Ночлег в палатке среди львов — незабываемо.', '2026-04-23 11:31:35.366472'::timestamp, 441);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2988, 'Марокко: не верьте местным, которые «показывают дорогу бесплатно». Потом потребуют деньги. Лучше пользуйтесь Google Maps офлайн, загрузив карты перед поездкой.', '2026-04-23 11:31:38.010781'::timestamp, 441);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2989, 'Водопад Виктория в сезон дождей — не водопад, а стена воды. Дождевик бесполезен, промокнете за 30 секунд. Зато радуга над каждым брызгом.', '2026-04-23 11:31:40.166295'::timestamp, 441);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2990, 'Килиманджаро: восхождение на 5 дней — минимальный акклиматизационный маршрут. Не слушайте тех, кто обещает за 3 дня — сойдёте от горной болезни.', '2026-04-23 11:31:43.148031'::timestamp, 441);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2991, 'Египет: пирамиды Гизы лучше смотреть на рассвете, когда нет толп и не палит солнце. И не берите верблюда — 5 долларов за посадку, 50 за слезание.', '2026-04-23 11:31:47.617999'::timestamp, 441);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2992, 'Дорога вдоль Тихоокеанского побережья (Highway 1) от Сан-Франциско до Лос-Анджелеса — лучший маршрут в моей жизни. Биг-Сур снимает любой стресс.', '2026-04-23 11:31:50.939969'::timestamp, 442);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2993, 'Нью-Йорк: не покупайте билет на Статую Свободы, смотрите с парома на Статен-Айленд — он бесплатный и проходит прямо мимо.', '2026-04-23 11:31:53.677246'::timestamp, 442);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2994, 'Гранд-Каньон: смотрите закат с южного края, но не на точке Mather Point — там толпа. Идите 10 минут на запад по тропе Rim Trail — и будете одни.', '2026-04-23 11:31:56.051488'::timestamp, 442);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2995, 'Национальный парк Йосемити: бронируйте кемпинг за 5 месяцев. Или приезжайте в 5 утра — места first-come-first-served заполняются к 7.', '2026-04-23 11:31:58.299246'::timestamp, 442);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2996, 'Аляска: круиз на пароме Alaska Marine Highway от Бейкера до Джуно. 4 дня среди ледников и китов за 400 долларов вместо 4000 за круиз.', '2026-04-23 11:32:00.641938'::timestamp, 442);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2998, 'Не берите пластиковые бутылки в поездки. Один многоразовый стакан с фильтром экономит 100+ пластиковых бутылок за месяц.', '2026-04-23 11:32:05.867310'::timestamp, 443);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (2999, 'На Бали действует запрет на пластиковые пакеты. Уважайте местные правила — носите с собой шопер. Иначе магазины заставят нести товар в руках.', '2026-04-23 11:32:08.423468'::timestamp, 443);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3000, 'В трекинг не берите влажные салфетки — они не разлагаются. Многоразовые бамбуковые салфетки весят столько же и моются водой.', '2026-04-23 11:32:10.790676'::timestamp, 443);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3003, 'Исландия: не ведитесь на Instagram-точки вроде самолёта на черном песке. Там очереди по часу. Идите вглубь на 500 метров — свои места открываете сами.', '2026-04-23 11:32:18.154259'::timestamp, 444);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3004, 'Фотография еды в Японии: не используйте вспышку в ресторанах — это бесит поваров и других гостей. Используйте настройки ISO и широкую диафрагму.', '2026-04-23 11:32:20.709963'::timestamp, 444);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3005, 'Северное сияние в Норвегии: снимайте на штативе с выдержкой 15-20 секунд. Телефон на ночном режиме тоже справляется, но результат хуже.', '2026-04-23 11:32:23.172172'::timestamp, 444);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3006, 'Дроны в национальных парках США почти везде запрещены. И не пытайтесь запустить тайком — рейнджеры вычисляют, штраф до 5000 долларов.', '2026-04-23 11:32:25.524781'::timestamp, 444);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3007, 'В Японии не дают чаевые. Это оскорбление. Лучше искренне поклонитесь и скажите «arigatou gozaimasu» — это ценится больше.', '2026-04-23 11:32:28.184824'::timestamp, 445);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3008, 'В мусульманских странах в месяц Рамадан не ешьте и не пейте на улице в светлое время. Местные постятся, неуважение может вызвать гнев.', '2026-04-23 11:32:30.645440'::timestamp, 445);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3009, 'Этикет в буддийском храме: снимайте обувь, не поворачивайтесь спиной к Будде, не тыкайте пальцем. И никогда не садитесь на статуи — даже для фото.', '2026-04-23 11:32:32.797674'::timestamp, 445);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3010, 'В Грузии вино пьют только за тост. Если к вам подняли бокал, ответьте тем же. А тамада — царь и бог за столом, перебивать нельзя.', '2026-04-23 11:32:35.149171'::timestamp, 445);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3011, 'На Ближнем Востоке левая рука считается нечистой. Не передавайте деньги и подарки левой рукой, не берите еду. Правой — всегда правой.', '2026-04-23 11:32:37.404005'::timestamp, 445);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3012, 'Путешествие с двумя детьми в Диснейленд Париж: берите отель с бесплатным трансфером, покупайте билеты онлайн за месяц (дешевле на 30%) и не пытайтесь обойти всё за день.', '2026-04-23 11:32:41.907328'::timestamp, 446);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3013, 'Лучший семейный пляж для малышей — Пунта-Умбия в Испании. Пологий заход, мелкий песок, вода как парное молоко, нет волн. И дельфины плавают у берега.', '2026-04-23 11:32:44.874935'::timestamp, 446);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3014, 'В поездку с ребёнком берите с собой надувную ванночку и маленькую бутылку средства для мытья посуды. Экономия на отелях и чистота.', '2026-04-23 11:32:48.255792'::timestamp, 446);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3015, 'Детский музей в Индианаполисе — лучший в мире. Дети могут копать динозавров, управлять краном, летать на симуляторе. Зависают на 6 часов.', '2026-04-23 11:32:51.123564'::timestamp, 446);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3016, 'Путешествие на поезде с коляской: выбирайте купе, а не плацкарт. В купе коляска влезает, есть розетка, можно закрыться от всех.', '2026-04-23 11:32:53.274508'::timestamp, 446);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3017, 'Одиночное путешествие в Японию — безопасно, удобно, не одиноко. В хостелах полно соло-туристов, легко знакомиться. А капсульные отели — мастхэв.', '2026-04-23 11:32:55.935945'::timestamp, 447);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3018, 'Не бойтесь ужинать в ресторане одному. Возьмите книгу или блокнот. Официанты в Европе привыкли, в Азии вообще не парятся.', '2026-04-23 11:32:58.362453'::timestamp, 447);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3019, 'Лучшая страна для соло-путешественников — Новая Зеландия. Все на кемперах, каждый второй один, подвезут, составят компанию на треккинг.', '2026-04-23 11:33:00.748816'::timestamp, 447);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3020, 'Путешествие соло учит доверять незнакомцам. В Непале местные фермеры поили меня чаем на перевалах, а в Грузии — угощали хачапури. Не будьте параноиками.', '2026-04-23 11:33:02.899480'::timestamp, 447);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3021, 'Одиночка в Венеции: купите проездной на вапоретто на 48 часов. За это время можно объехать все острова, найти скрытые дворики и не чувствовать себя лишним.', '2026-04-23 11:33:05.256553'::timestamp, 447);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3022, 'Настоящая паста карбонара — без сливок! Только яйца, пекорино, гуанчиале и перец. В Риме ищите траттории с табличкой «cucina tipica».', '2026-04-23 11:33:08.122379'::timestamp, 448);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3023, 'Уличная еда в Бангкоке — самая вкусная и безопасная. Пад тай с креветками за 50 бат, манго с клейким рисом — 40 бат. Смотрите где много местных.', '2026-04-23 11:33:10.375640'::timestamp, 448);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3024, 'Во Вьетнаме суп фо бо едят на завтрак. И никогда не просите соевый соус — это оскорбление повара. Только рыбий соус, лайм и чили.', '2026-04-23 11:33:12.935484'::timestamp, 448);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3026, 'В Японии не налегайте на васаби — он не для остроты, а для дезинфекции сырой рыбы. Настоящий васаби стоит дорого, вам дадут хрен.', '2026-04-23 11:33:17.442735'::timestamp, 448);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3027, 'Помпеи: не ходите с толпой. Возьмите аудиогид и уйдите в дальний угол Форума — там дома с сохранившимися фресками, куда не доходят экскурсии.', '2026-04-23 11:33:20.208129'::timestamp, 449);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3029, 'Ангкор-Ват: берите велосипед и уезжайте от главного храма в джунгли. Та-Пром — тот, где корни деревьев обвивают руины — пуст в 8 утра.', '2026-04-23 11:33:24.915428'::timestamp, 449);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3030, 'Петра в Иордании: ночное шоу со свечами — развод для туристов. Лучше придите на рассвете, когда солнце красит скалы в розовый, а бедуины ещё спят.', '2026-04-23 11:33:27.372525'::timestamp, 449);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3031, 'Афинский акрополь: не ходите в полдень. В 8 утра народу мало, солнце не палит. И возьмите бутылку воды — наверху продают по 5 евро.', '2026-04-23 11:33:29.729021'::timestamp, 449);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3033, 'Сингапур: сады у залива вечером — световое шоу супердеревьев каждые 2 часа. Ложитесь на траву и смотрите вверх, как в планетарии.', '2026-04-23 11:33:35.464494'::timestamp, 450);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3034, 'Барселона: парк Гуэля лучше смотреть на рассвете. Вход бесплатный до 8 утра, толп нет, и дракон в лучах солнца выглядит волшебно.', '2026-04-23 11:33:37.817771'::timestamp, 450);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3035, 'Лондон: не платите за колесо обозрения (London Eye). Идите на Sky Garden на 35 этаже — бесплатно, вид тот же, а кофе в 5 раз дешевле.', '2026-04-23 11:33:40.602271'::timestamp, 450);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3037, 'Дайвинг на Мальдивах: ночной дайв с мантами. Огромные скаты кружат вокруг, освещённые фонариками. Главное не делать резких движений.', '2026-04-23 11:33:48.514859'::timestamp, 451);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3038, 'Яхтинг в Хорватии: аренда 40-футовой яхты на неделю — 2000 евро на 6 человек. Стоянки в бухтах бесплатны, вода бирюзовая, как в открытке.', '2026-04-23 11:33:51.231203'::timestamp, 451);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3039, 'Круиз на пароме по фьордам Норвегии: Гейрангер-фьорд в солнечный день — вода отражает скалы, водопады падают с высоты 300 метров. Лучше любых круизных лайнеров.', '2026-04-23 11:33:53.652239'::timestamp, 451);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3041, 'Сёрфинг на Гавайях: пляж Вайкики для новичков. Волны мягкие, пологие, песок. Аренда доски 15 долларов в час. Через 2 часа уже стоял.', '2026-04-23 11:33:58.501839'::timestamp, 451);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3042, 'Трекинг к базовому лагерю Аннапурны: 10 дней, 5416 метров. Главное правило — не торопиться, пить 4 литра воды в день. Гид не нужен, тропа отмечена.', '2026-04-23 11:34:01.267813'::timestamp, 452);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3043, 'Восхождение на Эльбрус с юга: 2 дня, 5642 метра. Акклиматизация на Приюте 11 (4100 м) обязательна. И не берите с собой кеды — будете жалеть.', '2026-04-23 11:34:03.518514'::timestamp, 452);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3044, 'Перевал Дятлова в горах Северного Урала: не ходите без опыта. Место суровое, погода меняется за час, дорог нет. Туристы гибнут до сих пор.', '2026-04-23 11:34:05.875802'::timestamp, 452);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3045, 'Альпы, пеший маршрут Tour du Mont Blanc: 170 км за 10 дней. Ночуйте в хижинах (refuge), бронируйте за месяц. И не берите палатку — запрещено на большей части.', '2026-04-23 11:34:08.333002'::timestamp, 452);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3046, 'Швейцарская тропа Эйгера: участок с виа феррата — железными скобами над пропастью. Высота 2000 м, страшно до дрожи, но виды такие, что забываешь о страхе.', '2026-04-23 11:34:10.996054'::timestamp, 452);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3047, 'Сахара из Марокко: 2 дня на верблюде до лагеря у дюн Эрг-Шебби. Ночью — миллиард звёзд, тишина и песок, который светится в лунном свете.', '2026-04-23 11:34:13.965048'::timestamp, 453);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3048, 'Пустыня Атакама в Чили: долина Луны — пейзаж, похожий на марсианский. Закат в горах, когда солнце красит скалы в багровый — лучший в моей жизни.', '2026-04-23 11:34:16.287250'::timestamp, 453);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3049, 'Намибия: дюна 45 высотой 170 метров. Взобраться на неё на рассвете — песок оранжевый, тени от дюн создают оптическую иллюзию.', '2026-04-23 11:34:18.534916'::timestamp, 453);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3050, 'Вахтанги в Иордании: пустыня Вади-Рам. Езда на джипе по красному песку, ночёвка в бедуинском лагере. Обязательно попробуйте запечённого в песке цыплёнка — зикб.', '2026-04-23 11:34:21.133039'::timestamp, 453);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3051, 'Пустыня Гоби: палеонтологическая экспедиция. Мы нашли фрагмент яйца динозавра. Учёные говорят — 70 миллионов лет. Весь песок вокруг дышит историей.', '2026-04-23 11:34:23.366176'::timestamp, 453);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3052, 'Амазония: 5 дней в джунглях с проводником. Спали в гамаках, ловили пираний на ужин, слышали рёв ягуара в ночи. Отпугивали криками — помогло.', '2026-04-23 11:34:26.113851'::timestamp, 454);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3053, 'Остров Борнео: орангутаны в заповеднике. Смотрите на кормёжку в 9 утра — обезьяны спускаются с деревьев и берут бананы из рук. Не гладьте — укусят.', '2026-04-23 11:34:28.564037'::timestamp, 454);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3054, 'Коста-Рика: сёрфинг на тихоокеанском побережье и одновременно поход к действующему вулкану Ареналь. Лава видна ночью — красные реки в темноте.', '2026-04-23 11:34:30.861322'::timestamp, 454);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3055, 'Мадагаскар: лемуры в национальном парке Раномафана. Идите с гидом в 6 утра — они активны и не боятся. Увидите индри — самого крупного лемура.', '2026-04-23 11:34:33.218185'::timestamp, 454);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3056, 'Таиланд, остров Чанг: слоновий центр, где животных не заставляют работать. Можно кормить, мыть в реке. Эти слоны спаслись от логгерей.', '2026-04-23 11:34:35.572741'::timestamp, 454);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3057, 'Лыжный курорт Валь-Торанс во Франции — высота до 3200 м. Снег гарантирован даже в апреле. Красные трассы широкие, чёрные — для экстремалов.', '2026-04-23 11:34:38.452214'::timestamp, 455);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3058, 'Финская Лапландия: хаски-сафари на 40 км. Упряжка из 8 собак летит по лесу, мороз -20, щёки горят, но не чувствуешь холода от восторга.', '2026-04-23 11:34:41.937261'::timestamp, 455);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3059, 'Северное сияние в Тромсё: ловить его лучше в феврале. Уезжайте от города на 30 км, подальше от света. Вспышка длится 5-10 минут — успеваете сделать десяток кадров.', '2026-04-23 11:34:44.817216'::timestamp, 455);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3060, 'Байкал в феврале: лёд толщиной метр, трещины уходят на километры. Катание на коньках по льду — нереальное чувство свободы.', '2026-04-23 11:34:47.242177'::timestamp, 455);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3061, 'Аляска, дог-трекинг: 3 дня по маршруту Айдитарод. Сами управляете упряжкой из 12 собак. После 8 часов в седле всё болит, но сдаваться нельзя.', '2026-04-23 11:34:50.521490'::timestamp, 455);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3062, 'Велосипедный тур по Вьетнаму: от Хюэ до Хойана через перевал Хай Ван. 70 км, 500 метров подъёма, награда — спуск к пляжу Ланг-Ко. Есть можно всё, что продают на дороге.', '2026-04-23 11:34:53.441845'::timestamp, 456);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3063, 'Поездка на байке по Шри-Ланке: аренда 10 долларов в день. Маршрут Канди — Нувара-Элия через чайные плантации. Серпантин, слоны на дороге, дожди. Не для слабонервных.', '2026-04-23 11:34:56.052209'::timestamp, 456);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3064, 'Таиланд, петля Mae Hong Son: 1800 км по горам, 1864 поворота. Лучший мотоцикл — 250 кубов, не больше. Бензин на заправках каждые 50 км, отели прямо на трассе.', '2026-04-23 11:34:58.610452'::timestamp, 456);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3065, 'Мотопутешествие по Балканам: от Дубровника до Афин через Черногорию, Албанию, Грецию. Горные перевалы, побережье, древние руины. Албанцы обожают байкеров.', '2026-04-23 11:35:00.972915'::timestamp, 456);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3066, 'Камчатка на эндуро: 300 км грязи, брёвен и переправ. Дожди и медведи на дороге. Доехать до вулкана Толбачик — испытание, которое помнишь всю жизнь.', '2026-04-23 11:35:03.320846'::timestamp, 456);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3067, 'Записываю рифмы на стенах подъездов. Потом прихожу через месяц и вижу, что кто-то дописал свою строчку. Так рождается живой хип-хоп.', '2026-04-23 11:45:08.192102'::timestamp, 457);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3068, 'Самый сильный трек я написал после того, как просидел ночь на лавке у заколоченного магазина. Одиночество и фонари — лучшие музпродюсеры.', '2026-04-23 11:45:09.625970'::timestamp, 457);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3069, 'Уличная поэзия не про граффити. Это про то, как ты разглядываешь трещины на асфальте и находишь в них ритм.', '2026-04-23 11:45:11.273714'::timestamp, 457);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3070, 'Когда я слышу, как парни читают рэп во дворе под аккустику, я понимаю: культура жива. Студийный глянец не заменит хриплого голоса на ветру.', '2026-04-23 11:45:12.698315'::timestamp, 457);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3071, 'Однажды написал куплет о пьяном соседе. Он услышал, не обиделся, а сказал: «Ты точно описал мой вторник». Вот она, правда улиц.', '2026-04-23 11:45:14.234854'::timestamp, 457);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3072, 'Jetpack Compose — лучший друг, но не для списков с частыми обновлениями. `derivedStateOf` и `remember` спасают от перерисовок всего подряд.', '2026-04-23 11:45:16.694524'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3073, 'Однажды я забыл отменить корутину при выходе из фрагмента. Ждал 10 секунд GC — приложение подвисало. `viewModelScope` + `Dispatchers.IO` правильно использовать.', '2026-04-23 11:45:18.125159'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3074, 'Room с Flow — отлично, но для сложных запросов с несколькими таблицами лучше делать `@Transaction` и возвращать обычные списки, а не Flow.', '2026-04-23 11:45:19.774623'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3075, 'Билд-таймы в Android Studio? Используйте модули по фичам и `build.gradle` с `isSeparate = true`. Мои сборки ускорились с 3 минут до 45 секунд.', '2026-04-23 11:45:21.406849'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3076, 'Тёмная тема не только дизайн. На AMOLED-экранах экономия батареи до 30%. Только следите, чтобы контрастность текста была > 4.5:1.', '2026-04-23 11:45:23.347593'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3077, 'WorkManager — крутая штука, но периодические задачи с интервалом менее 15 минут могут быть отложены системой. Doze mode решает.', '2026-04-23 11:45:24.782099'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3078, 'Когда я перешёл с Java на Kotlin, сразу влюбился в `sealed class` для состояний экрана. Никаких больше `if (response is Success) ...`.', '2026-04-23 11:45:26.216990'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3079, 'SharedPreferences устарели. DataStore с протоколами буфера — быстрее и типобезопаснее. Но миграцию с Preferences нужно делать вручную.', '2026-04-23 11:45:27.866081'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3080, 'Тестируйте `onSaveInstanceState`! Однажды потерял состояние формы при повороте экрана. `rememberSaveable` в Compose спасает.', '2026-04-23 11:45:29.244073'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3081, 'Гугл выпустил Baseline Profiles для ускорения холодного старта. Использовал — запуск стал на 40% быстрее на старых устройствах.', '2026-04-23 11:45:30.822884'::timestamp, 458);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3082, 'Экстремофилы — бактерии, живущие в кипящих источниках (110°C), в ледяных озёрах Антарктиды, в радиоактивных отходах. Значит, жизнь может быть в самых странных местах.', '2026-04-23 11:45:32.769413'::timestamp, 398);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3083, 'Биосигнатуры на экзопланетах: кислород и метан вместе (фотосинтез и метаногенез). Но и абиотические процессы могут их давать, например, фотолиз воды.', '2026-04-23 11:45:34.406893'::timestamp, 398);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3084, 'Энцелад — спутник Сатурна с гейзерами воды из-под ледяной коры. Аппарат Cassini пролетел сквозь шлейф и обнаружил органику, водород и соль.', '2026-04-23 11:45:35.941546'::timestamp, 398);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3085, 'Марс в прошлом был тёплым и влажным. Глинистые минералы и русла рек. Если жизнь зародилась независимо на Марсе и Земле — это был бы ключ к повсеместности жизни.', '2026-04-23 11:45:37.377206'::timestamp, 398);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3086, 'Молекулы РНК могут самовоспроизводиться в пробирке (рибозимы). Теория «мира РНК» объясняет, как без ферментов могла возникнуть наследственность.', '2026-04-23 11:45:39.015988'::timestamp, 398);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3087, 'Сабвуфер должен не дрожать, а пульсировать в грудной клетке. Если ты не чувствуешь бас костями — твой бит не качает.', '2026-04-23 11:45:41.372850'::timestamp, 459);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3088, 'Правильный бас — это 40-60 Гц. Всё, что ниже, — уже инфразвук, он только сбивает с толку. Всё, что выше, — уже не бас, а середина.', '2026-04-23 11:45:42.878362'::timestamp, 459);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3089, 'Сделал ремикс на трек, где убрал все частоты выше 100 Гц. Остался только бас и кик. Люди в клубе танцевали, не понимая, почему их трясёт.', '2026-04-23 11:45:45.843669'::timestamp, 459);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3090, 'Микшируя бас, я всегда проверяю на дешёвых наушниках. Если там он не разваливается в кашу — значит, порядок.', '2026-04-23 11:45:48.229324'::timestamp, 459);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3091, 'Однажды на концерте бас был настроен так, что у людей начали вылетать стёкла из машин. С тех пор я знаю, где предел.', '2026-04-23 11:45:50.382175'::timestamp, 459);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3092, 'Через 10 лет рэп будет создавать нейросеть. Но она никогда не запишет трек о том, как разбил коленку в девять лет на школьной дискотеке.', '2026-04-23 11:45:53.964788'::timestamp, 460);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3093, 'Следующее поколение битов — это гибрид органики и синтетики. Живые ударные + модульный синтез + алгоритмическая генерация. Я уже это делаю.', '2026-04-23 11:45:55.500827'::timestamp, 460);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3094, 'Предсказываю: скоро исчезнет понятие «жанр» в хип-хопе. Будет просто «музыка», которую MC читает под любые ритмы — от африканского фолка до индастриала.', '2026-04-23 11:45:57.241811'::timestamp, 460);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3096, 'Я уже тестирую прототип: нейросеть анализирует текст и генерирует минус, который идеально подходит под смысл. Пока сыро, но через год будет прорыв.', '2026-04-23 11:46:00.004654'::timestamp, 460);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3097, 'Каждый мой трек — это речь перед районом. Я не просто читаю, я убеждаю, доказываю, заставляю задуматься. Микрофон — моя трибуна.', '2026-04-23 11:46:02.464916'::timestamp, 461);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3098, 'Когда я выхожу на бит, я представляю, что передо мной тысяча человек, а не экран компьютера. Так рождается настоящий накал.', '2026-04-23 11:46:03.897162'::timestamp, 461);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3099, 'Ораторское мастерство в рэпе — это умение делать паузу ровно в тот момент, когда слово уже прозвучало, но ещё не осмыслено.', '2026-04-23 11:46:05.360317'::timestamp, 461);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3100, 'Я не кричу в микрофон. Мой голос — это инструмент: то шёпот, то рык, то спокойная речь. Умение владеть голосом важнее громкости.', '2026-04-23 11:46:06.765199'::timestamp, 461);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3101, 'На баттле я однажды прочитал куплет шёпотом. Зал замолчал, оппонент растерялся. Тишина может быть громче крика.', '2026-04-23 11:46:08.608587'::timestamp, 461);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3102, 'Классический бум-бэп — это не ностальгия, это фундамент. Если ты не умеешь читать под джазовый сэмпл с вырезанным брейком, не берись за трэп.', '2026-04-23 11:46:11.381945'::timestamp, 462);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3103, 'Винил щёлкает — значит, бит живой. Цифра стерильна, а на пластинке остаются следы времени. Я до сих пор сэмплирую только с винила.', '2026-04-23 11:46:12.872616'::timestamp, 462);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3104, 'Когда слышу, как молодые называют MF DOOM «недооценённым», мне смешно. Мы в 90-х знали, что он гений, просто интернета не было.', '2026-04-23 11:46:14.341701'::timestamp, 462);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3105, 'Мой последний микстейп записан на двухдорожечный катушечный магнитофон. Звук грязный, но в нём есть душа, которой нет у ваших плагинов.', '2026-04-23 11:46:15.875436'::timestamp, 462);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3106, 'Баттлы на районе уже не те. Раньше проигравший отдавал свою цепочку, теперь — дизлайк в интернете. Где уважение к культуре?', '2026-04-23 11:46:17.413818'::timestamp, 462);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3107, 'Рифма «кровь/любовь» убила больше хип-хоп текстов, чем плохие биты. Ищи неочевидные созвучия, даже если придётся переписать куплет десять раз.', '2026-04-23 11:46:19.670381'::timestamp, 463);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3108, 'Панчлайн — это не просто острота. Это момент, когда слушатель останавливает трек и перематывает назад, чтобы переварить услышанное.', '2026-04-23 11:46:21.099860'::timestamp, 463);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3109, 'Сторителлинг в рэпе умер? Зайдите на SoundCloud нового поколения — там парни пишут 16-тактовые новеллы о том, как потеряли друга.', '2026-04-23 11:46:22.740005'::timestamp, 463);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3110, 'Когда я пишу текст, я сначала проговариваю его без музыки. Если он цепляет без бита — значит, в нём есть правда.', '2026-04-23 11:46:24.177143'::timestamp, 463);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3111, 'Хип-хоп — это поэзия бедных кварталов. Не нужно притворяться гангстером, если ты вырос в спальном районе. Честность важнее пафоса.', '2026-04-23 11:46:25.605922'::timestamp, 463);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3112, 'Круг — это магия. Когда пять человек передают микрофон по кругу, рождается энергия, которую не записать в студии. Уловить её может только тот, кто там стоял.', '2026-04-23 11:46:27.860879'::timestamp, 464);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3113, 'Однажды в кибер-баттле я прочитал текст, который готовил месяц. Оппонент выдал фристайл и порвал меня. С тех пор я тренирую импровизацию каждый день.', '2026-04-23 11:46:29.478698'::timestamp, 464);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3114, 'Хороший куплет в кругу должен звучать как разговор. Не надо кричать и размахивать руками — пусть слова работают сами за себя.', '2026-04-23 11:46:31.141449'::timestamp, 464);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3115, 'Cypher — это рентген. Он показывает, есть ли у тебя флоу или ты просто заучил чужие рифмы. Подготовленные тексты рассыпаются, если нет внутреннего метронома.', '2026-04-23 11:46:32.570510'::timestamp, 464);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3116, 'Записал свой первый круг на диктофон в 15 лет. Сейчас стыдно слушать, но именно там родилась моя манера читать — рваная, эмоциональная, с паузами не в такт.', '2026-04-23 11:46:34.104483'::timestamp, 464);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3117, 'Биоразнообразие стабилизирует экосистемы. Эксперимент с лугами: при 10 видах растений продуктивность на 50% выше, чем при одном.', '2026-04-23 11:46:35.948885'::timestamp, 396);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3118, 'Инвазивные виды — вторая причина вымирания после уничтожения среды. Борщевик Сосновского, кролики в Австралии, змееголов в США.', '2026-04-23 11:46:37.486496'::timestamp, 396);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3119, 'Коралловые рифы — это симбиоз полипа и водорослей зооксантелл. При нагреве воды полипы выгоняют водоросли (обесцвечивание) и умирают от голода.', '2026-04-23 11:46:38.920232'::timestamp, 396);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3120, 'Лесные пожары в Австралии 2019-2020 убили 3 миллиарда животных. Изменение климата увеличивает частоту и интенсивность пожаров.', '2026-04-23 11:46:41.070361'::timestamp, 396);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3121, 'Оплодотворение океана железом — идея убрать CO₂: железо стимулирует цветение фитопланктона, который поглощает углерод. Но эффект мал и непредсказуем.', '2026-04-23 11:46:43.065918'::timestamp, 396);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3122, 'Глубина обработки почвы: если пахать на 25 см вместо 30, урожайность падает на 15%. Но и топлива тратится меньше. Ищите баланс.', '2026-04-23 11:46:45.570051'::timestamp, 421);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3123, 'Женский рэп — это не про то, как круто ты трясёшь попой. Это про боль, силу и право быть услышанной в мире, где доминируют мужские голоса.', '2026-04-23 11:46:47.937248'::timestamp, 465);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3124, 'Мой флоу — как волна: то накрывает с головой, то отступает, оставляя песок. Главное — держать ритм, даже когда кажется, что задыхаешься.', '2026-04-23 11:46:50.079840'::timestamp, 465);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3125, 'Записала куплет за один дубль. Такое случается раз в год, когда текст и бит сливаются в оргазм. Не пытайтесь повторить — просто кайфуйте.', '2026-04-23 11:46:51.654687'::timestamp, 465);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3126, 'На баттле против меня вышел парень с заученными оскорблениями. Я ответила ему историей о том, как он боится собственной тени. Он замолчал.', '2026-04-23 11:46:53.252779'::timestamp, 465);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3127, 'Слушаю Cardi B и думаю: почему у нас до сих пор нет такой же харизматичной рэперши, которая бы не копировала запад, а говорила своим голосом?', '2026-04-23 11:46:54.686972'::timestamp, 465);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3128, 'Я проанализировал 100 треков разных эпох. Самые запоминающиеся флоу — те, где меняется плотность слогов: то дробь, то протяжные гласные.', '2026-04-23 11:46:57.045167'::timestamp, 466);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3129, 'Монотонность убивает даже самый умный текст. Если ты читаешь как диктор новостей, слушатель выключит трек через 30 секунд.', '2026-04-23 11:46:58.579470'::timestamp, 466);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3130, 'Твой флоу должен отражать содержание. Злой куплет — рваный ритм, грустный — плавный, как течение реки. Несоответствие формы и содержания — провал.', '2026-04-23 11:46:59.913064'::timestamp, 466);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3131, 'На лекции по рэпу я показал студентам волновую форму трека Kendrick Lamar. Они не поверили, что там столько микропауз и акцентов.', '2026-04-23 11:47:01.343321'::timestamp, 466);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3132, 'Флоу — это не только скорость, но и тембр, и артикуляция. Тот же текст, прочитанный шёпотом и криком, создаёт два разных трека.', '2026-04-23 11:47:02.879764'::timestamp, 466);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3133, 'Flutter — круто, но горячая перезагрузка иногда врёт. Если меняете глобальные переменные или статические поля — ждите сюрпризов.', '2026-04-23 11:48:02.786407'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3134, 'Перешёл с BLoC на Riverpod после года мучений. Кода стало меньше, а тестировать проще. Provider — прошлый век.', '2026-04-23 11:48:04.225038'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3135, 'Оптимизация Flutter: используйте `RepaintBoundary` для сложных анимаций. И избегайте `Opacity` в слоях — замените на `FadeTransition`.', '2026-04-23 11:48:05.699593'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3136, 'Мой опыт: flutter_localizations под iOS весит 2 МБ, но без него правильное плюральное правило для русского языка не работает. Стоит того.', '2026-04-23 11:48:07.292419'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3137, 'Гибридные навигационные стеки (GoRouter + нативные экраны) — боль. Пришлось писать платформенные каналы для передачи событий жизненного цикла.', '2026-04-23 11:48:08.927511'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3138, 'Flame для игр? Пока хобби-проекты, но для production лучше брать Unity или Godot. Хотя производительность Flame приятно удивила.', '2026-04-23 11:48:10.360934'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3139, 'Билд-варнинг: `use_deferred_image_loading` в iOS иногда ломает отображение картинок из памяти. Отключил — полетело.', '2026-04-23 11:48:11.794605'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3140, 'На Flutter Web пока что плавающие позиции `Stack` работают нестабильно. Для сложной вёрстки лучше рендерить CanvasKit, а не HTML.', '2026-04-23 11:48:13.129712'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3141, 'Адаптивные приложения на Flutter — это магия. MediaQuery и LayoutBuilder в связке с custom size classes заменяют UIKit-подход.', '2026-04-23 11:48:14.659282'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3142, 'Пакет `flutter_bloc` хорош, но для простых экранов даже `setState` — нормально. Не усложняйте там, где не надо.', '2026-04-23 11:48:16.094087'::timestamp, 467);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3143, 'Мой район — это персонаж. У него есть характер, настроение, запахи. Я просто записываю его монологи, накладываю на бит — и получается трек.', '2026-04-23 11:48:18.347390'::timestamp, 468);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3144, 'Лучший сторителлинг — это когда слушатель говорит: «Я был там, хотя никогда не выходил из своей комнаты».', '2026-04-23 11:48:19.576854'::timestamp, 468);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3145, 'Я рассказываю историю о том, как дядя Вася торгует семечками у метро. В ней нет перестрелок и наркотиков, но она держит за живое, потому что это реальность.', '2026-04-23 11:48:21.215667'::timestamp, 468);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3146, 'Пишу цикл треков о каждом доме на своей улице. В первом живёт ветеран, во втором — молодая мать-одиночка, в третьем — музыкант-неудачник. Это и есть хип-хоп хроника.', '2026-04-23 11:48:22.648823'::timestamp, 468);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3147, 'Когда я читаю эти истории на концертах, люди из других районов подходят и говорят: «У нас то же самое». Значит, я попал в нерв.', '2026-04-23 11:48:23.875976'::timestamp, 468);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3148, 'Припев — это крючок, который должен зацепить с первых секунд. Если после первого прослушивания человек не напевает его в душе — я провалился.', '2026-04-23 11:48:26.132302'::timestamp, 469);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3149, 'Лучшие хуки — это не сложные конструкции, а простые фразы, которые повторяются как мантра. «Бум-бэп, бум-бум-бэп» — и ты уже танцуешь.', '2026-04-23 11:48:27.463130'::timestamp, 469);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3150, 'Я пишу припевы так, чтобы их мог спеть любой, даже если у него нет слуха. Это не потакание, это уважение к слушателю.', '2026-04-23 11:48:28.903774'::timestamp, 469);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3151, 'Один хороший хук может спасти посредственный куплет. Но плохой хук убьёт даже гениальные стихи. Поэтому я начинаю трек именно с припева.', '2026-04-23 11:48:30.226404'::timestamp, 469);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3152, 'Мои припевы часто рождаются из случайных фраз. Кто-то сказал в очереди «сдачу не надо», я записал, переделал в ритм — получился хук для трека.', '2026-04-23 11:48:31.659920'::timestamp, 469);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3154, 'CoreData vs SwiftData: второй только начинает зреть. Миграции с CoreData на SwiftData — тот ещё квест, особенно с iCloud Sync. Подожду ещё года.', '2026-04-23 11:48:35.551171'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3155, 'Оптимизация iOS-приложения: избавился от лишних вызовов `reloadData()` в UITableView и получил +15 fps. Инструменты Instruments — огонь.', '2026-04-23 11:48:36.782412'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3156, 'Combine я так и не полюбил. Для простых async/await хватает, для сложных стримов проще взять RxSwift, он понятнее команде.', '2026-04-23 11:48:38.213663'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3157, 'Провёл эксперимент: переписал модуль на SwiftUI + Observation framework (iOS 17+). Кода стало на 30% меньше, багов на релизе — на 50%. Но поддержка iOS 16 убивает.', '2026-04-23 11:48:39.544927'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3158, 'Забавный кейс: на iOS 15.4 срабатывал `onAppear` после каждого перехода обратно, хотя вьюха не пересоздавалась. Пришлось заменить на `task(id:)` с проверкой.', '2026-04-23 11:48:40.874873'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3159, 'Push-уведомления на iOS: не забывайте про `didReceiveRemoteNotification:fetchCompletionHandler`. Если не вызвать completionHandler, система убьёт приложение в фоне.', '2026-04-23 11:48:42.689524'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3160, 'Почему я до сих пор не люблю SwiftUI для больших форм? Анимация клавиатуры съезжает, `@FocusState` иногда зависает. UIKit в этом плане надёжнее.', '2026-04-23 11:48:44.804386'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3161, 'WWDC23 принёс `StoreKit 2`, и это глоток свежего воздуха. Наконец-то транзакции не приходится парсить из сырого JSON.', '2026-04-23 11:48:46.515291'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3162, 'Совет: всегда подписывайте билды для TestFlight с распределённым сертификатом. Иначе при увольнении коллеги приложение падает.', '2026-04-23 11:48:48.183868'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3163, 'Тысяча продюсеров в Telegram-каналах просят бит бесплатно. Я говорю: «Сделай мне минус под 50% роялти». Молчат. Хастл — это не клянчить, а договариваться.', '2026-04-23 11:48:50.907978'::timestamp, 471);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3164, 'Продал свой первый бит за 50 баксов. Потом увидел, что парень накрутил на нём миллион прослушек. Обидно? Нет, это урок — всегда бери процент.', '2026-04-23 11:48:52.754044'::timestamp, 471);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3165, 'Рэп-индустрия — это бизнес. Если ты не умеешь продавать своё имя, даже самый гениальный куплет останется в твоём телефоне.', '2026-04-23 11:48:54.494879'::timestamp, 471);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3166, 'Заработал на стриминге за месяц 20 долларов. Потратил их на рекламу в соцсетях — вернулось 200. Не жалейте денег на продвижение.', '2026-04-23 11:48:55.928589'::timestamp, 471);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3167, 'Подписал контракт с лейблом, где мне обещали «полный карт-бланш». В итоге на релизе переписали половину текстов. Теперь у меня свой независимый лейбл.', '2026-04-23 11:48:57.362279'::timestamp, 471);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3168, 'Создаю биты только ночью. Днём слишком много лишних звуков, а в тишине слышно, как дышит каждый сэмпл.', '2026-04-23 11:48:59.512878'::timestamp, 472);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3169, 'Любой минус начинается с кика и снейра. Найди правильный грув — остальное приложится. Без базы даже самый модный synth провалится.', '2026-04-23 11:49:01.049307'::timestamp, 472);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3170, 'Олдскулы хотят, чтобы я клепал бум-бэп как в 90-х. А я экспериментирую с дрилл-битами и джазовыми гармониями. Эволюция или смерть.', '2026-04-23 11:49:02.789525'::timestamp, 472);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3171, 'Сделал ремикс на трек, который никто не просил. Просто хотел доказать себе, что могу перевернуть любую аранжировку с ног на голову.', '2026-04-23 11:49:04.427170'::timestamp, 472);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3172, 'Почему все молодые битмейкеры загоняют себя в рамки? Смешивай трап с босса-новой, клади Lo-fi поверх дабстепа — только так рождается новое.', '2026-04-23 11:49:05.967704'::timestamp, 472);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3173, 'Чистая архитектура в мобилках: не всегда нужно разделение на data/domain/presentation для каждого экрана. Начните с двух слоёв, усложняйте по мере роста.', '2026-04-23 11:49:08.217593'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3174, 'Модуляризация через feature-модули. Gradle-кеширование для каждого фичи отдельно ускорило сборку на CI на 40%.', '2026-04-23 11:49:09.855407'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3175, 'Внедрял MVI (Model-View-Intent) на проекте с 20 экранами. Пришлось отказаться — слишком много бойлерплейта. MVVM с LiveData/StateFlow проще.', '2026-04-23 11:49:11.294941'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3176, 'Зависимости: Dagger Hilt — стандарт для Android, но для iOS лучше использовать чистые синглтоны и фабрики. Контейнеры ввода излишни.', '2026-04-23 11:49:12.721998'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3177, 'Кэширование данных: Room + SQLite + Retrofit + offline-first. Синхронизация при восстановлении сети — самый частый источник багов.', '2026-04-23 11:49:14.157891'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3178, 'Выбор между WebView и нативом для сложных форм. Мы пошли на WebView и пожалели: проблемы с сенсорным вводом и памятью.', '2026-04-23 11:49:15.586448'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3179, 'Clean Architecture с use cases даёт преимущество при тестировании. Но количество интерфейсов растёт экспоненциально.', '2026-04-23 11:49:16.917705'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3180, 'Мониторинг ошибок: не только Crashlytics, но и Firebase Performance. Нашли узкое место в сериализации — время сократили вдвое.', '2026-04-23 11:49:18.461251'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3181, 'Гибридная навигация: нативные экраны перемежаются с WebView. Пришлось писать свой координатор для синхронизации стека.', '2026-04-23 11:49:19.894617'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3182, 'Оценка времени разработки: на проектирование архитектуры закладывайте 20% времени, иначе переписывать полгода.', '2026-04-23 11:49:21.424548'::timestamp, 473);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3183, 'Автотесты на iOS: XCUITest умеет записывать действия, но генерирует нечитаемый код. Пишите самописные Page Object на Swift.', '2026-04-23 11:49:23.574234'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3184, 'Android: Espresso + Idling Resources — ждать появления элементов. Без них тесты падают из-за асинхронности.', '2026-04-23 11:49:25.020826'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3185, 'Сниппет для эмуляции плохого интернета на реальном устройстве: Charles Proxy или Network Link Conditioner. Отлавливает баги с таймаутами.', '2026-04-23 11:49:26.441388'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3186, 'Инструмент для регрессии: screenshot testing с помощью Paparazzi (Android) или SnapshotTesting (iOS). Ловили баги в вёрстке, которые глазом не видно.', '2026-04-23 11:49:27.775036'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3188, 'При ручном тестировании составляйте чек-лист сценариев: офлайн-режим, переворот экрана, фоновый режим, push-уведомления в разных состояниях.', '2026-04-23 11:49:30.556953'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3189, 'Баги с памятью: используйте Xcode Memory Graph или Android Studio Memory Profiler. Один retain cycle — и приложение падает через час.', '2026-04-23 11:49:32.073226'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3190, 'Тестирование конфигураций: разные языки, разные версии ОС, разные разрешения экрана. Автоматизируйте на CI с помощью матрицы параметров.', '2026-04-23 11:49:33.409927'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3191, 'Не забывайте про тестирование обновлений с предыдущей версии. Миграции баз данных — частая причина крэшей после апдейта.', '2026-04-23 11:49:34.839670'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3192, 'Проверка прав доступа: при первом запуске запрашивайте только критичные. Иначе пользователь уходит.', '2026-04-23 11:49:36.375513'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3193, 'Хранение токенов: SharedPreferences — небезопасно. На Android используйте EncryptedSharedPreferences, на iOS — Keychain.', '2026-04-23 11:49:38.630620'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3194, 'Certificate pinning — мастхэв для финансовых приложений. Но обновлять сертификаты нужно через механизм обновления приложения, иначе блокировка.', '2026-04-23 11:49:40.267149'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3195, 'Обфускация: ProGuard/R8 для Android, для iOS — коммерческие решения типа DexGuard. Останавливает только новичков.', '2026-04-23 11:49:42.419629'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3196, 'Проверка root/jailbreak: не полагайтесь на один флаг. Используйте комбинацию: проверка наличия Cydia, Magisk, недоступности системных файлов.', '2026-04-23 11:49:44.132566'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3197, 'Сниффинг трафика: включайте NSAppTransportSecurity (iOS) и `android:usesCleartextTraffic="false"`. Иначе данные текут в открытую.', '2026-04-23 11:49:46.512171'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3198, 'Локальная БД: шифруйте SQLite с помощью SQLCipher. Пароль храните в Keychain/Keystore, иначе ключ в коде найдут дизассемблером.', '2026-04-23 11:49:48.357044'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3199, 'Валидация ввода: даже на клиенте. SQL-инъекции через локальные запросы — реальность, если используете сырые строки.', '2026-04-23 11:49:51.428921'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3200, 'DeepLink-фишинг: проверяйте, что ссылка пришла из доверенного источника. Иначе поддельный URL запустит ваше приложение с вредоносными параметрами.', '2026-04-23 11:49:52.873522'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3201, 'Clang sanitizers для C++ кода в нативных библиотеках. Один переполнение буфера — и уязвимость.', '2026-04-23 11:49:54.192295'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3202, 'Регулярно сканируйте зависимости на известные уязвимости (OWASP Dependency Check). Библиотеки часто устаревают.', '2026-04-23 11:49:55.626192'::timestamp, 475);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3203, 'Углеродные нанотрубки — свёрнутый графен. Прочность выше стали в 100 раз, электропроводность лучше меди. Уже используются в композитах для гоночных машин.', '2026-04-23 11:49:57.778236'::timestamp, 397);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3204, 'Квантовые точки — полупроводниковые нанокристаллы (CdSe, InAs). Цвет их свечения зависит от размера. Используются в QLED-телевизорах.', '2026-04-23 11:49:59.227244'::timestamp, 397);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3205, 'Золотые наночастицы — красный цвет при 20 нм, синий при 80 нм. Из-за плазмонного резонанса. Применяются для доставки лекарств к опухолям.', '2026-04-23 11:50:00.646180'::timestamp, 397);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3206, 'Самоочищающиеся поверхности с наноструктурой: оксид титана (TiO₂) под УФ разлагает органику. Нанесён на фасады зданий в Японии.', '2026-04-23 11:50:02.180678'::timestamp, 397);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3207, 'Нанопроволока из кремния в 1000 раз тоньше волоса. Используется в сверхчувствительных датчиках для детекции одиночных молекул.', '2026-04-23 11:50:04.024548'::timestamp, 397);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3208, 'Измеряйте холодный старт приложения. На Android: `adb shell am start -W`, на iOS: Instruments -> App Launch. Цель — меньше 1 секунды.', '2026-04-23 11:50:07.061168'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3209, 'Размер изображений: используйте WebP или HEIC, сжимайте до 80% качества. Экономия трафика до 50%.', '2026-04-23 11:50:08.428093'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3210, 'Лишние перерисовки: включите в Android Show GPU Overdraw. Сильное закрашивание красным — убивайте прозрачные слои.', '2026-04-23 11:50:09.929287'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3211, 'ListView/RecyclerView: ViewHolder паттерн — обязательно. Не делайте findViewById в `onBindViewHolder`.', '2026-04-23 11:50:11.397737'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3212, 'Сборка мусора в Unity на iOS — проблема. Старайтесь создавать объекты в пуле, а не динамически.', '2026-04-23 11:50:12.797156'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3213, 'Оптимизация батареи: не используйте GPS в фоне без крайней необходимости. Используйте значимые изменения местоположения.', '2026-04-23 11:50:14.578154'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3214, 'Размер APK: анализируйте с помощью Android Studio APK Analyzer. Удалите дублирующиеся библиотеки и неиспользуемые ресурсы.', '2026-04-23 11:50:16.106215'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3215, 'Ленивая загрузка: загружайте модули и фичи по требованию. Google Play Dynamic Delivery помогает.', '2026-04-23 11:50:17.648948'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3216, 'Профилирование: Systrace (Android) и os_signpost (iOS). Ищите долгие операции на UI-потоке.', '2026-04-23 11:50:19.044379'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3217, 'Кэширование сетевых ответов: используйте OkHttp cache с контрольными суммами. Уменьшает количество запросов.', '2026-04-23 11:50:20.511524'::timestamp, 476);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3218, 'Путешествую по городам и на каждом углу нахожу новую рифму. Вчера — «асфальт/шаль», сегодня — «метро/перо». Слова везде, главное — уметь их разглядеть.', '2026-04-23 11:50:22.660295'::timestamp, 477);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3219, 'Мой блокнот для рифм — это карта мира. В нём есть страницы, посвящённые Петербургу (рифмы про разводные мосты), и страницы про Ростов (про жару и рынки).', '2026-04-23 11:50:24.297853'::timestamp, 477);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3220, 'Кочевник не может писать об одном и том же. Сегодня я — битник в Нью-Йорке, завтра — самурай в Токио. Хип-хоп не имеет границ.', '2026-04-23 11:50:25.840611'::timestamp, 477);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3221, 'Самая неожиданная рифма, которую я нашёл: «Марсельеза» и «железо». Это было на вокзале в Лионе, когда я ждал поезд и слушал уличного музыканта.', '2026-04-23 11:50:27.315307'::timestamp, 477);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3222, 'Домашний рэп быстро надоедает. Чтобы текст был живым, нужно менять локации: пиши в поезде, в парке, в очереди за кофе. Атмосфера питает рифмы.', '2026-04-23 11:50:28.807750'::timestamp, 477);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3223, 'Флоу можно разрезать и сшивать заново. Если обычный слушатель не замечает швов — ты виртуоз. Если заметил — иди учись заново.', '2026-04-23 11:50:31.465727'::timestamp, 478);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3224, 'Самый сложный ритмический рисунок — это когда слова падают между долями. Не каждый MC способен на синкопы, не сбившись с дыхания.', '2026-04-23 11:50:32.900425'::timestamp, 478);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3225, 'Я оперирую трек: удаляю «больные» строчки, пришиваю новый хук, затягиваю петли сводкой. Хирургия звука требует холодной головы.', '2026-04-23 11:50:34.435691'::timestamp, 478);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3226, 'Когда рэпер приходит в студию и не знает, где у него пульс — это катастрофа. Объясняю на пальцах: слушай кик, он твой поводырь.', '2026-04-23 11:50:35.972009'::timestamp, 478);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3227, 'Исправил чужой кривой флоу за полчаса. Оказалось, человек просто боялся пауз. Я научил его молчать в микрофон — и трек задышал.', '2026-04-23 11:50:37.515569'::timestamp, 478);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3228, 'React Native: заменил старый Metro на Re.Pack (Webpack) — холодная перезагрузка стала на 60% быстрее. Особенно круто для крупных проектов.', '2026-04-23 11:50:39.864382'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3229, 'Hermes — мастхэв для RN 0.70+. Уменьшает размер бинарника на 20% и ускоряет старт. Только проверьте совместимость с `Intl`.', '2026-04-23 11:50:42.237152'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3230, 'Однажды на релизе поймал баг: `useEffect` срабатывал дважды из-за React.StrictMode. Оказалось, не очищал подписки. Мурашки по коже.', '2026-04-23 11:50:44.073599'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3231, 'Мосты (bridges) в RN — узкое место. Для частых обновлений (видео, анимации) лучше использовать Fabric TurboModules. Разница в fps колоссальная.', '2026-04-23 11:50:45.698808'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3232, 'Навигация: React Navigation 6 стала стабильной, но навигация глубоких ссылок (deeplinks) до сих пор требует магии с `linking.config`.', '2026-04-23 11:50:47.441514'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3233, 'Redux Toolkit + RTK Query убили столько боли. Никаких санок, автоматическое кеширование и инвалидация — рай для API.', '2026-04-23 11:50:49.525684'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3234, 'Плагин `react-native-permissions` — незаменим. Только не забудьте добавить использование в `Info.plist` и `AndroidManifest`, иначе крэш.', '2026-04-23 11:50:51.171325'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3235, 'Проверяйте `InteractionManager.runAfterInteractions` перед тяжёлыми расчётами. Иначе анимация перехода будет дёргаться.', '2026-04-23 11:50:52.794554'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3236, 'Экран загрузки (splash screen) на iOS — подводный камень. Используйте библиотеку `react-native-bootsplash`, она генерит нативные экраны.', '2026-04-23 11:50:54.402876'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3237, 'Ошибка: нельзя хранить большие изображения в состоянии. При скролле галереи память взлетала до 500 МБ. Решил `FlatList` с пропсом `removeClippedSubviews`.', '2026-04-23 11:50:55.943385'::timestamp, 479);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3238, 'Автономные дроны используют SLAM (одновременная локализация и картографирование) для навигации в помещениях без GPS. Карта строится в реальном времени.', '2026-04-23 11:50:57.783149'::timestamp, 395);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3239, 'Робот-хирург da Vinci увеличивает движения хирурга и убирает тремор. 7 степеней свободы, минимальные разрезы — пациент восстанавливается быстрее.', '2026-04-23 11:50:59.225480'::timestamp, 395);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3240, 'Каждый мой трек — это исповедь. Если я не выложусь на 100%, слушатель почувствует фальшь и выключит. Нельзя врать в рэпе.', '2026-04-23 11:51:01.981638'::timestamp, 480);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3241, 'Записал куплет, а потом заплакал. Потому что вспомнил то, о чём писал. Это и есть настоящий хип-хоп — когда боль становится искусством.', '2026-04-23 11:51:03.824799'::timestamp, 480);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3242, 'Мне говорят: «Ты слишком эмоциональный для рэпа». А я отвечаю: «Эмоции — это единственное, что отличает меня от робота с рифмами».', '2026-04-23 11:51:05.475937'::timestamp, 480);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3243, 'Иногда я выхожу на сцену без подготовки. Микрофон в руках, сердце стучит — и я просто говорю то, что во мне накипело. Это страшно и прекрасно.', '2026-04-23 11:51:07.103059'::timestamp, 480);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3244, 'Моя душа — это сэмпл, который я режу и склеиваю в треках. Иногда получается диссонанс, иногда — гармония. Но это всегда честно.', '2026-04-23 11:51:08.440256'::timestamp, 480);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3245, 'Настоящий хип-хоп рождается не в студии, а на районе. Когда пишешь о том, что видел своими глазами — каждое слово попадает в цель.', '2026-04-23 11:51:10.583708'::timestamp, 481);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3246, 'Куплет должен быть как удар в солнечное сплетение. Если после прослушивания у слушателя не меняется дыхание — ты не доработал.', '2026-04-23 11:51:12.017479'::timestamp, 481);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3247, 'Бит — это скелет трека, а флоу — его душа. Можно взять самый убойный минус, но без качающего ритма текста он останется пустышкой.', '2026-04-23 11:51:13.552107'::timestamp, 481);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3248, 'Я переслушал свой старый микстейп пятилетней давности. Стыдно за наивные рифмы, но энергия та самая, которой сейчас не хватает.', '2026-04-23 11:51:15.087902'::timestamp, 481);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3249, 'Баттл с самим собой — самый сложный. Когда заканчивается вдохновение, просто сядь и запиши любую чушь под бит. Потом выкинешь лишнее.', '2026-04-23 11:51:16.625971'::timestamp, 481);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3250, 'Запись куплета — это только 10% работы. Остальное: десятки дублей, тонкая настройка микрофона, борьба с шипением и щелчками.', '2026-04-23 11:51:18.978651'::timestamp, 482);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3251, 'Мастеринг — это алхимия. Из сырого микса можно выжать максимум 3-4 дБ громкости, не убив динамику. Кто говорит иначе — продаёт лимонады.', '2026-04-23 11:51:20.412550'::timestamp, 482);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3252, 'Лучший студийный монитор — это не тот, у которого плоская АЧХ, а тот, на котором ты привык слышать правду. У меня это Yamaha NS-10, старые, как хип-хоп.', '2026-04-23 11:51:23.891752'::timestamp, 482);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3253, 'Однажды сводил трек, где рэпер записывался в подвале на телефон. Я вытащил из этого шума такой звук, что сам не поверил. Студия — это умение, а не железо.', '2026-04-23 11:51:25.430572'::timestamp, 482);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3254, 'Перед тем как отправить трек на стриминг, я слушаю его на колонке за 10 долларов. Если там всё ещё качает — значит, релиз готов.', '2026-04-23 11:51:26.760802'::timestamp, 482);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3255, 'iOS HIG и Material Design не конфликтуют, но сочетать их нужно аккуратно. Кнопки должны выглядеть как кнопки на обеих платформах.', '2026-04-23 11:51:29.629710'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3256, 'Глубина навигации: более трёх уровней — пользователь теряется. Используйте нижнее меню для важных разделов, кнопку «Назад» — для остальных.', '2026-04-23 11:51:31.062206'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3257, 'Жесты свайпа (swipe back) на iOS естественны, на Android — тоже, но есть модели с жестом «домой». Проверяйте на реальных устройствах.', '2026-04-23 11:51:32.496568'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3258, 'Анимация перехода между экранами не должна длиться дольше 300 мс. Иначе кажется, что приложение тормозит.', '2026-04-23 11:51:33.929469'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3259, 'Доступность: кнопки должны быть не меньше 44x44 pt (48x48 dp). Добавьте `accessibilityLabel` для иконок, иначе VoiceOver будет читать «кнопка».', '2026-04-23 11:51:35.362719'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3260, 'Скелетон вместо спиннера при загрузке улучшает восприятие. Пользователь видит структуру, не раздражается.', '2026-04-23 11:51:37.013395'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3261, 'Вариант шрифтов: для iOS лучше использовать системный San Francisco, для Android — Roboto. Не заставляйте пользователя привыкать к чужому.', '2026-04-23 11:51:38.491436'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3262, 'Формы ввода: показывайте ошибку сразу после потери фокуса, а не после отправки. Поле с паролем должно иметь кнопку показать/скрыть.', '2026-04-23 11:51:39.971253'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3263, 'Динамический тип шрифта: поддерживайте увеличение размера шрифта в настройках системы. Иначе пожилые пользователи бросят приложение.', '2026-04-23 11:51:41.713034'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3264, 'Тёмная тема должна быть не просто инверсией цветов. Используйте разные оттенки серого для иерархии.', '2026-04-23 11:51:45.294715'::timestamp, 483);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3265, 'Строю куплет как дом: сначала фундамент (идея), потом стены (рифмы), потом крышу (панчлайн). Без фундамента всё рухнет.', '2026-04-23 11:51:48.320563'::timestamp, 484);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3266, 'Лучший куплет — это когда нельзя убрать ни одного слова. Каждая строчка работает на общую картину, каждая рифма держит конструкцию.', '2026-04-23 11:51:50.312994'::timestamp, 484);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3267, 'Мои тексты не рождаются за минуту. Я могу два дня крутить одну строку, пока она не встанет точно в паз.', '2026-04-23 11:51:52.378680'::timestamp, 484);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3268, 'Когда я пишу куплет для фита, я представляю голос другого MC. Его манера, его паузы — я должен оставить ему воздух, чтобы он не задохнулся.', '2026-04-23 11:51:53.999475'::timestamp, 484);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3269, 'Куплет о войне и куплет о любви строятся по-разному. Там, где нужна жёсткость, я использую короткие рубленые фразы. Там, где нежность — длинные, растянутые строки.', '2026-04-23 11:51:55.432873'::timestamp, 484);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3270, 'Пластинка не врет. Цифровой звук можно подкрутить, выровнять, сделать идеальным. Винил показывает всё: твои ошибки, твою душу, твой пот.', '2026-04-23 11:51:57.481160'::timestamp, 485);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3271, 'Собираю коллекцию редких хип-хоп пластинок 80-х. Некоторые из них стоят как машина, но я никогда не продам. Это моя библия.', '2026-04-23 11:51:59.019725'::timestamp, 485);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3272, 'Треск иглы на виниле — это не шум, это голос времени. Когда я сэмплирую старую запись, я слышу дыхание того, кто играл на этом инструменте.', '2026-04-23 11:52:00.450913'::timestamp, 485);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3273, 'Молодые битмейкеры не понимают, почему я не пользуюсь сплайсом. А я отвечаю: сэмпл, вырезанный вручную, звучит живее любого AI-генератора.', '2026-04-23 11:52:01.988082'::timestamp, 485);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3274, 'Винил учит терпению. Ты не можешь перемотать трек одним касанием. Ты слушаешь альбом от начала до конца, как это задумал артист.', '2026-04-23 11:52:03.341778'::timestamp, 485);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3275, '.NET MAUI наконец-то стал стабильным в .NET 8. Но для новых проектов всё ещё рассматриваю Flutter — горячая перезагрузка быстрее.', '2026-04-23 11:52:05.779535'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3276, 'Xamarin.Forms был болью. MAUI с обработчиками (handlers) дал прирост производительности на 30% за счёт отказа от рендереров.', '2026-04-23 11:52:07.091117'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3277, 'Использование Community Toolkit MVVM ускоряет разработку. `[ObservableProperty]` — лучшее, что случилось с XAML.', '2026-04-23 11:52:08.438324'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3278, 'Платформенный код: используйте условную компиляцию `#if IOS` вместо диспетчера зависимостей. Проще и быстрее.', '2026-04-23 11:52:09.973272'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3279, 'Библиотека SkiaSharp позволяет рисовать кастомные элементы без платформенных отличий. Экономия времени на 50%.', '2026-04-23 11:52:11.408640'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3280, 'Встроенный Dependency Injection в MAUI — плохо. Лучше использовать сторонний контейнер вроде Autofac, он гибче.', '2026-04-23 11:52:12.746726'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3281, 'Сборка под iOS из Windows — тот ещё квест. Требуется Mac с открытым SSH и правильными сертификатами.', '2026-04-23 11:52:14.481590'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3282, 'Hot Restart в VS Windows для iOS — пока сыро. После 5-го билда эмулятор падает. Пользуюсь только для последнего теста.', '2026-04-23 11:52:15.912452'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3283, 'Ошибка: не забывайте вызывать `base.OnBackButtonPressed()` в Android, иначе кнопка «Назад» не работает.', '2026-04-23 11:52:17.141000'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3284, 'Полезный совет: используйте `CommunityToolkit.Maui.Storage` для безопасного доступа к файловой системе. Обёртка над нативными API.', '2026-04-23 11:52:18.575821'::timestamp, 486);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3285, 'Прыжок с тарзанки в Замбии со 111 метров — сердце уходит в пятки. Но когда отпускаешь верёвку и летишь над водопадом Виктория — это чистый кайф.', '2026-04-23 11:53:34.863085'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3286, 'Сплавы по реке Фьютурале в Коста-Рике (класс V) — не для новичков. Два дня порогов, ночёвка в джунглях, анаконды в воде. Я вернулся другим человеком.', '2026-04-23 11:53:36.399205'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3287, 'Банджи-джампинг в Непале через ущелье Бхоут-Коши — мост высотой 160 метров, под тобой река с крокодилами. Требуют справку от врача. Стоит того.', '2026-04-23 11:53:37.938458'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3289, 'Сёрфинг в Португалии на Назаре — волны до 20 метров. Я не профессионал, просто смотрел с маяка. Адреналин даже от наблюдения.', '2026-04-23 11:53:41.211757'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3290, 'В Карелии мы плыли на байдарках. Внезапно начался шторм. Лодка перевернулась. Я оказался в ледяной воде, но успел схватить рюкзак. Доплыл до острова. Час сидел и стучал зубами. Теперь я уважаю прогноз погоды.', '2026-04-23 11:53:43.629821'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3291, 'На Байкале увидел нерпу впервые вживую. Она вылезла на лёд и смотрела на меня как на дурака. Мы замерли на минуту. Потом она нырнула. Я чувствовал, что прикоснулся к чему-то первозданному.', '2026-04-23 11:53:45.613322'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3292, 'Собрал в лесу грибы, принёс домой. Оказалось, что половина — ложные опята. Неделю я мучился животом. Теперь беру с собой опытного грибника или вообще не рискую.', '2026-04-23 11:53:47.289658'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3293, 'Мы с отцом посадили дуб, когда мне было 10 лет. Недавно я приехал в тот лес — дуб вырос огромным, выше сосен вокруг. Меня там уже не будет, а дерево простоит ещё сто лет. Есть в этом что-то правильное.', '2026-04-23 11:53:48.879882'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3294, 'В Крыму в походе мы забыли воду. Идти до источника ещё час. Нашли лужу после дождя, прокипятили на горелке. Никогда грязная вода не казалась такой вкусной. С тех пор вожу с собой фильтр-кувшин.', '2026-04-23 11:53:50.660898'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3295, 'Я видел северное сияние в Мурманске. Мы сидели на сопке в -35, пили чай из термоса. Небо взрывалось зелёным и фиолетовым. Органы чувств отказывались верить, что это реально.', '2026-04-23 11:53:52.166763'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3296, 'Енот украл у меня бутерброд в американском кемпинге. Я погнался за ним, споткнулся о корень и упал в грязь. Енот сидел на дереве и жевал мой хлеб. Звери — настоящие хозяева леса.', '2026-04-23 11:53:53.717357'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3297, 'Патрулирование акул в ЮАР: клетка опускается в воду, и мимо проплывают трехметровые белые акулы. Дайверы знают: не высовывай руки — откусят.', '2026-04-23 11:53:55.345754'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3298, 'Наблюдение за китами в Норвегии: лодка выходит в море в январе. Увидеть гигантского горбача, выпрыгивающего из воды — зрелище, от которого захватывает дух.', '2026-04-23 11:53:56.985376'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3299, 'Пингвины на Огненной Земле: колония на острове Мартильо. Идите по тропе за 50 метров — пингвины не боятся, ходят рядом. Главное не шуметь.', '2026-04-23 11:53:58.522830'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3300, 'Бурый медведь на Камчатке: сплав по реке, медведи ловят лосося. Держитесь на расстоянии, не берите еду с собой. Гид с ружьём — обязателен.', '2026-04-23 11:53:59.965844'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3301, 'Светлячки в Новой Зеландии: пещера Вайтомо. Тысячи светлячков на потолке — кажется, что смотришь на Млечный путь. Фотоаппарат бесполезен, просто запомните.', '2026-04-23 11:54:01.384467'::timestamp, 158);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3302, 'Когда Rolling Stones выпустили «Satisfaction», им сказали, что гитарный рифф звучит как уличная шарманка. А он стал самым узнаваемым в истории.', '2026-04-23 11:54:03.340484'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3303, 'В 1965 году Боб Дилан вышел на сцену с электрогитарой на фолк-фестивале в Ньюпорте. Его освистали и назвали предателем. Через год он изменил рок навсегда.', '2026-04-23 11:54:05.174004'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3304, 'The Velvet Underground продали всего 30 000 копий дебютного альбома. Но каждый, кто купил, потом основал свою группу.', '2026-04-23 11:54:07.025511'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3305, 'Вудсток должен был стать фестивалем на 50 000 человек. Приехало полмиллиона. Еду сбрасывали с вертолётов, а дожди превратили поле в болото. Это не остановило музыку.', '2026-04-23 11:54:08.452863'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3306, 'Led Zeppelin никогда не выпускали синглы в Великобритании. Им было плевать на хит-парады. И тем не менее «Stairway to Heaven» — самый проигрываемый трек на радио США всех времён.', '2026-04-23 11:54:10.095703'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3307, 'Queen записывали «Bohemian Rhapsody» три недели. Лейбл сказал, что 6-минутная песня с оперой и балладой никогда не станет хитом. Стала.', '2026-04-23 11:54:11.420334'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3308, 'The Clash могли выпустить «London Calling» как двойной альбом по цене одинарного. Они хотели, чтобы панк был доступен всем. Лейбл был в ярости, пластинка разошлась миллионами.', '2026-04-23 11:54:13.263716'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3309, 'В 1985 году на Live Aid Queen сыграли 20 минут, которые считаются лучшим живым выступлением в истории. Фредди Меркьюри заставил стадион Уэмбли хлопать в унисон.', '2026-04-23 11:54:14.696039'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3310, 'Kurt Cobain ненавидел, что Nirvana стала мейнстримом. «Smells Like Teen Spirit» он написал как пародию на песни Pixies, а получился гимн поколения.', '2026-04-23 11:54:16.350944'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3311, 'Рок-н-ролл умер? Нет, он просто переехал в гараж и подполье. В 2024 году тысячи групп записывают альбомы, о которых вы никогда не услышите, и это прекрасно.', '2026-04-23 11:54:17.767594'::timestamp, 254);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3312, 'Колодки Brembo Z04 — зверь. На треке после 5 кругов температура 400°C, тормозят без выцветания. Но на холодную скрипят как телега.', '2026-04-23 11:54:19.514972'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3313, 'Понижение давления в шинах перед треком: перед 2.0, зад 1.8. Пятно контакта увеличивается, и байк не скользит на выходе из поворота.', '2026-04-23 11:54:20.841582'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3314, 'Положение тела: сдвинутая в повороте задница, внешняя нога прижата к баку, внутреннее колено открыто. Локти вниз — так проще чувствовать переднюю вилку.', '2026-04-23 11:54:22.252718'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3315, 'Масло Motul 300V 15W-50 держит перегрузки. Обычное масло после двух сессий превращается в воду, а давление падает. Мотор дороже.', '2026-04-23 11:54:23.810885'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3317, 'Торможение на треке: 100% силы до начала поворота, потом плавно отпускаем. Если нажать на ручку в наклоне — передок сложится.', '2026-04-23 11:54:26.888125'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3318, 'Самый частый страх новичка — закрытый газ в повороте. Но мотоцикл стабильнее именно под тягой. Открывай потихоньку с середины дуги.', '2026-04-23 11:54:28.315329'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3319, 'После каждой трек-сессии проверяю давление в шинах. Оно растёт от нагрева на 0.3-0.4 бара. Если не спустить — на следующем круге потеряешь сцепление.', '2026-04-23 11:54:29.761641'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3320, 'Купил таймер LapTimer и понял, что 70% времени проигрываю на входе в поворот. Неправильная траектория — главный убийца секунд.', '2026-04-23 11:54:31.286054'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3321, 'Однажды на треке упал на скорости 80 км/ч из-за масла на асфальте. Скользил по траве, отделался синяками. С тех пор всегда осматриваю трассу перед выездом.', '2026-04-23 11:54:32.619508'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3322, 'Спутники Starlink на орбите 550 км движутся со скоростью 7.5 км/с. Чтобы их не столкнуть, нужны двигатели на эффекте Холла и миллион линий кода.', '2026-04-23 16:12:01.620747'::timestamp, 409);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3323, 'Промышленный робот KUKA KR 1000 titan поднимает тонну. Его точность — 0.05 мм. Используют для штамповки крыльев самолётов.', '2026-04-23 16:12:03.556681'::timestamp, 411);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3330, 'Чат-бот для психологии Woebot на основе КПТ. 2 миллиона пользователей. Уровень тревоги снижается на 20% за 2 недели. Дешевле живого психолога.', '2026-04-23 16:12:14.467898'::timestamp, 415);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3331, 'Ransomware для облачных хранилищ шифрует файлы и требует биткоины. Бэкап на внешний диск, отключённый от сети — единственная защита.', '2026-04-23 16:12:16.376853'::timestamp, 417);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3335, 'John Deere Model D выпускался 30 лет — с 1923 по 1953. Двухцилиндровый, низкооборотистый, тяговитый. До сих пор можно увидеть на парадах.', '2026-04-23 16:12:22.348124'::timestamp, 425);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3339, 'Реверсивное управление — руль и педали поворачиваются на 180°. Работаешь спиной вперёд, видишь навесное орудие.', '2026-04-23 16:12:28.233578'::timestamp, 434);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3340, 'Швейцария нереально красивая, но бюджет уничтожает. Совет: живите в немецком Фрайбурге или итальянской Комо, а в Швейцарию ездите на день по региональному абонементу.', '2026-04-23 16:12:29.764929'::timestamp, 439);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3341, 'Бангкок — город, который либо любишь, либо ненавидишь. Я в первой категории. Рынок Кхлонг Той — настоящий Таиланд без прикрас: запахи, крики, еда с тележки за 30 бат.', '2026-04-23 16:12:31.296692'::timestamp, 440);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3342, 'Самый экологичный способ путешествовать по Европе — ночной поезд. Спальное место, ноль выбросов и экономия на отеле. Бренд Nightjet — лучший.', '2026-04-23 16:12:32.810486'::timestamp, 443);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3343, 'Дауншифтинг в Португалии: остановились в эко-деревне, работали в саду 4 часа в день за еду и жильё. Лучший опыт, который меняет взгляд на потребление.', '2026-04-23 16:12:34.017153'::timestamp, 443);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3344, 'Лучшее время для фото в горах — за час до рассвета. Свет мягкий, туман на дне ущелья и ни одного человека в кадре. Будильник на 4 утра — лучший инструмент.', '2026-04-23 16:12:35.613695'::timestamp, 444);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3345, 'Кулинарный тур по Тоскане: не ходите в рестораны в туристических центрах. Езжайте в маленькие деревни — таверна за 10 евро даст обед из 5 блюд с вином.', '2026-04-23 16:12:37.203839'::timestamp, 448);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3346, 'Мачу-Пикчу: покупайте билет на 6 утра. Первый час вы почти один, пока туристы из Куско не подтянутся. И не забудьте паспорт — без него не пустят.', '2026-04-23 16:12:38.775812'::timestamp, 449);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3348, 'Берлин: лучший вид на город — с крыши Рейхстага. Бесплатно, но регистрация за месяц. В сумерках город выглядит как гигантская схема микросхем.', '2026-04-23 16:12:41.699000'::timestamp, 450);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3349, 'Стамбул: путешествуйте на паромах через Босфор. За 15 лир можно пересечь из Европы в Азию, любуясь дворцами и мечетями.', '2026-04-23 16:12:42.994081'::timestamp, 450);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3351, 'Снорклинг с черепахами на Галапагосах: не надо нырять глубоко, черепахи подплывают к поверхности. Держите дистанцию — не трогайте, можно схлопотать штраф.', '2026-04-23 16:12:46.221286'::timestamp, 451);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3352, 'Будущее за битами, которые меняются в реальном времени под настроение слушателя. Биометрия + ИИ — трек будет подстраиваться под твой пульс.', '2026-04-23 16:12:47.847489'::timestamp, 460);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3353, 'SwiftUI — это хорошо, но для сложных навигационных переходов всё ещё приходится использовать UIKit. UINavigationController + UIHostingController — мой хак на 2024 год.', '2026-04-23 16:12:49.413951'::timestamp, 470);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3354, 'Крэшлитикс + Firebase Test Lab: запуск тестов на сотнях устройств в облаке. Выявили проблемы на Samsung Galaxy J5, которые на пикселе не воспроизводились.', '2026-04-23 16:12:51.113241'::timestamp, 474);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3355, 'Восхождение на Килиманджаро через шотландский маршрут: 7 дней, ночёвки в палатках при минус 10, акклиматизация жёсткая. Но на вершине в 5 утра ты рыдаешь.', '2026-04-23 16:12:52.751175'::timestamp, 232);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3356, 'Гоночный комбез — одноразовая защита. Даже недорогой двухкожный держит падение на 100 км/ч. Джинсы с кевларом — для кофе, а не для трека.', '2026-04-23 16:12:54.519487'::timestamp, 26);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3358, 'Google Pixel 8 Pro — единственный смартфон с термометром. Измеряет температуру предметов (кастрюля, чай) и человеческое ухо. Имеет класс точности ±0.3°C, одобрен FDA.', '2026-04-23 16:13:37.786237'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3360, 'Экран с частотой 144 Гц на Xiaomi 13T Pro. Задержка сенсора — 5 мс. Играть в шутеры на телефоне стало реально, хотя пальцы всё равно толстые.', '2026-04-23 16:13:40.929008'::timestamp, 414);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3361, 'Variable rate seeding: карта почв — семена разного гибрида на разных участках. Урожайность выросла на 20%.', '2026-04-23 16:13:42.675427'::timestamp, 424);
INSERT INTO public."posts" ("id", "content", "created_at", "author_id") VALUES (3362, 'GPS-навигация на старых тракторах: можно поставить недорогой планшет с внешним GPS приёмником и приложением AgOpenGPS. 500$ вместо 10 000$.', '2026-04-23 16:13:44.485147'::timestamp, 429);
